var DATA_ES={
"exp1":{name:"Reino de Roma",desc:"Roma comenzó como un pequeño asentamiento en el monte Palatino bajo siete reyes.",facts:["Fundada en 753 a.C.","Siete reyes","Población ~30.000"],locs:[{n:"Roma",info:"Asentamiento original en siete colinas.",wiki:"Fundada el 21 de abril del 753 a.C. por Rómulo. Creció desde aldeas en las colinas hasta convertirse en ciudad-estado. Siete reyes gobernaron. La monarquía terminó cuando Tarquinio el Soberbio fue derrocado en el 509 a.C."}]},
"exp2":{name:"Conquista de Italia",desc:"La República conquistó la península itálica en 250 años.",facts:["La Guerra Latina aseguró el centro de Italia","Las Guerras Samnitas duraron más de 50 años","En 264 a.C. toda Italia estaba controlada"],locs:[{n:"Roma",info:"Sede de la República.",wiki:"Tras expulsar a los reyes, Roma estableció una república con dos cónsules y un Senado."},{n:"Veyes",info:"Ciudad etrusca destruida en el 396 a.C.",wiki:"Poderosa ciudad etrusca a 16 km de Roma. El asedio duró una década bajo Camilo. La conquista duplicó el territorio de Roma."},{n:"Capua",info:"Aliada clave de Roma en Campania.",wiki:"La ciudad más grande de Campania. Aliada con Roma en el 343 a.C. Se pasó a Aníbal en el 216 a.C."},{n:"Tarento",info:"Su caída en el 272 a.C. completó el control de Italia.",wiki:"La colonia griega más rica. Invitó a Pirro para defenderla. Cayó en el 272 a.C. completando la dominación romana."}],pathLabels:["Asedio de Veyes, 396 a.C.","Expansión hacia Campania","Conquista de la Magna Grecia"]},
"exp3":{name:"Dominio del Mediterráneo",desc:"Tres guerras púnicas convirtieron a Roma en dueña del Mediterráneo.",facts:["La Primera Guerra Púnica ganó Sicilia","Cartago destruida en 146 a.C.","Grecia cayó el mismo año"],locs:[{n:"Roma",info:"República que proyecta poder a través del mar.",wiki:"Roma se transformó de potencia terrestre italiana en superpotencia mediterránea a través de las guerras púnicas."},{n:"Cartago",info:"Destruida en el 146 a.C.",wiki:"Imperio comercial fenicio. Bajo Aníbal casi conquistó Roma. Completamente destruida en la Tercera Guerra Púnica."},{n:"Siracusa",info:"Cayó en el 212 a.C. pese a Arquímedes.",wiki:"La ciudad griega más poderosa de Sicilia. Las máquinas de guerra de Arquímedes mantuvieron a raya a los romanos durante dos años."},{n:"Corinto",info:"Saqueada en el 146 a.C.",wiki:"Una de las ciudades más ricas de Grecia. Mumio la destruyó el mismo año que Cartago."}],pathLabels:["Las flotas romanas combaten contra Cartago","Marcelo asedia Siracusa","Mumio marcha sobre Corinto"]},
"exp4":{name:"Expansión de la República Tardía",desc:"Generales ambiciosos expandieron la República: la Galia, Oriente y Egipto cayeron.",facts:["César conquistó la Galia","Pompeyo reorganizó Oriente","Egipto cayó en 30 a.C."],locs:[{n:"Roma",info:"Desgarrada por guerras civiles.",wiki:"El poder pasó del Senado a generales con ejércitos leales."},{n:"Lutetia",info:"La futura París. Conquistada por César.",wiki:"Pequeña ciudad gala en el Sena. Creció bajo dominio romano con termas, foro y anfiteatro."},{n:"Antioquía",info:"Capital de la Siria romana.",wiki:"Una de las grandes ciudades helenísticas. Reorganizada por Pompeyo en el 64 a.C. La tercera ciudad más grande del Imperio."},{n:"Alejandría",info:"Cayó tras la derrota de Cleopatra, 30 a.C.",wiki:"Capital intelectual del mundo antiguo. Tras Accio, Egipto se convirtió en provincia romana."}],pathLabels:["Las legiones de César marchan hacia la Galia","Pompeyo reorganiza Siria","Octaviano persigue a Antonio hasta Egipto"]},
"exp5":{name:"Máxima Extensión Imperial bajo Trajano",desc:"Extensión máxima: de Britania a Mesopotamia, 5 millones de km².",facts:["5 millones de km²","55-70 millones de personas","400.000 km de calzadas"],locs:[{n:"Roma",info:"Capital con 1 millón de habitantes.",wiki:"Bajo el Principado, el centro del mundo conocido. La Pax Romana trajo dos siglos de paz."},{n:"Londinium",info:"Capital de Britania.",wiki:"Fundada hacia el 47 d.C. Tras ser quemada por Boudica, fue reconstruida hasta 60.000 habitantes."},{n:"Sarmizegetusa",info:"Capital dacia conquistada por Trajano.",wiki:"Capital sagrada dacia. Minas de oro valoradas en 165 toneladas de oro."},{n:"Ctesifonte",info:"Conquista romana más oriental.",wiki:"Trajano la capturó en el 116 d.C. — máxima extensión oriental. Abandonada por Adriano."}],pathLabels:["Claudio invade Britania, 43 d.C.","Trajano cruza el Danubio hacia Dacia","Trajano avanza sobre Partia"]},
"exp6":{name:"Consolidación de Adriano",desc:"Adriano abandonó las conquistas orientales, construyó murallas y estableció fronteras defendibles.",facts:["Abandonó las conquistas orientales de Trajano","117 km de muralla en Britania","Visitó casi todas las provincias"],locs:[{n:"Roma",info:"Capital imperial bajo un emperador constructor.",wiki:"Adriano se retiró de las conquistas mesopotámicas de Trajano inmediatamente al tomar el poder. Se centró en la consolidación sobre la expansión, viajando a casi todas las provincias en persona."},{n:"Muro de Adriano",info:"Frontera de 117 km a través del norte de Britania.",wiki:"Construido entre 122-128 d.C. 117 km de costa a costa con 80 fortines, 160 torres y 15 fuertes. Definió la frontera noroccidental de Roma durante 300 años."},{n:"Atenas",info:"La ciudad amada de Adriano.",wiki:"Adriano era un apasionado helenófilo. Completó el Templo de Zeus Olímpico tras 600 años de construcción. Construyó un arco inscrito: 'Esta es la ciudad de Adriano.'"},{n:"Tívoli",info:"Villa de Adriano — obra maestra arquitectónica.",wiki:"Más de 30 edificios en 120 hectáreas recreando lugares que Adriano visitó. Incluía réplicas del Canopo egipcio y el Liceo griego."}],pathLabels:["Construye el Muro a través de Britania","Reconstruye Atenas con esplendor griego","Diseña su retiro villa en Tívoli"]},
"exp7":{name:"Crisis y Fragmentación",desc:"El Imperio casi colapsó: 26 pretendientes, estados separatistas, peste e invasiones.",facts:["26 pretendientes rivales en 50 años","Aureliano: 'Restaurador del Mundo'","Murallas Aurelianas construidas alrededor de Roma"],locs:[{n:"Roma",info:"Aureliano construyó muros defensivos en el 271 d.C.",wiki:"La crisis comenzó cuando Maximino el Tracio asesinó a Severo Alejandro en el 235. Cincuenta años de caos: 26 pretendientes al trono, invasiones bárbaras, peste y colapso económico. Aureliano reunificó el imperio hacia el 274."},{n:"Augusta Treverorum",info:"Capital del Imperio Galo separatista.",wiki:"Póstumo declaró el Imperio Galo en el 260, gobernando la Galia, Britania e Hispania independientemente durante 14 años. Tréveris sirvió como su capital."},{n:"Palmira",info:"Imperio oriental separatista de Zenobia.",wiki:"La reina Zenobia se apoderó de las provincias orientales de Roma en el 270, gobernando Egipto, Siria y Anatolia. Aureliano la derrotó y capturó en el 272."},{n:"Sirmio",info:"Punto clave de despliegue militar en el Danubio.",wiki:"Base estratégica para la defensa del Danubio. Varios emperadores fueron proclamados aquí durante la crisis. Lugar de nacimiento de varios emperadores soldado."}],pathLabels:["El Imperio Galo se separa, 260 d.C.","Zenobia se apodera del Este, 270 d.C.","Aureliano reconquista el imperio"]},
"exp8":{name:"Tetrarquía de Diocleciano",desc:"Sistema de cuatro emperadores reorganizó un imperio destrozado en un estado funcional.",facts:["Gobierno de cuatro emperadores","Se crearon más de 100 provincias","Primer emperador en abdicar voluntariamente"],locs:[{n:"Nicomedia",info:"Capital oriental de Diocleciano.",wiki:"Diocleciano gobernó desde aquí en lugar de Roma. Construyó un complejo palaciego masivo. Emitió el Edicto de Precios Máximos para combatir la inflación."},{n:"Mediolanum",info:"Capital occidental de Maximiano.",wiki:"Milán reemplazó a Roma como capital occidental efectiva. Más cerca de las fronteras alpina y del Rin que necesitaban defensa."},{n:"Augusta Treverorum",info:"Capital de Constancio en la Galia.",wiki:"Tréveris se convirtió en residencia imperial importante. La Puerta Nigra y las termas imperiales sobreviven de este período."},{n:"Sirmio",info:"Capital danubiana de Galerio.",wiki:"Controlaba la crítica frontera del Danubio. Una de las cuatro capitales tetrárquicas que gestionaban la defensa del vasto imperio."}],pathLabels:["Este y Oeste dividen el gobierno","Augusto y César occidentales coordinan","Augusto y César orientales coordinan"]},
"exp9":{name:"Conquista de Hispania",desc:"200 años de conquista desde las guerras púnicas hasta Augusto: la guerra provincial más larga de Roma.",facts:["200 años para conquistar","Numancia: 20 años de resistencia","Cuna de Trajano y Adriano"],locs:[{n:"Numancia",info:"Resistió a Roma durante 20 años.",wiki:"Fortaleza celtíbera que desafió a Roma durante dos décadas. En el 133 a.C., Escipión Emiliano la asedió con 60.000 tropas. Los 4.000 defensores eligieron el suicidio colectivo antes que rendirse."},{n:"Itálica",info:"Primer asentamiento romano en Hispania, 206 a.C.",wiki:"Fundada por Escipión Africano para veteranos heridos. Lugar de nacimiento de los emperadores Trajano y Adriano. Anfiteatro espectacular con capacidad para 25.000."},{n:"Emerita Augusta",info:"Actual Mérida — fundada por Augusto para legionarios retirados.",wiki:"Fundada en el 25 a.C. como colonia para veteranos de las guerras cántabras. Teatro, anfiteatro, acueducto y puente sobreviven. Llamada 'la Roma española.'"},{n:"Carthago Nova",info:"Capturada por Escipión en el 209 a.C.",wiki:"Base de Aníbal en España. Escipión Africano la capturó en un solo día aprovechando la marea baja en la laguna. Las minas de plata más ricas de España estaban cerca."}],pathLabels:["Los Escipiones invaden España durante las guerras púnicas","200 años de resistencia en el centro de España","Augusto completa la conquista"]},
"exp10":{name:"Conquista de Britania",desc:"Claudio invadió con 40.000 soldados; Boudica casi lo revirtió.",facts:["40.000 soldados invadieron","Boudica quemó tres ciudades","'Crean un desierto y lo llaman paz'"],locs:[{n:"Richborough",info:"Lugar de desembarco de la invasión romana, 43 d.C.",wiki:"Rutupiae — donde desembarcaron cuatro legiones bajo Aulo Plaucio. El propio Claudio llegó con elefantes de guerra para el empuje final hacia Camulodunum."},{n:"Camulodunum",info:"Actual Colchester — primera capital romana de Britania.",wiki:"Capital de la tribu catuvelaunos. Claudio aceptó la rendición de 11 reyes británicos aquí. Se construyó un enorme templo a Claudio — luego quemado por Boudica."},{n:"Londinium",info:"Quemada por Boudica en el 60 d.C., reconstruida como capital provincial.",wiki:"Originalmente un pequeño puesto comercial. Tras ser quemada por Boudica, fue reconstruida como la ciudad más grande de Britania con unos 60.000 habitantes."},{n:"Mons Graupius",info:"Batalla más septentrional de Agrícola, 84 d.C.",wiki:"Agrícola derrotó a los caledonios bajo Calgaco. Tácito registra: 'Crean un desierto y lo llaman paz.' Lo más al norte que Roma luchó jamás en Britania."}],pathLabels:["Las legiones avanzan hacia Camulodunum, 43 d.C.","Londinium se convierte en el centro de la Britania romana","Agrícola avanza hacia las Tierras Altas de Escocia"]},
"exp11":{name:"Conquista de Grecia y Macedonia",desc:"Cuatro guerras macedónicas acabaron con la independencia griega; Flaminino declaró la libertad griega, luego Roma destruyó Corinto.",facts:["Flaminino declaró la libertad griega (196 a.C.)","Pidna acabó con el reino macedonio","Corinto destruida el mismo año que Cartago (146 a.C.)"],locs:[{n:"Cinoscéfalos",info:"197 a.C.: Flaminino derrotó la falange de Filipo V.",wiki:"La batalla de Cinoscéfalos demostró la superioridad de la legión romana sobre la falange macedonia. La formación rígida de Filipo V se desintegró en terreno irregular mientras los manípulos romanos flexibles explotaban cada brecha. Flaminino declaró dramáticamente la libertad griega en los Juegos Ístmicos del 196 a.C. — la multitud lloró."},{n:"Pidna",info:"168 a.C.: fin decisivo del reino macedonio.",wiki:"Emilio Paulo aplastó al rey Perseo en Pidna. La falange demostró de nuevo ser fatalmente inflexible — una vez abiertas las brechas, los legionarios penetraron y masacraron desde dentro. 20.000 macedonios muertos. Perseo fue paseado en el triunfo de Paulo."},{n:"Corinto",info:"146 a.C.: destruida por Mumio — mismo año que Cartago.",wiki:"El cónsul Mumio arrasó Corinto para enviar un mensaje: la resistencia era inútil. Los tesoros artísticos fueron enviados a Roma. La ciudad permaneció abandonada 100 años hasta que César la refundó en el 44 a.C. Grecia se convirtió en la provincia romana de Acaya."}],pathLabels:["Guerras Macedónicas: de Cinoscéfalos a Pidna","Roma aplasta la última resistencia en Corinto"]},
"exp12":{name:"Anexión de Egipto",desc:"Octavio se apoderó de Egipto tras Accio: la provincia más rica se convirtió en dominio personal del emperador.",facts:["Provincia personal del emperador — senadores excluidos","Un tercio del suministro de grano de Roma","13 obeliscos egipcios siguen en Roma"],locs:[{n:"Alejandría",info:"Cleopatra y Antonio murieron aquí, 30 a.C.",wiki:"Tras derrotar a Antonio y Cleopatra en Accio (31 a.C.), Octaviano entró en Alejandría en el 30 a.C. Ambos se suicidaron. Egipto se convirtió en provincia romana — pero a diferencia de cualquier otra, era propiedad personal del emperador, prohibida a los senadores. Su excedente de grano alimentaba Roma; sus impuestos enriquecieron el tesoro. Egipto producía un tercio del suministro de grano de Roma."},{n:"Roma",info:"Obeliscos egipcios transportados para adornar la capital.",wiki:"Augusto trajo obeliscos egipcios a Roma, iniciando una moda que continuó durante siglos. Trece obeliscos antiguos siguen en pie en Roma. El control de Egipto dio a Augusto un poder económico sin igual — quien controlaba el grano de Egipto tenía a Roma por la garganta."}],pathLabels:["Grano y riqueza fluyen de Egipto a Roma"]},
"exp13":{name:"Romanización",desc:"Cómo los pueblos conquistados se volvieron romanos: calzadas, colonias, ciudadanía, latín y arquitectura transformaron el Mediterráneo.",facts:["Calzadas, colonias, ciudadanía, latín","Los galos fueron emperadores en pocas generaciones","Timgad: 'cazar, bañarse, jugar, reír — esto es vivir'"],locs:[{n:"Roma",info:"Centro del proceso de romanización.",wiki:"El genio de Roma fue la integración, no solo la conquista. Los pueblos derrotados fueron gradualmente absorbidos mediante un sistema en capas: las calzadas los conectaban, las colonias se asentaban entre ellos, el latín se convirtió en la lengua del derecho y el comercio, y la ciudadanía se extendía como recompensa. En pocas generaciones, los 'bárbaros' se convirtieron en romanos — senadores, emperadores y poetas."},{n:"Nemausus",info:"Actual Nimes — una obra maestra de la romanización.",wiki:"Nemausus (Nimes) en la Galia meridional ejemplifica la romanización. El templo de la Maison Carrée, el anfiteatro y la Tour Magne muestran cómo una ciudad celta se transformó en una ciudad completamente romana. La familia del emperador Antonino Pío procedía de aquí — los galos se habían convertido en emperadores."},{n:"Timgad",info:"Ciudad romana de cuadrícula perfecta en el norte de África.",wiki:"Fundada por Trajano en el 100 d.C. para veteranos. Construida sobre un plan de cuadrícula perfecto con foro, teatro, termas, biblioteca y arco triunfal. Una inscripción reza: 'Cazar, bañarse, jugar, reír — esto es vivir.' Enterrada por la arena, es una de las ciudades romanas mejor conservadas."}],pathLabels:["La romanización transforma la Galia","Ciudades de cuadrícula romana plantadas en África"]},
"exp14":{name:"El Limes: Defensas de Frontera",desc:"Frontera Rin-Danubio con empalizadas, murallas de piedra, torres de vigilancia y fuertes: la piel del imperio.",facts:["568 km de Limes germánico con 900 torres","Frontera del Danubio: la más larga","Patrimonio de la Humanidad UNESCO"],locs:[{n:"Fuerte Saalburg",info:"Fuerte romano reconstruido en el Limes germánico.",wiki:"El Saalburg es un fuerte auxiliar reconstruido en el Limes germánico superior en Alemania. El káiser Guillermo II lo reconstruyó en 1897-1907. El Limes Germanicus se extendía 568 km desde el Rin hasta el Danubio con 900 torres de vigilancia y 60 fuertes. Patrimonio de la Humanidad por la UNESCO."},{n:"Carnuntum",info:"Importante base legionaria en el Limes del Danubio.",wiki:"Carnuntum custodiaba la frontera del Danubio con una fortaleza legionaria y ciudad civil de 50.000. Marco Aurelio escribió sus Meditaciones aquí. La escuela de gladiadores reconstruida y el Heidentor (puerta pagana) están entre los restos fronterizos mejor conservados."},{n:"Dura Europos",info:"Fortaleza del desierto en la frontera oriental del Éufrates.",wiki:"Guarnición fronteriza en el Éufrates en Siria. Las excavaciones revelaron una sinagoga, iglesia doméstica cristiana y mitreo uno junto al otro — reflejando la naturaleza multicultural de la vida fronteriza. Destruida por los sasánidas hacia el 257 d.C."}],pathLabels:["Los Limes germánico y del Danubio se conectan","Frontera oriental en el Éufrates"]},
"exp15":{name:"División del Imperio",desc:"La muerte de Teodosio dividió el imperio entre sus hijos Arcadio y Honorio; nunca se reunificó.",facts:["Teodosio murió el 17 de enero del 395 d.C.","Oriente sobrevivió 1.058 años más","Occidente cayó en 81 años"],locs:[{n:"Constantinopla",info:"Capital del Imperio Romano de Oriente bajo Arcadio.",wiki:"Cuando Teodosio I murió el 17 de enero del 395 d.C., el Imperio Romano se dividió entre sus dos hijos jóvenes. Arcadio (17 años) recibió el Este, gobernando desde Constantinopla. Esta división resultó permanente — las dos mitades nunca se reunieron. El Este prosperó otros 1.058 años; el Oeste cayó en 81."},{n:"Rávena",info:"Capital occidental bajo Honorio.",wiki:"Honorio (10 años) recibió el Oeste, trasladando pronto su capital de Milán a Rávena — protegida por marismas y un corto cruce marítimo a Constantinopla. Desde aquí, una sucesión de emperadores cada vez más impotentes vio desmoronarse el imperio occidental."},{n:"Milán",info:"Capital occidental antes del traslado a Rávena.",wiki:"Milán (Mediolanum) había servido como capital occidental desde la época de Diocleciano. Honorio la abandonó por Rávena en el 402 tras la amenaza de las fuerzas góticas de Alarico en el norte de Italia. El traslado simbolizó la retirada del Oeste de la defensa activa."}],pathLabels:["El imperio se divide permanentemente","La capital se retira a Rávena"]},
"cam1":{name:"Campaña Italiana de Aníbal",desc:"Aníbal cruzó los Alpes con elefantes, devastando Italia durante 15 años.",facts:["Cruzó los Alpes con 37 elefantes","Cannas: ~70.000 muertos","Derrotado en Zama en 202 a.C."],locs:[{n:"Carthago Nova",info:"Punto de partida.",wiki:"Aníbal partió con unos 90.000 infantes, 12.000 jinetes, 37 elefantes."},{n:"Cruce de los Alpes",info:"37 elefantes. Muchos perecieron.",wiki:"Una de las hazañas más audaces de la historia. Llegó con solo unos 26.000 hombres."},{n:"Lago Trasimeno",info:"217 a.C.: la emboscada más grande de la historia.",wiki:"15.000 romanos muertos en tres horas."},{n:"Cannas",info:"216 a.C.: 50-70.000 muertos.",wiki:"La victoria táctica más perfecta de la historia. El doble envolvimiento mató a 50-70.000."},{n:"Zama",info:"202 a.C.: Escipión derrota a Aníbal.",wiki:"Escipión usó las propias tácticas de Aníbal contra él."}],pathLabels:["Aníbal cruza los Pirineos y la Galia","Descenso de los Alpes a Italia","Marcha hacia el sur hasta Cannas","Escipión invade África"],pathWikis:["Partió en primavera del 218 a.C. con 90.000 tropas y 37 elefantes.","El cruce alpino mató a miles. Emergió con solo 26.000 hombres.","Tras Trebia y Trasimeno, 86.400 romanos se encontraron con Aníbal en Cannas.","Escipión invadió en el 204 a.C., forzando el regreso de Aníbal."]},
"cam2":{name:"Guerras Gálicas de César",desc:"Ocho años conquistando la Galia, extendiendo Roma hasta el Atlántico.",facts:["~1 millón de galos muertos","Alesia: asedio magistral","De Bello Gallico"],locs:[{n:"Roma",info:"César necesitaba gloria.",wiki:"A los 42, profundamente endeudado. Vio oportunidad en la Galia."},{n:"Bibracte",info:"58 a.C.: primera victoria.",wiki:"Derrotó a unos 70.000 guerreros helvecios."},{n:"Gergovia",info:"52 a.C.: rara derrota.",wiki:"Perdió 700 legionarios y 46 centuriones."},{n:"Alesia",info:"52 a.C.: asedio decisivo.",wiki:"Atrapó a 80.000 guerreros con 40 km de muros. Derrotó al ejército de socorro de 250.000."},{n:"Uxeloduno",info:"51 a.C.: resistencia final.",wiki:"Cortó el suministro de agua. Cortó las manos a todos los guerreros."}],pathLabels:["Las legiones interceptan a los helvecios","Hacia la Galia central","Persecución hasta Alesia","Pacificación final"],pathWikis:["Marchó forzada desde Roma a Ginebra en 8 días.",null,"Construyó 40 km de obras de asedio.",null]},
"cam3":{name:"Guerra Civil de César",desc:"Tras el Rubicón, César persiguió a Pompeyo por el Mediterráneo.",facts:["'Alea iacta est'","Derrotó a Pompeyo en Farsalia","Se convirtió en dictador perpetuo"],locs:[{n:"Rubicón",info:"Cruzarlo era traición.",wiki:"10 de enero del 49 a.C. 'Alea iacta est.'"},{n:"Farsalia",info:"48 a.C.: derrotó a Pompeyo.",wiki:"22.000 contra 45.000. La cuarta línea oculta dispersó la caballería de Pompeyo."},{n:"Alejandría",info:"Aliado con Cleopatra.",wiki:"Pompeyo asesinado en la playa. César instaló a Cleopatra."},{n:"Tapsos",info:"46 a.C.: África.",wiki:"Catón se suicidó antes que aceptar la clemencia de César."},{n:"Munda",info:"45 a.C.: batalla más dura.",wiki:"César personalmente animó a las tropas. 30.000 pompeyanos murieron."}],pathLabels:["Persigue a Pompeyo hasta Grecia","Persigue a Pompeyo hasta Egipto","Campañas en África","Batalla final en España"],pathWikis:["Se apoderó de Italia en 60 días, cruzó el Adriático en invierno.","Pompeyo asesinado en la playa por agentes de Ptolomeo.",null,null]},
"cam4":{name:"Revuelta de Esclavos de Espartaco",desc:"70.000 esclavos en el mayor levantamiento de la historia romana.",facts:["70.000 esclavos se unieron","Derrotaron ejércitos romanos","6.000 crucificados"],locs:[{n:"Capua",info:"Escapó de la escuela de gladiadores.",wiki:"73 a.C.: Espartaco lideró a 70 gladiadores fuera. Miles se unieron — creció hasta 70.000."},{n:"Monte Vesubio",info:"Primer campamento rebelde.",wiki:"Los romanos asediaron el único camino. Espartaco descendió en rappel por los acantilados de noche."},{n:"Lucania",info:"Batalla final. 6.000 crucificados.",wiki:"71 a.C.: Craso acorraló a Espartaco. El cuerpo nunca fue encontrado. 6.000 crucificados en la Vía Apia."}],pathLabels:["Los gladiadores escapan al Vesubio","Acorralado por Craso"]},
"cam5":{name:"Batalla del Bosque de Teutoburgo",desc:"Arminio aniquiló tres legiones: el mayor desastre de Roma.",facts:["20.000 muertos","'¡Devuélveme mis legiones!'","Moldeó las fronteras europeas"],locs:[{n:"Bosque de Teutoburgo",info:"20.000 hombres destruidos.",wiki:"9 de septiembre del 9 d.C. Arminio llevó a las legiones a una emboscada durante tres días de combate bajo la lluvia. Augusto: '¡Devuélveme mis legiones!'"},{n:"Roma",info:"Augusto quedó devastado.",wiki:"Los números de legiones XVII-XIX retirados permanentemente. Estableció el Rin como frontera de Roma para siempre."}],pathLabels:["Varo marcha hacia Germania"]},
"cam6":{name:"Guerra Pírrica",desc:"Pirro de Epiro invadió Italia con elefantes: ganó batallas pero perdió la guerra.",facts:["'¡Otra victoria así y estamos perdidos!'","20 elefantes de guerra","Roma ganó todo el sur de Italia"],locs:[{n:"Tarento",info:"Colonia griega que invitó a Pirro.",wiki:"Ciudad más rica de la Magna Grecia. Insultó a los embajadores romanos, luego entró en pánico y llamó a Pirro con 25.000 tropas y 20 elefantes de guerra."},{n:"Heraclea",info:"280 a.C.: primera victoria de Pirro.",wiki:"Los romanos enfrentaron elefantes de guerra por primera vez. Pirro ganó pero perdió 4.000 hombres — un anticipo de los costes por venir."},{n:"Ásculo",info:"279 a.C.: '¡Otra victoria así y estamos perdidos!'",wiki:"Batalla de dos días. Pirro ganó de nuevo pero sufrió bajas devastadoras. Origen de la frase 'victoria pírrica.'"},{n:"Benevento",info:"275 a.C.: victoria decisiva de Roma.",wiki:"El cónsul Manio Curio Dentato volvió los elefantes de Pirro contra sus propios hombres. Pirro se retiró a Epiro, terminando la resistencia griega en Italia."}],pathLabels:["Pirro marcha desde Tarento","Avanza hacia el norte hasta Ásculo","Choque final en Benevento"],pathWikis:["Desembarcó con 25.000 soldados, 20 elefantes y sueños de imperio occidental.",null,"Los elefantes entraron en pánico y pisotearon a las propias tropas de Pirro."]},
"cam7":{name:"Guerras Judeo-Romanas",desc:"La Gran Revuelta: el Templo destruido, la última resistencia en Masada.",facts:["Templo destruido en 70 d.C.","960 murieron en Masada","El Arco de Tito sigue en pie"],locs:[{n:"Jerusalén",info:"Templo destruido en el 70 d.C.",wiki:"Tito asedió Jerusalén con 70.000 tropas. Tras cinco meses, los romanos atravesaron los muros y quemaron el Segundo Templo. Josefo registró que 1,1 millones murieron y 97.000 fueron esclavizados."},{n:"Jotapata",info:"Asedio de 47 días; Josefo se rindió.",wiki:"Josefo comandó la defensa. Tras la caída, se escondió en una cueva y sobrevivió a un pacto de suicidio. Profetizó que Vespasiano sería emperador."},{n:"Masada",info:"Última resistencia — 960 eligieron la muerte antes que la esclavitud.",wiki:"Fortaleza montañosa de Herodes. Los romanos construyeron una rampa de asedio masiva durante meses. En la noche final, 960 defensores se mataron antes que rendirse. Solo 7 sobrevivieron."},{n:"Roma",info:"El Arco de Tito conmemora la victoria.",wiki:"Tito celebró un triunfo. El Arco de Tito muestra a soldados llevando la menorá del Templo. Los botines financiaron la construcción del Coliseo."}],pathLabels:["Vespasiano pacifica Galilea, 67 d.C.","Tito asedia Jerusalén, 70 d.C.","Asedio de Masada, 73 d.C."],pathWikis:["Redujo metódicamente fortaleza tras fortaleza.","Asedio de cinco meses. El Templo quemado en agosto.","Silva construyó muros de circunvalación y una rampa de asalto masiva."]},
"cam8":{name:"Guerras Dacias de Trajano",desc:"Dos campañas conquistaron Dacia: enorme botín de oro financió el programa constructivo de Trajano.",facts:["165 toneladas de oro capturadas","Decebalo se suicidó","Columna de Trajano: 2.662 figuras"],locs:[{n:"Roma",info:"La Columna de Trajano conmemora las guerras.",wiki:"Trajano lanzó la mayor campaña militar romana desde Augusto. La victoria trajo 165 toneladas de oro y 330 de plata a Roma, financiando obras públicas masivas."},{n:"Drobeta",info:"Puente de Trajano sobre el Danubio.",wiki:"Apolodoro diseñó el puente más grande del mundo antiguo — 1.135 m de largo con 20 pilares. Cada pilar se elevaba 50 m desde el lecho del río. Adriano lo desmanteló después."},{n:"Tapae",info:"Batalla clave en ambas campañas.",wiki:"Lugar de grandes enfrentamientos en el 101 y 105 d.C. Los romanos lucharon a través de pasos montañosos para alcanzar Sarmizegetusa."},{n:"Sarmizegetusa Regia",info:"Capital dacia — asaltada en el 106 d.C.",wiki:"Centro político y religioso sagrado dacio en las montañas de Orăștie. Trajano la asedió y destruyó. El rey Decébalo se cortó la garganta antes que ser capturado."}],pathLabels:["Las legiones cruzan el Danubio en Drobeta","Avanzan por pasos montañosos hasta Tapae","Asaltan Sarmizegetusa Regia"],pathWikis:["Puente de Trajano: 1.135 m, el más grande del mundo antiguo.",null,"Decébalo se suicidó. Dacia se convirtió en provincia romana."]},
"cam9":{name:"Batalla de Adrianópolis",desc:"La caballería goda aniquiló el ejército de Valente: la peor derrota desde Cannas.",facts:["Emperador Valente muerto","Peor derrota desde Cannas","Principio del fin de Roma"],locs:[{n:"Adrianópolis",info:"9 de agosto del 378 d.C.: derrota que destrozó el imperio.",wiki:"El emperador Valente atacó sin esperar refuerzos occidentales. La caballería gótica regresó inesperadamente y rodeó al ejército romano. Dos tercios del ejército oriental — 20.000 hombres — murieron, incluido el propio emperador."},{n:"Constantinopla",info:"Teodosio reconstruyó el ejército oriental.",wiki:"Tras Adrianópolis, Teodosio I fue nombrado para restaurar el orden. Asentó a los godos como foederati dentro del imperio — un precedente que resultaría fatal."},{n:"Roma",info:"El Imperio Occidental sacudido hasta sus cimientos.",wiki:"Ammiano Marcelino, que pudo presenciar la batalla, la llamó la peor derrota desde Cannas. Demostró que Roma ya no podía derrotar a ejércitos bárbaros en batalla campal."}],pathLabels:["Valente marcha desde Constantinopla","Supervivientes huyen a Constantinopla"],pathWikis:["Se negó a esperar los refuerzos occidentales de Graciano.",null]},
"cam10":{name:"Guerra Civil de Sila",desc:"Primer general romano en marchar sobre Roma; las proscripciones mataron a miles.",facts:["Primer general en marchar sobre Roma","520 nombres proscritos","Abdicó voluntariamente la dictadura"],locs:[{n:"Roma",info:"Marchó sobre su propia ciudad dos veces.",wiki:"En el 88 a.C., Sila se convirtió en el primer romano en marchar legiones contra Roma cuando su mando oriental fue transferido a Mario. Tras derrotar a Mitrídates, regresó en el 83 a.C. y aplastó a los marianos en la batalla de la Puerta Colina."},{n:"Atenas",info:"Saqueada en el 86 a.C. durante la guerra mitridática.",wiki:"Sila asedió y saqueó Atenas para castigar su alianza con Mitrídates. Despojó la ciudad de tesoros. Derrotó a Mitrídates en Queronea y Orcómeno."},{n:"Preneste",info:"Mario el Joven atrapado y muerto aquí.",wiki:"Las fuerzas de Sila asediaron Preneste. Cayo Mario el Joven se suicidó cuando cayó la ciudad. Sila exhibió su cabeza en las puertas de Roma."},{n:"Puerta Colina",info:"82 a.C.: batalla decisiva por la propia Roma.",wiki:"1 de noviembre del 82 a.C. Las fuerzas de Sila combatieron toda la noche contra samnitas y marianos en las puertas de Roma. La victoria le dio control total. Luego publicó las listas de proscripción."}],pathLabels:["Sila saquea Atenas, derrota a Mitrídates","Regresa a Italia para la guerra civil","Asedia a los marianos en Preneste"],pathWikis:["Despojó tesoros griegos. Ganó en Queronea y Orcómeno.","Desembarcó en Brundisium con 40.000 veteranos.",null]},
"cam11":{name:"Guerras Marcomanas",desc:"Marco Aurelio luchó contra tribus germánicas a lo largo del Danubio durante 14 años.",facts:["Meditaciones escritas en campaña","Leyenda del Milagro de la Lluvia","14 años de guerra fronteriza"],locs:[{n:"Roma",info:"Vendió mobiliario del palacio para financiar la guerra.",wiki:"Las guerras marcomanas fueron la amenaza más seria desde Aníbal. Los bárbaros llegaron hasta Aquilea en el norte de Italia. Marco Aurelio subastó muebles imperiales en lugar de subir impuestos."},{n:"Carnuntum",info:"Fortaleza legionaria y cuartel general de Marco Aurelio.",wiki:"Base importante en el Danubio donde Marco Aurelio dirigió operaciones. Escribió partes de sus Meditaciones aquí entre campañas."},{n:"Vindobona",info:"Actual Viena. Marco Aurelio pudo morir aquí.",wiki:"Fortaleza fronteriza que se convirtió en campamento permanente. Algunas fuentes dicen que Marco Aurelio murió aquí el 17 de marzo del 180 d.C."},{n:"Aquilea",info:"Los bárbaros llegaron tan al sur en el 167 d.C.",wiki:"Marcomanos y cuados invadieron la propia Italia por primera vez en siglos, asediando Aquilea. El shock obligó a Roma a tomar la amenaza en serio."}],pathLabels:["Marco Aurelio corre al norte cuando los bárbaros alcanzan Italia","Contraofensiva hasta la frontera del Danubio","Operaciones a lo largo del Danubio, 170-180 d.C."]},
"cam12":{name:"Batalla de Carras",desc:"Catástrofe de Craso contra Partia: 20.000 muertos, 10.000 capturados.",facts:["20.000 muertos, 10.000 capturados","Oro fundido vertido en la garganta de Craso","Acabó con el Primer Triunvirato"],locs:[{n:"Carras",info:"Actual Harran, Turquía.",wiki:"Junio del 53 a.C. Craso llevó siete legiones profundamente al desierto mesopotámico. Arqueros a caballo partos con reabastecimiento por caravana de camellos rodearon a los romanos. La caballería de Surena fingió retirada y luego llovió flechas. 20.000 romanos muertos, 10.000 capturados. Craso muerto en una conferencia — oro fundido vertido por su garganta, burlándose de su codicia."},{n:"Roma",info:"Destrozó el Primer Triunvirato.",wiki:"Con Craso muerto, el equilibrio entre César y Pompeyo colapsó. La guerra civil se hizo inevitable. Las águilas capturadas atormentaron a Roma durante 33 años hasta que Augusto las recuperó diplomáticamente en el 20 a.C."}],pathLabels:["Craso marcha hacia el desierto"]},
"cam13":{name:"Revuelta de Boudica",desc:"La reina icena quemó Colchester, Londres y St Albans: 70.000 muertos.",facts:["70.000 romanos muertos","Tres ciudades destruidas","Boudica se envenenó tras la derrota"],locs:[{n:"Camulodunum",info:"Primera ciudad destruida — templo de Claudio quemado.",wiki:"60 d.C. Los icenos y trinovantes de Boudica quemaron la colonia indefensa. El templo de Claudio, donde se refugiaron los defensores, cayó tras dos días. La capa de ceniza sigue visible en excavaciones arqueológicas."},{n:"Londinium",info:"Abandonada por Suetonio — quemada hasta los cimientos.",wiki:"El gobernador Suetonio Paulino se retiró en lugar de defender Londres, sacrificando la ciudad. Una capa de ceniza roja-negra del 60 d.C. yace 4 metros bajo las calles modernas."},{n:"Verulamium",info:"Actual St Albans — tercera ciudad destruida.",wiki:"El municipio fue quemado tras Londres. Tácito registra 70.000 romanos y aliados muertos en las tres ciudades. Boudica no mostró interés en tomar prisioneros."}],pathLabels:["El ejército de Boudica marcha hacia el sur hasta Londres","La destrucción continúa en Verulamium"]},
"cam14":{name:"Invasión de Atila al Occidente",desc:"Los Campos Cataláunicos detuvieron a los hunos en la Galia; luego Atila invadió Italia.",facts:["Campos Cataláunicos: primera derrota de Atila","Refugiados de Aquileya fundaron Venecia","León I negoció la retirada"],locs:[{n:"Campos Cataláunicos",info:"Junio del 451: una de las batallas más grandes de la historia.",wiki:"Aecio — 'el último de los romanos' — aliado con visigodos bajo Teodorico I para enfrentar a Atila. La batalla fue masiva y caótica. Teodorico murió pero los hunos fueron detenidos. Atila se retiró — su primera derrota."},{n:"Aquilea",info:"Asediada y destruida por Atila, 452 d.C.",wiki:"Atila invadió Italia en el 452. Aquilea fue asediada tres meses y luego arrasada tan completamente que virtualmente desapareció. Los refugiados que huyeron a islas de la laguna fundarían eventualmente Venecia."},{n:"Mantua",info:"El papa León I se encontró con Atila aquí.",wiki:"El papa León I, con dos senadores, se encontró con Atila cerca de Mantua y lo persuadió de retirarse. La peste en su ejército y las fuerzas romanas orientales amenazando su patria influyeron en su decisión."},{n:"Roma",info:"Salvada por la diplomacia — por los pelos.",wiki:"La propia Roma se salvó solo porque Atila dio la vuelta. El encuentro se hizo legendario — Rafael lo pintó después en el Vaticano."}],pathLabels:["Atila se vuelve de la Galia hacia Italia","Avanza hacia Roma","El papa León persuade la retirada"]},
"cam15":{name:"Tercera Guerra Púnica",desc:"Escipión Emiliano asedió Cartago durante tres años; ardió 17 días.",facts:["Ardió 17 días","50.000 esclavizados","'Cartago debe ser destruida'"],locs:[{n:"Cartago",info:"Ardió 17 días. Población esclavizada.",wiki:"Roma exigió términos imposibles: Cartago debía abandonar su ciudad y trasladarse 10 millas tierra adentro. Cuando los cartagineses se negaron, Escipión Emiliano asedió la ciudad tres años. En primavera del 146 a.C., los romanos combatieron calle por calle durante seis días. La ciudad ardió 17 días. 50.000 supervivientes fueron vendidos como esclavos. Carthago delenda est."},{n:"Roma",info:"La demanda de Catón cumplida: 'Cartago debe ser destruida.'",wiki:"Catón el Viejo terminaba cada discurso en el Senado con 'Carthago delenda est.' Incluso tras la destrucción de Cartago, el sitio fue maldito y dejado desolado. Julio César la refundó después como colonia romana."}],pathLabels:["Escipión Emiliano zarpa hacia Cartago"]},
"cam16":{name:"Revuelta de Bar Kojba",desc:"Última revuelta judía: Adriano la aplastó, renombró Judea y prohibió a los judíos entrar en Jerusalén.",facts:["580.000 muertos","Judea renombrada Siria Palestina","Judíos prohibidos en Jerusalén"],locs:[{n:"Jerusalén",info:"Reconstruida como Aelia Capitolina con templo a Júpiter.",wiki:"El plan de Adriano de construir una colonia romana sobre las ruinas de Jerusalén y erigir un templo a Júpiter en el Monte del Templo provocó la revuelta. Simón bar Kojba lideró una guerra de guerrillas. Tras aplastar la revuelta, Adriano renombró Jerusalén Aelia Capitolina y prohibió a los judíos entrar."},{n:"Betar",info:"Última resistencia de Bar Kojba, 135 d.C.",wiki:"La última fortaleza cayó tras un brutal asedio. Bar Kojba fue muerto. Casio Dión registra 580.000 judíos muertos en la guerra, 50 fortalezas y 985 aldeas destruidas. Judea fue renombrada Siria Palestina para borrar la conexión judía."}],pathLabels:["Guerra de guerrillas por toda Judea"]},
"cam17":{name:"Asedio de Numancia",desc:"Escipión Emiliano asedió la fortaleza celtíbera con 60.000 soldados; 4.000 defensores eligieron el suicidio colectivo.",facts:["20 años de resistencia celtíbera","9 km de murallas de asedio","4.000 defensores eligieron suicidio colectivo"],locs:[{n:"Numancia",info:"Actual Garray, cerca de Soria, España.",wiki:"Numancia resistió a Roma 20 años, humillando a múltiples ejércitos romanos. En el 134 a.C., el Senado envió a Escipión Emiliano — destructor de Cartago — con 60.000 tropas. Construyó 9 km de muros de circunvalación en lugar de arriesgar asalto. Tras ocho meses de hambruna, la mayoría de los 4.000 defensores se mataron y quemaron la ciudad antes que rendirse. El sitio se convirtió en símbolo de resistencia heroica."},{n:"Roma",info:"El Senado humillado por repetidas victorias numantinas.",wiki:"Múltiples comandantes romanos sufrieron derrotas o tratados vergonzosos en Numancia. El Senado repudió un tratado en el 137 a.C. y envió al general deshonrado Mancino de vuelta desnudo a los numantinos. Solo el asedio metódico de Escipión tuvo éxito."}],pathLabels:["Escipión marcha a Numancia con 60.000 tropas"]},
"cam18":{name:"Belisario y la Guerra Gótica",desc:"Reconquista de Italia por Justiniano: Belisario capturó Roma, pero dos décadas de guerra devastaron la península.",facts:["Roma cambió de manos cinco veces","La población de Italia pudo reducirse a la mitad","El Senado se reunió por última vez"],locs:[{n:"Roma",info:"Cambió de manos cinco veces durante la guerra.",wiki:"Belisario entró en Roma en diciembre del 536 con solo 5.000 tropas. Los godos la asediaron en 537-538 con 150.000 hombres; Belisario resistió. Roma cambió de manos cinco veces durante la guerra. Los acueductos de la ciudad fueron cortados, su población se desplomó y el Senado se reunió por última vez. Italia fue reconquistada pero devastada."},{n:"Rávena",info:"Capital gótica — Belisario la capturó en el 540.",wiki:"Belisario capturó la capital gótica Rávena en el 540 mediante negociación en lugar de asedio. Pero la guerra se prolongó — los godos se reagruparon bajo Totila, que reconquistó la mayor parte de Italia. Justiniano envió a Narsés, que finalmente derrotó a los godos en Tagina (552) y Mons Lactarius (553)."},{n:"Constantinopla",info:"Justiniano dirigió la reconquista desde aquí.",wiki:"La ambición de Justiniano de restaurar el Imperio Romano impulsó la Guerra Gótica. Reconquistó el norte de África (533-534), luego Italia, luego el sur de España. Pero el coste fue enorme: la población de Italia pudo reducirse a la mitad, y los territorios reconquistados pronto se perdieron."}],pathLabels:["Belisario zarpa para reconquistar Italia","Capital gótica capturada en Rávena"]},
"fig1":{name:"Julio César",desc:"General, político, autor. Asesinado en los Idus de marzo.",facts:["Piratas a los 25 años","Calendario juliano","23 puñaladas"],locs:[{n:"Roma",info:"Nacido ~100 a.C. Asesinado el 15 de marzo del 44 a.C.",wiki:"Familia patricia. Capturado por piratas a los 25. Reformó el calendario. Apuñalado 23 veces."},{n:"Galia",info:"8 años conquistando.",wiki:"Conquistó 800.000 km². Se estima 1 millón de muertos."},{n:"Rubicón",info:"Cruzado en el 49 a.C.",wiki:"Cruzarlo bajo armas era traición."},{n:"Alejandría",info:"Aliado con Cleopatra.",wiki:"Lloró ante la cabeza cortada de Pompeyo. Engendró a Cesarión."}],pathLabels:["Parte hacia la Galia","Regreso y Rubicón","Viaje a Egipto"]},
"fig2":{name:"Augusto",desc:"Primer emperador. 41 años de Pax Romana.",facts:["'Encontré Roma de ladrillos'","41 años de reinado","Guardia Pretoriana"],locs:[{n:"Roma",info:"De ladrillo a mármol.",wiki:"Nacido Cayo Octavio. Adoptado por César. Creó el Principado."},{n:"Accio",info:"31 a.C.: derrotó a Antonio.",wiki:"La flota de Agripa aplastó a Antonio y Cleopatra."},{n:"Alejandría",info:"Antonio y Cleopatra murieron.",wiki:"Ambos se suicidaron cuando llegó Octaviano."},{n:"Nola",info:"Murió en el 14 d.C.",wiki:"'¿He representado bien el papel?'"}],pathLabels:["La flota zarpa hacia Accio","Persecución hasta Egipto","Viaje final"]},
"fig3":{name:"Constantino el Grande",desc:"Reunificó el Imperio. Legalizó el cristianismo. Fundó Constantinopla.",facts:["Puente Milvio 312","Edicto de Milán 313","Constantinopla más de 1.100 años"],locs:[{n:"Naissus",info:"Nacido en el 272 d.C.",wiki:"Nacido de Constancio Cloro y Helena."},{n:"York",info:"Proclamado emperador en el 306.",wiki:"Las legiones lo proclamaron Augusto a la muerte de su padre."},{n:"Roma",info:"Puente Milvio 312.",wiki:"Derrotó a Majencio. Vio la cruz: 'Con este signo vencerás.'"},{n:"Constantinopla",info:"Nueva Roma. 1.100 años.",wiki:"Dedicada el 11 de mayo del 330 d.C."}],pathLabels:["A Britania con su padre","Marcha sobre Roma","Fundación de Constantinopla"]},
"fig4":{name:"Trajano",desc:"Optimus Princeps: máxima extensión territorial. Primer emperador nacido fuera de Italia.",facts:["Primer emperador no italiano","5 millones de km² en su apogeo","Optimus Princeps: 'Mejor Gobernante'"],locs:[{n:"Itálica",info:"Nacido en el 53 d.C. cerca de la actual Sevilla.",wiki:"Nacido en Itálica, Hispania Bética — el primer emperador no italiano. Ascendió por rangos militares bajo Domiciano. Adoptado por Nerva en el 97 d.C."},{n:"Roma",info:"Construyó Foro, Columna, mercados.",wiki:"El Senado le dio el título Optimus Princeps — 'Mejor Gobernante.' Construyó el mayor complejo de foros de Roma con los Mercados y la Columna de Trajano."},{n:"Sarmizegetusa",info:"Conquistó Dacia en el 106 d.C.",wiki:"Dos campañas brutales (101-102, 105-106) conquistaron Dacia. Capturó 165 toneladas de oro. La Columna de Trajano representa las guerras en 155 escenas con 2.662 figuras."},{n:"Ctesifonte",info:"Capturó la capital parta en el 116 d.C.",wiki:"Máxima extensión oriental. Trajano lloró supuestamente ante el Tigris, diciendo que era demasiado viejo para seguir a Alejandro. Cayó enfermo y murió al regresar."},{n:"Selinus",info:"Murió aquí en agosto del 117 d.C.",wiki:"Murió de enfermedad en Cilicia en el viaje de regreso. Las cenizas llevadas de vuelta a Roma y colocadas dentro de su Columna — un honor único."}],pathLabels:["Asciende hasta emperador","Conquista Dacia en dos campañas","Avanza sobre Partia, 114-116 d.C.","Muere en el viaje de regreso"]},
"fig5":{name:"Marco Aurelio",desc:"Emperador filósofo. Meditaciones. Último de los Cinco Buenos Emperadores.",facts:["Filósofo estoico en el trono","Meditaciones escritas en campaña","Vendió muebles del palacio para la guerra"],locs:[{n:"Roma",info:"Nacido el 26 de abril del 121 d.C. Emperador 161-180.",wiki:"Nacido en familia prominente. Adoptado por Antonino Pío por disposición de Adriano. Co-gobernó con Lucio Vero 161-169. Vendió mobiliario del palacio para financiar guerras en lugar de subir impuestos. Su estatua ecuestre en el Capitolio es una de las más famosas de la antigüedad."},{n:"Carnuntum",info:"Cuartel general durante las guerras marcomanas.",wiki:"Importante fortaleza legionaria en el Danubio. Marco Aurelio pasó años aquí dirigiendo campañas. Escribió partes de sus Meditaciones entre batallas."},{n:"Vindobona",info:"Actual Viena. Probable lugar de muerte.",wiki:"Fortaleza fronteriza. Marco Aurelio probablemente murió aquí el 17 de marzo del 180 d.C. Sus últimas palabras supuestamente instaron a sus oficiales a pensar en las tropas."},{n:"Sirmio",info:"Base panónica estratégica.",wiki:"Área importante de despliegue para operaciones en el Danubio. Marco Aurelio escribió grandes secciones de sus Meditaciones aquí entre 170-180 d.C."}],pathLabels:["Campañas en la frontera del Danubio","Operaciones entre Carnuntum y Vindobona","Escribe Meditaciones en Sirmio"]},
"fig6":{name:"Nerón",desc:"Emperador artista. Matricidio. Gran Incendio. Persecución de cristianos. Suicidio.",facts:["Asesinó a su madre","Construyó la Domus Aurea","'¡Qué artista muere en mí!'"],locs:[{n:"Antium",info:"Nacido el 15 de diciembre del 37 d.C.",wiki:"Nacido Lucio Domicio Enobarbo. Su madre Agripina tramó su adopción por el emperador Claudio. Se convirtió en emperador a los 17 cuando Claudio fue envenenado."},{n:"Roma",info:"Emperador 54-68 d.C. Gran Incendio 64 d.C.",wiki:"El reinado temprano guiado por Séneca y Burro fue elogiado. Tras el 59 d.C., asesinó a su madre, dio una patada mortal a su esposa embarazada y construyó la Casa Dorada. Tras el Gran Incendio del 64, culpó a los cristianos. Los senadores se rebelaron en el 68; Nerón huyó y se apuñaló."},{n:"Baiae",info:"Intentó asesinar a Agripina aquí.",wiki:"En el 59 d.C., Nerón diseñó un barco colapsable para ahogar a su madre. Ella nadó hasta la orilla. Luego envió soldados que la apuñalaron. Ella dijo supuestamente: 'Golpea aquí — aquí parió a Nerón.'"},{n:"Corinto",info:"Intentó abrir un canal a través del istmo.",wiki:"Nerón recorrió Grecia en 66-67 d.C., compitiendo en los juegos olímpicos (ganó cada prueba por defecto). Intentó excavar el Canal de Corinto con 6.000 prisioneros de guerra judíos."}],pathLabels:["Se convierte en emperador a los 17","Intento de asesinato de Agripina en Baiae","Recorre Grecia, compite en los Juegos Olímpicos"]},
"fig7":{name:"Escipión el Africano",desc:"El mayor general republicano de Roma. Derrotó a Aníbal en Zama a los 31 años.",facts:["Derrotó a Aníbal a los 31","Conquistó Hispania a los 25","Murió en amargo exilio"],locs:[{n:"Roma",info:"Nacido ~236 a.C. en familia patricia.",wiki:"Sobrevivió a Cannas a los 17. Elegido comandante de España a los 25 sin autoridad legal — el Senado estaba desesperado. Sus tácticas audaces y carisma personal transformaron la fortuna de Roma."},{n:"Carthago Nova",info:"Capturada en un solo día, 209 a.C.",wiki:"Escipión descubrió que el puerto era vadeable con marea baja. Atacó desde la laguna mientras la fuerza principal asaltaba los muros. Capturó la capital española de Cartago en un día."},{n:"Zama",info:"202 a.C.: derrotó a Aníbal.",wiki:"La batalla decisiva de la Segunda Guerra Púnica. Escipión usó cuernos para asustar a los elefantes de Aníbal, volviéndolos contra sus propias líneas. Ganó el nombre 'Africano.'"},{n:"Liternum",info:"Murió en exilio voluntario ~183 a.C.",wiki:"Enemigos políticos liderados por Catón lo acusaron de corrupción. Se retiró amargamente a su finca. Supuestamente pidió que su epitafio dijera: 'Patria ingrata, no tendrás mis huesos.'"}],pathLabels:["Conquista la España cartaginesa a los 25","Invade África, derrota a Aníbal en Zama","Se retira a Liternum en desgracia"]},
"fig8":{name:"Diocleciano",desc:"Ascendió desde la nada. Terminó la Crisis. Creó la Tetrarquía. Abdicó voluntariamente.",facts:["De hijo de esclavo a emperador","Primera abdicación voluntaria","Se retiró a cultivar coles"],locs:[{n:"Salona",info:"Nacido ~244 d.C. en Dalmacia.",wiki:"Nacido Diocles en familia de bajo estatus — posiblemente hijo de liberto. Ascendió por rangos militares bajo Aureliano, Probo y Caro."},{n:"Nicomedia",info:"Capital imperial y sede del poder oriental.",wiki:"Gobernó desde Nicomedia en lugar de Roma. Lanzó la Gran Persecución de cristianos en el 303 d.C. Reorganizó el imperio en más de 100 provincias con una burocracia masiva nueva."},{n:"Roma",info:"Visitó Roma solo una vez como emperador.",wiki:"Diocleciano marginó a Roma. Visitó en el 303 para su celebración vicennalia pero encontró a los ciudadanos insolentes. Sus reformas salvaron el imperio pero terminaron el Principado."},{n:"Palacio de Split",info:"Se retiró aquí a cultivar coles.",wiki:"Construyó un enorme palacio fortificado en Split (Croacia) para su retiro. Cuando le instaron a retomar el poder, respondió: 'Si pudieras mostrar las coles que planté, no me pedirías que renuncie a esta paz.'"}],pathLabels:["Asciende al poder, gobierna desde Nicomedia","Visita Roma solo una vez","Se retira al Palacio de Split, 305 d.C."]},
"fig9":{name:"Adriano",desc:"Constructor, viajero, helenófilo: visitó cada provincia y remodeló el imperio.",facts:["Visitó cada provincia","Reconstruyó el Panteón","Deificó a su amante Antinoo"],locs:[{n:"Itálica",info:"Nacido en el 76 d.C. cerca de Sevilla.",wiki:"Nacido en Itálica, Hispania, como su predecesor Trajano. Ascendió por rangos militares y administrativos. Se convirtió en pupilo de Trajano y eventualmente su sucesor."},{n:"Roma",info:"Reconstruyó el Panteón. Construyó su enorme mausoleo.",wiki:"Reconstruyó el Panteón con su cúpula revolucionaria — sigue siendo la cúpula de hormigón sin refuerzo más grande del mundo. Su mausoleo se convirtió en Castel Sant'Angelo. Abandonó las conquistas orientales de Trajano para centrarse en fronteras defendibles."},{n:"Atenas",info:"Completó el Templo de Zeus Olímpico tras 600 años.",wiki:"La pasión de Adriano por la cultura griega transformó Atenas. Completó el Templo de Zeus Olímpico iniciado 600 años antes. Construyó un nuevo barrio de la ciudad con un arco inscrito: 'Esta es la ciudad de Adriano, no de Teseo.'"},{n:"Tívoli",info:"Villa de Adriano — 120 hectáreas de genio arquitectónico.",wiki:"Más de 30 edificios recreando lugares que Adriano visitó: Canopo egipcio, Liceo griego, Valle de Tempe tesalio. El proyecto de construcción privada más ambicioso de la historia romana."},{n:"Egipto",info:"Antinoo se ahogó en el Nilo, 130 d.C.",wiki:"El amado compañero de Adriano Antinoo se ahogó en el Nilo en circunstancias misteriosas. Adriano quedó devastado y lo deificó, fundando la ciudad de Antinoópolis y encargando cientos de estatuas — sobreviven más que de cualquier otra figura de la antigüedad."}],pathLabels:["Asciende a emperador","Transforma Atenas","Diseña su villa en Tívoli","Viaja a Egipto — Antinoo se ahoga"]},
"fig10":{name:"Vespasiano",desc:"Emperador soldado que restauró el orden tras la guerra civil y construyó el Coliseo.",facts:["Fundó la dinastía Flavia","Construyó el Coliseo","'¡Por Júpiter, creo que me estoy volviendo dios!'"],locs:[{n:"Falacrina",info:"Nacido en el 9 d.C. en el campo sabino.",wiki:"Nacido en modesta familia ecuestre. Ascendió por servicio militar en Britania y África. Nerón lo envió a aplastar la revuelta judía en el 66 d.C."},{n:"Roma",info:"Fundó la dinastía Flavia. Construyó el Coliseo.",wiki:"Restauró el tesoro tras la extravagancia de Nerón. Inició el Coliseo (Anfiteatro Flavio) en el sitio del lago privado de Nerón — devolviendo al pueblo lo que Nerón había robado. Famoso por su humor terrenal."},{n:"Jerusalén",info:"Comandó el asedio antes de ser emperador.",wiki:"Dirigió la Guerra Judía antes de ser proclamado emperador por las legiones orientales en el 69 d.C. Dejó a su hijo Tito para terminar el asedio de Jerusalén."}],pathLabels:["Asciende desde orígenes humildes","Comanda la Guerra Judía","Proclamado emperador, regresa a Roma"]},
"fig11":{name:"Cayo Mario",desc:"Cónsul siete veces. Salvó a Roma de las hordas del norte. Reformó el ejército. Proscribió rivales.",facts:["Cónsul siete veces","Salvó a Roma de la invasión germánica","Las reformas del ejército permitieron guerras civiles"],locs:[{n:"Arpino",info:"Nacido en el 157 a.C. — mismo pueblo que Cicerón.",wiki:"'Hombre nuevo' (novus homo) de familia modesta. Ascendió por puro talento militar y astucia política. Primero de su familia en alcanzar el consulado."},{n:"Aquae Sextiae",info:"102 a.C.: destruyó a los teutones.",wiki:"Actual Aix-en-Provence. Mario aniquiló a los teutones — 100.000 muertos o capturados. La victoria salvó Italia de la invasión germánica."},{n:"Vercelas",info:"101 a.C.: destruyó a los cimbrios.",wiki:"Al año siguiente, Mario y Catulo aplastaron a los cimbrios en Vercelas. La amenaza germánica combinada que había aterrorizado a Roma durante una década fue eliminada."},{n:"Roma",info:"Cónsul siete veces. Rival de Sila.",wiki:"Abrió el ejército a los pobres sin tierras, creando soldados profesionales leales a sus comandantes más que al estado. Esta reforma hizo posibles a los caudillos que destruyeron la República. Su rivalidad con Sila produjo la primera guerra civil de Roma."}],pathLabels:["Hombre nuevo asciende al poder","Destruye a los teutones","Destruye a los cimbrios","Regresa a la guerra política"]},
"fig12":{name:"Tiberio",desc:"Emperador reacio pero capaz que estabilizó las fronteras pero se retiró a Capri y dejó que Sejano aterrorizara Roma.",facts:["Abandonó Roma permanentemente en 26 d.C.","Reino del terror de Sejano (23-31 d.C.)","Brillante general, emperador amargado"],locs:[{n:"Roma",info:"Emperador 14-37 d.C. Dejó Roma permanentemente en el 26 d.C.",wiki:"Tiberio Claudio Nerón fue hijastro de Augusto, adoptado a regañadientes como heredero. Brillante general que aseguró el Rin y el Danubio, se convirtió en emperador amargo y desconfiado. En el 26 d.C. se retiró a Capri, gobernando por cartas y su prefecto Sejano — que condujo un reinado del terror hasta que Tiberio lo arrestó y ejecutó en el 31 d.C."},{n:"Capri",info:"Tiberio gobernó desde aquí 11 años.",wiki:"Tiberio construyó doce villas en Capri, gobernando el imperio por correspondencia. Las fuentes antiguas (Suetonio, Tácito) describen libertinaje y crueldad, aunque pueden ser propaganda senatorial. Nunca regresó a Roma. Murió en Miseno en el 37 d.C. — Calígula pudo haberlo asfixiado."},{n:"Frontera del Rin",info:"Las mayores campañas militares de Tiberio fueron aquí.",wiki:"Antes de ser emperador, Tiberio fue el mejor general de Roma. Campañeó extensamente en Germania, Panonia e Iliria. Tras el desastre de Teutoburgo (9 d.C.), Tiberio restauró la frontera del Rin. Su competencia militar nunca fue cuestionada — solo su personalidad."}],pathLabels:["Se retira a Capri, 26 d.C.","Campañas anteriores en el Rin"]},
"fig13":{name:"Claudio",desc:"Emperador inesperado: erudito tartamudo que conquistó Britania, construyó Portus y reformó la administración.",facts:["Encontrado escondido tras una cortina","Conquistó Britania","Probablemente envenenado por Agripina"],locs:[{n:"Roma",info:"Emperador 41-54 d.C. Encontrado escondido tras una cortina.",wiki:"Cuando la Guardia Pretoriana asesinó a Calígula en el 41 d.C., encontraron a Claudio escondido tras una cortina y lo proclamaron emperador. El desprecio del Senado se convirtió en respeto a regañadientes: Claudio demostró ser un administrador efectivo. Expandió la ciudadanía, reformó los tribunales, construyó el puerto de Portus y completó el acueducto Aqua Claudia. Fue probablemente envenenado por su esposa Agripina en el 54 d.C. para instalar a su hijo Nerón."},{n:"Lugdunum",info:"Nacido aquí en el 10 a.C. — actual Lyon.",wiki:"Nacido en Lugdunum (Lyon), capital de la Galia. Su nacimiento provincial y discapacidades físicas (tartamudeo, cojera y babeo) llevaron a su propia familia a despreciarlo. Augusto lo llamó 'una pobre criatura.' Pero su estudio de por vida de historia y derecho lo hizo uno de los gobernantes más competentes de Roma."},{n:"Camulodunum",info:"Claudio recibió personalmente la rendición de Britania aquí.",wiki:"Claudio invadió Britania en el 43 d.C. con cuatro legiones y — en un golpe propagandístico — elefantes de guerra. Llegó en persona durante 16 días para aceptar la rendición de 11 reyes británicos en Camulodunum (Colchester). Fue la primera gran conquista nueva de Roma en décadas."}],pathLabels:["De Lugdunum a emperador","Claudio invade Britania"]},
"fig14":{name:"Justiniano I",desc:"Último emperador que hablaba latín nativo. Corpus Iuris Civilis. Santa Sofía. Reconquistó Occidente. Sobrevivió a los disturbios de Nika.",facts:["Corpus Iuris Civilis: base del derecho europeo","Santa Sofía: catedral más grande durante 1.000 años","'El púrpura es el más noble sudario' — Teodora"],locs:[{n:"Constantinopla",info:"Emperador 527-565 d.C. Transformó la ciudad.",wiki:"Justiniano I fue el último gran emperador romano. Codificó toda la ley romana en el Corpus Iuris Civilis — aún base del derecho civil europeo. Construyó Santa Sofía — la catedral más grande durante 1.000 años. Reconquistó el norte de África, Italia y el sur de España. Sobrevivió a los disturbios de Nika (532 d.C.) solo porque la emperatriz Teodora endureció su determinación: 'La púrpura es el sudario más noble.' También sobrevivió a la Peste Justiniana que mató quizás al 40% de Constantinopla."},{n:"Rávena",info:"Centro de la Italia reconquistada — mosaicos impresionantes.",wiki:"Los mosaicos de San Vital en Rávena — mostrando a Justiniano y Teodora en esplendor imperial — están entre las mayores obras de arte supervivientes de la antigüedad tardía. Rávena se convirtió en el centro administrativo de la Italia bizantina."}],pathLabels:["Reconquista Italia"]},
"fig15":{name:"Aureliano",desc:"Restitutor Orbis: reunificó el imperio fragmentado, derrotó a Zenobia, construyó las Murallas Aurelianas. Asesinado en su apogeo.",facts:["Restitutor Orbis: Restaurador del Mundo","19 km de Murallas Aurelianas siguen en pie","Asesinado por un documento falsificado"],locs:[{n:"Roma",info:"Construyó las Murallas Aurelianas — 19 km rodeando Roma.",wiki:"Aureliano ascendió desde humildes orígenes danubianos para ser emperador en el 270 d.C. En cinco años reunificó el imperio destrozado: derrotó a los godos en el Danubio, reconquistó el Imperio Palmireno (272) y aplastó el Imperio Galo separatista (274). Construyó los 19 km de Murallas Aurelianas alrededor de Roma — señal de que la propia capital ya no estaba segura. Asesinado por sus propios oficiales en el 275, basado en un documento falsificado."},{n:"Palmira",info:"Derrotó a Zenobia aquí, 272 d.C.",wiki:"Aureliano marchó al este y derrotó a las fuerzas de Zenobia en Immae y Emesa, luego asedió Palmira. Zenobia fue capturada intentando huir a Persia. Fue paseada en cadenas de oro en el triunfo de Aureliano — pero perdonada, supuestamente viviendo sus días como matrona romana."},{n:"Tréveris",info:"Aplastó el Imperio Galo aquí, 274 d.C.",wiki:"El Imperio Galo había sido independiente desde el 260 d.C., controlando la Galia, Britania e Hispania. Aureliano derrotó al último emperador galo Tétrico en Chalons en el 274, reunificando el Oeste. El Senado lo proclamó Restitutor Orbis — Restaurador del Mundo."}],pathLabels:["Reconquista el Este de Zenobia","Aplasta el Imperio Galo"]},
"evt1":{name:"Fundación de Roma",desc:"Rómulo fundó la ciudad tras matar a Remo.",facts:["21 de abril de 753 a.C.","Siete reyes","Símbolo de la loba"],locs:[{n:"Monte Palatino",info:"Colina central.",wiki:"Los gemelos amamantados por la loba. Remo saltó los muros; Rómulo lo mató. Habitación desde ~1000 a.C."}]},
"evt2":{name:"Batalla de Cannas",desc:"El doble envolvimiento de Aníbal mató a 50-70.000.",facts:["50-70.000 muertos","Aún se estudia en academias","Roma rechazó rendirse"],locs:[{n:"Cannas",info:"Aún estudiada en academias.",wiki:"2 de agosto del 216 a.C. Aníbal dejó que el centro cediera, luego rodeó. 50-70.000 murieron incluyendo 80 senadores."},{n:"Roma",info:"Pánico. Emergencia declarada.",wiki:"El Senado reclutó esclavos. Roma se negó a negociar."}],pathLabels:["Las noticias llegan a Roma"]},
"evt3":{name:"Erupción del Vesubio",desc:"Enterró Pompeya y Herculano.",facts:["Plinio el Joven lo documentó","~16.000 muertos","Redescubierto en el siglo XVIII"],locs:[{n:"Monte Vesubio",info:"Columna de 33 km.",wiki:"24 de agosto del 79 d.C. Plinio el Joven lo describió."},{n:"Pompeya",info:"Enterrada 4-6 m de profundidad.",wiki:"Ciudad de 20.000 perfectamente conservada."},{n:"Herculano",info:"Flujos de 500°C.",wiki:"Los flujos piroclásticos conservaron madera y pergaminos."}],pathLabels:["La oleada engulle Pompeya","La nube entierra Herculano"]},
"evt4":{name:"Asesinato de César",desc:"Idus de marzo, 44 a.C.: 23 puñaladas en el Teatro de Pompeyo.",facts:["15 de marzo de 44 a.C.","23 puñaladas","Bruto y Casio entre los conspiradores"],locs:[{n:"Rávena",info:"Capital occidental.",wiki:"4 de septiembre del 476. Odoacro depuso a Rómulo Augústulo. Lo envió a vivir con pensión."},{n:"Roma",info:"Saqueada dos veces.",wiki:"La población cayó de 1 millón a ~100.000."},{n:"Constantinopla",info:"Sobrevivió hasta 1453.",wiki:"El Imperio de Oriente prosperó tras sus muros otro milenio."}],pathLabels:["La autoridad occidental termina","La influencia oriental continúa"]},
"evt5":{name:"Batalla de Accio",desc:"31 a.C.: la flota de Agripa aplastó a Marco Antonio y Cleopatra.",facts:["31 a.C.","Agripa comandó la flota","Antonio y Cleopatra huyeron a Egipto"],locs:[{n:"Teatro de Pompeyo",info:"Lugar del asesinato.",wiki:"60 conspiradores rodearon a César. Casca golpeó primero. 23 heridas. Solo una mortal."}]},
"evt6":{name:"Gran Incendio de Roma",desc:"64 d.C.: Nerón culpó a los cristianos.",facts:["Ardió 6 días","10 de 14 distritos","Nerón culpó a los cristianos"],locs:[{n:"Río Alia",info:"Romanos derrotados 11 millas al norte de Roma.",wiki:"18 de julio del 390 a.C. Los galos senones bajo Breno aplastaron al ejército romano en el afluente del Alia. El camino a Roma quedó abierto."},{n:"Monte Capitolino",info:"Única parte de Roma que resistió.",wiki:"Mientras los galos quemaban la ciudad, los defensores mantuvieron el Capitolio siete meses. Las sagradas ocas de Juno alertaron a los guardias de un asalto nocturno. Marco Manlio arrojó a los atacantes por el acantilado."},{n:"Veyes",info:"Refugiados romanos se refugiaron aquí.",wiki:"Los supervivientes huyeron a la ciudad etrusca recientemente conquistada. Camilo organizó un contraataque y fue aclamado como 'segundo fundador' de Roma."}],pathLabels:["Los galos marchan desde el Alia hacia Roma","Camilo contraataca desde Veyes"],pathWikis:["Los defensores de la ciudad colapsaron en pánico. La mayoría de romanos huyeron.",null]},
"evt7":{name:"Año de los Cuatro Emperadores",desc:"69 d.C.: Galba, Otón, Vitelio, Vespasiano en 18 meses.",facts:["Cuatro emperadores en 18 meses","Vespasiano restauró el orden","La guerra civil reveló el secreto: los emperadores podían hacerse fuera de Roma"],locs:[{n:"Accio",info:"2 de septiembre del 31 a.C.: 500 naves chocaron.",wiki:"La flota de Agripa de 400 naves de guerra ligeras superó en maniobrabilidad a las 290 naves más pesadas de Antonio. Las 60 naves egipcias de Cleopatra huyeron a mitad de batalla; Antonio abandonó su flota para seguirla."},{n:"Alejandría",info:"Antonio y Cleopatra se suicidaron.",wiki:"Octaviano los persiguió hasta Egipto. Antonio se atravesó con su espada. Cleopatra se mató — la tradición dice por mordedura de áspid — el 12 de agosto del 30 a.C. Egipto se convirtió en la provincia más rica de Roma."},{n:"Roma",info:"Octaviano regresó con poder absoluto.",wiki:"Sin rivales restantes, Octaviano controlaba el mundo romano. En el 27 a.C., el Senado le concedió el título Augusto. La República había muerto; el Imperio había comenzado."}],pathLabels:["La flota de Agripa zarpa hacia Accio","Octaviano persigue hasta Alejandría"],pathWikis:["400 naves contra 290. Las naves romanas más ligeras resultaron decisivas.","Los suicidios de Antonio y Cleopatra terminaron la última resistencia."]},
"evt8":{name:"Saqueo de Roma (410)",desc:"Los visigodos de Alarico: primer saqueo en 800 años.",facts:["Primer saqueo en 800 años","Tres días","Inspiró La Ciudad de Dios"],locs:[{n:"Mediolanum",info:"Edicto emitido aquí en febrero del 313 d.C.",wiki:"Constantino (emperador occidental) y Licinio (emperador oriental) acordaron conceder tolerancia religiosa en todo el imperio. Las iglesias recibieron estatus legal y la propiedad confiscada fue restaurada."},{n:"Roma",info:"El culto cristiano salió a la luz.",wiki:"En décadas, el cristianismo pasó de secta perseguida a religión dominante. Constantino financió construcción masiva de iglesias incluyendo la antigua Basílica de San Pedro."},{n:"Nicomedia",info:"Donde comenzó la persecución de Diocleciano en el 303.",wiki:"Solo diez años antes, el primer edicto de Diocleciano fue publicado aquí ordenando destruir iglesias y quemar escrituras. La inversión bajo Constantino fue total."}],pathLabels:["El Edicto llega a Roma — las iglesias emergen","De persecución en Nicomedia a tolerancia en Milán"]},
"evt9":{name:"Caída del Imperio Romano de Occidente",desc:"476 d.C.: Odoacro depuso a Rómulo Augústulo. El Senado envió las insignias a Constantinopla.",facts:["476 d.C.","Rómulo Augústulo: último emperador","Insignias enviadas a Constantinopla"],locs:[{n:"Río Rubicón",info:"10 de enero del 49 a.C.: punto sin retorno.",wiki:"El Rubicón era la frontera legal de Italia. Cualquier general cruzándolo bajo armas cometía traición. César dudó, luego dijo 'Alea iacta est' — la suerte está echada — y condujo su única legión hacia el sur."},{n:"Rávena",info:"Punto de despliegue de César en la Galia Cisalpina.",wiki:"César esperó aquí con solo una legión — la 13.ª — mientras negociaba con el Senado. Cuando las negociaciones fallaron, tomó su decisión fatídica."},{n:"Roma",info:"Pompeyo y el Senado huyeron en pánico.",wiki:"César se apoderó de Italia en solo 60 días sin derramamiento de sangre. Pompeyo y la mayoría de senadores huyeron a Grecia. César encontró el tesoro aún lleno y lo tomó."}],pathLabels:["César parte de Rávena hacia el Rubicón","Marcha sobre Roma — Pompeyo huye"],pathWikis:[null,"Se apoderó de Italia en 60 días sin batalla mayor."]},
"evt10":{name:"Edicto de Milán",desc:"313 d.C.: Constantino y Licinio legalizaron el cristianismo.",facts:["313 d.C.","Tolerancia religiosa","Los bienes de la Iglesia fueron devueltos"],locs:[{n:"Roma",info:"14 días de saqueo metódico.",wiki:"2 de junio del 455 d.C. El rey vándalo Genserico desembarcó en Ostia y entró en Roma sin oposición. El papa León I negoció: sin quemar ni matar, pero todo lo de valor fue arrebatado. El Templo de Júpiter en el Capitolio fue despojado de sus tejas de bronce dorado."},{n:"Cartago",info:"Capital del reino vándalo.",wiki:"Genserico se había apoderado de Cartago en el 439 y construyó una poderosa flota. Irónico que Cartago — destruida por Roma en el 146 a.C. — ahora enviara naves a saquear Roma."},{n:"Ostia",info:"La flota vándala desembarcó aquí.",wiki:"El puerto de Roma ofrecía fácil acceso. La flota cargó barcos de botín incluyendo la menorá del Templo de Jerusalén, originalmente capturada por Tito en el 70 d.C."}],pathLabels:["La flota vándala zarpa desde Cartago","Genserico entra en Roma sin oposición"],pathWikis:["Irónica inversión — Cartago contraataca.",null]},
"evt11":{name:"Año de los Cuatro Emperadores",desc:"69 d.C.: guerra civil tras la muerte de Nerón. Vespasiano prevaleció tras meses.",facts:["Cuatro emperadores en 18 meses","Vespasiano restauró el orden","La guerra civil reveló el secreto del imperio"],locs:[{n:"Roma",info:"Tres emperadores murieron aquí en 18 meses.",wiki:"El suicidio de Nerón en junio del 68 dejó sin heredero. Galba (España) se apoderó del poder pero fue asesinado en el Foro tras 7 meses. Otón lo derrocó pero perdió ante Vitelio en Bedriaco tras 3 meses. Vitelio fue linchado por las tropas de Vespasiano en diciembre del 69."},{n:"Bedriaco",info:"Dos batallas decisivas combatidas aquí en el 69 d.C.",wiki:"Pequeña aldea cerca de Cremona donde se combatieron ambas batallas críticas del 69 d.C. Primera: las fuerzas de Vitelio derrotaron a Otón (que luego se suicidó). Segunda: las fuerzas de Vespasiano destruyeron al ejército de Vitelio."},{n:"Alejandría",info:"Vespasiano proclamado emperador aquí.",wiki:"Las legiones orientales proclamaron emperador a Vespasiano el 1 de julio del 69 d.C. El suministro de grano de Egipto le dio apalancamiento económico sobre Roma. Restauró el orden y fundó la dinastía Flavia."}],pathLabels:["Los ejércitos chocan en Bedriaco — dos veces","Vespasiano marcha desde el Este para restaurar el orden"]},
"evt12":{name:"Guerra Social",desc:"Los aliados italianos exigieron ciudadanía: la guerra más sangrienta de Roma desde Aníbal.",facts:["~300.000 muertos","Toro italiano vs lobo romano","Roma ganó la guerra, los aliados ganaron la paz"],locs:[{n:"Ásculo",info:"La guerra estalló aquí cuando el pretor romano fue asesinado.",wiki:"91 a.C. Cuando el pretor Servilio fue asesinado por italianos enfadados en Ásculo, estalló la guerra a gran escala. Los aliados italianos que habían combatido junto a Roma durante siglos exigían derechos de ciudadanía iguales."},{n:"Corfinio",info:"Capital rebelde — renombrada 'Italia.'",wiki:"Los rebeldes establecieron su propio estado con Corfinio como capital, renombrándola 'Italia.' Acuñaron monedas mostrando el toro italiano embistiendo al lobo romano — poderoso símbolo de su causa."},{n:"Roma",info:"Ganó militarmente pero cedió políticamente.",wiki:"Aproximadamente 300.000 murieron — el conflicto más sangriento en Italia desde Aníbal. Roma ganó las batallas pero concedió ciudadanía a todos los italianos mediante la Lex Julia (90 a.C.) y Lex Plautia Papiria (89 a.C.). La guerra duplicó el cuerpo ciudadano de Roma."}],pathLabels:["La rebelión se extiende por el centro de Italia","Roma concede la ciudadanía"]},
"evt13":{name:"Batalla del Puente Milvio",desc:"Constantino vs. Majencio: 'In hoc signo vinces' cambió el curso de la civilización occidental.",facts:["'In hoc signo vinces'","Majencio se ahogó en el Tíber","Cambió la historia religiosa de Occidente"],locs:[{n:"Puente Milvio",info:"28 de octubre del 312 d.C.",wiki:"Constantino vio una visión — cruz o chi-rho en el cielo con las palabras 'In hoc signo vinces' (Con este signo vencerás). Ordenó pintar el símbolo cristiano en los escudos. Majencio, confiando en un oráculo, eligió combatir fuera de los muros de Roma. Sus tropas fueron empujadas al Tíber; Majencio se ahogó. Constantino entró en Roma como único emperador occidental."},{n:"Roma",info:"Constantino entró como libertador.",wiki:"Constantino atribuyó su victoria al Dios cristiano. En meses co-emitió el Edicto de Milán legalizando el cristianismo. En un siglo, el imperio era oficialmente cristiano. La batalla cambió la trayectoria religiosa de la civilización occidental."}],pathLabels:["Constantino entra en Roma victorioso"]},
"evt14":{name:"Primer y Segundo Triunviratos",desc:"Reparto privado de poder que mató la República: César-Pompeyo-Craso, luego Octaviano-Antonio-Lépido.",facts:["Primero: César-Pompeyo-Craso (60 a.C.)","Segundo: Octaviano-Antonio-Lépido (43 a.C.)","2.300 proscritos en el Segundo"],locs:[{n:"Roma",info:"Donde ambos triunviratos ejercieron poder.",wiki:"El Primer Triunvirato (60 a.C.) fue un pacto informal: César obtuvo la Galia, Pompeyo España, Craso Siria. Colapsó cuando Craso murió en Carras. El Segundo Triunvirato (43 a.C.) fue promulgado legalmente: Octaviano, Antonio y Lépido dividieron el mundo romano y publicaron listas de proscripción — 300 senadores y 2.000 ecuestres, incluyendo a Cicerón."},{n:"Luca",info:"Conferencia renovó el Primer Triunvirato, 56 a.C.",wiki:"César, Pompeyo y Craso se reunieron en Luca (Lucca) para renovar su alianza. 200 senadores asistieron — mostrando cuánto poder había pasado del Senado a estos tres hombres."},{n:"Bononia",info:"Segundo Triunvirato formado aquí, 43 a.C.",wiki:"Actual Bolonia. Octaviano, Antonio y Lépido se reunieron en una isla en un río cerca de Bononia. Dividieron el mundo romano y elaboraron listas de proscripción — intercambiando enemigos y aliados de cada uno. Antonio exigió la cabeza de Cicerón; Octaviano accedió a regañadientes."}],pathLabels:["200 senadores asisten a la conferencia de Luca","Las listas de proscripción llegan a Roma"]},
"evt15":{name:"Nacimiento de la República",desc:"Tarquinio el Soberbio expulsado tras la violación de Lucrecia: 'nunca más un rey'. Nació la República romana.",facts:["El suicidio de Lucrecia desencadenó la revuelta","Dos cónsules reemplazaron al rey","'Rex' se convirtió en la peor acusación política"],locs:[{n:"Roma",info:"509 a.C.: el último rey expulsado.",wiki:"Según la tradición, Tarquinio el Soberbio fue derrocado tras la violación de la noble Lucrecia por su hijo Sexto, que se suicidó antes que vivir en deshonra. Lucio Junio Bruto lideró la revuelta. Se eligieron dos cónsules — el poder sería compartido y anual. El odio de los romanos a la monarquía moldeó su política durante 500 años: 'rex' (rey) se convirtió en la acusación política más mortífera."}]},
"evt16":{name:"División Permanente del Imperio",desc:"La muerte de Teodosio I dividió permanentemente el imperio. Arcadio recibió Oriente, Honorio Occidente. Nunca se reunificó.",facts:["Teodosio murió el 17 de enero del 395 d.C.","El Imperio de Oriente duró 1.058 años más","El Imperio de Occidente cayó en 81 años"],locs:[{n:"Constantinopla",info:"Capital oriental bajo Arcadio.",wiki:"Cuando Teodosio I murió el 17 de enero del 395 d.C., el imperio se dividió entre sus hijos: Arcadio (17 años) en el Este y Honorio (10 años) en el Oeste. Las divisiones anteriores habían sido administrativas; esta se hizo permanente. El Imperio de Oriente — más rico, más urbanizado, con fronteras más cortas — prosperó. El Imperio de Occidente colapsó en 81 años."},{n:"Rávena",info:"Capital occidental bajo Honorio.",wiki:"El emperador niño Honorio trasladó la capital occidental de Milán a Rávena en el 402. Protegida por marismas, sirvió como último refugio de los emperadores occidentales. Cuando Alarico saqueó Roma en el 410, Honorio estaba seguro en Rávena — la leyenda dice que confundió la noticia con la muerte de su gallina llamada Roma."}],pathLabels:["Imperio dividido: Este y Oeste"]},
"eng1":{name:"Red de Calzadas Romanas",desc:"400.000 km de calzadas, 80.000 km pavimentadas en piedra.",facts:["Vía Apia: 312 a.C.","4,5 m de ancho","'Todos los caminos llevan a Roma'"],locs:[{n:"Roma",info:"Hito Dorado.",wiki:"Milliarium Aureum — inicio simbólico de todas las calzadas."},{n:"Brundisium",info:"Terminal de la Vía Apia.",wiki:"Extremo oriental de la primera autopista de Roma."},{n:"Londinium",info:"Centro viario de Britania.",wiki:"Cinco calzadas principales irradiaban desde aquí."}],pathLabels:["Vía Apia","Calzadas a Britania"]},
"eng2":{name:"El Coliseo",desc:"50.000 asientos para combates de gladiadores.",facts:["100.000 m³ de travertino","Batallas navales","Velario retráctil"],locs:[{n:"Coliseo",info:"189×156 m, 48 m de altura.",wiki:"100.000 m³ de travertino. Inundado para batallas navales. Toldo retráctil operado por 1.000 marineros."}]},
"eng3":{name:"Panteón",desc:"Cúpula de hormigón sin refuerzo más grande: sigue en pie.",facts:["Cúpula de 43,3 m","1.900 años de antigüedad","Miguel Ángel: 'obra de ángeles'"],locs:[{n:"Panteón",info:"Cúpula de 43,3 m. Óculo de 8,8 m.",wiki:"Hormigón con grados desde basalto pesado hasta piedra pómez ligera. Miguel Ángel: 'obra de ángeles.'"}]},
"eng4":{name:"Acueductos Romanos",desc:"11 acueductos alimentaban Roma: ingeniería por gravedad a través de continentes.",facts:["11 acueductos, más de 500 km hasta Roma","Pont du Gard: 1 cm/180 m de pendiente","Segovia en uso hasta 1973"],locs:[{n:"Roma",info:"11 acueductos suministraban 1 millón de m³/día.",wiki:"Los 11 acueductos de Roma sumaban más de 500 km. El Aqua Appia (312 a.C.) fue el primero. En el período imperial, suministraban suficiente agua para 1 millón de metros cúbicos diarios — más per cápita que muchas ciudades modernas."},{n:"Pont du Gard",info:"48,8 m de altura — el puente de acueducto romano más alto.",wiki:"Construido ~40-60 d.C. para llevar agua 50 km hasta Nemausus (Nimes). Tres niveles de arcos. Gradiente medio de solo 1 cm por cada 180 m — el agua fluía solo por gravedad. Patrimonio de la Humanidad por la UNESCO."},{n:"Segovia",info:"167 arcos de granito — en uso hasta 1973.",wiki:"Construido en el siglo I d.C. con 20.400 bloques de granito sin mortero. 28 m de altura en su punto más alto. Notablemente, suministró agua a Segovia hasta 1973."},{n:"Cartago",info:"Acueducto de 132 km — el más largo del mundo romano.",wiki:"El Acueducto de Zaghouan se extendía 132 km desde manantiales de montaña hasta Cartago. Secciones aún permanecen. Restaurado por Adriano tras daños por terremoto."}],pathLabels:["La ingeniería de acueductos llega a la Galia","El agua romana llega a Hispania","El acueducto más largo construido en África"]},
"eng5":{name:"Muro de Adriano",desc:"117 km de frontera a través de Britania: la muralla más famosa de Roma.",facts:["117 km de costa a costa","80 fortines, 160 torres","Manejada durante ~300 años"],locs:[{n:"Wallsend",info:"Terminal oriental en el Tyne.",wiki:"Llamado Segedunum. Extremo oriental del muro donde encontraba el río. Guarnición de 600 infantes. Reconstrucción a escala completa visible hoy."},{n:"Fuerte de Housesteads",info:"El fuerte mejor conservado del Muro.",wiki:"Vercovicium — guarnecido por 800 hombres. Situado espectacularmente en los riscos de Whin Sill. Incluye la letrina romana mejor conservada de Britania."},{n:"Vindolanda",info:"Famosas tablillas de escritura descubiertas aquí.",wiki:"Anterior al propio Muro. Las Tablillas de Vindolanda — postales de madera finas — son los documentos manuscritos más antiguos de Britania. Incluyen una invitación a fiesta de cumpleaños de la esposa de un comandante."},{n:"Bowness-on-Solway",info:"Terminal occidental en el Mar de Irlanda.",wiki:"Extremo occidental del Muro. Extendido por un sistema de torres de vigilancia y fuertes por la costa de Cumbria para protegerse de flanqueos por mar."}],pathLabels:["El muro corre de este a oeste por los riscos","Vindolanda protege la calzada Stanegate","El muro continúa hasta la costa de Solway"]},
"eng6":{name:"Termas de Caracalla",desc:"Complejo de ocio de 100.000 m²: gimnasio, biblioteca, jardines y baños para 1.600.",facts:["Complejo de 100.000 m²","10 toneladas de madera quemadas diariamente","Biblioteca, gimnasio, jardines incluidos"],locs:[{n:"Termas de Caracalla",info:"Segundas termas más grandes de Roma.",wiki:"Inauguradas en 216 d.C. Podían servir a 1.600 bañistas simultáneamente. Contaba con caldarium (caliente), tepidarium (tibio), frigidarium (frío) y natatio (piscina). 10 toneladas de madera quemadas diariamente para calefacción. Interior adornado con mármol, mosaicos y cientos de estatuas incluyendo el Hércules Farnesio y el Toro Farnesio."},{n:"Roma",info:"Suministrada por el acueducto Aqua Antoniniana.",wiki:"Una rama de acueducto dedicada suministraba los 8 millones de litros de agua. El complejo también incluía bibliotecas, gimnasios, tiendas y jardines. Operó más de 300 años hasta que los godos cortaron los acueductos en 537 d.C."}]},
"eng7":{name:"Circo Máximo",desc:"Estadio de carreras de carros para 250.000 espectadores: el recinto más grande y querido de Roma.",facts:["250.000 espectadores","621 m × 118 m","Carreras de carros durante más de 1.000 años"],locs:[{n:"Circo Máximo",info:"621 m × 118 m — más grande que cualquier estadio moderno.",wiki:"Ubicado entre las colinas Palatina y Aventina. Las carreras de carros comenzaron aquí bajo los reyes. Julio César lo amplió; Augusto añadió un obelisco egipcio. Tras el Gran Incendio del 64 d.C., Nerón lo reconstruyó para 250.000 espectadores. Últimas carreras en 549 d.C. bajo el rey ostrogodo Totila."}]},
"eng8":{name:"Columna de Trajano",desc:"Monumento de mármol de 30 m con 2.662 figuras talladas: el mayor memorial de guerra de Roma.",facts:["30 m de alto, 1.100 toneladas de mármol","2.662 figuras talladas","Escalera interna de 185 peldaños"],locs:[{n:"Foro de Trajano",info:"Completado en mayo de 113 d.C.",wiki:"Diseñado por Apolodoro de Damasco. 19 enormes tambores de mármol de Carrara, cada uno pesando ~32 toneladas. Un friso espiral continuo recorre 23 veces el fuste por 190 metros, representando 155 escenas de las Guerras Dacias con 2.662 figuras. Trajano aparece 58 veces. Una escalera interna de 185 peldaños lleva a la cima. Originalmente coronado por una estatua de bronce de Trajano; reemplazada por San Pedro en 1587."}]},
"eng9":{name:"Foro Romano",desc:"Corazón de Roma durante 1.200 años: templos, tribunales, mercados y crisol de la historia.",facts:["1.200 años de uso continuo","César incinerado aquí","La cabeza de Cicerón expuesta en la Rostra"],locs:[{n:"Foro Romano",info:"Centro político, religioso y comercial.",wiki:"Originalmente un valle pantanoso entre las colinas, drenado por la Cloaca Máxima en el siglo VI a.C. Durante 1.200 años fue el centro de la vida pública romana: elecciones, juicios, triunfos, funerales, comercio y discursos. César fue incinerado aquí. Augusto lo declaró 'demasiado pequeño' y construyó su propio foro — luego Trajano construyó uno aún mayor."},{n:"Templo de Saturno",info:"Tesorería del Estado y uno de los templos más antiguos.",wiki:"Fundado ~498 a.C. Albergaba el aerarium — la tesorería estatal de Roma. Durante las Saturnales, se retiraban las ligaduras de lana del templo. Ocho columnas supervivientes datan de una restauración del siglo IV."},{n:"Rostra",info:"La tribuna del orador — decorada con proas de naves.",wiki:"Nombrada por las proas de bronce (rostrum) tomadas de naves enemigas en Antium en 338 a.C. Donde Cicerón pronunció sus mayores discursos. Tras su asesinato, su cabeza y manos cortadas fueron clavadas aquí por Antonio."}]},
"eng10":{name:"Puente de Trajano",desc:"Puente de arco más largo del mundo durante 1.000 años: 1.135 m sobre el Danubio.",facts:["1.135 m — el más largo durante 1.000 años","20 pilares de piedra, 50 m de alto","Adriano lo desmanteló"],locs:[{n:"Drobeta",info:"Actual Drobeta-Turnu Severin, Rumanía.",wiki:"Diseñado por Apolodoro de Damasco para las Guerras Dacias de Trajano. 1.135 metros de longitud con 20 arcos de madera sobre pilares de piedra, cada uno elevándose 50 metros desde el lecho del río. El puente de arcos más largo del mundo durante más de 1.000 años. Adriano desmanteló la superestructura para impedir cruces bárbaros — los pilares de piedra sobrevivieron hasta la era moderna."}]},
"eng11":{name:"Calefacción por Hipocausto",desc:"Calefacción bajo el suelo con pilas de pilae y tubuli en paredes: usada en baños y casas ricas.",facts:["Suelo elevado sobre pilares de ladrillo (pilae)","Baldosas huecas (tubuli) canalizaban el calor","Esencial para la cultura de baños romanos"],locs:[{n:"Pompeya",info:"Sistemas de hipocausto bien conservados en las Termas del Foro.",wiki:"El hipocausto (latín: hypocaustum, 'quemar debajo') era el sistema de calefacción central de Roma. Un horno (praefurnium) calentaba aire que circulaba bajo un suelo elevado sostenido por pequeños pilares de ladrillo (pilae). El aire caliente subía por baldosas huecas (tubuli) en las paredes. El sistema era esencial para las termas — el caldarium (sala caliente) requería temperaturas de hasta 40°C."},{n:"Bath",info:"Aquae Sulis: termas romanas en Britania con hipocausto intacto.",wiki:"Las termas romanas de Bath (Aquae Sulis) están entre las mejor conservadas del mundo. El manantial sagrado suministra agua a 46°C naturalmente, pero el complejo también usaba calefacción por hipocausto para salas adicionales. La Gran Piscina, el templo de Sulis Minerva y los canales de calefacción bajo el suelo son todos visibles hoy."}],pathLabels:["La tecnología del hipocausto se extiende por el imperio"]},
"eng12":{name:"Arcos Triunfales",desc:"Arcos monumentales que conmemoran victorias militares: desde el primero de Escipión hasta el de Constantino.",facts:["Arco de Tito: botines del Templo de Jerusalén","Arco de Constantino: arco superviviente más grande","Inspiró el Arco de Triunfo de París"],locs:[{n:"Roma/Arco de Tito",info:"81 d.C.: conmemora la conquista de Jerusalén. Muestra el botín del Templo.",wiki:"El Arco de Tito conmemora el asedio de Jerusalén (70 d.C.). Su relieve interior muestra soldados llevando la menorá y los vasos sagrados del Templo — una de las obras de arte histórico más importantes del mundo. El arco estableció el estándar para todos los arcos triunfales posteriores, incluyendo el Arco de Triunfo de París."},{n:"Roma/Arco de Constantino",info:"315 d.C.: el arco romano superviviente más grande.",wiki:"El Arco de Constantino es el arco triunfal más grande y último gran arco de Roma. Construido en 315 d.C. para celebrar la victoria de Constantino en el Puente Milvio, famosamente reutilizó (expolió) escultura de monumentos anteriores de Trajano, Adriano y Marco Aurelio — quizás porque los artesanos ya no podían igualar la calidad anterior."}]},
"eng13":{name:"Puertos y Rompeolas Romanos",desc:"Hormigón hidráulico que fragua bajo el agua: Cesarea Marítima y Portus revolucionaron la ingeniería marítima.",facts:["Hormigón hidráulico fraguaba bajo el agua","Cesarea: mayor puerto artificial antiguo","Portus: la cuenca hexagonal de Trajano albergaba 200 barcos"],locs:[{n:"Cesarea Marítima",info:"Puerto artificial de Herodes usando tecnología romana de hormigón.",wiki:"El rey Herodes construyó el puerto de Cesarea (Sebastos) entre 22-10 a.C. usando hormigón hidráulico romano — pozzolana mezclada con cal y agua de mar que endurecía bajo el agua. El puerto era más grande que El Pireo. Se hundieron moldes de madera y se rellenaron con hormigón. Era el puerto artificial más grande del mundo antiguo."},{n:"Portus",info:"El gran puerto de Roma construido por Claudio y Trajano.",wiki:"Claudio comenzó Portus en 42 d.C. para reemplazar la Ostia sedimentada. Trajano lo amplió con una cuenca interior hexagonal (112 d.C.) que podía manejar 200 naves. El complejo cubría 3,5 km² y alimentaba a la población de Roma de más de un millón. Permanecen restos de almacenes, canales y la base del faro."}],pathLabels:["La ingeniería marítima conecta los puertos"]},
"eng14":{name:"Domus Aurea",desc:"Casa Dorada de Nerón: 300 habitaciones, comedor giratorio y sala octogonal que revolucionó la arquitectura.",facts:["300 habitaciones con pan de oro y gemas","Sala octogonal precedió la cúpula del Panteón","'Grotesco' deriva de sus habitaciones enterradas"],locs:[{n:"Roma/Esquilino",info:"Construido tras el Gran Incendio del 64 d.C.",wiki:"Tras el Gran Incendio del 64 d.C. que despejó vastas áreas del centro de Roma, Nerón construyó su fantástico complejo palaciego — la Domus Aurea (Casa Dorada). Cubría 100-300 acres con un lago artificial, viñedos y un coloso de bronce de Nerón de 120 pies. La sala octogonal usaba una revolucionaria cúpula de hormigón con óculo, precediendo la cúpula del Panteón por 60 años. El comedor giratorio (coenatio rotunda) ha sido confirmado arqueológicamente. Enterrada por Trajano y Tito, fue redescubierta durante el Renacimiento cuando artistas como Rafael y Miguel Ángel se bajaban a las 'grutas' — la palabra 'grotesco' proviene de estas visitas."}]},
"eng15":{name:"Puentes Romanos",desc:"Alcántara (aún en uso), Pont du Gard, Pons Fabricius: ingeniería que sobrevivió al imperio 2.000 años.",facts:["Alcántara: 'He construido un puente que durará para siempre'","Pons Fabricius: más de 2.000 años de uso continuo","Ingeniería de arcos de dovelas insuperada hasta el s. XIX"],locs:[{n:"Alcántara",info:"Puente de seis arcos que aún soporta tráfico tras 2.000 años.",wiki:"El Puente de Alcántara sobre el Tajo en España fue construido en 104-106 d.C. por el arquitecto Lacer. Sus arcos centrales abarcan 29 metros y se elevan 48 metros sobre el río. Una inscripción declara: 'He construido un puente que durará para siempre.' Aún soporta tráfico. La ingeniería del puente — arcos de dovelas sobre pilares de granito — no fue superada hasta el siglo XIX."},{n:"Roma/Pons Fabricius",info:"Puente más antiguo de Roma, aún intacto (62 a.C.).",wiki:"El Pons Fabricius fue construido en 62 a.C. y conecta el Campo de Marte con la Isla Tiberina. Es el puente más antiguo de Roma aún en su estado original — más de 2.000 años de uso continuo. La inscripción nombra a su constructor: L. Fabricius. Dos hermas de Jano de cuatro caras custodian el pilar central."}],pathLabels:["La ingeniería de puentes romanos abarca el imperio"]},
"cul1":{name:"Eneida de Virgilio",desc:"Épica nacional de Roma: el viaje de Eneas desde Troya.",facts:["11 años, nunca terminada","Augusto la salvó","Épica fundacional de Roma"],locs:[{n:"Roma",info:"Augusto lo encargó.",wiki:"11 años escribiendo. Virgilio pidió quemarlo en su lecho de muerte. Augusto lo salvó."},{n:"Nápoles",info:"Virgilio vivió aquí.",wiki:"La tumba en Posillipo se convirtió en lugar de peregrinación."}],pathLabels:["Obra maestra presentada a Augusto"]},
"cul2":{name:"Juegos del Coliseo",desc:"Combate gladiatorio durante más de 300 años.",facts:["100 días inaugurales","Categorías de luchadores","Prohibidos en 404 d.C."],locs:[{n:"Roma",info:"50.000 observaban a los luchadores.",wiki:"Los gladiadores entrenaban en categorías. La mayoría de las peleas no eran a muerte. Prohibido en 404 d.C."}]},
"cul3":{name:"Metamorfosis de Ovidio",desc:"Épica en 15 libros de 250 mitos de transformación: exiliado por Augusto por 'un poema y un error'.",facts:["15 libros, 250 mitos","Exiliado por Augusto","400 manuscritos medievales sobreviven"],locs:[{n:"Roma",info:"Escrito aquí; publicado ~8 d.C.",wiki:"Ovidio era el poeta más popular de Roma. Las Metamorfosis — 15 libros, 250 mitos, 12.000 versos — se convirtieron en 'la Biblia para artistas.' Augusto lo desterró en 8 d.C. por 'carmen et error' — un poema y un error. El crimen exacto sigue siendo el mayor misterio literario de la historia."},{n:"Sulmo",info:"Lugar de nacimiento de Ovidio — actual Sulmona.",wiki:"Nacido el 20 de marzo del 43 a.C. en una familia ecuestre. Formado en retórica pero atraído irresistiblemente por la poesía. 'Todo lo que intentaba decir salía en verso.'"},{n:"Tomis",info:"Desterrado aquí en el Mar Negro hasta su muerte.",wiki:"Actual Constanța, Rumanía. Una remota ciudad fronteriza de habla no latina. Ovidio pasó su última década escribiendo cartas de desesperación (Tristia, Epistulae ex Ponto) suplicando regresar. Nunca lo hizo. Sobreviven 400 manuscritos medievales de las Metamorfosis — testimonio del poder de la obra."}],pathLabels:["El joven Ovidio llega a Roma","Augusto destierra a Ovidio a Tomis, 8 d.C."],pathWikis:[null,"'Carmen et error' — el crimen exacto sigue siendo desconocido."]},
"cul4":{name:"Teatro Romano",desc:"Plauto, Terencio y Séneca: comedia y tragedia que moldearon el drama occidental.",facts:["Plauto: más de 130 obras atribuidas","Teatro de Orange: mejor conservado","Inspiró a Shakespeare y Molière"],locs:[{n:"Roma",info:"Teatro de Pompeyo: primer teatro permanente de piedra.",wiki:"Los romanos inicialmente prohibieron teatros permanentes por considerarlos moralmente corruptores. Pompeyo sorteó la ley en 55 a.C. construyendo un templo sobre las gradas. El Teatro de Pompeyo resultante tenía capacidad para 20.000 — y fue donde César fue asesinado."},{n:"Orange",info:"Teatro romano mejor conservado del mundo.",wiki:"Construido bajo Augusto en la Galia meridional. El muro escénico de 37 m de altura sobrevive intacto — Luis XIV lo llamó 'la más bella pared de mi reino.' Capacidad para 9.000. Aún acoge representaciones de ópera."},{n:"Aspendos",info:"Teatro notablemente intacto en Turquía.",wiki:"Construido en 155 d.C. Capacidad para 15.000. Acústica tan perfecta que una moneda caída en el escenario puede oírse en la última fila. Sobrevive porque los turcos selyúcidas lo usaron como caravasar."}],pathLabels:["El teatro romano llega a la Galia","La cultura teatral se extiende a Asia Menor"]},
"cul5":{name:"Saturnales",desc:"Mayor festival de Roma: inversión de roles, regalos y carnaval durante una semana en diciembre.",facts:["17-23 de diciembre","Los amos servían a los esclavos","Influenció las tradiciones navideñas"],locs:[{n:"Templo de Saturno",info:"El festival comenzaba con sacrificio aquí.",wiki:"Las Saturnales honraban a Saturno, dios de la semilla y la siembra. 17-23 de diciembre: negocios cerrados, tribunales cerrados, escuelas canceladas. Un banquete público y sacrificio en el Templo de Saturno iniciaban las festividades. El juego era legal. Se elegía un 'Rey de las Saturnales' para dar órdenes absurdas."},{n:"Roma",info:"Toda la ciudad celebraba.",wiki:"Los amos servían a sus esclavos en la cena. Dar regalos (especialmente velas de cera y pequeñas figurillas llamadas sigillaria) era costumbre. Catulo lo llamó 'el mejor de los días.' Séneca se quejaba de que no podías escapar del ruido. Muchos estudiosos lo ven como precursor de las celebraciones navideñas."}]},
"cul6":{name:"Mosaicos y Arte Romano",desc:"Desde el Mosaico de Alejandro hasta Piazza Armerina: millones de teselas contaron las historias de Roma.",facts:["Mosaico de Alejandro: 1,5 millones de teselas","Frescos de Pompeya preservados bajo ceniza","Piazza Armerina: 3.500 m² de mosaicos"],locs:[{n:"Pompeya",info:"Mosaico de Alejandro: 1,5 millones de teselas.",wiki:"El Mosaico de Alejandro de la Casa del Fauno representa a Alejandro Magno cargando contra Darío III en Issos. Hecho de 1,5 millones de pequeñas piezas de piedra coloreadas. Los frescos de Pompeya — preservados bajo ceniza volcánica — proporcionan nuestra mejor ventana a la vida diaria romana, desde escenas de jardín hasta arte erótico."},{n:"Roma",info:"Los bustos retrataban el carácter individual.",wiki:"El arte romano se apartó del idealismo griego para abrazar el verismo — realismo 'con verrugas y todo.' Los bustos retratos de senadores envejecidos con arrugas y calvas eran marcas de honor, mostrando una vida de servicio."},{n:"Piazza Armerina",info:"3.500 m² de mosaicos romanos tardíos.",wiki:"La Villa Romana del Casale en Sicilia contiene la colección más extensa de mosaicos romanos del mundo. 3.500 m² de suelos representando escenas de caza, relatos mitológicos y las famosas 'Chicas en Bikini' — atletas femeninas en trajes de dos piezas."}],pathLabels:["Los mejores mosaicos en Pompeya","Obra maestra romana tardía en Sicilia"]},
"cul7":{name:"Latín y el Alfabeto",desc:"De dialecto italiano regional a lingua franca del Mediterráneo: dio origen a cinco lenguas modernas.",facts:["Originó francés, español, italiano, portugués, rumano","Alfabeto latino usado por más de 3.000 millones","Lengua de la Iglesia Católica durante 1.500 años"],locs:[{n:"Roma",info:"El latín se convirtió en la lengua del derecho, la literatura y el imperio.",wiki:"El latín evolucionó de un dialecto del Lacio en la lingua franca del Mediterráneo. El latín clásico (Cicerón, Virgilio) dio paso al latín vulgar — la lengua hablada de soldados, comerciantes y colonos — que se fragmentó en francés, español, italiano, portugués y rumano."},{n:"Lacio",info:"Cuna de la lengua latina.",wiki:"La región al sur del Tíber donde se originó el latín. El alfabeto latino, adaptado del guion etrusco (a su vez del griego), se convirtió en el sistema de escritura más ampliamente usado del mundo. 26 letras ahora usadas por más de 3.000 millones de personas."}]},
"cul8":{name:"Horacio y la Poesía Romana",desc:"'Carpe diem': Sátiras, Odas y Epístolas que definieron la edad dorada augusta.",facts:["'Carpe diem'","Hijo de liberto","Ars Poetica influyó 2.000 años de crítica"],locs:[{n:"Venusia",info:"Nacido en 65 a.C. — actual Venosa.",wiki:"Hijo de un liberto (antiguo esclavo) que invirtió todo en la educación de su hijo. Luchó en el bando perdedor en Filipos con Bruto. La pobreza y la poesía lo llevaron al círculo de Mecenas."},{n:"Roma",info:"Poeta laureado de Augusto junto a Virgilio.",wiki:"Las Sátiras de Horacio ridiculizaban la sociedad romana con ingenio suave. Sus Odas perfeccionaron la poesía lírica latina. 'Carpe diem, quam minimum credula postero' — aprovecha el día, confiando lo menos posible en el mañana. Su Ars Poetica influyó en la crítica literaria durante 2.000 años."},{n:"Tíbur",info:"La querida granja sabina de Horacio — regalo de Mecenas.",wiki:"Zona de la actual Tívoli. Mecenas le dio a Horacio una granja en las colinas Sabinas. El agradecido poeta escribió aquí algunas de sus mejores obras, celebrando la vida rural simple. 'Esto es lo que pedí: un pedazo de tierra no demasiado grande.'"}],pathLabels:["El hijo del liberto llega a Roma","Se retira a su granja sabina"]},
"cul9":{name:"Tácito y la Historiografía Romana",desc:"Anales, Historias, Germania: 'Crean un desierto y lo llaman paz'.",facts:["'Crean un desierto y lo llaman paz'","'Cuanto más corrupto el estado, más leyes'","Germania: fuente etnográfica invaluable"],locs:[{n:"Roma",info:"Senador, cónsul y el mayor historiador de Roma.",wiki:"Publio Cornelio Tácito fue senador y cónsul que escribió las dos mayores obras de la historia romana. Los Anales cubren los emperadores julio-claudios (14-68 d.C.); las Historias cubren el Año de los Cuatro Emperadores hasta los flavios (69-96 d.C.). Su prosa es comprimida, sardónica y devastadora. Vio la corrupción moral como inseparable del poder absoluto: 'Cuanto más corrupto el estado, más numerosas las leyes.' Su Germania es el relato antiguo más detallado de los pueblos germánicos — usado y mal usado por generaciones posteriores."},{n:"Germania",info:"Sujeto de la obra etnográfica de Tácito.",wiki:"La Germania de Tácito (98 d.C.) describía costumbres, guerra y sociedad germánicas. Contrastaba la 'noble salvaje' germánica con la decadencia romana — en parte como crítica social. La obra fue posteriormente mal apropiada para fines nacionalistas, pero sigue siendo una fuente etnográfica invaluable."}],pathLabels:["Tácito describe el mundo germánico"]},
"cul10":{name:"Juvenal y la Sátira Romana",desc:"'Pan y circo'. '¿Quién vigila a los vigilantes?' Comentario social mordaz como arte exclusivamente romano.",facts:["'Panem et circenses' — pan y circo","'Quis custodiet ipsos custodes?'","Sátira: 'totalmente nuestra' — Quintiliano"],locs:[{n:"Roma",info:"Escribió 16 Sátiras atacando la sociedad romana.",wiki:"Décimo Junio Juvenal perfeccionó la sátira en verso — un género que los propios romanos consideraban exclusivamente suyo ('satura tota nostra est' — Quintiliano). Sus 16 Sátiras atacan todos los niveles de la sociedad romana: patrones codiciosos, libertos pretenciosos, funcionarios corruptos, calles peligrosas y la decadencia moral de la élite. 'Panem et circenses' (pan y circo) — su frase sobre cómo los gobernantes distraen a las masas — sigue siendo una de las frases latinas más citadas. 'Quis custodiet ipsos custodes?' (¿Quién vigilará a los vigilantes?) inspiró obras desde Alan Moore hasta el derecho constitucional."},{n:"Aquinum",info:"Probable lugar de nacimiento de Juvenal — actual Aquino.",wiki:"Juvenal probablemente procedía de Aquinum en el Lacio. Poco se sabe de su vida — puede que fuera desterrado a Egipto. Sus Sátiras fueron populares en la Edad Media y el Renacimiento, influyendo en Pope, Swift y Johnson."}],pathLabels:["De Aquinum a la escena literaria de Roma"]},
"cul11":{name:"Tito Livio y Ab Urbe Condita",desc:"142 libros desde la fundación de Roma hasta su tiempo: mitos fundacionales, ejemplos morales y orgullo nacional. Solo 35 sobreviven.",facts:["142 libros — solo 35 sobreviven","Mitos fundacionales de Roma","Amigo personal de Augusto"],locs:[{n:"Padua",info:"Lugar de nacimiento de Livio (Patavium).",wiki:"Tito Livio (59 a.C. – 17 d.C.) nació en Padua, una ciudad conservadora famosa por su rectitud moral — Asinio Polión se burlaba de Livio por su 'Patavinidad.' Pasó la mayor parte de su vida en Roma escribiendo Ab Urbe Condita Libri (Libros desde la Fundación de la Ciudad) — 142 libros cubriendo del 753 a.C. al 9 a.C. Solo 35 sobreviven completos."},{n:"Roma",info:"Livio pasó décadas investigando en Roma.",wiki:"La historia de Livio dio a Roma su relato nacional: Rómulo y Remo, el rapto de las sabinas, Horacio en el puente, los galos saqueando Roma, Aníbal a las puertas. Su propósito era moral: la grandeza de Roma venía de virtus (valor), pietas (deber) y fides (honor). Augusto era amigo personal."}],pathLabels:["De Padua a Roma: la carrera literaria de Livio"]},
"cul12":{name:"Bibliotecas Romanas",desc:"Desde la primera biblioteca pública de Asinio Polión hasta la Bibliotheca Ulpia de Trajano: templos del conocimiento.",facts:["Roma tuvo 28 bibliotecas públicas","Bibliotheca Ulpia: salas gemelas griega y latina","Biblioteca de Celso albergaba 12.000 rollos"],locs:[{n:"Roma/Foro de Trajano",info:"Bibliotheca Ulpia — la mayor biblioteca romana.",wiki:"El Foro de Trajano contenía la Bibliotheca Ulpia (112 d.C.) — salas gemelas de literatura griega y latina flanqueando la Columna de Trajano. Las bibliotecas públicas romanas guardaban rollos de papiro en armarium (armarios) de madera con salas de lectura. En su apogeo, Roma tenía 28 bibliotecas públicas. Asinio Polión fundó la primera en 39 a.C."},{n:"Éfeso/Biblioteca de Celso",info:"Sobrevive la espectacular fachada de la biblioteca de Celso.",wiki:"La Biblioteca de Celso en Éfeso fue construida en 117 d.C. como tumba monumental y biblioteca. Su fachada de dos pisos — con estatuas de Sabiduría, Conocimiento, Inteligencia y Excelencia — está entre las ruinas romanas más fotografiadas. Contenía 12.000 rollos. El edificio combinaba biblioteca y mausoleo: Celso fue enterrado bajo la sala de lectura."}],pathLabels:["Bibliotecas romanas por todo el imperio"]},
"cul13":{name:"Lucrecio y De Rerum Natura",desc:"Poema epicúreo sobre la naturaleza del universo: teoría atómica 1.800 años antes de Dalton.",facts:["Teoría atómica 1.800 años antes de Dalton","'Nada surge de la nada'","Redescubierto en 1417, ayudó a desencadenar el Renacimiento"],locs:[{n:"Roma",info:"Escrito en las últimas décadas de la República.",wiki:"Tito Lucrecio Caro escribió De Rerum Natura (Sobre la Naturaleza de las Cosas) alrededor del 55 a.C. — un poema de 7.400 versos explicando la física epicúrea. Argumentaba que todo consiste en átomos y vacío, que el alma es mortal, que los dioses no intervienen en la naturaleza y que de la nada nada surge. El poema se perdió durante siglos hasta que Poggio Bracciolini redescubrió un manuscrito en 1417 — un evento que ayudó a desencadenar el Renacimiento y la Revolución Científica."}]},
"cul14":{name:"Marcial y el Epigrama Romano",desc:"Más de 1.500 epigramas ingeniosos y obscenos: la mejor fuente de la vida romana callejera.",facts:["Más de 1.500 epigramas — muchos obscenos","Mejor fuente de vida romana callejera","Plinio pagó su viaje de retiro a Hispania"],locs:[{n:"Roma",info:"Marcial vivió y escribió en Roma durante 34 años.",wiki:"Marco Valerio Marcial escribió más de 1.500 epigramas entre aproximadamente 86-103 d.C. Son breves, agudos y a menudo obscenos — satirizando todo desde malos poetas y parásitos de cena hasta humillaciones cliente-patrón y costumbres sexuales. Proporcionan una ventana incomparable a la vida cotidiana romana: barberías, tabernas, juegos gladiatorios, bloques de apartamentos, salutaciones del alba y el agotador calendario social de un cliente."},{n:"Bílbilis",info:"Lugar de nacimiento de Marcial en España.",wiki:"Marcial nació en Bílbilis (actual Calatayud) en España. Se mudó a Roma alrededor de los 24 años, pasando 34 años como cliente literario buscando mecenazgo. Se retiró a España en la vejez, escribiendo que echaba terriblemente de menos Roma. Plinio el Joven pagó su viaje de regreso."}],pathLabels:["De Bílbilis a Roma: los 34 años de carrera literaria de Marcial"]},
"cul15":{name:"Música y Representación Romanas",desc:"Tibia, lira e hidraulis (órgano de agua): música en juegos, banquetes, funerales, teatro y ritos religiosos.",facts:["Hidraulis (órgano de agua): instrumento antiguo más complejo","Nerón obsesionado con actuar","Los músicos eran admirados pero legalmente 'deshonrados'"],locs:[{n:"Roma",info:"La música impregnaba la vida pública y privada romana.",wiki:"La música era esencial en la vida romana: las tibiae (flautas dobles) acompañaban sacrificios y funerales, las liras sonaban en banquetes, los instrumentos de metal (tubae, cornua) resonaban en el ejército y la arena. La hydraulis (órgano de agua) era el instrumento más impresionante — Nerón estaba famosamente obsesionado con actuar. Actores y músicos tenían estatus social ambiguo: admirados pero legalmente infames (deshonrados)."},{n:"Pompeya",info:"Instrumentos musicales y frescos preservados aquí.",wiki:"Pompeya preservó instrumentos musicales reales y frescos representando actuaciones. Se encontraron un par de tibiae, un sistro (sonajero egipcio) y címbalos de bronce. Los frescos muestran músicos en banquetes y representaciones teatrales. Los graffiti nombran a los artistas favoritos. El anfiteatro acogía música junto con juegos gladiatorios."}]},
"rel1":{name:"Auge del Cristianismo",desc:"De secta judía a religión oficial en 350 años.",facts:["Legalizado en 313","Oficial en 380","De secta a religión estatal"],locs:[{n:"Jerusalén",info:"Jesús crucificado ~30 d.C.",wiki:"El cristianismo comenzó con Jesús. Pablo lo expandió a los gentiles."},{n:"Antioquía",info:"Aquí se les llamó por primera vez 'cristianos'.",wiki:"Centro crucial temprano de la fe."},{n:"Roma",info:"Pedro y Pablo martirizados aquí.",wiki:"Constantino legalizó en 313. Teodosio lo hizo oficial en 380."}],pathLabels:["Pablo difunde el Evangelio","El cristianismo llega a Roma"]},
"rel2":{name:"Panteón Romano y Religión Estatal",desc:"Júpiter, Marte, Venus: la Tríada Capitolina y ritos estatales que unían a Roma.",facts:["Tríada Capitolina: Júpiter, Juno, Minerva","Augures leían vuelos de aves","Templo de Júpiter reconstruido 3 veces"],locs:[{n:"Monte Capitolino",info:"Templo de Júpiter Óptimo Máximo.",wiki:"El lugar más sagrado de Roma. El Templo de Júpiter Óptimo Máximo coronaba la colina desde 509 a.C. Reconstruido tres veces tras incendios. Los generales terminaban los triunfos aquí. La Tríada Capitolina — Júpiter, Juno y Minerva — encarnaba el poder estatal romano."},{n:"Roma",info:"Augures, flamines y pontífices mantenían la pax deorum.",wiki:"La religión romana era transaccional: realizar rituales correctos, recibir favor divino (pax deorum). Los augures leían vuelos de aves antes de cualquier decisión importante. El pontífice máximo supervisaba todos los asuntos religiosos. Cada aspecto de la vida pública — guerras, elecciones, construcción — requería consulta divina."},{n:"Delfos",info:"Los romanos también consultaban el oráculo griego.",wiki:"Roma respetaba y absorbía dioses extranjeros. Los Libros Sibilinos (profecías griegas) se consultaban en emergencias. Este sincretismo — absorbiendo a Isis, Mitra, Cibeles — era únicamente romano."}],pathLabels:["Los romanos adoptan tradiciones religiosas griegas"]},
"rel3":{name:"Vestales",desc:"Fuego sagrado de Vesta: 30 años de servicio, privilegios extraordinarios y castigos aterradores.",facts:["30 años de servicio","Elegidas a los 6-10 años","Romper castidad = enterrada viva"],locs:[{n:"Templo de Vesta",info:"Templo circular en el Foro — fuego sagrado nunca extinguido.",wiki:"Seis sacerdotisas atendían la llama eterna de Vesta, simbolizando la supervivencia de Roma. Elegidas entre 6-10 años de familias nobles. Servían 30 años de castidad: 10 aprendiendo, 10 actuando, 10 enseñando. Si el fuego se apagaba, la Vestal responsable era azotada. Si rompía su voto de castidad, era enterrada viva en una cámara subterránea con una pequeña lámpara y comida — una 'muerte sin sangre.'"},{n:"Roma",info:"Las Vestales tenían derechos extraordinarios para mujeres romanas.",wiki:"Las Vestales estaban emancipadas de la autoridad paterna — único para mujeres romanas. Podían poseer propiedad, hacer testamentos y votar. Montaban en carruajes, se sentaban en asientos reservados en los juegos, y cualquier hombre que dañara a una Vestal era ejecutado. El culto duró más de 1.000 años hasta que Teodosio I prohibió el culto pagano en 394 d.C."}]},
"rel4":{name:"Cultos Mistéricos: Mitraísmo",desc:"Ritos subterráneos de sacrificio del toro: el culto de soldados que rivalizó con el cristianismo.",facts:["Más de 1.000 inscripciones encontradas","700 representaciones de sacrificio del toro","Siete grados de iniciación"],locs:[{n:"Roma",info:"Docenas de mitreos encontrados bajo la ciudad.",wiki:"El mitraísmo era una religión mistérica centrada en el dios Mitra matando un toro cósmico. Popular del siglo I al IV d.C., especialmente entre soldados y comerciantes. Sobreviven más de 1.000 inscripciones y 700 representaciones del sacrificio del toro. Siete grados de iniciación: Corax (Cuervo), Nymphus, Miles (Soldado), Leo, Perses, Heliodromus y Pater."},{n:"Ostia",info:"18 mitreos encontrados — mayor concentración en cualquier lugar.",wiki:"La ciudad portuaria de Roma tenía más templos mitraicos que ninguna otra. Los miembros compartían comidas rituales en salas subterráneas diseñadas para parecer cuevas, recreando la caverna primordial donde Mitra mató al toro."},{n:"Carnuntum",info:"Importante centro militar del culto en el Danubio.",wiki:"El culto era especialmente popular en las fronteras militares. El mitreo de Carnuntum ha sido reconstruido. En 308 d.C., los emperadores se reunieron aquí y sacrificaron a Mitra — uno de los últimos actos oficiales del culto antes de la supresión cristiana."}],pathLabels:["El mitraísmo prospera en el puerto de Roma","Los soldados llevan el culto a las fronteras"]},
"rel5":{name:"Gran Persecución y Edicto de Milán",desc:"Última y peor persecución de cristianos por Diocleciano: terminada por la legalización de Constantino.",facts:["Última y peor persecución","Iglesias destruidas, escrituras quemadas","Terminada por Edicto de Milán 313"],locs:[{n:"Nicomedia",info:"La persecución comenzó aquí el 23 de febrero de 303 d.C.",wiki:"El primer edicto de Diocleciano fue publicado en la pared de la iglesia frente a su palacio. Los soldados demolieron la iglesia, quemaron las escrituras y despojaron a los cristianos de derechos legales. Edictos posteriores exigían sacrificio universal a los dioses romanos. La persecución fue más feroz en Oriente."},{n:"Roma",info:"Los martirios crearon santos aún venerados hoy.",wiki:"En Roma y África, los cristianos fueron encarcelados, torturados y ejecutados. Las iglesias fueron destruidas y la propiedad confiscada. Pero la persecución resultó contraproducente — el martirio inspiró conversos. La frase de Tertuliano resultó profética: 'La sangre de los mártires es la semilla de la Iglesia.'"},{n:"Mediolanum",info:"Edicto de Milán puso fin a la persecución, 313 d.C.",wiki:"Constantino y Licinio acordaron tolerancia religiosa. El cristianismo fue legalizado. La propiedad confiscada fue devuelta. En 67 años, Teodosio haría del cristianismo la única religión legal del imperio."}],pathLabels:["La persecución se extiende de Oriente a Occidente","Constantino pone fin a la persecución en Milán"]},
"rel6":{name:"Filosofía Estoica",desc:"Desde el pórtico de Zenón hasta la tienda de Marco Aurelio: la virtud como único bien.",facts:["Zenón, Séneca, Epicteto, Marco Aurelio","'Lo que depende de nosotros' vs 'lo que no'","Filosofía antigua más influyente hoy"],locs:[{n:"Atenas",info:"Stoa Poikile — donde nació el estoicismo.",wiki:"Zenón de Citio comenzó a enseñar en la Stoa Poikile (Pórtico Pintado) en Atenas alrededor del 300 a.C. La filosofía enseñaba que la virtud es el único bien verdadero, las emociones vienen de juicios falsos y debemos enfocarnos en lo que podemos controlar. Se convirtió en la filosofía dominante de Roma."},{n:"Roma",info:"Séneca, Epicteto y Marco Aurelio la hicieron romana.",wiki:"El estoicismo fue adaptado al temperamento práctico romano. Séneca — tutor de Nerón — escribió ensayos sobre la ira, la misericordia y la brevedad de la vida. Epicteto — nacido esclavo — enseñó que la libertad se encuentra en aceptar lo que no puedes cambiar. Marco Aurelio — emperador del mundo — escribió las Meditaciones en su tienda de campaña."},{n:"Nicópolis",info:"Donde Epicteto enseñó tras el exilio de Roma.",wiki:"Epicteto, nacido esclavo en Hierápolis, fue exiliado de Roma por Domiciano. Estableció una escuela en Nicópolis en Grecia. Su alumno Arriano registró sus enseñanzas como los Discursos y el Enquiridión — manuales para vivir que siguen en impresión 1.900 años después."}],pathLabels:["El estoicismo viaja de Atenas a Roma","Epicteto exiliado a Nicópolis"]},
"rel7":{name:"Culto Imperial y Deificación",desc:"De Divus Iulius a Teodosio: adorar al emperador como dios.",facts:["Julio César: primer romano deificado","Rechazar sacrificar = traición","Cristianos perseguidos por rechazar"],locs:[{n:"Roma",info:"Templo de Divus Julius en el Foro.",wiki:"Julio César fue el primer romano deificado por el Senado (42 a.C.). Augusto construyó un templo en el lugar de cremación de César. Los emperadores vivos no eran adorados en la propia Roma, pero en las provincias orientales se ofrecían honores divinos libremente. Negarse a sacrificar al genio del emperador se convirtió en la base legal para perseguir a los cristianos."},{n:"Éfeso",info:"Templo de Adriano — culto provincial al emperador.",wiki:"Las ciudades orientales competían por construir templos a los emperadores. Éfeso ganó el título 'neokoros' (guardián del templo) por sus templos del culto imperial. El Templo de Adriano en la Calle de los Curetes sobrevive con su elegante arco."},{n:"Pérgamo",info:"Templo de Trajano en la acrópolis.",wiki:"La acrópolis de Pérgamo albergaba un enorme templo a Trajano y Zeus. La ciudad estuvo entre las primeras en recibir permiso para construir un templo del culto imperial. El Libro del Apocalipsis puede referirse al altar de Pérgamo como 'el trono de Satanás.'"}],pathLabels:["El culto imperial se extiende al este","Pérgamo construye templos al emperador"]},
"rel8":{name:"Culto de Isis",desc:"Diosa egipcia adoptada por Roma: ritos mistéricos, iniciación y devotos en todo el imperio.",facts:["El Senado prohibió el culto repetidamente — volvía","Apuleyo describió la iniciación en El Asno de Oro","File: último templo pagano, cerrado en 537 d.C."],locs:[{n:"Roma",info:"Iseum Campense — importante templo de Isis en el Campo de Marte.",wiki:"El culto a Isis se extendió de Egipto a Roma en el siglo I a.C. El culto ofrecía lo que la religión romana tradicional carecía: salvación personal, vida después de la muerte, rituales emocionales y una diosa compasiva. Los iniciados pasaban por ceremonias dramáticas descritas por Apuleyo en El Asno de Oro. El Senado prohibió repetidamente el culto (58, 53, 48 a.C.) pero siguió regresando. Tras Augusto, fue oficialmente tolerado. El Iseum Campense en Roma era uno de los templos más grandiosos de la ciudad."},{n:"Pompeya",info:"Templo de Isis — uno de los primeros edificios excavados.",wiki:"El Templo de Isis de Pompeya, excavado en 1764, fue uno de los primeros edificios antiguos en ser descubiertos. El culto era tan popular que el templo fue reconstruido a expensas privadas tras el terremoto del 62 d.C. — antes de que muchos edificios públicos fueran reparados."},{n:"File",info:"Último templo pagano del mundo romano — cerrado en 537 d.C.",wiki:"El Templo de Isis en File en el Alto Egipto fue el último templo pagano en funcionamiento del mundo romano. El general de Justiniano Narsés lo cerró en 537 d.C. — más de 150 años después de que Teodosio prohibiera el culto pagano. Los sacerdotes nubios habían continuado los ritos por tratado especial."}],pathLabels:["El culto a Isis se extiende de Egipto a Roma","El culto prospera en Pompeya"]},
"rel9":{name:"Concilio de Nicea",desc:"Primer concilio ecuménico: 318 obispos definieron la ortodoxia cristiana bajo la mirada de Constantino.",facts:["318 obispos asistieron","Credo Niceno: declaración cristiana fundacional","Estableció la fecha de Pascua"],locs:[{n:"Nicea",info:"Actual İznik, Turquía.",wiki:"Constantino convocó el primer concilio ecuménico en Nicea en junio del 325 d.C. Aproximadamente 318 obispos asistieron — casi todos del imperio oriental. El debate central: ¿era Cristo de la misma sustancia (homoousios) que Dios Padre, o un ser creado? Arrio de Alejandría argumentó que Cristo fue creado; Atanasio argumentó que era coeterno con el Padre. El concilio se puso del lado de Atanasio, produciendo el Credo Niceno que sigue siendo la declaración fundamental de la fe cristiana. El concilio también fijó la fecha de Pascua y estableció reglas para el gobierno de la Iglesia."},{n:"Constantinopla",info:"Constantino presidió desde su nueva capital.",wiki:"Constantino, aunque aún no bautizado, presidió la sesión de apertura en púrpura imperial. Buscaba unidad por razones políticas — una Iglesia dividida amenazaba la estabilidad imperial. El Credo Niceno que ayudó a forjar aún es recitado por más de 2.000 millones de cristianos hoy."}],pathLabels:["Constantino convoca a los obispos en Nicea"]},
"rel10":{name:"Judaísmo en el Imperio Romano",desc:"Del culto del Templo a la diáspora: religio licita, tres revueltas y sinagogas en todo el imperio.",facts:["Religio licita: estatus legal protegido","40.000-50.000 judíos en Roma","Sinagoga de Sardes: la más grande conocida, 60 m"],locs:[{n:"Jerusalén",info:"Templo destruido en 70 d.C. Judíos prohibidos tras 135 d.C.",wiki:"Pompeyo conquistó Jerusalén en 63 a.C. El judaísmo tenía un estatus legal único como religio licita (religión permitida) — los judíos estaban exentos del culto al emperador y del servicio militar. El Templo era el centro de la vida judía hasta que Tito lo destruyó en 70 d.C. Tras la revuelta de Bar Kojba (132-136), Adriano prohibió a los judíos en Jerusalén por completo y renombró la provincia Siria Palestina."},{n:"Roma",info:"Trastévere: corazón de la comunidad judía de Roma.",wiki:"La comunidad judía de Roma — una de las más antiguas de Europa — estaba centrada en Trastévere. En su apogeo, 40.000-50.000 judíos vivían en Roma. Se conocen seis sinagogas por inscripciones. Los judíos fueron expulsados por Claudio (~49 d.C.) pero regresaron. Las relaciones fluctuaron entre tolerancia y persecución."},{n:"Sardes",info:"La sinagoga antigua más grande conocida — dentro de un gimnasio romano.",wiki:"La sinagoga de Sardes en Turquía es la más grande conocida de la antigüedad — 60 metros de largo, lujosamente decorada con mosaicos y mármol. Notablemente, fue construida dentro del complejo del gimnasio romano de la ciudad, sugiriendo alta integración social. Sobreviven más de 80 inscripciones de donantes judíos, incluyendo concejales."}],pathLabels:["La diáspora judía llega a Roma","Sinagogas por todo el imperio"]},
"rel11":{name:"Culto de Cibeles (Magna Mater)",desc:"Primer culto oriental adoptado oficialmente por Roma: la Gran Madre llegó durante las guerras púnicas.",facts:["Primer culto oriental adoptado oficialmente","Sacerdotes Galli auto-castrados","Taurobolio: baño ritual en sangre de toro"],locs:[{n:"Roma/Templo del Palatino",info:"Templo de Magna Mater en la Colina Palatina.",wiki:"En 204 a.C., durante los días más oscuros de la Segunda Guerra Púnica, Roma trajo la piedra negra sagrada de Cibeles desde Pesino en Asia Menor a la Colina Palatina. Los Libros Sibilinos habían profetizado que la presencia de la Gran Madre expulsaría a Aníbal de Italia. Su culto extático — con sacerdotes Gali auto-castrados, tambores, címbalos y el taurobolio (baño ritual en sangre de toro) — escandalizó la sensibilidad romana pero era demasiado poderoso para prohibirlo."},{n:"Pesino",info:"Centro original del culto en Asia Menor (actual Turquía).",wiki:"Pesino era el centro original del culto a Cibeles en Frigia. El meteorito sagrado — una imagen anicónica de la diosa — se guardaba aquí hasta que los romanos lo solicitaron en 204 a.C. El sumo sacerdote de la ciudad entregó la piedra a los embajadores romanos, que la llevaron a Roma con gran ceremonia."}],pathLabels:["Piedra sagrada traída de Pesino a Roma (204 a.C.)"]},
"rel12":{name:"Augurio y Adivinación Romanos",desc:"Augures leían vuelos de aves, haruspices leían entrañas, Libros Sibilinos consultados en crisis: ninguna decisión mayor sin aprobación divina.",facts:["Los augures no predecían — leían aprobación divina","Sin auspicios: elecciones, guerras o leyes","Libros Sibilinos consultados en crisis nacionales"],locs:[{n:"Roma/Capitolino",info:"Los augures observaban desde la Colina Capitolina.",wiki:"La augurio era fundamental para la vida pública romana. Los augures (uno de los cuatro principales colegios sacerdotales de Roma) no predecían el futuro — determinaban si los dioses aprobaban una acción propuesta observando vuelos de aves, rayos y otros signos. Nada significativo ocurría sin tomar los auspicios: elecciones, guerras, leyes. Incluso Julio César fue augur. Cicerón, él mismo augur, escribió escépticamente sobre ello."},{n:"Cumas",info:"Hogar de la Sibila — guardiana de los Libros Sibilinos.",wiki:"La Sibila de Cumas, profetisa de Apolo, custodiaba los Libros Sibilinos — una colección de oráculos consultados por el Senado durante crisis graves. Los libros originales ardieron en 83 a.C.; se compilaron reemplazos de oráculos de todo el Mediterráneo. Prescribían rituales como la adopción del culto a Cibeles. La Cuarta Égloga de Virgilio canalizó la profecía de la Sibila de una edad de oro."}],pathLabels:["Los Libros Sibilinos consultados en el Capitolino"]},
"rel13":{name:"Mártires Cristianos Primeros",desc:"Pedro crucificado cabeza abajo, Pablo decapitado, Perpetua en la arena: 'la sangre de los mártires es semilla de la Iglesia'.",facts:["'La sangre de los mártires es semilla de la Iglesia'","Perpetua guió la espada a su propia garganta","El cristianismo creció más rápido durante persecuciones"],locs:[{n:"Roma/Colina Vaticana",info:"Tradición: Pedro crucificado aquí bajo Nerón.",wiki:"La persecución de cristianos comenzó bajo Nerón en 64 d.C. — chivos expiatorios tras el Gran Incendio. Pedro fue tradicionalmente crucificado cabeza abajo en la Colina Vaticana; Pablo decapitado en la Vía Ostiensis. Las persecuciones fueron esporádicas hasta que Decio (250 d.C.) y Diocleciano (303 d.C.) lanzaron campañas en todo el imperio. La frase de Tertuliano 'la sangre de los mártires es la semilla de la Iglesia' (Apologeticum 50.13) resultó profética: el cristianismo creció más rápido durante las persecuciones."},{n:"Cartago",info:"Perpetua y Felicidad martirizadas aquí, 203 d.C.",wiki:"Vibia Perpetua, una noble de 22 años, y su esclava Felicidad fueron ejecutadas en la arena de Cartago el 7 de marzo del 203 d.C. El diario de prisión de Perpetua — uno de los primeros escritos por una mujer cristiana — describe sus visiones y su negativa a sacrificar al genio del emperador. Guió la espada del gladiador a su propia garganta."},{n:"Lyon",info:"Mártires de Lugdunum, 177 d.C.",wiki:"En 177 d.C., una multitud atacó a cristianos en Lugdunum (Lyon). El gobernador los envió a la arena. La esclava Blandina soportó tortura desde el amanecer hasta el anochecer — suspendida en una estaca, atacada por bestias y finalmente muerta por un toro. La Carta de las Iglesias de Vienne y Lyon preserva el relato de testigo presencial."}],pathLabels:["Martirio de Roma al norte de África","La persecución llega a la Galia"]},
"rel14":{name:"Neoplatonismo",desc:"Plotino, Porfirio, Proclo: la última gran filosofía pagana. 'El Uno' emana toda realidad.",facts:["'El Uno' emana toda realidad","Influenció profundamente a Agustín","Academia cerrada por Justiniano en 529 d.C."],locs:[{n:"Roma",info:"Plotino enseñó aquí desde 244 d.C.",wiki:"Plotino (204-270 d.C.) estudió en Alejandría y enseñó en Roma durante 25 años. Sus Enéadas — compiladas por su alumno Porfirio — describen cómo toda la realidad emana de 'Lo Uno' a través de niveles sucesivos: Nous (Intelecto), Alma y Materia. El objetivo del filósofo es el retorno místico a Lo Uno. El neoplatonismo influyó profundamente en Agustín, que tomó prestado su marco para la teología cristiana."},{n:"Alejandría",info:"Plotino estudió con Ammonio Saccas aquí.",wiki:"Alejandría fue la cuna del neoplatonismo. Ammonio Saccas enseñó tanto a Plotino como a Orígenes (el teólogo cristiano). La fusión de la ciudad de filosofía griega, misticismo egipcio y teología judía creó las condiciones intelectuales para el neoplatonismo. Hipatia de Alejandría (murió 415 d.C.) fue la última gran maestra neoplatónica — asesinada por una multitud cristiana."},{n:"Atenas",info:"Academia Neoplatónica cerrada por Justiniano, 529 d.C.",wiki:"Proclo (412-485 d.C.) dirigió la Academia Neoplatónica en Atenas, sistematizando la filosofía. En 529 d.C., el emperador Justiniano cerró la Academia — tradicionalmente vista como el fin de la filosofía antigua. Los siete últimos filósofos huyeron a la corte sasánida en Persia antes de regresar bajo un tratado de paz."}],pathLabels:["Plotino: de Alejandría a Roma","Academia cerrada por Justiniano"]},
"rel15":{name:"Monacato y los Padres del Desierto",desc:"Antonio de Egipto, reglas comunales de Pacomio, Benito de Nursia: ascetas que moldearon la civilización medieval.",facts:["Antonio de Egipto: primer gran ermitaño","Regla de Benito: ora et labora","Los monjes preservaron manuscritos clásicos en la Edad Oscura"],locs:[{n:"Nitria/Desierto Egipcio",info:"Miles de monjes se establecieron en comunidades del desierto.",wiki:"El monacato cristiano comenzó en Egipto. Antonio el Grande (c. 251-356 d.C.) se retiró al desierto alrededor del 270 d.C., luchando contra demonios y atrayendo seguidores. Para el 400 d.C., miles de monjes vivían en comunidades del desierto en Nitria, Scetis y Kellia. Pacomio (c. 292-348) creó los primeros monasterios comunitarios con reglas escritas. Los dichos de los Padres del Desierto — directos, paradójicos, profundos — influyeron en toda la espiritualidad cristiana posterior."},{n:"Monte Cassino",info:"Benedicto fundó su gran monasterio aquí, c. 529 d.C.",wiki:"Benedicto de Nursia (c. 480-547 d.C.) fundó el monasterio de Monte Cassino alrededor del 529 d.C. y escribió su Regla — una guía práctica equilibrando oración (ora), trabajo (labora) y estudio. La Regla Benedictina se convirtió en el estándar del monacato occidental. Los monjes preservaron manuscritos clásicos, mantuvieron la agricultura y proporcionaron estabilidad a través de la Edad Oscura. Monte Cassino fue destruido y reconstruido cuatro veces — más recientemente en la Segunda Guerra Mundial."},{n:"Roma",info:"El papa Gregorio I promovió el monacato benedictino.",wiki:"El papa Gregorio Magno (590-604 d.C.) — él mismo antiguo monje — defendió la Regla de Benedicto. Escribió los Diálogos, que popularizaron la vida y milagros de Benedicto. A través de la influencia de Gregorio, los monasterios benedictinos se convirtieron en la institución religiosa estándar de la Europa medieval, preservando alfabetización, agricultura y cultura a través de siglos de convulsión."}],pathLabels:["Del desierto egipcio a Monte Cassino","La Regla de Benedicto llega a Roma"]},
"plg1":{name:"Peste Antonina",desc:"Viruela de Partia mató a 5-10 millones.",facts:["Probablemente viruela","5-10 millones muertos","2.000/día en Roma"],locs:[{n:"Seleucia",info:"Los soldados la contrajeron aquí.",wiki:"Los soldados romanos saquearon Seleucia durante la guerra de Vero."},{n:"Roma",info:"2.000 murieron diariamente.",wiki:"Galeno describió los síntomas. Marco Aurelio reclutó gladiadores."},{n:"Aquilea",info:"La peste golpeó al ejército.",wiki:"Devastó a los ejércitos de la frontera del Danubio."}],pathLabels:["La peste llevada desde Partia","Devasta a los ejércitos del norte"]},
"plg2":{name:"Gran Incendio de Roma",desc:"Destruyó dos tercios de la ciudad. Nerón culpó a los cristianos.",facts:["Ardió 6 días","10 de 14 distritos","Nerón culpó a los cristianos"],locs:[{n:"Roma",info:"Ardió 6 días.",wiki:"18 de julio del 64 d.C. 10 de 14 distritos dañados. Nerón abrió jardines a los refugiados."}]},
"plg3":{name:"Saqueo de Roma (410)",desc:"Visigodos de Alarico: primer saqueo en 800 años.",facts:["Primer saqueo en 800 años","Tres días","Inspiró La Ciudad de Dios"],locs:[{n:"Roma",info:"Tres días de saqueo.",wiki:"24 de agosto del 410 d.C. Las iglesias fueron respetadas. Jerónimo: 'La ciudad que conquistó el mundo es ella misma conquistada.'"}]},
"plg4":{name:"Peste de Cipriano",desc:"5.000 murieron por día en Roma; la población de Alejandría se redujo a la mitad.",facts:["5.000/día murieron en Roma","Alejandría: 500k a 190k","Nombrada por el obispo Cipriano"],locs:[{n:"Roma",info:"5.000 muertes diarias en el pico.",wiki:"La peste estalló en 249 d.C. y devastó el imperio durante más de una década. En su apogeo, aproximadamente 5.000 personas morían diariamente solo en Roma. Los síntomas incluían fiebre, diarrea, vómitos continuos, extremidades gangrenosas, sordera y ceguera. La enfermedad pudo haber sido viruela o fiebre hemorrágica viral."},{n:"Alejandría",info:"La población colapsó de 500.000 a 190.000.",wiki:"Alejandría fue devastada. El obispo Dionisio registró que la población de la ciudad se redujo a la mitad. Las calles estaban llenas de muertos sin enterrar. La población superviviente era menor que el número de ancianos solos antes de la peste."},{n:"Cartago",info:"El obispo Cipriano documentó la peste aquí.",wiki:"La peste lleva el nombre de San Cipriano, obispo de Cartago, cuyos relatos de primera mano son la principal fuente histórica. La describió como juicio de Dios. Los cristianos que cuidaron a los enfermos ganaron conversos — la peste aceleró el crecimiento del cristianismo."}],pathLabels:["La peste se extiende por el Mediterráneo","Cipriano documenta los horrores en Cartago"]},
"plg5":{name:"Saqueo Galo de Roma (390 a.C.)",desc:"Breno quemó Roma y exigió oro: el trauma moldeó la política romana durante siglos.",facts:["'Vae victis' — ay de los vencidos","Los gansos salvaron el Capitolio","1.000 libras de oro de rescate"],locs:[{n:"Río Alia",info:"El ejército romano fue derrotado aquí.",wiki:"Los galos sénones bajo Breno aplastaron al ejército romano en el río Alia, 11 millas al norte de Roma. La derrota fue tan traumática que el 18 de julio (dies Alliensis) se convirtió en un día de mala suerte en el calendario romano para siempre."},{n:"Monte Capitolino",info:"Resistió siete meses mientras la ciudad ardía.",wiki:"Los galos ocuparon y quemaron el resto de la ciudad. Los gansos sagrados de Juno graznaron para advertir de un asalto nocturno. Cuando los romanos acordaron el rescate, Breno lanzó su espada sobre las balanzas exigiendo más. 'Vae victis!' — ay de los vencidos. Camilo llegó con un ejército y expulsó a los galos."}],pathLabels:["Los galos marchan desde el Alia a Roma"]},
"plg6":{name:"Saqueo de Roma por los Vándalos (455)",desc:"Flota de Genserico desde Cartago: 14 días de saqueo sistemático.",facts:["14 días de saqueo","Menorá de Jerusalén tomada","León I negoció que no hubiera matanzas"],locs:[{n:"Roma",info:"14 días de saqueo metódico.",wiki:"2 de junio del 455 d.C. El rey vándalo Genserico entró en una Roma indefensa. El papa León I lo persuadió de no quemar la ciudad ni asesinar civiles. Pero todo lo de valor fue arrebatado: las tejas de bronce dorado del Templo de Júpiter, los tesoros del Templo incluyendo la menorá judía tomada por Tito en 70 d.C., y miles de cautivos incluyendo la emperatriz Eudoxia y sus hijas."},{n:"Cartago",info:"La flota vándala partió desde aquí.",wiki:"Ironía histórica: Cartago — destruida por Roma en 146 a.C. — ahora enviaba una flota para saquear Roma. Genserico había capturado Cartago en 439 d.C. y construyó la armada más poderosa del Mediterráneo occidental."},{n:"Ostia",info:"La flota vándala desembarcó aquí.",wiki:"El puerto de Roma proporcionó fácil acceso. Tras el saqueo, las naves vándalas fueron cargadas con arte, oro, plata y cautivos. Los vándalos navegaron de regreso a Cartago con el mayor botín desde la caída de Troya."}],pathLabels:["La flota vándala zarpa desde Cartago","Genserico entra en Roma"]},
"plg7":{name:"Terremoto de Antioquía",desc:"Golpeó mientras Trajano invernaba allí; apenas escapó mientras cientos de miles morían.",facts:["Trajano apenas escapó","Cientos de miles muertos","Desencadenó un tsunami"],locs:[{n:"Antioquía",info:"Uno de los terremotos más mortíferos del mundo antiguo.",wiki:"13 de diciembre del 115 d.C. El emperador Trajano estaba invernando en Antioquía preparando su campaña parta cuando un masivo terremoto golpeó. Casio Dión informa que escapó por una ventana mientras los edificios colapsaban a su alrededor. La ciudad — una de las más grandes de Roma con ~500.000 personas — fue devastada. Las réplicas continuaron durante días. Un tsunami golpeó la costa. Trajano organizó esfuerzos de socorro pero Antioquía tardó décadas en recuperarse."}]},
"plg8":{name:"Peste de Justiniano",desc:"Primera pandemia de peste bubónica: 25-50 millones muertos. Constantinopla perdió el 40% de su población.",facts:["25-50 millones muertos","5.000-10.000/día en Constantinopla","Yersinia pestis confirmada por ADN"],locs:[{n:"Constantinopla",info:"El propio emperador Justiniano cayó enfermo pero sobrevivió.",wiki:"La peste llegó a Constantinopla en la primavera del 542. En su pico, 5.000-10.000 morían diariamente. Los cuerpos se apilaban en torres y se arrojaban al mar. Justiniano contrajo la enfermedad pero sobrevivió. La peste regresó en oleadas durante 200 años. El análisis de ADN moderno de víctimas confirmó Yersinia pestis — la misma bacteria que causó la Peste Negra 800 años después."},{n:"Pelusio",info:"Primer brote registrado en el mundo romano, 541 d.C.",wiki:"La peste llegó al puerto egipcio de Pelusio en 541 d.C., probablemente desde África Oriental o Asia Central vía rutas comerciales del Océano Índico. Los barcos de grano de Egipto la llevaron luego por el Mediterráneo."},{n:"Alejandría",info:"Los barcos de grano llevaron la peste desde aquí.",wiki:"El papel de Alejandría como centro de grano del imperio la convirtió en centro de distribución de la peste. Los barcos que llevaban grano a Constantinopla también llevaban ratas y pulgas infectadas. La pandemia mató un estimado de 25-50 millones de personas — quizás el 40-50% de la población del imperio oriental."}],pathLabels:["La peste llega a los puertos egipcios","Los barcos de grano llevan la peste a Constantinopla"]},
"plg9":{name:"Grandes Inundaciones del Tíber",desc:"Maldición recurrente de Roma: el Campo de Marte sumergido días, graneros arruinados, enfermedades desatadas.",facts:["Más de 30 inundaciones mayores registradas","Augusto creó una comisión del Tíber","Campo de Marte sumergido durante días"],locs:[{n:"Roma",info:"Grandes inundaciones registradas en 54 a.C., 69 d.C., 217 d.C. y muchas más.",wiki:"El Tíber inundó Roma repetidamente a lo largo de su historia. Las fuentes antiguas registran más de 30 grandes inundaciones. El bajo Campo de Marte y el Foro Boario eran especialmente vulnerables. En 54 a.C., la inundación fue tan severa que los botes reemplazaron a los carruajes. En 69 d.C., los soldados de Otón tuvieron que vadear agua hasta el pecho. Augusto creó una comisión permanente del Tíber (curatores riparum et alvei Tiberis) y limpió el lecho del río. Trajano construyó un canal en Ostia para desviar las aguas de inundación. A pesar de estos esfuerzos, las inundaciones continuaron — destrozaron almacenes de grano, propagaron enfermedades y socavaron edificios."}]},
"plg10":{name:"Terremoto y Tsunami de Creta del 365",desc:"Terremoto masivo frente a Creta envió un tsunami por el Mediterráneo: barcos lanzados 3 km tierra adentro.",facts:["Magnitud estimada 8.0+","Creta occidental elevada 9 metros","Barcos lanzados 3 km tierra adentro en Alejandría"],locs:[{n:"Creta",info:"Epicentro frente a Creta occidental — magnitud estimada 8.0+.",wiki:"El 21 de julio del 365 d.C., un masivo terremoto golpeó frente a Creta occidental. El análisis geológico moderno estima magnitud 8.0+. El terremoto elevó Creta occidental 9 metros — las instalaciones portuarias antiguas están ahora varadas muy por encima del nivel del mar. El tsunami resultante irradió por todo el Mediterráneo oriental."},{n:"Alejandría",info:"Barcos depositados en tejados. Amiano Marcelino lo presenció.",wiki:"El tsunami devastó Alejandría. El historiador Amiano Marcelino, que puede haberlo presenciado, describe el mar retirándose y luego regresando con enorme fuerza. Los barcos fueron depositados en tejados y a 2 millas tierra adentro. Miles se ahogaron. El aniversario se conmemoró anualmente en Alejandría durante siglos como un 'día de horror.'"}],pathLabels:["El tsunami cruza el Mediterráneo hasta Alejandría"]},
"plg11":{name:"Terremoto de Pompeya del 62 d.C.",desc:"Terremoto mayor dañó gravemente Pompeya y Herculano 17 años antes del Vesubio; gran parte de la ciudad aún se reconstruía.",facts:["5 de febrero del 62 d.C.","Gran parte de Pompeya aún en reconstrucción cuando erupcionó el Vesubio","Séneca lo describió en Cuestiones Naturales"],locs:[{n:"Pompeya",info:"Gravemente dañada — extensa reconstrucción en curso en 79 d.C.",wiki:"El 5 de febrero del 62 d.C., un poderoso terremoto golpeó la región de la Bahía de Nápoles. Pompeya sufrió graves daños: el Foro, los templos y muchas casas fueron parcialmente destruidos. Diecisiete años de reconstrucción estaban en curso cuando el Vesubio eruptó en 79 d.C. — los arqueólogos pueden distinguir el daño del terremoto de la destrucción volcánica. Séneca escribió un famoso relato del terremoto en sus Cuestiones Naturales."},{n:"Herculano",info:"También dañado en el terremoto del 62 d.C.",wiki:"Herculano estaba más cerca del epicentro y sufrió daños significativos. El terremoto fue probablemente causado por movimiento de magma bajo el Vesubio — una advertencia que los romanos no pudieron interpretar. Muchas familias ricas ya habían abandonado el área antes de la erupción del 79 d.C."}]},
"plg12":{name:"Erupción del Vesubio",desc:"24 de agosto del 79 d.C.: enterró Pompeya y Herculano.",facts:["24 de agosto del 79 d.C.","Plinio el Joven lo documentó","~16.000 muertos"],locs:[{n:"Roma",info:"Destruyó el Templo de la Paz y los almacenes circundantes.",wiki:"Un devastador incendio estalló en Roma en 192 d.C. durante el reinado de Cómodo. Destruyó el Templo de la Paz (obra maestra de Vespasiano, considerado uno de los edificios más bellos de Roma), almacenes con especias y medicinas exóticas de Oriente, y vastos archivos de registros públicos. Casio Dión comparó el desastre con el Gran Incendio del 64 d.C. Cómodo propuso renombrar Roma 'Colonia Commodiana' durante la reconstrucción — fue asesinado el 31 de diciembre del 192."}]},
"plg13":{name:"Terremoto de Antioquía del 526",desc:"Uno de los terremotos más mortíferos de la antigüedad: ~250.000 muertos.",facts:["~250.000 muertos","Destruyó la ciudad","Justiniano la reconstruyó"],locs:[{n:"Maguncia",info:"Punto de cruce en el Rin helado, 31 de diciembre del 406.",wiki:"En la noche del 31 de diciembre del 406 d.C., una masiva coalición de vándalos, alanos y suevos cruzó el Rin helado cerca de Maguncia. Los guardias fronterizos francos fueron superados. Los bárbaros se dispersaron por la Galia, saqueando ciudades que habían estado en paz durante generaciones. Jerónimo escribió: 'Innumerables y muy salvajes pueblos han ocupado ahora toda la Galia.' En cuatro años, los vándalos llegarían a España; en 30, tomarían Cartago. La frontera del Rin nunca fue restaurada."}]},
"plg14":{name:"Hambruna del 436 d.C.",desc:"Sequía y plagas de langostas devastaron el imperio; miles murieron de hambre.",facts:["Sequía y langostas","Miles murieron de hambre","Debilitó al imperio occidental"],locs:[{n:"Roma",info:"Ciudad de más de 1 millón totalmente dependiente del grano importado.",wiki:"La población de más de un millón de Roma dependía enteramente del grano importado — principalmente de Egipto, el norte de África y Sicilia. Cualquier interrupción (piratería, tormentas, inestabilidad política) causaba crisis alimentarias inmediatas. En 57 a.C., disturbios forzaron al Senado a conceder a Pompeyo poder extraordinario sobre el suministro de grano. César y luego Augusto formalizaron la annona — una distribución estatal de grano que para el Imperio alimentaba gratis a 200.000 ciudadanos. El control de la annona era poder en sí mismo."},{n:"Ostia",info:"Puerto de Roma: cuello de botella crítico para las importaciones de grano.",wiki:"Ostia era el cordón umbilical de Roma. Los barcos de grano de Egipto, África y Sicilia descargaban aquí antes de que las barcazas llevaran suministros río arriba por el Tíber. Cuando el puerto se sedimentó, Claudio construyó Portus cerca. Una interrupción del suministro de grano aquí podría matar de hambre a Roma en semanas."}],pathLabels:["Barcazas de grano río arriba por el Tíber hasta Roma"]},
"plg15":{name:"Incendio de Roma del 64 d.C.",desc:"Ardió 6 días; Nerón construyó la Domus Aurea en las cenizas.",facts:["Ardió 6 días","10 de 14 distritos destruidos","Nerón construyó la Domus Aurea"],locs:[{n:"Roma",info:"La población colapsó de ~800.000 a ~500.000.",wiki:"Alarico y sus visigodos bloquearon Roma tres veces entre 408-410 d.C. El primer asedio (408) causó hambruna horrible: 'los habitantes estaban al punto de comerse unos a otros' escribió Zósimo. La ciudad pagó un rescate masivo. El segundo asedio (409) instaló un emperador títere. El tercer asedio (24 de agosto del 410) terminó en el saqueo de Roma — la primera vez en 800 años que la ciudad caía ante un enemigo extranjero. La población ya había colapsado por hambre y enfermedad. Agustín escribió La Ciudad de Dios en respuesta."}]},
"bio1":{name:"Cicerón",desc:"El mayor orador de Roma. Defensor de la República. Su cabeza clavada en la Rostra.",facts:["El mayor orador latino","Aplastó a Catilina","Cabeza clavada en la Rostra"],locs:[{n:"Arpino (nacimiento)",info:"Pequeña ciudad en la colina — también lugar de nacimiento de Mario.",wiki:"Nacido el 3 de enero del 106 a.C. Un 'novus homo' — el primero de su familia en alcanzar el consulado."},{n:"Roma",info:"Cónsul 63 a.C. Sofocó a Catilina. Asesinado por Antonio 43 a.C.",wiki:"Como cónsul, sofocó la conspiración de Catilina. El mayor orador latino. Sus obras filosóficas transmitieron el pensamiento griego a Roma. Pronunció las Filípicas contra Antonio. Asesinado el 7 de diciembre del 43 a.C. Cabeza y manos clavadas en la Rostra."},{n:"Atenas",info:"Estudió filosofía aquí.",wiki:"Estudió en la Academia y con filósofos estoicos."},{n:"Túsculo",info:"Villa donde escribió sus grandes obras.",wiki:"Retiro favorito. Escribió las Disputaciones Tusculanas, Sobre la vejez, Sobre la amistad."}],pathLabels:["El joven Cicerón llega a Roma","Estudia filosofía en Atenas","Regresa — asciende a cónsul"],pathWikis:["Llegó siendo adolescente. Ganó su primer gran caso a los 25 años.",null,null]},
"bio2":{name:"Séneca el Joven",desc:"Filósofo estoico. Preceptor de Nerón. Predicaba la sencillez con 300 millones de sestercios.",facts:["Filósofo estoico","Preceptor de Nerón","300 millones de sestercios"],locs:[{n:"Córduba (nacimiento)",info:"Actual Córdoba, España.",wiki:"Nacido ~4 a.C. Su padre fue un famoso retórico. Su sobrino fue el poeta Lucano."},{n:"Roma",info:"Preceptor de Nerón. Suicidio forzado 65 d.C.",wiki:"Gobernó efectivamente Roma durante los primeros años de Nerón. Acumuló 300 millones de sestercios mientras escribía sobre la pobreza. Suicidio forzado 65 d.C. — abrió las venas dictando filosofía."},{n:"Córcega",info:"Exiliado 8 años por Claudio.",wiki:"Exiliado 41-49 d.C. Escribió Sobre la brevedad de la vida."}],pathLabels:["Llega a Roma desde Hispania","Exiliado a Córcega","Reclamado para ser preceptor de Nerón"]},
"bio3":{name:"Plinio el Viejo",desc:"El mayor enciclopedista. 37 volúmenes. Murió investigando el Vesubio.",facts:["37 volúmenes","Historia Natural","Murió en la erupción del 79 d.C."],locs:[{n:"Como (nacimiento)",info:"Actual Como.",wiki:"Nacido 23 d.C. Familia ecuestre. Sirvió en Germania."},{n:"Roma",info:"Consejero de Vespasiano. Escribió Historia Natural.",wiki:"Enciclopedia de 37 volúmenes citando más de 2.000 libros. Leyó constantemente, incluso durante las comidas."},{n:"Miseno",info:"Comandante de la flota cuando entró en erupción el Vesubio.",wiki:"Navegó por la bahía para investigar y rescatar."},{n:"Estabia",info:"Murió por gases volcánicos.",wiki:"Cenó con calma, durmió. Murió por gases en la playa. La 'erupción pliniana' lleva su nombre."}],pathLabels:["Llega a Roma","Comandante de flota en Miseno","Navega hacia la erupción"],pathWikis:[null,null,"La curiosidad venció a la prudencia. Ordenó a la flota avanzar hacia la piedra pómez cayendo, dictando observaciones."]},
"bio4":{name:"Agripina la Menor",desc:"Madre de Nerón. Casada con Claudio. Asesinada por orden de su hijo.",facts:["Madre de Nerón","Casada con Claudio","Asesinada por su hijo"],locs:[{n:"Colonia (nacimiento)",info:"Actual Colonia — nombrada en su honor.",wiki:"Nacida el 6 de noviembre del 15 d.C. Bisnieta de Augusto. Colonia se llamó Colonia Agrippinensis."},{n:"Roma",info:"Casada con su tío Claudio. Puede haberlo envenenado. Asesinada por Nerón.",wiki:"Casada con Claudio 49 d.C. Puede haberlo envenenado con setas 54 d.C. Nerón intentó hundir el barco, luego envió soldados. Ella dijo: 'Golpea aquí — aquí parió a Nerón.'"},{n:"Baya",info:"Fallido asesinato de Nerón hundiendo el barco.",wiki:"El techo con plomo se derrumbó, matando a su acompañante. Agripina nadó hasta la orilla."}],pathLabels:["Traída a Roma como infante imperial","Fallido asesinato de Nerón con el barco"]},
"bio5":{name:"Livia Drusila",desc:"Esposa de Augusto. Madre de Tiberio. La mujer más poderosa de Roma.",facts:["Esposa de Augusto","68 años de matrimonio","Deificada por Claudio"],locs:[{n:"Túsculo (nacimiento)",info:"Familia de agricultores.",wiki:"Nacido 234 a.C. Ideal ciudadano-campesino-soldado."},{n:"Roma",info:"Cónsul 195 a.C. Censor 184 a.C.",wiki:"Expulsó a senadores corruptos. Primer historiador en prosa latina. De Agri Cultura. Terminaba cada discurso: 'Cartago debe ser destruida.'"},{n:"Cartago",info:"Horrorizado por su recuperación.",wiki:"153 a.C.: mostró higos frescos en el Senado — recogidos hacía 3 días en Cartago."}],pathLabels:["Llega a Roma","Embajada a Cartago"],pathWikis:[null,"Vio la riqueza renovada de la ciudad. Se convenció de que Roma nunca estaría segura mientras Cartago existiera."]},
"bio6":{name:"Cleopatra",desc:"Última reina de Egipto. Aliada de César y Antonio. Suicidio con áspid.",facts:["Última reina ptolemaica","Aliada de César y Antonio","Suicidio en 30 a.C."],locs:[{n:"Jerusalén (nacimiento)",info:"Familia sacerdotal. Lideró fuerzas rebeldes.",wiki:"Nacido 37 d.C. Nombrado comandante rebelde en Galilea sin experiencia militar."},{n:"Jotapata",info:"Se rindió tras asedio de 47 días.",wiki:"Se escondió en una cueva con 40 hombres. Pacto de suicidio pero manipuló el orden para sobrevivir. Profetizó que Vespasiano sería emperador."},{n:"Roma",info:"Vivió en la casa de Vespasiano. Escribió sus historias.",wiki:"Recibió ciudadanía y pensión. Escribió Guerra de los judíos, Antigüedades de los judíos. Sin él sabríamos casi nada sobre la destrucción del Templo."}],pathLabels:["Comanda fuerzas rebeldes en Galilea","Presencia el asedio de Jerusalén","Llevado a Roma como protegido flavio"],pathWikis:[null,"Acompañó a Tito, instando a la rendición. Vio arder el Templo.",null]},
"bio7":{name:"Agripa",desc:"General y arquitecto de Augusto. Victorioso en Accio. Construyó el Panteón original.",facts:["Victorioso en Accio","Yerno de Augusto","Construyó acueductos y el Panteón"],locs:[{n:"Roma (nacimiento)",info:"Familia patricia. Sobrevivió a Cannas a los 17.",wiki:"Nacido ~236 a.C. en los Cornelios Escipiones, una de las familias patricias más antiguas de Roma. A los 17 sobrevivió la matanza de Cannas. Elegido para comandar en Hispania a los 25 sin haber ocupado magistratura — el Senado estaba desesperado."},{n:"Cartago Nova",info:"Capturada en un solo día, 209 a.C.",wiki:"Escipión descubrió que la laguna del puerto era vadeable con marea baja. Mientras la fuerza principal atacaba las murallas, un equipo de asalto vadearon la laguna y escalaron las murallas marítimas indefensas. La ciudad cayó en un solo día."},{n:"Zama",info:"Derrotó a Aníbal, 202 a.C.",wiki:"La batalla decisiva de la Segunda Guerra Púnica. Escipión usó cuernos y trompetas para aterrorizar a los 80 elefantes de guerra de Aníbal, que huyeron hacia las líneas cartaginesas. El propio Aníbal dijo que Escipión era el mayor general que jamás vivió."},{n:"Liternum",info:"Murió en exilio voluntario ~183 a.C.",wiki:"Enemigos políticos liderados por Catón el Viejo lo acusaron de aceptar sobornos. Amargamente decepcionado, se retiró a su finca. Su epitafio decía: 'Ingrata patria, no tendrás mis huesos.'"}],pathLabels:["Comanda en Hispania a los 25 años","Invade África, derrota a Aníbal","Se retira en desgracia a Liternum"]},
"bio8":{name:"Bruto",desc:"Asesino de César. '¡Tú también, hijo mío!' Defendió la República hasta Filipos.",facts:["Uno de los asesinos de César","'¡Tú también, hijo mío!'","Suicidio en Filipos"],locs:[{n:"Alejandría (nacimiento)",info:"Nacida 69 a.C. Dinastía ptolemaica.",wiki:"Nacida en la dinastía griega macedonia que gobernó Egipto desde la muerte de Alejandro. Única gobernante ptolemaica que aprendió egipcio. También hablaba etíope, hebreo, arameo, árabe, siríaco, medo y parto. Brillante administradora que restauró la economía de Egipto."},{n:"Roma",info:"Vivió aquí como invitada de César, 46-44 a.C.",wiki:"Llegó con su hijo Cesarión. Los romanos se escandalizaron. Tras el asesinato de César, huyó de vuelta a Alejandría."},{n:"Tarso",info:"Conoció a Antonio aquí en 41 a.C.",wiki:"Llegó en una barcaza dorada con velas púrpura y remos de plata. Vestida como Afrodita. Antonio quedó instantáneamente encantado. Su alianza produjo tres hijos y una asociación política que aterrorizó a Roma."},{n:"Accio",info:"Derrota naval, septiembre 31 a.C.",wiki:"Flota combinada de 350 naves enfrentó a las 400 de Octaviano bajo Agripa. Las 60 naves egipcias de Cleopatra huyeron con el tesoro a mitad de la batalla. Antonio abandonó su flota para seguirla. Ambos se suicidaron en Alejandría al año siguiente."}],pathLabels:["Viaja a Roma con César","Regresa al este, conoce a Antonio en Tarso","Flota combinada navega a Accio","Huye a Alejandría — suicidio"]},
"bio9":{name:"Catón el Viejo",desc:"Censor incorruptible. 'Cartago debe ser destruida.' Defensor de la virtud romana.",facts:["'Cartago debe ser destruida'","Censor 184 a.C.","Modelo de virtud romana"],locs:[{n:"Roma (nacimiento)",info:"Patricio empobrecido. Ascendió por astucia.",wiki:"Nacido 138 a.C. en una antigua familia patricia en dificultades. Vivió en una pensión de joven. Ascendió por talento militar en África bajo Mario. En 88 a.C. fue el primer romano en marchar legiones contra su propia ciudad."},{n:"Atenas",info:"Saqueada 86 a.C. durante la Guerra Mitridática.",wiki:"Sila sitió Atenas para castigar su alianza con Mitrídates VI del Ponto. Tras capturar la ciudad, la despojó de tesoros pero perdonó los edificios. Derrotó a Mitrídates en las batallas de Queronea y Orcómeno."},{n:"Puerta Colina",info:"82 a.C.: batalla decisiva en las puertas de Roma.",wiki:"1 de noviembre del 82 a.C. Los veteranos de Sila lucharon toda la noche contra samnitas y marianos. La victoria le dio control total. Luego revivió el cargo dormido de dictador y publicó listas de proscripción — 520 nombres de senadores y ecuestres para matar al instante."},{n:"Puteoli",info:"Murió 78 a.C. tras retirarse a sus fincas.",wiki:"Asombrosamente, Sila renunció a la dictadura tras aprobar reformas constitucionales. Se retiró a su finca. Murió en 78 a.C., al parecer de una enfermedad que hacía que los piojos devoraran su carne. Su epitafio: 'Ningún amigo me sirvió, ningún enemigo me ofendió, a quien no haya pagado en su totalidad.'"}],pathLabels:["Marcha al este contra Mitrídates","Regresa a la guerra civil en la Puerta Colina","Renuncia a la dictadura y se retira"],pathWikis:[null,"Luchó toda la noche. 50.000 murieron en la batalla.",null]},
"bio10":{name:"Tiberio Graco",desc:"Tribuno que propuso reforma agraria. Asesinado por el Senado.",facts:["Reforma agraria 133 a.C.","Asesinado por senadores","Inició la violencia política"],locs:[{n:"Roma",info:"Tres triunfos — igualado solo por Rómulo.",wiki:"Nacido 106 a.C. en Piceno. Levantó tres legiones a los 23 años desde las fincas familiares. Sila lo llamó 'Magnus' (el Grande). Ganó triunfos sobre África, Hispania y el Este. Construyó el primer teatro de piedra permanente de Roma. Formó el Primer Triunvirato con César y Craso en 60 a.C."},{n:"Mediterráneo",info:"Barrió piratas en 3 meses, 67 a.C.",wiki:"Recibió mando extraordinario con 500 naves y 120.000 tropas. Barrió el Mediterráneo de piratas en solo tres meses — campaña casi incruenta que restauró el suministro de grano de Roma."},{n:"Jerusalén",info:"Capturó 63 a.C. Entró en el Santo de los Santos.",wiki:"Intervino en una guerra civil judea. Sitió el Monte del Templo durante tres meses. Entró en el Santo de los Santos — la sala más sagrada del judaísmo — pero al parecer no tocó nada. Judea se convirtió en estado cliente romano."},{n:"Pelusio",info:"Asesinado el 28 de septiembre del 48 a.C.",wiki:"Tras la derrota en Farsalia, Pompeyo huyó a Egipto buscando refugio. Los consejeros de Ptolomeo XIII decidieron que un Pompeyo muerto era menos peligroso que uno vivo. Al bajar Pompeyo del barco, lo apuñalaron. César al parecer lloró ante la cabeza cercenada de su rival."}],pathLabels:["Barre piratas del Mediterráneo","Conquista el Este, captura Jerusalén","Huye a Egipto tras Farsalia"]},
"bio11":{name:"Cayo Graco",desc:"Herman menor de Tiberio. Extendió la reforma. Suicidio en el Aventino.",facts:["Tribuno 123-122 a.C.","Grano subsidiado para pobres","Suicidio tras fracaso"],locs:[{n:"Roma (nacimiento)",info:"Nacido el 26 de abril del 121 d.C. en familia prominente.",wiki:"Preparado para el poder desde la infancia. Adriano lo notó pronto; Antonino Pío lo adoptó. Co-gobernó con Lucio Vero 161-169. Vendió muebles del palacio y joyas imperiales en lugar de subir impuestos para financiar las guerras marcomanas. Su estatua ecuestre en el Capitolio sobrevivió porque los romanos medievales pensaban que era Constantino."},{n:"Carnunto",info:"Cuartel general de las campañas danubianas.",wiki:"Importante fortaleza legionaria. Marco Aurelio pasó años aquí dirigiendo operaciones contra marcomanos y cuados. Entre batallas y consejos de guerra, escribió el diario filosófico privado que conocemos como las Meditaciones."},{n:"Sirmio",info:"Escribió gran parte de las Meditaciones aquí.",wiki:"Importante base panonia. Los libros 2-3 de las Meditaciones llevan el encabezado 'Escrito en Sirmio' y 'Entre los cuados, en el río Gran'. Nunca pensadas para publicación — pura autoexamen."},{n:"Vindobona",info:"Probable lugar de muerte, 17 de marzo del 180 d.C.",wiki:"Actual Viena. La mayoría de las fuentes dicen que Marco Aurelio murió aquí. Sus últimas palabras registradas instaron a sus oficiales: 'Id hacia el sol naciente; yo ya me pongo.' Su hijo Cómodo, que lo sucedió, deshizo su legado."}],pathLabels:["Campañas en el Danubio","Escribe Meditaciones entre batallas","Muere en la frontera, 180 d.C."]},
"bio12":{name:"Lucrecia",desc:"Su violación por Tarquinio desencadenó la expulsión de los reyes.",facts:["Violada por Sexto Tarquinio","Suicidio desencadenó la revuelta","'Nunca más un rey'"],locs:[{n:"Cartago (nacimiento)",info:"Nacido 247 a.C. Hijo de Amílcar Barca.",wiki:"A los 9 años su padre Amílcar le hizo jurar un juramento de odio eterno contra Roma en un altar. Criado en los campamentos militares de Iberia. A los 26 comandaba todas las fuerzas cartaginesas en Hispania."},{n:"Alpes",info:"Cruzó con 37 elefantes, otoño 218 a.C.",wiki:"Una de las hazañas militares más audaces de la historia. Partió con 90.000 infantes, 12.000 jinetes y 37 elefantes de guerra. El brutal cruce alpino de 15 días mató a miles. Llegó a Italia con solo 26.000 hombres — y procedió a aterrorizar a Roma durante 15 años."},{n:"Cannas",info:"Agosto 216 a.C.: 50-70.000 romanos muertos.",wiki:"La victoria táctica más perfecta de la historia. Aníbal dejó que su centro se doblara hacia atrás, atrayendo a los romanos, mientras la caballería completaba un doble envolvimiento. 50-70.000 romanos murieron en una sola tarde — incluyendo 80 senadores. Aún se estudia en academias militares de todo el mundo."},{n:"Zama",info:"Derrotado por Escipión, 202 a.C.",wiki:"Reclamado para defender Cartago. Escipión volvió sus propias tácticas de elefantes contra él. Tras la derrota, Aníbal se convirtió en político reformista en Cartago, luego huyó a cortes orientales."},{n:"Libisa",info:"Se envenenó ~183 a.C. en Bitinia.",wiki:"Perseguido implacablemente por Roma incluso en exilio. Finalmente acorralado en Bitinia (actual Turquía), tomó veneno que había guardado largo tiempo en un anillo. 'Aliviemos a los romanos de la ansiedad que han experimentado tanto tiempo, ya que creen que prueba demasiado su paciencia esperar la muerte de un anciano.'"}],pathLabels:["Parte de Iberia, cruza los Alpes","Devasta Italia durante 15 años","Reclamado a Cartago, derrotado en Zama","Exilio y muerte en Bitinia"]},
"bio13":{name:"Cornelia",desc:"Madre de los Graco. 'Estas son mis joyas' — sus hijos.",facts:["Madre de los Graco","'Estas son mis joyas'","Modelo de matrona romana"],locs:[{n:"Roma",info:"Casada con Augusto 38 a.C. Ejercía inmensa influencia.",wiki:"Nacida 58 a.C. en familia noble. Casada con Octaviano (Augusto) en 38 a.C. estando embarazada de su segundo hijo. Durante 51 años fue su consejera más cercana. Administró una vasta fortuna personal y red de clientes. Rumores la acusaron de envenenar a los herederos de Augusto para allanar el camino a su hijo Tiberio — probable calumnia de enemigos políticos."},{n:"Nola",info:"Augusto murió aquí en sus brazos, 14 d.C.",wiki:"Augusto murió en Nola el 19 de agosto del 14 d.C. Livia estaba a su lado. Sus últimas palabras para ella: 'Vive consciente de nuestro matrimonio, Livia, y adiós.' Gestionó la transición a Tiberio tan suavemente que la noticia de la muerte de Augusto y la sucesión de Tiberio se anunciaron simultáneamente."},{n:"Prima Porta",info:"Su villa — sitio de la famosa estatua de Augusto.",wiki:"Villa campestre de Livia al norte de Roma. La famosa estatua de Augusto en traje militar se encontró aquí. La sala subterránea del jardín de la villa, pintada con exquisitos frescos botánicos, sobrevive en el Palazzo Massimo."}],pathLabels:["Junto al lecho de muerte de Augusto en Nola","Villa en Prima Porta"]},
"bio14":{name:"Fulvia",desc:"Esposa de Marco Antonio. Comandó ejércitos contra Octaviano.",facts:["Esposa de Antonio y Clodio","Comandó tropas en Perusa","Aguja clavada en la lengua de Cicerón"],locs:[{n:"Itálica",info:"Nacido 76 d.C. en Hispania.",wiki:"Nacido en Itálica en una familia hispana romanizada relacionada con Trajano. Pupilo de Trajano desde los 10 años tras la muerte de su padre. Ascendió por servicio militar y administrativo."},{n:"Roma",info:"Reconstruyó el Panteón. Tumba masiva se convirtió en Castel Sant'Angelo.",wiki:"El legado arquitectónico de Adriano no tiene parangón entre los emperadores. El Panteón, el Templo de Venus y Roma, y su mausoleo (Castel Sant'Angelo) transformaron la ciudad. Fue el primer emperador en llevar barba — tributo a los filósofos griegos."},{n:"Atenas",info:"Su ciudad amada — completó el Templo de Zeus Olímpico.",wiki:"Adriano pasó años en Atenas. Completó el Templo de Zeus Olímpico tras 600 años. Construyó un barrio entero nuevo de la ciudad. Iniciado en los Misterios Eleusinos."},{n:"Tívoli",info:"Villa Adriana — el proyecto de construcción privada más ambicioso de la historia romana.",wiki:"120 hectáreas con más de 30 edificios recreando lugares de sus viajes. Canal de Canopo de Egipto, Liceo y Academia de Atenas, teatro marítimo para retiro privado."},{n:"Egipto",info:"Antinoo se ahogó en el Nilo, 130 d.C.",wiki:"El compañero de Adriano Antinoo se ahogó en el Nilo en circunstancias misteriosas. El dolor de Adriano fue extraordinario — fundó una ciudad, deificó a Antinoo y encargó más estatuas de él que de cualquier otra figura antigua. Su poema final: 'Animula vagula blandula' — 'Alma pequeña, errante, huésped gentil.'"}],pathLabels:["De Hispania a emperador","Años en Atenas","Viaja a Egipto — pierde a Antinoo"]},
"bio15":{name:"Teodora",desc:"Emperatriz de Justiniano. Actriz. 'El púrpura es el más noble sudario.'",facts:["De actriz a emperatriz","'El púrpura es el más noble sudario'","Influenció la política imperial"],locs:[{n:"Palmira",info:"Ciudad oasis comercial del desierto — capital de Zenobia.",wiki:"Palmira creció rica como ciudad caravanera entre Roma y Partia. Tras el asesinato de su marido Odenato en 267, Zenobia gobernó como regente de su hijo. Reclamaba descendencia de Cleopatra y Dido."},{n:"Antioquía",info:"Tomada por las fuerzas de Zenobia.",wiki:"El general de Zenobia Zabdas conquistó Siria y tomó Antioquía — la tercera ciudad más grande de Roma. Su imperio abarcó eventualmente Siria, Palestina, Egipto y gran parte de Anatolia."},{n:"Emesa",info:"Actual Homs — batalla decisiva contra Aureliano.",wiki:"Aureliano derrotó a las fuerzas de Zenobia en Emesa en 272. Ella se retiró a Palmira donde Aureliano la sitió. Intentó huir a Persia pero fue capturada cruzando el Éufrates."},{n:"Roma",info:"Desfilada en el triunfo de Aureliano con cadenas de oro.",wiki:"Zenobia fue exhibida en el triunfo de Aureliano, al parecer cargada de joyas y cadenas de oro. A diferencia de la mayoría de cautivos, fue perdonada. Algunas fuentes dicen que vivió el resto de su vida como matrona romana en Tívoli."}],pathLabels:["Conquista Siria y el Este","Aureliano la derrota en Emesa","Desfilada en Roma con cadenas de oro"]},
"bio16":{name:"Helena",desc:"Madre de Constantino. Peregrinación a Tierra Santa. Encontró la Vera Cruz.",facts:["Madre de Constantino","Peregrinación a Jerusalén","Tradición de la Vera Cruz"],locs:[{n:"Roma",info:"Emperador 37-41 d.C.",wiki:"Nacido Cayo Julio César Germánico. 'Calígula' (botita) era un apodo infantil de los soldados. Los primeros seis meses fueron prometedores — reclamó exiliados, abolió juicios por traición. Tras una enfermedad grave, se volvió errático: se declaró dios, mantuvo conversaciones con Júpiter, planeó hacer cónsul a su caballo Incitato."},{n:"Antium",info:"Nacido aquí, 12 d.C.",wiki:"Actual Anzio, al sur de Roma. Nacido del amado general Germánico y Agripina la Mayor. De pequeño llevaba botas de soldado en miniatura en el campamento de su padre — de ahí 'botita.'"},{n:"Baya",info:"Construyó un puente de pontones a través de la bahía de Nápoles.",wiki:"Para refutar una profecía de que tenía 'no más posibilidad de ser emperador que de montar un caballo a través de la bahía de Baya', Calígula ordenó un puente de pontones de barcos de 3 millas a través de la bahía y cabalgó sobre él en triunfo."}],pathLabels:["Criado en la corte imperial","Puente de barcos a través de la bahía"]},
"bio17":{name:"Zenobia",desc:"Reina de Palmira. Conquistó Egipto. Capturada por Aureliano.",facts:["Reina de Palmira","Conquistó Egipto y Siria","Paseada en cadenas de oro"],locs:[{n:"Arpino",info:"Nacido 157 a.C. — ciudad natal de Mario y Cicerón.",wiki:"Modesta ciudad en las colinas al sureste de Roma. Mario era un novus homo — el primero de su familia en alcanzar el Senado. Sus modales rudos ofendían a los aristócratas pero los soldados lo amaban."},{n:"Aquae Sextiae",info:"102 a.C.: aniquiló a los teutones.",wiki:"Actual Aix-en-Provence. Mario destruyó a los teutones en una batalla masiva — al parecer 100.000 muertos o capturados. La victoria fue tan completa que se dijo que los campos locales fueron fertilizados por los muertos."},{n:"Roma",info:"Siete consulados. Proscripciones. Murió enero 86 a.C.",wiki:"La rivalidad de Mario con Sila produjo la primera guerra civil de Roma. Tras la marcha de Sila sobre Roma, Mario huyó a África. Regresó en 87 a.C., desató una matanza contra los partidarios de Sila, y murió de pleuresía solo 17 días después de su séptimo consulado."}],pathLabels:["El Hombre Nuevo asciende en Roma","Salva a Roma de la invasión germánica","Regresa a la guerra política y civil"]},
"bio18":{name:"Boudica",desc:"Reina icena. Quemó tres ciudades. Envenenada tras la derrota.",facts:["Reina de los icenos","70.000 romanos muertos","Envenenada tras derrota"],locs:[{n:"Roma",info:"Ambos sirvieron como tribunos. Ambos fueron asesinados.",wiki:"Tiberio Graco (tribuno 133 a.C.) propuso redistribuir tierras públicas a los pobres. Cuando el Senado lo bloqueó, los evitó — sin precedentes. Fue golpeado hasta la muerte por senadores con patas de silla. Su hermano menor Cayo (tribuno 123-122 a.C.) fue más lejos: subsidios de grano, construcción de caminos, reforma de jurados. También fue asesinado — perseguido por una turba senatorial. 3.000 de sus partidarios fueron ejecutados."},{n:"Colonia de Cartago",info:"Cayo propuso una colonia aquí — indignó al Senado.",wiki:"Cayo Graco propuso refundar Cartago como colonia romana (Colonia Junonia). Los senadores conservadores quedaron horrorizados por asentar ciudadanos romanos en las ruinas malditas. La colonia se usó como pretexto para actuar contra Cayo."}],pathLabels:["Cayo propone colonia en Cartago"]},
"bio19":{name:"Livia Drusila",desc:"Esposa de Augusto durante 52 años. Madre de Tiberio.",facts:["52 años de matrimonio","Poder detrás del trono","Deificada por Claudio"],locs:[{n:"Constantinopla",info:"Gobernaron conjuntamente 527-548 (muerte de Teodora).",wiki:"Justiniano I (482-565) y su esposa Teodora (c. 497-548) formaron una de las asociaciones más trascendentales de la historia. Teodora — antigua actriz y bailarina (considerada deshonrosa) — era brillante, despiadada y decisiva. Durante los disturbios de Nika de 532, cuando Justiniano preparaba huir, Teodora declaró: 'El púrpura es el sudario más noble.' La revuelta fue aplastada. Juntos construyeron Santa Sofía, codificaron el derecho romano (Corpus Juris Civilis), reconquistaron el norte de África e Italia, y sobrevivieron a la Peste Justiniana."},{n:"Rávena/San Vital",info:"Impresionantes mosaicos muestran a la pareja imperial.",wiki:"Los mosaicos de San Vital en Rávena (completados 547 d.C.) muestran a Justiniano y Teodora en esplendor imperial — cada uno liderando una procesión de cortesanos y clero. Están entre las mayores obras de arte supervivientes de la antigüedad tardía. El panel de Teodora la muestra cubierta de joyas y vistiendo púrpura imperial."}],pathLabels:["Pareja imperial inmortalizada en mosaicos de Rávena"]},
"bio20":{name:"Agripina la Menor",desc:"Hermana de Calígula. Madre de Nerón. Asesinada por su hijo.",facts:["Cuarta esposa de Claudio","Envenenó a Claudio","Asesinada por Nerón en 59 d.C."],locs:[{n:"Roma",info:"Gobernó efectivamente el Imperio Occidental desde aquí.",wiki:"Flavio Estilicón (359-408 d.C.) era hijo de padre vándalo y madre romana. Como magister militum (comandante en jefe), era el verdadero poder tras el niño emperador Honorio, cuyo tutor era. Estilicón derrotó a los godos de Alarico en Pollentia (402) y Verona (403), y destruyó una masiva invasión gótico-huna en Faesulae (406). A pesar de su lealtad y victorias, una conspiración palaciega lo acusó de traición. Se rindió pacíficamente y fue ejecutado el 22 de agosto del 408."},{n:"Rávena",info:"Honorio ordenó la ejecución de Estilicón desde aquí.",wiki:"La corte en Rávena se volvió contra Estilicón — celosa de su poder y sospechosa de su herencia bárbara. Tras su ejecución, un pogromo contra familias de soldados bárbaros empujó a 30.000 guerreros a los brazos de Alarico. En dos años, Alarico saqueó Roma. La destrucción de Estilicón selló el destino del Occidente."},{n:"Pollentia",info:"Estilicón derrotó a Alarico aquí el Domingo de Pascua, 402.",wiki:"El Domingo de Pascua, 6 de abril del 402 d.C., Estilicón atacó el campamento de Alarico en Pollentia (actual Pollenzo). El momento — atacar en día santo — fue controvertido, pero la victoria salvó Italia temporalmente. Estilicón capturó el campamento de Alarico incluyendo a su esposa. Fue la última gran victoria romana en Occidente."}],pathLabels:["Estilicón derrota a Alarico en Pollentia","Estilicón ejecutado en Rávena"]},
"eco1":{name:"Comercio de la Ruta de la Seda",desc:"El oro romano fluía hacia oriente por seda china.",facts:["Oro por seda","120+ barcos/año a India","Plinio: 50 millones de sestercios/año a India"],locs:[{n:"Roma",info:"El Senado intentó prohibir la seda.",wiki:"Plinio: 100 millones de sestercios drenados al este anualmente."},{n:"Antioquía",info:"Centro de mercancías orientales.",wiki:"Donde las mercancías de la Ruta de la Seda entraban al sistema comercial romano."},{n:"Palmira",info:"Centro comercial del desierto.",wiki:"Se enriqueció con aranceles comerciales. Imperio independiente de Zenobia 272 d.C."}],pathLabels:["Oro por mercancías orientales","Caravanas vía Palmira"]},
"eco2":{name:"Minería de Plata de Hispania",desc:"Río Tinto y Cartago Nova: las minas más ricas del imperio.",facts:["Río Tinto: 200.000 esclavos","Cartago Nova: minas de plata","25.000 toneladas de plata extraídas"],locs:[{n:"Alejandría",info:"Las flotas de grano partían cada temporada.",wiki:"La crecida del Nilo producía enormes excedentes."},{n:"Roma",info:"1 millón dependiente del grano.",wiki:"200.000 recibían grano gratuito mensualmente. Control = poder."},{n:"Ostia",info:"Puerto de Roma.",wiki:"Claudio y Trajano construyeron enormes puertos."}],pathLabels:["Flotas de grano desde Alejandría","Río arriba por el Tíber hasta Roma"]},
"eco3":{name:"Comercio del Grano",desc:"Egipto, África y Sicilia alimentaban Roma. El annona era sagrado.",facts:["Egipto: un tercio del grano de Roma","Annona: distribución gratuita","400.000 beneficiarios en su apogeo"],locs:[{n:"Roma",info:"Ceca romana en el Templo de Juno Moneta.",wiki:"El denario se introdujo ~211 a.C. durante la Segunda Guerra Púnica, conteniendo 4,5 g de plata. Durante siglos fue la moneda más confiable del Mediterráneo. Nerón inició la degradación en 64 d.C., reduciendo el contenido de plata. Para el siglo III, el antoniniano de reemplazo era solo bronce con baño de plata. La palabra 'moneda' deriva de Juno Moneta, en cuyo templo se acuñaban las monedas."},{n:"Cartago Nova",info:"Las minas de plata más ricas del mundo romano.",wiki:"Las minas de plata de Hispania eran el tesoro del imperio. En su apogeo, 40.000 esclavos trabajaban solo las minas de Cartago Nova, produciendo plata que alimentaba la ceca romana. Plinio registró su producción asombrosa."},{n:"Laurión",info:"Minas de plata griegas explotadas por Roma.",wiki:"Las famosas minas de plata atenienses. Roma continuó su explotación tras conquistar Grecia. Combinadas con la plata hispana, alimentaron el sistema del denario que unificó el comercio mediterráneo."}],pathLabels:["Plata de minas hispanas alimenta la ceca","Plata griega complementa el suministro"]},
"eco4":{name:"Moneda Romana",desc:"Denario, sestercio, áureo. De plata pura a aleación en la crisis del siglo III.",facts:["Denario: moneda estándar","Áureo: oro puro","Crisis: plata cayó del 50% al 2%"],locs:[{n:"Las Médulas",info:"La mayor mina de oro a cielo abierto del mundo romano.",wiki:"En el noroeste de Hispania, los romanos usaron 'ruina montium' — minería hidráulica que derrumbaba montañas enteras usando presión de agua. Plinio describió la técnica: canales llevaban agua desde millas de distancia, luego la liberaban para destrozar las caras rocosas. Las Médulas produjeron un estimado de 5 toneladas de oro al año. El paisaje marcado es ahora Patrimonio de la Humanidad por la UNESCO."},{n:"Sarmizegetusa",info:"165 toneladas de oro dacio financiaron el programa constructivo de Trajano.",wiki:"La conquista de Dacia por Trajano en 106 d.C. estuvo parcialmente motivada por su oro. Las 165 toneladas de oro y 330 de plata capturadas financiaron el Foro de Trajano, la Columna y las masivas obras públicas en Roma."},{n:"Dolaucothi",info:"Única mina de oro romana conocida en Britania.",wiki:"En Gales, los romanos usaron acueductos y técnicas de lavado para extraer oro. La mina operó desde ~75 d.C. y muestra sofisticada ingeniería romana adaptada al clima húmedo británico."}],pathLabels:["Oro de las montañas arruinadas de Hispania","Oro dacio financia la Roma de Trajano","Oro extraído de las colinas galesas"]},
"eco5":{name:"Puerto de Ostia",desc:"Puerta de Roma al mar: almacenaba grano para un millón de personas.",facts:["Población ~100.000","Puerto hexagonal de Trajano: 32 hectáreas","Almacenaba grano para 1 millón"],locs:[{n:"Ostia Antica",info:"Población ~100.000 en su apogeo.",wiki:"Puerto principal de Roma en la desembocadura del Tíber. Para el siglo II d.C., bulliciosa ciudad de ~100.000 con bloques de apartamentos, termas, templos y teatro. La Plaza de las Corporaciones — con mosaicos anunciando empresas navieras de todo el Mediterráneo — es como unas páginas amarillas antiguas."},{n:"Portus",info:"Puerto hexagonal de Trajano: 32 hectáreas.",wiki:"Claudio construyó un puerto masivo al norte de Ostia en 42 d.C., pero se sedimentó. Trajano lo resolvió con una innovadora cuenca portuaria hexagonal de 32 hectáreas, conectada al Tíber por canal. Podía atracar cientos de naves simultáneamente."},{n:"Roma",info:"Todo lo que Roma consumía llegaba por Ostia.",wiki:"Grano, aceite de oliva, vino, mármol, animales salvajes para el anfiteatro — prácticamente todo entraba a Roma vía Ostia y Portus. Los horrea (almacenes) guardaban grano suficiente para alimentar a un millón de romanos."}],pathLabels:["Mercancías viajan río arriba por el Tíber hasta Roma","El puerto de Trajano se conecta con Ostia"]},
"eco6":{name:"Comercio de Vino y Aceite",desc:"Monte Testaccio: una colina de 35 m con 53 millones de ánforas rotas.",facts:["Monte Testaccio: 53 millones de ánforas","Colina de 35 m de recipientes de aceite","Hispania exportaba 20 millones de litros/año"],locs:[{n:"Monte Testaccio",info:"Colina de 35 m hecha enteramente de ánforas de aceite rotas.",wiki:"Colina artificial en Roma hecha de aproximadamente 53 millones de ánforas rotas — mayormente contenedores de aceite de oliva de la provincia Bética de Hispania. Las ánforas de aceite no podían reutilizarse porque la arcilla absorbía aceite rancio. El vertido organizado (los fragmentos se apilaban, se rociaban con cal) muestra la sofisticada gestión de residuos de Roma."},{n:"Bética",info:"Corazón olivarero de Hispania.",wiki:"El valle del Guadalquivir en el sur de Hispania era el mayor proveedor de aceite de oliva de Roma. Las fincas producían un estimado de 20 millones de litros anuales. Los sellos de ánforas muestran un sofisticado sistema de control de calidad e impuestos."},{n:"Leptis Magna",info:"Gran exportador de aceite de oliva en África.",wiki:"Leptis Magna en la actual Libia creció rica con exportaciones de aceite de oliva. El emperador Septimio Severo — nacido aquí — aseguró que el aceite africano compitiera con el suministro hispano. Las magníficas ruinas de la ciudad reflejan la riqueza del aceite."}],pathLabels:["Aceite hispano enviado a Roma","Aceite africano complementa el suministro"],pathWikis:["20 millones de litros anuales desde la Bética.",null]},
"eco7":{name:"Fiscalidad y los Publicani",desc:"Arrendamiento de impuestos: empresas privadas pujaban por derechos de cobro.",facts:["Empresas privadas pujaban por impuestos","80.000 romanos masacrados en Asia (88 a.C.)","Cicerón procesó a Verres por saquear Sicilia"],locs:[{n:"Roma",info:"El Senado subastaba contratos de impuestos provinciales.",wiki:"Los publicani eran recaudadores de impuestos privados que pujaban por el derecho a cobrar impuestos en las provincias romanas. Pagaban al estado por adelantado, luego extraían lo que podían de los provinciales — quedándose el excedente. Las familias ecuestres se enriquecieron fabulosamente. El sistema estaba maduro para el abuso: la acusación de Cicerón contra Verres expuso cómo gobernadores y publicani podían despojar una provincia."},{n:"Éfeso",info:"Asia Menor — provincia fiscal más rica.",wiki:"La provincia de Asia (oeste de Turquía) era la más lucrativa de Roma. Cuando Mitrídates VI invadió en 88 a.C., ordenó la masacre de todos los romanos e italianos — 80.000 fueron asesinados en un solo día, medida de cuánto odiaban a los recaudadores."}],pathLabels:["Los publicani extraen riqueza de Asia"]},
"eco8":{name:"La Distribución de Grano (Annona)",desc:"Grano gratuito o subsidiado para más de 200.000 ciudadanos mensualmente.",facts:["200.000 beneficiarios mensuales","Cayo Graco lo inició (123 a.C.)","'Pan y circo' — Juvenal"],locs:[{n:"Roma",info:"200.000 ciudadanos recibían grano gratuito.",wiki:"Cayo Graco introdujo grano subsidiado en 123 a.C. Para 58 a.C. (ley de Clodio), era gratuito. Augusto fijó las listas en 200.000 receptores. Las distribuciones mensuales de grano (luego pan, aceite y cerdo) continuaron 600 años. Los políticos que controlaban el suministro de grano controlaban Roma — Pompeyo, César y Augusto lo entendieron."},{n:"Ostia",info:"Las naves de grano descargaban aquí.",wiki:"Enormes graneros en Ostia y Portus almacenaban el grano. Los retrasos en la flota de grano podían causar disturbios. Claudio construyó un nuevo puerto en Portus específicamente para manejar el volumen."},{n:"Alejandría",info:"Egipto suministraba un tercio del grano de Roma.",wiki:"La crecida del Nilo de Egipto producía enorme excedente de grano. Controlar Egipto significaba controlar el suministro de alimentos de Roma — una razón por la que Augusto lo hizo provincia personal prohibida a senadores."}],pathLabels:["Flotas de grano desde Egipto a Ostia","Grano distribuido en Roma"]},
"eco9":{name:"Banca y Crédito Romanos",desc:"Argentarii operaban desde tabernae en el Foro: depósitos, préstamos, cartas de crédito.",facts:["Argentarii: banqueros romanos","Cartas de crédito para transferencias","Tipos de interés típicos 6-12%"],locs:[{n:"Roma",info:"Foro: centro de la banca romana.",wiki:"Los banqueros romanos (argentarii) operaban desde tiendas (tabernae) bordeando el Foro. Aceptaban depósitos, hacían préstamos, cambiaban moneda y actuaban como subastadores. Los nummularii se especializaban en cambio de dinero y prueba de pureza de monedas. Las cartas de crédito (permutationes) permitían a los comerciantes transferir fondos sin llevar efectivo por caminos peligrosos. Las tasas de interés estaban reguladas — típicamente 6-12% anual. La banca romana carecía de instituciones modernas como bancos centrales o seguro de depósitos, pero la red financiera era lo suficientemente sofisticada para apoyar el comercio mediterráneo."},{n:"Pompeya",info:"Los registros del banquero Lucio Cecilio Jucundo sobrevivieron.",wiki:"Las tablillas de cera del banquero pompeyano Cecilio Jucundo, preservadas por el Vesubio, proporcionan los registros supervivientes más detallados de transacciones financieras romanas: recibos de subastas, pagos de alquiler y documentos de préstamos — una instantánea de la vida comercial diaria."}]},
"eco10":{name:"Edicto de Precios de Diocleciano",desc:"Primer intento mundial de control de precios: precios máximos para más de 1.200 productos.",facts:["Más de 1.200 productos y servicios con precio","Pena de muerte por incumplimiento","Abandonado silenciosamente en años"],locs:[{n:"Antioquía",info:"Probablemente emitido desde aquí en 301 d.C.",wiki:"Enfrentando severa inflación tras décadas de degradación monetaria, Diocleciano emitió el Edictum de Pretiis Rerum Venalium (Edicto de Precios Máximos) en 301 d.C. Fijó precios techo para más de 1.200 bienes y servicios — desde trigo y vino hasta cortes de pelo y honorarios legales. Las violaciones se castigaban con la muerte. El edicto fue un desastre económico: los comerciantes retiraron mercancías del mercado, florecieron los mercados negros, y el edicto fue abandonado silenciosamente en años."},{n:"Afrodisias",info:"Mejor copia conservada del edicto.",wiki:"La copia superviviente más completa del Edicto de Precios de Diocleciano está tallada en piedra en Afrodisias en Turquía. La inscripción lista precios en denarios communes — revelando tanto el rango de bienes en la economía romana como la desesperación del gobierno por controlar la inflación."}],pathLabels:["Edicto distribuido por todo el imperio"]},
"eco11":{name:"Latifundios y Agricultura Romana",desc:"Grandes fincas trabajadas por esclavos que desplazaron a pequeños agricultores.",facts:["Plinio: 'Los latifundios han arruinado Italia'","Graco asesinado por reforma agraria","África del Norte: región agrícola más rica de Roma"],locs:[{n:"Roma",info:"Debates políticos sobre reforma agraria.",wiki:"Tras las Guerras Púnicas, los romanos ricos consolidaron pequeñas granjas en vastas fincas (latifundios) trabajadas por esclavos capturados en guerras de conquista. Campesinos desplazados inundaron Roma. Los intentos de reforma agraria de los hermanos Graco (133-121 a.C.) terminaron en sus asesinatos. Plinio el Viejo escribió 'latifundia perdidere Italiam' (los latifundios han arruinado Italia). El sistema persistió durante todo el Imperio — grandes fincas en el norte de África, Hispania y la Galia producían el grano, aceite de oliva y vino que sustentaban el mundo romano."},{n:"Sicilia",info:"Enormes fincas de grano — escenario de dos revueltas de esclavos.",wiki:"Sicilia fue la primera provincia de Roma y su granero. Gigantescos latifundios trabajados por esclavos producían enorme riqueza — y provocaron dos masivas revueltas de esclavos (135-132 a.C. y 104-100 a.C.). La explotación fue tan severa que Cicerón acusó al gobernador Verres por sus depredaciones."},{n:"Volubilis",info:"Producción de aceite de oliva romano en el norte de África.",wiki:"Volubilis en el actual Marruecos tenía más de 60 prensas de aceitunas — vasta operación industrial de aceite de oliva. Las fincas del norte de África producían enormes cantidades de aceite, grano y vino para exportar a Roma. África Proconsular se convirtió en la provincia agrícola más rica de Roma."}],pathLabels:["Grano siciliano a Roma","Aceite y grano del norte de África"]},
"eco12":{name:"Industria de Cerámica Romana",desc:"Producción masiva de terra sigillata: marcas, formas estandarizadas. Hallada de Escocia a India.",facts:["Primera vajilla romana producida en masa","60 millones de vasijas de La Graufesenque","Hallada de Escocia a India"],locs:[{n:"Arezzo",info:"Arretium: centro original de producción de terra sigillata.",wiki:"La cerámica aretina — loza de barniz rojo brillante — fue la primera vajilla romana producida en masa. Grandes talleres usando mano de obra esclava producían vasijas estandarizadas estampadas con el nombre del fabricante. En su apogeo (30 a.C. - 30 d.C.), los talleres de Arezzo empleaban cientos y exportaban por todo el Mediterráneo. La producción luego se desplazó a la Galia y el Rin."},{n:"La Graufesenque",info:"Taller galo que reemplazó a Arezzo como principal productor.",wiki:"La Graufesenque en el sur de la Galia se convirtió en el productor dominante de terra sigillata desde aproximadamente 40-120 d.C. Los registros de hornos en fragmentos de cerámica muestran que una sola cocción podía contener 30.000 vasijas. El sitio produjo un estimado de 60 millones de vasijas. La distribución se extendió desde Escocia hasta India — notable economía de escala antigua."}],pathLabels:["La producción se desplaza de Arezzo a la Galia"]},
"eco13":{name:"Crisis Monetaria del Siglo III",desc:"El contenido de plata cayó del 50% al 2%: hiperinflación, trueque y casi colapso económico.",facts:["Plata cayó del 50% al 2%","Precios subieron 1.000% en 50 años","Controles de precios de Diocleciano fallaron"],locs:[{n:"Roma",info:"Las cecas imperiales degradaron la moneda para financiar los ejércitos.",wiki:"Durante la Crisis del Siglo III (235-284 d.C.), los emperadores degradaron rápidamente la moneda de plata para pagar ejércitos: el antoniniano pasó de 50% plata a menos del 2%. Los precios subieron 1.000% en 50 años. El Edicto de Precios Máximos de Diocleciano (301 d.C.) intentó frenar la inflación con penas de muerte — falló. Reformó la moneda en su lugar, pero el daño económico persistió décadas. La confianza en la moneda era tan baja que muchas regiones volvieron al trueque."}]},
"eco14":{name:"Comercio Marítimo con India",desc:"Los monzones permitieron comercio directo Roma-India: pimienta, especias, gemas, seda.",facts:["Más de 120 barcos/año a India","Plinio: India drenaba 50 millones de sestercios anuales","Papiro de Muziris: un cargamento valía 7 millones"],locs:[{n:"Alejandría",info:"Centro egipcio para el comercio oriental.",wiki:"Tras la conquista de Egipto por Augusto (30 a.C.), los comerciantes romanos explotaron un descubrimiento griego: los vientos monzónicos permitían navegación directa a India. Las naves partían de puertos del Mar Rojo en julio y regresaban en diciembre. El Periplo del Mar Eritreo (c. 40-70 d.C.) es una guía de comerciantes que describe la ruta, puertos y mercancías."},{n:"Berenice",info:"Puerto del Mar Rojo — punto de partida para India.",wiki:"Berenice era un importante puerto romano en el Mar Rojo. Las excavaciones han revelado cerámica india, granos de pimienta del sur de Asia y madera de teca. Las naves zarpaban desde aquí a India llevando oro, plata, vino y coral — regresando con pimienta, perlas, gemas, seda y especias."},{n:"Muziris",info:"Principal puerto comercial en la costa Malabar de India.",wiki:"Muziris (actual Pattanam, Kerala) era el destino principal de los comerciantes romanos. El Papiro de Muziris describe una carga valorada en 7 millones de sestercios — el precio de una finca italiana. Las excavaciones arqueológicas encontraron ánforas y monedas romanas. Plinio se quejó de que India drenaba a Roma de 50 millones de sestercios anuales por bienes de lujo."}],pathLabels:["Río abajo por el Nilo al Mar Rojo","Navegación monzónica a India"]},
"eco15":{name:"Industria Textil Romana",desc:"Lana, lino, seda. Fullonicae procesaban tela. Pompeya tenía 13 fullonicae.",facts:["Toga: 5-7 metros de lana, 5 kg","12.000 caracoles = 1,5 g de púrpura tiria","Usar púrpura sin autorización era delito capital"],locs:[{n:"Roma",info:"Centro de demanda de textiles.",wiki:"La industria textil romana era vasta y variada. La lana era el tejido principal, procesada en fullonicae (lavanderías/talleres de bataneros) usando orina, tierra de batán y azufre. Lino de Egipto, algodón de India y seda de China abastecían mercados de lujo. La toga requería 5-7 metros de lana y pesaba 5 kg — llevarla era marca de ciudadanía y una prueba física."},{n:"Pompeya",info:"13 fullonicae conservadas — mejor evidencia de la industria.",wiki:"Las 13 fullonicae de Pompeya dan la mejor imagen del procesamiento textil romano. La Fullonica de Estéfano está notablemente conservada: cubas de pisado donde los trabajadores pisaban tela en orina, pilas de enjuague, marcos de secado y dispositivos de prensado. Los frescos muestran el proceso paso a paso. El gremio de bataneros era una de las asociaciones comerciales más poderosas de Pompeya."},{n:"Tiro",info:"Fuente del tinte púrpura tirio — más caro que el oro.",wiki:"La púrpura tiria se extraía de caracoles murex — 12.000 caracoles producían 1,5 gramos de tinte. Una libra de púrpura tiria doble teñida costaba más que el oro. El color se volvió sinónimo de poder imperial: la túnica del emperador era púrpura, y llevarla sin autorización era delito capital."}],pathLabels:["Tinte púrpura tirio fluye a Roma","Procesamiento textil para mercados romanos"]},
"law1":{name:"Ley de las Doce Tablas",desc:"Primer código legal escrito: fundamento del derecho occidental.",facts:["Primera ley escrita","Pública en el Foro","Fundamento del derecho occidental"],locs:[{n:"Roma",info:"Tablillas de bronce en el Foro.",wiki:"451-449 a.C. Revolucionario: la ley debe ser escrita, pública, igual. Base del derecho romano durante 900 años."}]},
"law2":{name:"Pax Romana",desc:"Dos siglos de paz y prosperidad.",facts:["207 años","55-70 millones de personas","Gibbon: 'la más feliz'"],locs:[{n:"Roma",info:"207 años de estabilidad.",wiki:"El comercio floreció, población 55-70 millones. Gibbon: 'más feliz y próspero.'"},{n:"Londinium",info:"Las ciudades provinciales florecieron.",wiki:"Las ciudades crecieron por todo el imperio."},{n:"Antioquía",info:"Las ciudades orientales prosperaron.",wiki:"Mayor prosperidad bajo la estabilidad imperial."}],pathLabels:["Paz a las provincias","El comercio enriquece el Este"]},
"law3":{name:"Esclavitud Romana",desc:"Hasta el 40% de Italia esclavizada.",facts:["35-40% esclavizados","10.000/día en Delos","César esclavizó ~1 millón de galos"],locs:[{n:"Roma",info:"500 esclavos por romano rico.",wiki:"2-3 millones en Italia. Los esclavos de minas vivían meses. Los esclavos griegos se volvieron consejeros."},{n:"Delos",info:"10.000 esclavos/día.",wiki:"Mayor mercado de esclavos en su apogeo."}],pathLabels:["Comercio de esclavos desde Delos"]},
"law4":{name:"Edicto de Caracalla",desc:"Ciudadanía universal para todos los hombres libres: el acto legal más revolucionario de la historia romana.",facts:["Todos los hombres libres fueron ciudadanos","Amplió la base fiscal","Constitutio Antoniniana"],locs:[{n:"Roma",info:"Emitido 212 d.C. por el emperador Caracalla.",wiki:"La Constitutio Antoniniana otorgó plena ciudadanía romana a todos los hombres libres del imperio y derechos equivalentes a todas las mujeres libres. Antes del 212, la ciudadanía estaba mayormente limitada a italianos y provinciales selectos. De la noche a la mañana, millones se convirtieron en ciudadanos. Los cínicos notaron que también expandió masivamente la base fiscal — los ciudadanos pagaban impuesto de sucesión."},{n:"Alejandría",info:"Egipcios, sirios, galos — todos se convirtieron en ciudadanos.",wiki:"Por primera vez, un granjero en Egipto tenía el mismo estatus legal que el hijo de un senador en Roma. El edicto transformó la ciudadanía de un privilegio exclusivo en un derecho universal. Se encontró escrito en un papiro (P. Giss. 40) en Egipto, nuestra copia superviviente principal."}],pathLabels:["La ciudadanía se extiende a todos los rincones del imperio"]},
"law5":{name:"El Senado Romano",desc:"De consejo asesor de reyes a poder supremo a sello imperial: 1.200 años.",facts:["300 senadores (República), 900 bajo César","SPQR: Senatus Populusque Romanus","Poder máximo a mediados de la República"],locs:[{n:"Curia Julia",info:"Casa del Senado en el Foro — aún en pie.",wiki:"El Senado se reunía en la Curia, reconstruida por César y Augusto (el edificio actual data de la restauración de Diocleciano). Originalmente 100 miembros bajo los reyes, expandido a 300 en la República, 600 bajo Sila y 900 bajo César. Los senadores llevaban la toga praetexta con amplia franja púrpura. La frase SPQR (Senatus Populusque Romanus) — 'El Senado y Pueblo de Roma' — aparecía en estandartes, edificios y monedas."},{n:"Roma",info:"Poder máximo a mediados de la República; declinó bajo los emperadores.",wiki:"El poder del Senado alcanzó su máximo entre las Guerras Púnicas y la República tardía. Controlaba política exterior, finanzas y nombramientos provinciales. Bajo los emperadores, se volvió cada vez más ceremonial. Augusto mantuvo la ficción de autoridad senatorial; para la época de Diocleciano, era irrelevante. Sin embargo sobrevivió — la última reunión registrada fue en 603 d.C."}]},
"law6":{name:"Cursus Honorum",desc:"La escalera política: cuestor, edil, pretor, cónsul, con límites de edad estrictos.",facts:["Cuestor a los 30, Cónsul a los 42","Sila formalizó el sistema","Los strongmen eludieron las reglas"],locs:[{n:"Roma",info:"El camino de todo romano ambicioso al poder.",wiki:"El cursus honorum ('curso de honores') era la secuencia fija de cargos para políticos aspirantes. Tras 10 años de servicio militar, un hombre podía postularse para cuestor (edad mínima 30 tras las reformas de Sila), luego edil, pretor (39 años) y finalmente cónsul (42 años). Ocupar cada cargo 'en su año' (suo anno) — a la edad mínima — se consideraba marca de talento excepcional. César, Cicerón y Augusto lo lograron. Brechas de dos años entre cargos prevenían acumulación de poder. El sistema se rompió en la República tardía cuando hombres fuertes como Pompeyo (cónsul a los 35) evitaron las reglas."}]},
"law7":{name:"Administración Provincial",desc:"Gobernadores con poder casi absoluto. Cicerón procesó a Verres por saquear Sicilia.",facts:["Gobernadores con poder casi absoluto","In Verrem de Cicerón expuso la corrupción","Augusto dividió provincias en senatoriales e imperiales"],locs:[{n:"Roma",info:"El Senado asignaba provincias a exmagistrados.",wiki:"Los gobernadores provinciales (procónsules o propretores) tenían imperium — autoridad militar y judicial casi absoluta. El sistema invitaba al abuso: Verres despojó a Sicilia de arte, grano y dignidad. La acusación de Cicerón (70 a.C.) en los discursos In Verrem expuso corrupción sistemática. Augusto reformó el sistema, dividiendo provincias en senatoriales e imperiales."},{n:"Siracusa",info:"Verres saqueó la mayor ciudad de Sicilia.",wiki:"Verres robó obras de arte de templos, crucificó a un ciudadano romano y extorsionó fortunas. Los discursos de Cicerón fueron tan devastadores que Verres huyó al exilio antes de que concluyera el juicio. Se llevó su arte robado."},{n:"Éfeso",info:"Capital de la provincia más rica — Asia.",wiki:"El gobernador de Asia controlaba la provincia más rica del imperio. Éfeso servía como capital administrativa. Los consejos provinciales (koina) podían enviar embajadas a Roma para quejarse de malos gobernadores — control limitado del poder."}],pathLabels:["Cicerón acusa a Verres en Sicilia","Los gobernadores gobiernan Asia desde Éfeso"]},
"law8":{name:"Corpus Iuris Civilis",desc:"Codificación de Justiniano de todo el derecho romano: base del derecho civil europeo.",facts:["Compilado 529-534 d.C.","Base del derecho civil europeo","Aún citado en tribunales modernos"],locs:[{n:"Constantinopla",info:"Compilado bajo Justiniano I.",wiki:"El emperador Justiniano I ordenó al jurista Triboniano compilar todo el derecho romano en una sola obra. El resultado — el Corpus Juris Civilis — consiste en el Codex (constituciones imperiales), Digest (escritos de juristas), Instituciones (manual) y Novelas (nuevas leyes). Preservó 1.000 años de pensamiento legal romano y se convirtió en la base del derecho civil europeo. Conceptos como 'inocente hasta que se demuestre culpable' y 'carga de la prueba en el acusador' provienen directamente de él."},{n:"Roma",info:"Culminación de 1.000 años de tradición legal romana.",wiki:"Aunque compilado en Constantinopla, el Corpus se basó en siglos de jurisprudencia romana desde las Doce Tablas hasta Gayo, Ulpiano y Papiniano. Redescubierto en Italia en el siglo XI, se convirtió en la base del derecho en la Europa continental. El Código Civil de Napoleón estuvo fuertemente influenciado por él."}],pathLabels:["El legado del derecho romano regresa al Occidente"]},
"law9":{name:"Tribuno de la Plebe",desc:"Sagrado e inviolable: poder de veto sobre cualquier magistrado.",facts:["Creado 494 a.C. en la Secesión de la Plebe","Sacrosanto: dañar a un tribuno = muerte","Augusto lo hizo base del poder imperial"],locs:[{n:"Roma",info:"Creado 494 a.C. durante la Primera Secesión de la Plebe.",wiki:"Cuando los plebeyos se secesionaron al Monte Sagrado en 494 a.C. — efectivamente en huelga — los patricios se vieron forzados a crear el tribuno de la plebe. Los tribunos eran sacrosantos: dañar a uno era delito capital. Podían vetar (intercessio) cualquier acto de cualquier magistrado, incluyendo cónsules. Originalmente cargo defensivo protegiendo a ciudadanos comunes del abuso patricio, se convirtió en el arma política más poderosa en la República tardía. Tiberio Graco lo usó para aprobar reforma agraria (133 a.C.). Su hermano Cayo expandió su alcance. Clodio lo usó contra Cicerón. César tuvo autoridad tribunicia para protegerse. Augusto hizo de la potestas tribunicia la base legal del poder imperial — sin ocupar nunca el cargo."}]},
"law10":{name:"Ciudadanía Romana",desc:"Grados de civis a peregrinus: derechos a votar, comerciar, apelar y casarse.",facts:["Ciudadanos plenos: votar, comerciar, apelar, casarse","Esclavos liberados podían obtener ciudadanía","Edicto de Caracalla (212 d.C.) la hizo universal"],locs:[{n:"Roma",info:"La ciudadanía era la herramienta más poderosa de integración de Roma.",wiki:"La ciudadanía romana (civitas) era escalonada: los ciudadanos plenos (cives Romani) tenían derechos de voto, matrimonio, comercio y apelación. Los derechos latinos (ius Latii) ofrecían algunos privilegios. Los aliados (socii) tenían menos. Los extranjeros (peregrini) tenían casi ninguno. A diferencia de las ciudades griegas, Roma otorgaba ciudadanía ampliamente — a esclavos liberados, comunidades aliadas y pueblos conquistados. Esta era la genialidad de Roma: convertir enemigos en interesados. Caminos a la ciudadanía: nacimiento, servicio militar (25 años para auxiliares), manumisión o concesión imperial."},{n:"Delos",info:"Los comerciantes italianos se identificaban orgullosamente como 'Romani.'",wiki:"Las inscripciones en Delos muestran a comerciantes italianos llamándose cives Romani (ciudadanos romanos) — la ciudadanía era insignia de prestigio y protección legal por todo el Mediterráneo. Los 80.000 romanos masacrados por Mitrídates en 88 a.C. fueron objetivo precisamente porque su estatus de ciudadano los marcaba como privilegiados."}]},
"law11":{name:"Tribunales y Sistema de Juicios Romanos",desc:"Quaestiones perpetuae, brillantez forense de Cicerón, cognitio imperial reemplazó jurados.",facts:["Primer tribunal permanente: 149 a.C. por extorsión","Discursos forenses de Cicerón son obras maestras","Cognitio imperial reemplazó tribunales con jurado"],locs:[{n:"Roma/Foro",info:"Los juicios se celebraban en el Foro — escenario público de Roma.",wiki:"El sistema legal romano evolucionó de formas tempranas de arbitraje privado a tribunales públicos sofisticados. En 149 a.C. se estableció la primera quaestio perpetua (tribunal de jurado permanente) para casos de extorsión. Para la República tardía, ocho tribunales manejaban diferentes crímenes. Jurados de senadores (luego también ecuestres) escuchaban casos argumentados por oradores como Cicerón, cuyos discursos forenses son obras maestras de retórica. Bajo el Imperio, el sistema cognitio reemplazó a los jurados: un solo magistrado escuchaba casos, examinaba testigos y emitía juicio — más eficiente, pero con menos protección para el acusado."}]},
"law12":{name:"El Dictador: Poderes de Emergencia",desc:"Cargo constitucional con límite de 6 meses. Cincinato volvió a su arado. Sila y César rompieron el molde.",facts:["Cincinato: dimitió tras 16 días","Sila: dictador 'para reescribir la constitución'","César: dictador perpetuo — asesinado en 44 días"],locs:[{n:"Roma",info:"Dictadores nombrados durante emergencias militares.",wiki:"El dictador romano era un cargo constitucional para crisis existenciales. El Senado autorizaba el nombramiento; un cónsul nominaba al dictador, que tenía poder supremo por máximo 6 meses o hasta que terminara la crisis. Cincinato (458 a.C.) famosamente volvió a su arado tras 16 días. El cargo se usó unas 85 veces. Sila rompió el molde: nombrado dictador en 82 a.C. 'para reescribir la constitución', mantuvo el poder 2 años. César fue más lejos: nombrado dictator perpetuo (dictador en perpetuidad) en febrero 44 a.C. Fue asesinado el 15 de marzo — los Idus de marzo. El cargo nunca se revivió."}]},
"law13":{name:"Censores y el Censo",desc:"Dos censores cada 5 años: realizaban el censo, revisaban el Senado, adjudicaban contratos públicos.",facts:["Magistratura romana más prestigiosa","Nota censoria podía destruir carreras","Augusto absorbió los poderes"],locs:[{n:"Roma/Campo de Marte",info:"Los ciudadanos se reunían aquí para el censo.",wiki:"La censura era la magistratura más prestigiosa de Roma — ocupada al final de una carrera, tras el consulado. Dos censores, elegidos cada 5 años, servían 18 meses. Sus deberes: realizar el censo (contar ciudadanos y sus propiedades), asignar ciudadanos a tribus y clases, revisar la lista del Senado (expulsando miembros indignos), adjudicar contratos públicos para caminos, templos y acueductos, y realizar el lustrum (ceremonia de purificación). La nota censoria (marca de desaprobación del censor) podía destruir una carrera. El cargo declinó bajo Augusto, que absorbió sus poderes en el principado."}]},
"law14":{name:"Derecho de Familia Romano",desc:"Patria potestas, matrimonio cum manu, adopción, herencia: fundamento de conceptos de derecho civil moderno.",facts:["Patria potestas: poder legal absoluto del padre","La adopción era herramienta política","Influenció directamente el Código Napoleónico"],locs:[{n:"Roma",info:"El derecho familiar romano moldeó las tradiciones legales occidentales.",wiki:"La familia romana (familia) era una unidad legal bajo el poder absoluto (patria potestas) del paterfamilias — quien técnicamente tenía poder de vida y muerte sobre esposa, hijos y esclavos. En la práctica, esto se moderaba por costumbre social. Las mujeres podían casarse 'con manus' (bajo control legal del marido) o 'sin manus' (reteniendo independencia legal). La adopción era herramienta política crucial: Augusto, Tiberio, Trajano y Adriano fueron adoptados. El derecho sucesorio se volvió increíblemente sofisticado, con reglas sobre testamentos, sucesión intestada y fideicomisos que influyeron directamente en el Código Napoleónico."}]},
"law15":{name:"Comitia y Asambleas Populares",desc:"Asamblea Centuriada (guerra/elecciones), Asamblea Tribal (legislación), Consejo Plebeyo.",facts:["Asamblea Centuriada: organizada por riqueza","Plebiscitos tenían fuerza de ley tras 287 a.C.","Augusto preservó formas pero vació su poder"],locs:[{n:"Roma/Campo de Marte",info:"Terrenos de asamblea — los ciudadanos votaban aquí.",wiki:"La República Romana tenía múltiples asambleas de votación. La Comitia Centuriata (organizada por riqueza) elegía cónsules y pretores, declaraba la guerra y juzgaba casos capitales. La Comitia Tributa (organizada por tribu) elegía magistrados menores y aprobaba leyes. El Concilium Plebis (Consejo Plebeyo, patricios excluidos) elegía tribunos y aprobaba plebiscitos — que tras 287 a.C. tenían fuerza de ley para todos los ciudadanos. La votación era por grupo, no individual — las centurias ricas votaban primero y podían determinar el resultado antes de que votaran ciudadanos más pobres. Augusto preservó las formas pero las vació de poder real."}]},
"mil1":{name:"La Legión Romana",desc:"Centuria, cohorte, legión: la fuerza de combate más efectiva del mundo antiguo.",facts:["~5.200 hombres por legión","Gladius, pilum, scutum","Marchaban 32 km/día, construían campamentos cada noche"],locs:[{n:"Roma",info:"Centro de administración y entrenamiento militar.",wiki:"La legión era la unidad militar distintiva de Roma. Tras las reformas marianas (~107 a.C.), cada legión comprendía ~5.200 hombres organizados en 10 cohortes de 6 centurias cada una. Una centuria (80 hombres) era comandada por un centurión. Equipo estándar: gladius (espada corta), pilum (jabalina), scutum (escudo rectangular) y lorica segmentata (armadura segmentada). Las legiones marchaban 20 millas por día y construían campamentos fortificados cada noche."},{n:"Castra Praetoria",info:"Cuarteles de la Guardia Pretoriana en Roma.",wiki:"Construido por Sejano bajo Tiberio. Concentró la élite de la Guardia Pretoriana dentro de las murallas de Roma — movimiento políticamente peligroso. Los restos de los cuarteles siguen visibles cerca de la estación Termini."},{n:"Vindonissa",info:"Fortaleza legionaria en Suiza.",wiki:"Actual Windisch. Una de las fortalezas legionarias mejor conservadas de la frontera del Rin. Hogar de la Legio XIII Gemina y luego la Legio XXI Rapax. Las excavaciones revelaron hospitales, termas, anfiteatro y tablillas de escritura."}],pathLabels:["Los pretorianos custodian al emperador","Legiones desplegadas en las fronteras"]},
"mil2":{name:"Reformas de Mario",desc:"Mario abrió el ejército a los pobres sin tierra: creó soldados profesionales leales a sus generales.",facts:["Abrió ejército a los sin tierra","Creó soldados profesionales","Lealtad pasó del estado al comandante"],locs:[{n:"Roma",info:"Transformó el reclutamiento militar romano.",wiki:"Antes del 107 a.C., solo ciudadanos propietarios podían servir. Mario reclutó a los proletarii sin tierras, equipándolos a costa del estado. Esto creó un ejército profesional pero desplazó la lealtad de los soldados de la República a su comandante — quien proporcionaba tierras y paga. La reforma hizo posible a todo caudillo desde Sila hasta César y Augusto."},{n:"Aquae Sextiae",info:"102 a.C.: el nuevo ejército destruyó a los teutones.",wiki:"Las legiones reformadas de Mario resultaron devastadoras contra los teutones germánicos en Aquae Sextiae (actual Aix-en-Provence). El ejército disciplinado y estandarizado aplastó a una vasta horda germánica."},{n:"Vercelas",info:"101 a.C.: los cimbrios destruidos.",wiki:"Al año siguiente, Mario y Catulo aniquilaron a los cimbrios en Vercelas. Las dos victorias validaron el nuevo sistema militar y hicieron de Mario un héroe nacional."}],pathLabels:["El nuevo ejército derrota a los teutones","Los cimbrios destruidos al año siguiente"]},
"mil3":{name:"Guardia Pretoriana",desc:"Guardia imperial de élite de 5.000 hombres: hicieron y deshicieron emperadores durante 300 años.",facts:["Triple paga legionaria","Asesinaron a Calígula","Subastaron el imperio en 193 d.C."],locs:[{n:"Roma",info:"Castra Praetoria — sus cuarteles cerca del Monte Viminal.",wiki:"Augusto formalizó la Guardia Pretoriana como nueve cohortes de soldados de élite, cada una de 500 hombres, con triple paga legionaria. Bajo Sejano (prefecto de Tiberio), las nueve cohortes se concentraron en un solo cuartel en Roma — convirtiéndolas en fuerza política. Asesinaron a Calígula, subastaron el imperio a Didio Juliano (193 d.C.), y hicieron o derrotaron a docenas de emperadores. Constantino los disolvió tras la Batalla del Puente Milvio en 312."}]},
"mil4":{name:"Marina Romana y Classis",desc:"De flota novata a dominio del Mediterráneo: el puente de abordaje corvus cambió la guerra naval.",facts:["Construyeron 120 barcos en 60 días","Puente de abordaje corvus","Plinio el Viejo comandó en Miseno"],locs:[{n:"Miseno",info:"Base naval principal — Classis Misenensis.",wiki:"Roma no tenía marina antes del 260 a.C. Durante la Primera Guerra Púnica, copiaron una quinquerreme cartaginesa capturada y construyeron 120 naves en 60 días. El corvus (puente de abordaje) permitía a la infantería romana luchar en el mar. Para el imperio, la Classis Misenensis en Miseno era la mayor flota, comandada por Plinio el Viejo cuando entró en erupción el Vesubio."},{n:"Rávena",info:"Base de la flota adriática — Classis Ravennas.",wiki:"La segunda flota imperial principal protegía el Adriático y el Mediterráneo oriental. El suburbio Classe preserva el nombre. Las flotas también patrullaban el Rin (Classis Germanica) y el Danubio (Classis Pannonica)."},{n:"Accio",info:"31 a.C.: batalla naval decisiva del mundo antiguo.",wiki:"Las naves de guerra más ligeras de Agripa derrotaron a la flota más pesada de Antonio y Cleopatra. La victoria hizo a Octaviano amo del mundo romano y demostró que el poder naval podía decidir el destino de los imperios."}],pathLabels:["Dos flotas principales custodian el Mediterráneo","Batalla decisiva en Accio"]},
"mil5":{name:"El Triunfo Romano",desc:"Mayor honor militar: el general victorioso desfilaba por Roma como un dios viviente.",facts:["Rostro pintado de rojo como Júpiter","Esclavo susurraba 'Recuerda que eres mortal'","Último triunfo: 403 d.C."],locs:[{n:"Vía Sacra",info:"Ruta de la procesión triunfal por el Foro.",wiki:"El triunfo era el máximo honor militar de Roma. El general cabalgaba en un carro de cuatro caballos, rostro pintado de rojo como Júpiter, vistiendo toga púrpura. Ante él: botín, cautivos, pinturas de batallas. Tras él: sus tropas cantando canciones obscenas. Un esclavo susurraba 'Memento mori' — 'Recuerda que eres mortal.' La ruta iba desde el Campo de Marte por el Foro hasta el Templo de Júpiter en el Capitolio."},{n:"Monte Capitolino",info:"Los triunfos terminaban en el Templo de Júpiter.",wiki:"El general subía al Capitolio para sacrificar a Júpiter Óptimo Máximo. Los líderes enemigos a veces eran ejecutados en la prisión Tullianum adyacente. Vercingétorix y Yugurta murieron allí. El último triunfo tradicional fue el de Honorio en 403 d.C."}],pathLabels:["La procesión sube al templo de Júpiter"]},
"mil6":{name:"Guerra de Asedio",desc:"Circunvalación, arietes, torres de asedio, testudo: dominio romano en Alesia, Masada y Jerusalén.",facts:["Alesia: 39 km de murallas","Masada: rampa de asedio masiva","Jerusalén: Templo destruido 70 d.C."],locs:[{n:"Alesia",info:"Doble circunvalación de César, 52 a.C.",wiki:"César atrapó a 80.000 galos bajo Vercingétorix dentro de Alesia construyendo 18 km de murallas interiores (circunvalación) y 21 km de murallas exteriores (contravalación) para repeler un ejército de socorro. Cuando 250.000 galos atacaron desde fuera, César mantuvo ambas líneas. Fue la obra maestra del asedio antiguo."},{n:"Masada",info:"Rampa de asedio romana: ingeniería vs desesperación.",wiki:"Fortaleza montañosa de Herodes en el desierto de Judea. Tras la caída de Jerusalén en 70 d.C., 960 resistentes judíos resistieron tres años. Los romanos construyeron una enorme rampa de tierra por la cara del acantilado. La noche antes del asalto final, los defensores eligieron suicidio masivo antes que esclavitud."},{n:"Jerusalén",info:"Asedio de cinco meses destruyó el Segundo Templo, 70 d.C.",wiki:"Tito sitió Jerusalén con 70.000 tropas usando torres de asedio, arietes y terraplenes. Los defensores lucharon con extraordinaria ferocidad. El Templo ardió en agosto del 70 d.C. Josefo registra 1,1 millones de muertos y 97.000 esclavizados."}],pathLabels:["La pericia de asedio romana abarca el imperio","De Jerusalén a Masada"]},
"mil7":{name:"Auxilia: Tropas No Ciudadanas",desc:"La mitad del ejército romano eran auxiliares: caballería, arqueros, honderos que ganaban ciudadanía tras 25 años.",facts:["La mitad del ejército eran auxiliares","Ciudadanía tras 25 años","Tablillas de Vindolanda: 'envíen más cerveza'"],locs:[{n:"Roma",info:"Los auxiliares complementaron a las legiones desde la República.",wiki:"Las unidades auxiliares (auxilia) proporcionaban las tropas especializadas que faltaban a las legiones: caballería, arqueros, honderos e infantería ligera. Reclutados de pueblos no ciudadanos por todo el imperio — jinetes bátavos, arqueros sirios, honderos baleáricos, caballería númida. Para el período imperial, los auxiliares numeraban aproximadamente igual que los legionarios (~150.000 cada uno). Tras 25 años de servicio, los auxiliares recibían ciudadanía romana registrada en un diploma de bronce."},{n:"Vindolanda",info:"Fuerte auxiliar en el Muro de Adriano.",wiki:"Vindolanda estaba guarnecida por cohortes auxiliares bátavas y tungrias de los Países Bajos. Las famosas tablillas de Vindolanda — postales de madera fina — revelan la vida diaria: peticiones de cerveza y calcetines, invitación a fiesta de cumpleaños, e informes sobre la capacidad de lucha de los 'Brittunculi' (miserables británicos) locales."},{n:"Dura-Europos",info:"Guarnición en el Éufrates — base auxiliar multicultural.",wiki:"Fortaleza fronteriza en Siria guarnecida por diversas unidades auxiliares. Las excavaciones revelaron una sinagoga, casa-iglesia cristiana y templo mitraico uno junto al otro — reflejando la naturaleza multicultural de las fuerzas auxiliares."}],pathLabels:["Los bátavos sirven en el Muro de Adriano","Auxiliares custodian la frontera del Éufrates"]},
"mil8":{name:"Campamentos Militares Romanos (Castra)",desc:"Diseño estandarizado construido cada noche en la marcha: porta praetoria, via principalis, hospital, granero.",facts:["Construían campamento cada noche en ~3 horas","Diseño estándar replicado en el imperio","Discurso de Adriano a tropas sobrevive en Lambaesis"],locs:[{n:"Caerleon",info:"Isca Augusta — fortaleza legionaria mejor conservada en Britania.",wiki:"Hogar de la Legio II Augusta. Todo el trazado estandarizado es rastreable: barracones, termas, anfiteatro, hospital, graneros. Las excavaciones revelaron el único bloque de letrinas legionarias conocido en Britania. Una legión en marcha construía un campamento similar (temporal) cada noche — foso, terraplén y empalizada — en unas 3 horas."},{n:"Lambesis",info:"Campo legionario mejor conservado en África.",wiki:"Hogar de la Legio III Augusta en Numidia (Argelia). El discurso de Adriano a las tropas está inscrito en una columna — el discurso militar romano superviviente más completo. El principia (cuartel general), praetorium (casa del comandante) y barracones sobreviven notablemente intactos."},{n:"Carnunto",info:"Importante base legionaria en el Danubio — reconstruida.",wiki:"Fortaleza legionaria y ciudad civil en la frontera danubiana. Marco Aurelio escribió porciones de sus Meditaciones aquí. La escuela de gladiadores reconstruida y el anfiteatro militar muestran la infraestructura completa que apoyaba una legión permanente."}],pathLabels:["Legión destinada a Britania","Legión custodia África","Defensa de la frontera danubiana"]},
"mil9":{name:"Reformas del Ejército Romano Tardío",desc:"Diocleciano y Constantino transformaron el ejército: limitanei en fronteras, comitatenses como reserva móvil.",facts:["Ejército duplicado a ~400.000","Limitanei (frontera) + comitatenses (móvil)","En 476, ejército occidental era mayormente germánico"],locs:[{n:"Roma",info:"El ejército se duplicó bajo Diocleciano a ~400.000.",wiki:"Diocleciano duplicó el ejército de ~300.000 a ~400.000 hombres. Lo dividió en limitanei (tropas de guarnición fronteriza) y comitatenses (ejércitos de campaña móviles que podían responder a amenazas). Constantino reorganizó más, creando unidades de élite palatini y reduciendo tamaños de legiones. Los foederati germánicos (unidades aliadas bárbaras) se volvieron cada vez más importantes — para el siglo V formaban el núcleo de los ejércitos occidentales."},{n:"Adrianópolis",info:"378 d.C.: catástrofe demostró los límites del nuevo ejército.",wiki:"El desastre en Adrianópolis, donde la caballería gótica destruyó el ejército de campaña de Valente, expuso debilidades fatales. El ejército romano tardío dependía cada vez más de caballería sobre infantería, y de reclutas bárbaros sobre ciudadanos romanos."},{n:"Rávena",info:"Última capital occidental — defendida por foederati.",wiki:"Para el siglo V, el ejército occidental era abrumadoramente germánico. Odoacro, que depuso al último emperador en 476, era él mismo un oficial germánico al servicio de Roma. El ejército que 'cayó' ya era apenas romano."}],pathLabels:["El ejército de campaña falla en Adrianópolis","Tropas germánicas defienden la última capital"]},
"mil10":{name:"Condecoraciones y Honores Militares",desc:"Corona civica, corona muralis, dona militaria: medallas romanas al valor.",facts:["Corona civica: corona de roble por salvar ciudadano","Corona muralis: primero sobre la muralla enemiga","Condecoraciones en lápidas"],locs:[{n:"Roma",info:"Honores militares exhibidos en funerales y lápidas.",wiki:"Las condecoraciones militares romanas (dona militaria) recompensaban actos específicos de valor. La corona civica (corona de roble) se otorgaba por salvar la vida de un conciudadano en batalla — el mayor honor personal. La corona muralis (corona de oro con almenas) iba al primer hombre sobre una muralla enemiga. La corona navalis honraba el valor naval. Centuriones y oficiales recibían torques (collares), armillae (brazaletes) y phalerae (discos medallón). Estas condecoraciones se exhibían en lápidas — muchas sobreviven como nuestra mejor evidencia de la vida militar romana."}]},
"mil11":{name:"Entrenamiento y Disciplina Legionaria",desc:"'Entrenaban como en batallas sin sangre' — Vegecio. Marchas, drill de armas, construcción de campamentos. Decimación.",facts:["Marchas de 30 km con 27 kg de equipo","Campamentos cada noche en la marcha","Vegecio: 'batallas sin sangre, entrenamiento sangriento'"],locs:[{n:"Roma",info:"Los reclutas entrenaban en el Campo de Marte.",wiki:"El entrenamiento militar romano era legendario. Los reclutas entrenaban 4 meses: marchar 20 millas romanas (30 km) en 5 horas con 27 kg de equipo, ejercitar con espadas de madera ponderadas contra postes, construir campamentos fortificados cada noche en la marcha, y nadar con armadura. Vegecio (siglo IV d.C.) escribió: 'Entrenaban como en batallas sin sangre para que lucharan como en entrenamiento sangriento.' La disciplina era brutal: la decimación (ejecutar a cada décimo hombre en una unidad deshonrada) era rara pero real."},{n:"Lambesis",info:"Base legionaria en Numidia — el discurso de Adriano sobrevive.",wiki:"Lambesis en el norte de África era la base de la Legio III Augusta. Una notable inscripción preserva el discurso de Adriano a la legión en 128 d.C. — elogiando su entrenamiento, criticando maniobras específicas y estableciendo estándares. Es el relato superviviente más detallado de las expectativas de entrenamiento militar romano."}],pathLabels:["Estándares de entrenamiento aplicados por todo el imperio"]},
"mil12":{name:"Caballería Romana",desc:"De equites ciudadanos a alae auxiliares a cataphracti: la caballería evolucionó a lo largo de la historia romana.",facts:["Romanos mediocres a caballo — confiaban en aliados","Cataphracti: lanceros totalmente acorazados","Adrianópolis (378): caballería destruyó las legiones"],locs:[{n:"Roma",info:"Equites: la clase de caballería original de Roma.",wiki:"La caballería romana evolucionó dramáticamente. En la República, los equites ciudadanos proporcionaban caballería ligera — pero los romanos eran medianos jinetes. Desde el siglo II a.C., Roma dependió cada vez más de caballería aliada y auxiliar: caballo ligero númida, caballería pesada gala, y eventualmente cataphracti sármatas (lanzeros completamente acorazados). Para el Imperio tardío, la caballería se volvió el brazo decisivo. Victorias clave de caballería: Zama (202 a.C.), Farsalia (48 a.C.); derrota clave: Adrianópolis (378 d.C.), donde la caballería gótica destruyó la infantería romana."},{n:"Ribchester",info:"Fuerte de caballería romana en Britania — unidad sármata estacionada aquí.",wiki:"Ribchester (Bremetennacum) en Lancashire albergaba una unidad de caballería incluyendo jinetes sármatas — 5.500 fueron enviados a Britania por Marco Aurelio en 175 d.C. El famoso casco de Ribchester — casco deportivo de caballería de bronce — es uno de los mejores artefactos militares romanos jamás encontrados."}],pathLabels:["Caballería sármata destinada a Britania"]},
"mil13":{name:"Veteranos y Colonias Militares",desc:"Soldados licenciados recibían tierra en coloniae: romanizando fronteras de Colonia a Mérida a Timgad.",facts:["Colonias romanizaron regiones fronterizas","Veteranos trajeron ley, idioma, arquitectura","'Cazar, bañarse, jugar, reír — eso es vivir'"],locs:[{n:"Colonia",info:"Colonia Claudia Ara Agrippinensium — fundada para veteranos.",wiki:"Las colonias militares (coloniae) servían dual propósito: recompensar veteranos con tierras y romanizar regiones fronterizas. Colonia fue fundada como Colonia Claudia Ara Agrippinensium en 50 d.C., convirtiéndose en capital de Germania Inferior. Los veteranos trajeron derecho romano, idioma, arquitectura y cultura a las fronteras. Sus familias se casaron con locales, creando poblaciones romanizadas."},{n:"Mérida",info:"Emerita Augusta: colonia para veteranos de las Guerras Cántabras.",wiki:"Augusto fundó Emerita Augusta (Mérida) en 25 a.C. para veteranos de las Legiones V y X tras las Guerras Cántabras. Se convirtió en capital de Lusitania. Su teatro, anfiteatro, circo, acueductos y puentes sobreviven — una de las ciudades romanas mejor conservadas del occidente."},{n:"Timgad",info:"Colonia de cuadrícula perfecta de Trajano en el norte de África.",wiki:"Trajano fundó Thamugadi (Timgad) en 100 d.C. para veteranos de la Legio III Augusta. Dispuesta en cuadrícula perfecta, incluía foro, teatro, biblioteca, 14 termas y arco triunfal. Una inscripción dice: 'Cazar, bañarse, apostar, reír — eso es vivir.'"}],pathLabels:["Veteranos colonizan el Rin","Veteranos se establecen en Iberia","Veteranos colonizan el norte de África"]},
"mil14":{name:"Medicina Militar Romana",desc:"Valetudinaria (hospitales de campaña), instrumentos quirúrgicos: mejor atención traumatológica que la Europa medieval.",facts:["Cada legión tenía hospital de campaña","Más de 40 instrumentos quirúrgicos en Pompeya","Mejor atención traumatológica que Europa medieval"],locs:[{n:"Vindonissa",info:"Base legionaria con mejor valetudinarium conservado.",wiki:"El ejército romano tenía el sistema médico más avanzado del mundo antiguo. Cada legión tenía un valetudinarium (hospital de campaña) — instalación construida con salas, quirófanos y jardines de hierbas. Vindonissa (Windisch, Suiza) tiene el mejor ejemplo conservado. Los médicos militares (medici) realizaban amputaciones, extraían puntas de flecha y trataban heridas con vinagre (antiséptico). Los instrumentos quirúrgicos de Pompeya y Rímini rivalizan en sofisticación con herramientas del siglo XIX."},{n:"Pompeya",info:"Instrumentos quirúrgicos encontrados en la Casa del Cirujano.",wiki:"La Casa del Cirujano en Pompeya produjo más de 40 instrumentos quirúrgicos: escalpelos, fórceps, palancas óseas, catéteres, espéculos vaginales y herramientas para trepanación (perforar el cráneo). La calidad y variedad demuestran una práctica médica sofisticada que no tuvo parangón hasta la era moderna."}],pathLabels:["Conocimiento médico militar por todo el imperio"]},
"mil15":{name:"Los Foederati",desc:"Tropas aliadas bárbaras asentadas dentro del imperio: Alarico, Estilicón y Odoacro fueron foederati.",facts:["Adrianópolis (378): peor derrota desde Cannas","Foederati eran soldados-colonos bárbaros","Odoacro: el último foederatus depuso al último emperador"],locs:[{n:"Adrianópolis",info:"378 d.C.: los visigodos destruyeron el ejército romano.",wiki:"Tras la expulsión por los hunos, los visigodos cruzaron el Danubio en 376 como foederati — colonos aliados que proporcionarían servicio militar. El maltrato llevó a rebelión. En Adrianópolis (378), la caballería gótica destruyó el ejército del emperador Valente — la peor derrota romana desde Cannas. Teodosio estableció a los godos como foederati dentro del imperio, creando precedente: grupos bárbaros proporcionarían cada vez más la mano de obra militar de Roma mientras mantenían su propia identidad y liderazgo."},{n:"Rávena",info:"Odoacro — el último foederatus — depuso al último emperador occidental.",wiki:"Para mediados del siglo V, el ejército romano occidental estaba compuesto en gran parte por foederati bajo generales bárbaros. Odoacro — jefe germánico que era él mismo foederatus — depuso al último emperador occidental Rómulo Augústulo en 476. Envió las insignias imperiales a Constantinopla. Los defensores se habían convertido en conquistadores."}],pathLabels:["De Adrianópolis a Rávena: los foederati toman el control"]},
"cit1":{name:"Éfeso",desc:"250.000 habitantes, Biblioteca de Celso, Templo de Artemisa: joya del Asia romana.",facts:["250.000 habitantes","Biblioteca de Celso: 12.000 rollos","Teatro: 24.000 asientos"],locs:[{n:"Éfeso",info:"Tercera ciudad más grande del Imperio romano.",wiki:"Capital de la provincia de Asia con ~250.000 habitantes. La Biblioteca de Celso albergaba 12.000 rollos. El teatro tenía capacidad para 24.000 personas — donde estalló un motín contra San Pablo (Hechos 19). El Templo de Artemisa era una de las Siete Maravillas del Mundo. El puerto de la ciudad se fue colmatando gradualmente, lo que provocó su declive."}]},
"cit2":{name:"Leptis Magna",desc:"Lugar de nacimiento de Septimio Severo: las ruinas romanas mejor conservadas de África.",facts:["Lugar de nacimiento del emperador Septimio Severo","Riqueza del aceite de oliva","Enterrada por arena — superbamente conservada"],locs:[{n:"Leptis Magna",info:"Libia actual — Patrimonio de la Humanidad por la UNESCO.",wiki:"Originalmente una colonia fenicia, Leptis Magna floreció bajo Roma. Cuando el hijo nativo Septimio Severo se convirtió en emperador (193 d.C.), colmó la ciudad con un nuevo foro, basílica y arco triunfal. El comercio del aceite de oliva la hizo próspera. Enterrada por la arena durante siglos, sus ruinas están entre las mejor conservadas del mundo romano."}]},
"cit3":{name:"Pompeya y Herculano",desc:"Congeladas en el tiempo por el Vesubio: ventana incomparable a la vida diaria romana.",facts:["20.000 habitantes en Pompeya","Termopolios: comida rápida antigua","Herculano: rollos carbonizados sobreviven"],locs:[{n:"Pompeya",info:"Población ~20.000. Enterrada bajo 4-6 m de piedra pómez y ceniza.",wiki:"Colonizada por los veteranos de Sila en 80 a.C. Una próspera ciudad comercial con foros, termas, anfiteatro, burdeles, panaderías y mostradores de comida rápida (termopolios). La erupción del 24 de agosto del 79 d.C. la enterró bajo metros de material volcánico, preservando edificios, frescos, grafitis, alimentos e incluso las siluetas de las víctimas."},{n:"Herculano",info:"Ciudad balneario más rica — preservada por flujos piroclásticos.",wiki:"Más pequeña y rica que Pompeya. Los flujos piroclásticos a 500°C carbonizaron y preservaron vigas de madera, muebles, alimentos e incluso una biblioteca de rollos de papiro (Villa de los Papiros). Los cuerpos hallados en los refugios de barcas mostraron a personas huyendo hacia el mar."}],pathLabels:["Ambas enterradas por el Vesubio, 79 d.C."]},
"cit4":{name:"Antioquía",desc:"Tercera ciudad romana más grande (~500.000). Capital oriental. Donde se nombró por primera vez a 'cristianos'.",facts:["~500.000 habitantes","'Cristianos' nombrados aquí por primera vez","Famosa calle principal columnada"],locs:[{n:"Antioquía",info:"Antakya actual, Turquía.",wiki:"Fundada en 300 a.C. por Seleuco I. Pompeyo la anexó en 64 a.C. Con ~500.000 habitantes, era la tercera ciudad del imperio tras Roma y Alejandría. Famosa por su calle principal columnada de 6 km, los juegos olímpicos y los jardines de placer en Dafne. Hechos 11:26 registra que \"los discípulos fueron llamados cristianos por primera vez en Antioquía\". Múltiples terremotos devastadores azotaron la ciudad."}]},
"cit5":{name:"Cartago Renacida",desc:"Reconstruida por César y Augusto: se convirtió en la 4.ª ciudad del imperio y capital de África.",facts:["Destruida 146 a.C., refundada 44 a.C.","~500.000 habitantes","Hogar de Agustín y Tertuliano"],locs:[{n:"Cartago",info:"Destruida en 146 a.C., refundada en 44 a.C.",wiki:"Julio César planificó la colonia; Augusto la realizó. La refundada Colonia Julia Cartago creció rápidamente hasta convertirse en la cuarta ciudad más grande del imperio con ~500.000 personas. Capital de África Proconsular, exportaba vastas cantidades de trigo, aceite de oliva y cerámica. Tertuliano, Cipriano y Agustín trabajaron aquí. Los vándalos la capturaron en 439 d.C."}]},
"cit6":{name:"Constantinopla: Nueva Roma",desc:"Fundada por Constantino 330 d.C.: triple muralla, 500.000 personas, sobrevivió cuando Occidente cayó.",facts:["Dedicada el 11 de mayo del 330 d.C.","Murallas Teodosianas: intactas 800 años","500.000 habitantes"],locs:[{n:"Constantinopla",info:"Estambul actual — capital durante 1.100 años.",wiki:"Constantino eligió la antigua ciudad griega de Bizancio para su nueva capital en 324 d.C. Dedicada el 11 de mayo del 330 como \"Nueva Roma\". Sus triples murallas teodosianas (construidas en 413 d.C.) eran las fortificaciones más formidables del mundo medieval — no fueron franqueadas hasta 1204 (cruzados) y 1453 (otomanos). Con 500.000 habitantes, un hipódromo con capacidad para 100.000, Santa Sofía y los tesoros acumulados del mundo romano, fue la mayor ciudad de Europa durante mil años."}]},
"cit7":{name:"Alejandría",desc:"Segunda ciudad del imperio: 500.000 personas, la Gran Biblioteca y el Faro.",facts:["~500.000 habitantes","Gran Biblioteca: mayor colección antigua","Faro: una de las Siete Maravillas"],locs:[{n:"Alejandría",info:"Fundada por Alejandro en 331 a.C. Romana desde 30 a.C.",wiki:"Alejandría era la segunda ciudad del Imperio romano con ~500.000 habitantes. La Gran Biblioteca (y su biblioteca filial en el Serapeo) albergaba cientos de miles de rollos — la mayor colección de conocimiento del mundo antiguo. El Faro de Alejandría, una de las Siete Maravillas, guiaba a los barcos hacia el doble puerto. El Mouseion (Museo) era un instituto de investigación financiado por el Estado donde trabajaron Euclides, Eratóstenes y Herón. La ciudad era intensamente multicultural — barrios griego, judío y egipcio coexistían con tensión. El excedente de trigo de Egipto convirtió a Alejandría en la clave para alimentar Roma."}]},
"cit8":{name:"Atenas bajo Roma",desc:"Capital intelectual: escuelas de filosofía sobrevivieron 900 años hasta que Justiniano las cerró en 529 d.C.",facts:["Saqueada por Sila, reconstruida por Adriano","Ciudad universitaria para élites romanas","Escuelas de filosofía cerradas 529 d.C."],locs:[{n:"Atenas",info:"Saqueada por Sila (86 a.C.), reconstruida por Adriano.",wiki:"Roma conquistó Atenas en 146 a.C. y Sila la saqueó en 86 a.C., pero el prestigio intelectual de la ciudad aseguró su supervivencia. Permaneció como la ciudad universitaria del Mediterráneo — Cicerón, Horacio, Bruto y Marco Aurelio estudiaron aquí. Adriano la colmó de edificios: el Templo de Zeus Olímpico, una nueva biblioteca y un barrio entero. En 176 d.C., Marco Aurelio dotó cuatro cátedras de filosofía (platónica, aristotélica, estoica, epicúrea). Las escuelas de filosofía sobrevivieron hasta que Justiniano las cerró en 529 d.C. — poniendo fin a 900 años de enseñanza continua."}]},
"cit9":{name:"Londinium",desc:"Fundada tras la invasión de Claudio, quemada por Boudica, reconstruida para 60.000 personas.",facts:["Fundada ~47 d.C.","Quemada por Boudica, 60 d.C.","Población ~60.000 en su apogeo"],locs:[{n:"Londinium",info:"Londres actual — capital de la Britania romana.",wiki:"Londinium fue fundada alrededor del 47 d.C. como asentamiento comercial en el punto más bajo de cruce del Támesis. Boudica la quemó hasta los cimientos en 60 d.C. — el estrato de destrucción es visible en las excavaciones arqueológicas. Reconstruida, creció hasta ~60.000 personas en el siglo II con un foro-basílica (más grande que cualquiera en Roma), un anfiteatro, termas públicas y una enorme muralla defensiva (partes sobreviven). El Mitreo (templo de Mitra) fue descubierto en 1954. La Londres romana fue abandonada alrededor del 410 cuando las legiones se retiraron."}]},
"cit10":{name:"Mediolanum (Milán)",desc:"Capital imperial occidental desde 286 d.C.: donde se emitió el Edicto de Milán y Ambrosio desafió a un emperador.",facts:["Capital occidental desde 286 d.C.","Edicto de Milán emitido aquí (313)","Ambrosio obligó a Teodosio a hacer penitencia"],locs:[{n:"Mediolanum",info:"Milán actual — reemplazó a Roma como capital occidental.",wiki:"Originalmente un asentamiento celta conquistado en 222 a.C., Mediolanum se convirtió en la capital de facto del imperio occidental bajo Maximiano (286 d.C.). Más cerca de las fronteras alpinas que Roma, era estratégicamente vital. El Edicto de Milán (313 d.C.) que legalizaba el cristianismo fue emitido aquí. El obispo Ambrosio la convirtió en un centro de autoridad cristiana — en 390, obligó al emperador Teodosio a hacer penitencia pública por la masacre de Tesalónica, estableciendo el principio de que incluso los emperadores estaban sujetos a la ley moral. La corte se trasladó a Rávena en 402 tras la amenaza de invasión de Alarico."}]},
"cit11":{name:"Tréveris (Augusta Treverorum)",desc:"'Segunda Roma' al norte de los Alpes: capital imperial con la Porta Nigra y la Basílica de Constantino.",facts:["Mayor puerta de ciudad romana conservada (Porta Nigra)","Sala de audiencias de Constantino sigue en pie","9 monumentos romanos Patrimonio UNESCO"],locs:[{n:"Tréveris",info:"Residencia imperial desde Diocleciano hasta Valentiniano.",wiki:"Augusta Treverorum (Tréveris) fue fundada a finales del siglo I a.C. Se convirtió en residencia imperial bajo la Tetrarquía, acogiendo a Constantino I y a su madre Helena. En su apogeo, tenía 80.000 habitantes. La Porta Nigra — la mayor puerta de ciudad romana que sobrevive — está construida con 7.200 bloques de piedra sin argamasa. La Aula Palatina (Basílica) de Constantino es la mayor sala de audiencias romana que sobrevive. Las termas imperiales, el anfiteatro y el puente sobreviven. Tréveris tiene más monumentos romanos que cualquier ciudad fuera de Italia — nueve son Patrimonio de la Humanidad por la UNESCO."}]},
"cit12":{name:"Rávena",desc:"Última capital occidental: protegida por marismas. Impresionantes mosaicos romanos tardíos en San Vital y Gala Placidia.",facts:["Protegida por marismas — casi inexpugnable","Mosaicos unen arte romano y bizantino","8 edificios Patrimonio UNESCO"],locs:[{n:"Rávena",info:"Capital occidental 402-476 d.C.",wiki:"Rávena reemplazó a Milán como capital occidental en 402 d.C. Protegida por marismas circundantes, era casi inexpugnable. Honorio, Valentiniano III y los últimos emperadores occidentales gobernaron desde aquí. Tras la caída del Imperio Occidental, Teodorico el Ostrogodo la convirtió en su capital. Los mosaicos de San Vital, Gala Placidia y Sant'Apollinare Nuovo están entre las mayores obras de arte supervivientes de la antigüedad tardía — composiciones de oro y azul brillantes que unen los mundos romano y bizantino. Ocho edificios de Rávena son Patrimonio de la Humanidad por la UNESCO."}]},
"cit13":{name:"Palmira",desc:"Ciudad caravanera del desierto en la Ruta de la Seda: Templo de Bel, avenida columnada, reino separatista de Zenobia.",facts:["Encrucijada del comercio Roma-Persia-India","Zenobia gobernó brevemente de Egipto a Anatolia","Gran Columnata: 1,1 km"],locs:[{n:"Palmira",info:"Patrimonio de la Humanidad por la UNESCO en el desierto sirio.",wiki:"Palmira (Tadmor) se encontraba en el cruce de rutas caravaneras que unían Roma con Persia e India. Bajo soberanía romana desde el siglo I d.C., creció fabulosamente rica gracias a los impuestos comerciales. El Templo de Bel (32 d.C.) fusionaba la arquitectura grecorromana y del Próximo Oriente. La Gran Columnata se extendía 1,1 km. Bajo la reina Zenobia (267-272), Palmira controló brevemente un imperio que se extendía desde Egipto hasta Anatolia antes de que Aureliano la reconquistara. Patrimonio de la Humanidad por la UNESCO, gravemente dañada en la guerra civil siria."}]},
"cit14":{name:"Corinto",desc:"Destruida por Mumio (146 a.C.), refundada por César (44 a.C.): epístolas de Pablo, canal fallido de Nerón.",facts:["Destruida 146 a.C., refundada por César 44 a.C.","Pablo escribió dos epístolas aquí","Intento de canal de Nerón usó 6.000 prisioneros"],locs:[{n:"Corinto",info:"Importante colonia romana que controlaba el Istmo.",wiki:"El Corinto romano tuvo dos vidas. Mumio destruyó la ciudad griega en 146 a.C. como castigo por la resistencia — permaneció abandonada un siglo. Julio César la refundó como colonia romana (Colonia Laus Julia Corinthiensis) en 44 a.C. Se convirtió en la capital de Acaya y una de las ciudades más ricas del imperio oriental, controlando el comercio a través del Istmo. El apóstol Pablo pasó 18 meses aquí (50-52 d.C.) y escribió dos famosas epístolas a su conflictiva comunidad cristiana. Nerón intentó abrir un canal a través del Istmo en 67 d.C. usando 6.000 prisioneros judíos — el proyecto fue abandonado."}]},
"cit15":{name:"Cesarea Marítima",desc:"Puerto artificial de Herodes con hormigón romano submarino: capital provincial de Judea. Prisión de Pablo.",facts:["Mayor puerto artificial antiguo","Inscripción de Poncio Pilato encontrada aquí","Pablo encarcelado dos años"],locs:[{n:"Cesarea",info:"Mayor puerto artificial del mundo antiguo.",wiki:"Herodes el Grande construyó Cesarea entre 22-10 a.C., nombrándola en honor a Augusto. El puerto artificial (Sebastos) usaba hormigón hidráulico romano — pozzolana enviada desde Italia que fraguaba bajo el agua. La ciudad tenía teatro, hipódromo, palacio, acueducto y sistema de alcantarillado impulsado por el mar. Se convirtió en la capital provincial romana de Judea. El nombre de Poncio Pilato fue encontrado aquí en una piedra dedicatoria — la única evidencia arqueológica de su existencia. Pablo estuvo prisionero aquí dos años (58-60 d.C.) antes de ser enviado a Roma. La ciudad acogió el primer bautismo de gentiles (Cornelio) y fue el origen de la historia eclesiástica pionera de Eusebio."}]},
"sci1":{name:"Galeno y la Medicina Romana",desc:"Médico de gladiadores y emperadores. La teoría de los cuatro humores dominó la medicina 1.300 años.",facts:["4 millones de palabras de textos supervivientes","Teoría de cuatro humores: 1.300 años","Médico de gladiadores y emperadores"],locs:[{n:"Pérgamo",info:"Nacido en 129 d.C. — formado en el famoso Asclepeion.",wiki:"Galeno nació en el seno de una familia acomodada de arquitectos en Pérgamo. Se formó en el Asclepeion (templo de curación) de la ciudad y estudió en Esmirna, Corinto y Alejandría. Su carrera temprana tratando gladiadores le dio un conocimiento incomparable de anatomía y traumatología."},{n:"Roma",info:"Médico de Marco Aurelio y otros tres emperadores.",wiki:"Galeno se trasladó a Roma en 162 d.C. y se convirtió en médico de Marco Aurelio, Cómodo y Septimio Severo. Escribió 4 millones de palabras de textos médicos supervivientes — más que cualquier otro autor antiguo. Su teoría de los cuatro humores (sangre, flema, bilis amarilla, bilis negra) dominó la medicina occidental hasta el siglo XVII."},{n:"Alejandría",info:"Estudió anatomía en la mayor escuela de medicina.",wiki:"La escuela de medicina de Alejandría permitía la disección humana — prohibida en otros lugares. Galeno estudió aquí, construyendo sobre el trabajo de Herófilo y Erasístrato. Su conocimiento anatómico, aunque basado en gran medida en disección animal, permaneció como estándar durante 1.300 años."}],pathLabels:["De Pérgamo a médico imperial","Estudios en Alejandría"]},
"sci2":{name:"Ptolomeo y el Cosmos",desc:"Almagesto: modelo geocéntrico usado 1.400 años. Geografía: cartografió el mundo conocido.",facts:["Almagesto: estándar durante 1.400 años","Geografía: primer atlas con coordenadas","Modelo geocéntrico hasta Copérnico"],locs:[{n:"Alejandría",info:"Vivió y trabajó en el Museo y la Biblioteca.",wiki:"Claudio Ptolomeo trabajó en Alejandría ~100-170 d.C. Su Almagesto (árabe para \"El Más Grande\") presentaba un modelo geocéntrico del universo con precisión matemática suficiente para predicciones precisas. Fue el texto astronómico estándar durante 1.400 años hasta Copérnico. Su Geografía intentó cartografiar todo el mundo conocido con coordenadas — el primer atlas. Su Óptica estudió la refracción y la visión. También pudo haber compuesto el Tetrabiblos sobre astrología."}]},
"sci3":{name:"Hormigón Romano y Ciencia de Materiales",desc:"Opus caementicium con ceniza volcánica creó hormigón autorreparable: el Panteón sigue en pie 1.900 años después.",facts:["Hormigón autorreparable","Cúpula del Panteón: 1.900 años","Cemento moderno dura 50-100 años"],locs:[{n:"Roma",info:"Cúpula del Panteón: mayor cúpula de hormigón sin refuerzo jamás construida.",wiki:"El hormigón romano (opus caementicium) mezclaba ceniza volcánica pozzolánica con cal y agua de mar. Los científicos modernos descubrieron que esto crea cristales de tobermorita de aluminio que en realidad se fortalecen con el tiempo — hormigón autorreparable. La cúpula del Panteón (43,3 m de luz) ha resistido 1.900 años sin refuerzo. Las estructuras modernas de cemento Portland duran 50-100 años."},{n:"Pozzuoli",info:"Fuente de ceniza pozzolánica — el ingrediente clave.",wiki:"La ceniza volcánica de Puteoli (Pozzuoli) cerca de Nápoles dio su nombre al cemento pozzolánico. Cuando se mezclaba con cal y agua de mar, creaba un cemento hidráulico que fraguaba bajo el agua — permitiendo la construcción de puertos en todo el Mediterráneo."},{n:"Cesarea",info:"Puerto de Herodes — hormigón que fraguaba bajo el agua.",wiki:"El puerto del rey Herodes en Cesarea Marítima usó tecnología de hormigón romano para construir enormes cimientos submarinos. El hormigón se mezclaba en barcazas y se bajaba al mar en moldes de madera. El análisis moderno muestra que incorporaba ceniza volcánica importada de Italia."}],pathLabels:["Ceniza pozzolánica: clave del hormigón de Roma","La tecnología del hormigón submarino llega a Judea"]},
"sci4":{name:"Cloaca Máxima y Saneamiento",desc:"Sistema de alcantarillado más antiguo del mundo: drenaba el Foro, conectado a acueductos, aún parcialmente en uso.",facts:["Construida ~600 a.C.","Agripa navegó por ella","Aún parcialmente en uso hoy"],locs:[{n:"Roma",info:"Foro Romano — construido sobre tierras pantanosas drenadas.",wiki:"La tradición atribuye al rey Tarquinio Prisco (~600 a.C.) el inicio de la Cloaca Máxima para drenar el valle pantanoso del Foro. Originalmente un canal abierto, fue progresivamente cubierto. En el siglo I d.C., se conectaba a los 11 acueductos y servía como columna vertebral de la red de alcantarillado de Roma. La salida al Tíber sigue visible. Agripa navegó famosamente por ella en barca durante su renovación. Partes del sistema siguen en uso tras 2.600 años — testimonio de la ingeniería romana."}]},
"sci5":{name:"Historia Natural de Plinio",desc:"37 volúmenes citando más de 2.000 obras: la primera enciclopedia, de astronomía a zoología.",facts:["37 volúmenes, más de 2.000 fuentes","Primera enciclopedia","Murió investigando el Vesubio"],locs:[{n:"Comum",info:"Nacido en 23 d.C. — Como actual.",wiki:"Nacido en una familia ecuestre. Sirvió en el ejército en Germania. Su sobrino Plinio el Joven preservó su legado y describió su muerte en el Vesubio."},{n:"Roma",info:"Escribió la Historia Natural mientras asesoraba a Vespasiano.",wiki:"Plinio leía constantemente — durante las comidas, en su litera, en las termas. Su liberto leía en voz alta mientras dictaba notas. La Historia Natural (Naturalis Historia) cubre geografía, antropología, zoología, botánica, medicina, mineralogía e historia del arte en 37 libros citando más de 2.000 fuentes. Permaneció como obra de referencia estándar durante 1.500 años."},{n:"Estabia",info:"Murió investigando el Vesubio, 79 d.C.",wiki:"Como comandante de la flota en Miseno, Plinio navegó hacia el Vesubio para investigar y rescatar supervivientes. Vencido por los gases volcánicos en la playa de Estabia. Las cartas de su sobrino a Tácito proporcionan el relato antiguo más detallado de una erupción volcánica."}],pathLabels:["De Como a Roma","Investigación fatal del Vesubio"]},
"sci6":{name:"Vitruvio y De Architectura",desc:"Único tratado de arquitectura antigua superviviente: firmitas, utilitas, venustas moldearon la construcción 2.000 años.",facts:["Firmitas, utilitas, venustas","Único texto de arquitectura antigua superviviente","Inspiró todo el Renacimiento"],locs:[{n:"Roma",info:"Dedicado a Augusto.",wiki:"Marco Vitruvio Polión sirvió como ingeniero militar bajo César y Augusto. Su De Architectura (Diez libros sobre arquitectura) es el único tratado arquitectónico completo de la antigüedad. Cubre planificación urbana, materiales de construcción, templos, edificios públicos, suministro de agua, astronomía y máquinas. Sus tres principios — firmitas (solidez), utilitas (funcionalidad), venustas (belleza) — se convirtieron en la base de la arquitectura occidental. Redescubierto en 1414, inspiró directamente a Brunelleschi, Alberti, Palladio y todo el Renacimiento."}]},
"sci7":{name:"Topografía y Medición Romanas",desc:"Groma, libella y corobates: herramientas de precisión que trazaron ciudades, calzadas e imperio.",facts:["Groma: herramienta de puntería de bastón cruzado","Milla romana: 1.000 pasos (1.480 m)","Cuadrícula de centuriación visible desde el espacio"],locs:[{n:"Roma",info:"Estandarización de medidas en todo el imperio.",wiki:"Los agrimensores romanos (agrimensores o gromáticos) usaban la groma — un instrumento de puntería en forma de cruz — para trazar carreteras perfectamente rectas, ciudades en cuadrícula y divisiones de tierras (centuriación). La libella era un nivel simple; el corobates un banco de nivelación de 6 metros para gradientes de acueductos. Unidades estándar: el pie romano (29,6 cm), el paso (5 pies), la milla (1.000 pasos = 1.480 m) y el iugerum (medida de tierra)."},{n:"Pompeya",info:"Groma encontrada en taller de agrimensor.",wiki:"Se encontró una groma intacta en un taller de agrimensor en Pompeya — uno de los pocos instrumentos de topografía romanos supervivientes. La planta en cuadrícula de la ciudad demuestra la precisión que estas herramientas podían lograr."},{n:"Orange",info:"Mapa catastral de mármol — mayor levantamiento topográfico romano superviviente.",wiki:"Tres grandes fragmentos de mármol en Orange (Arausio) en Francia conservan parte de un levantamiento catastral romano — un mapa detallado de división de tierras mostrando parcelas, caminos y cursos de agua. El ejemplo más extenso superviviente de cartografía de centuriación romana."}],pathLabels:["Herramientas de agrimensor encontradas en Pompeya","Levantamientos catastrales en la Galia"]},
"sci8":{name:"Herón de Alejandría",desc:"Eolípila (motor de vapor), autómatas, máquinas expendedoras: genio 1.800 años adelantado.",facts:["Eolípila: primer dispositivo de vapor","Primera máquina expendedora","La esclavitud hizo innecesarias las máquinas ahorradoras de trabajo"],locs:[{n:"Alejandría",info:"Trabajó en el Museo de Alejandría.",wiki:"Herón de Alejandría fue un matemático e ingeniero que inventó dispositivos asombrosamente adelantados a su tiempo. La eolípila fue el primer dispositivo conocido impulsado por vapor — una esfera giratoria impulsada por chorros de vapor. Construyó la primera máquina expendedora (dispensador de agua bendita operado por monedas), puertas automáticas para templos, un órgano impulsado por viento y un carro programable impulsado por pesos y cuerdas. Su Métrica contenía fórmulas para calcular áreas y volúmenes. Ninguna de sus invenciones se desarrolló industrialmente — la esclavitud hacía económicamente innecesarios los dispositivos ahorradores de mano de obra."}]},
"sci9":{name:"Frontino y el Suministro de Agua de Roma",desc:"De Aquaeductu: el manual de ingeniería que mantuvo hidratado a un millón de romanos.",facts:["9 acueductos documentados","~1 millón m³/día","Expuso robo generalizado de agua"],locs:[{n:"Roma",info:"Comisario de aguas (curator aquarum) bajo Nerva.",wiki:"Sexto Julio Frontino sirvió como gobernador de Britania, cónsul tres veces y curator aquarum (comisario de aguas) desde 97 d.C. Su De Aquaeductu Urbis Romae es el relato más detallado superviviente de la ingeniería hidráulica romana. Documentó los 9 acueductos de Roma (11 según conteos posteriores), sus fuentes, longitudes, capacidades y mantenimiento. Calculó el flujo diario total en casi 1 millón de metros cúbicos — más per cápita que muchas ciudades modernas. Expuso el extendido desvío ilegal y robo de agua por funcionarios corruptos."}]},
"sci10":{name:"Fabricación de Vidrio Romana",desc:"Soplado de vidrio sirio revolucionó la producción: el vidrio pasó de lujo a commodity cotidiana.",facts:["Soplado inventado ~50 a.C. en Siria","Precios cayeron 90%","Vaso Portland: obra maestra del vidrio camafeo"],locs:[{n:"Roma",info:"Los recipientes de vidrio se volvieron asequibles para los romanos ordinarios.",wiki:"El soplado de vidrio fue inventado en Siria alrededor del 50 a.C. y se extendió rápidamente por el mundo romano. Antes de esto, el vidrio era un lujo formado por fundición lenta. El soplado permitió la producción en masa — los precios cayeron un 90%. En el siglo I d.C., la vajilla de vidrio, tarros de almacenamiento e incluso ventanas de vidrio eran comunes. Los vidrieros romanos lograron una extraordinaria maestría: el Vaso Portland (vidrio camafeo), copas de jaula (diatretum — vidrio tallado en jaula independiente) y técnicas de millefiori."},{n:"Sidón",info:"Lugar de nacimiento del soplado de vidrio.",wiki:"Saida actual, Líbano. Los vidrieros sirios revolucionaron el oficio alrededor del 50 a.C. La técnica se extendió por el Mediterráneo en décadas. Sidón permaneció como centro de vidrio premium durante todo el período romano."},{n:"Colonia Agrippina",info:"Colonia actual — importante centro de producción de vidrio.",wiki:"Colonia se convirtió en el principal centro de producción de vidrio al norte de los Alpes. Los talleres del Rin producían el famoso vidrio de hilo de serpiente, copas de jaula y recipientes grabados. Los fragmentos de vidrio están entre los hallazgos más comunes en los yacimientos romanos del norte de Europa."}],pathLabels:["El soplado de vidrio se extiende desde Siria a Roma","La producción de vidrio llega al Rin"]},
"sci11":{name:"Calendario Juliano",desc:"Reforma de César con Sosígenes: año de 365,25 días, años bisiestos. Usado 1.600 años.",facts:["Año de 365,25 días con años bisiestos","Usado 1.600 años","Julio nombrado por Julio César"],locs:[{n:"Roma",info:"Introducido el 1 de enero del 45 a.C.",wiki:"Julio César, como Pontífice Máximo, reformó el caótico calendario romano en 46 a.C. con ayuda del astrónomo alejandrino Sosígenes. El antiguo calendario lunar había derivado tanto que las fiestas de invierno caían en otoño. El calendario solar de César tenía 365 días con un día bisiesto cada 4 años — promediando 365,25 días. El año solar real es 365,2422 días, así que el calendario juliano ganaba unos 11 minutos por año. Para 1582, estaba 10 días desfasado, provocando la reforma del papa Gregorio XIII. Julio fue renombrado en honor al propio Julio César."},{n:"Alejandría",info:"Sosígenes, el astrónomo que diseñó la reforma, procedía de aquí.",wiki:"Sosígenes de Alejandría proporcionó la experiencia astronómica para la reforma de César, basándose en siglos de observación solar egipcia y griega. La Gran Biblioteca de Alejandría había acumulado registros astronómicos precisos que hicieron posible el cálculo de 365,25 días."}],pathLabels:["La astronomía alejandrina reforma el calendario romano"]},
"sci12":{name:"Celso y De Medicina",desc:"Única enciclopedia médica romana superviviente: los cuatro signos de inflamación y técnicas quirúrgicas sofisticadas.",facts:["Cuatro signos de inflamación: rubor, tumor, calor, dolor","Describió cirugía de cataratas y hernias","Entre los primeros textos médicos impresos (1478)"],locs:[{n:"Roma",info:"Escrito durante el reinado de Tiberio.",wiki:"Aulo Cornelio Celso escribió De Medicina alrededor del 25-35 d.C. como parte de una enciclopedia más amplia. Es el único manual médico romano superviviente y la mejor fuente para la práctica médica antigua. Celso definió los cuatro signos clásicos de inflamación — rubor (enrojecimiento), tumor (hinchazón), calor (calor) y dolor (dolor) — aún enseñados en las facultades de medicina. Describió operaciones quirúrgicas para cataratas, hernias, cálculos vesicales y amígdalas con notable precisión. La obra fue redescubierta en 1443 y estuvo entre los primeros textos médicos impresos (1478)."}]},
"sci13":{name:"Ciencia Agrícola Romana",desc:"Catón, Varrón, Columela: tratados de agricultura científica sobre rotación de cultivos, gestión de fincas.",facts:["Catón: obra en prosa latina más antigua superviviente","Columela: 12 libros sobre todos los aspectos de la agricultura","Varrón: incluso cubrió gestión avícola"],locs:[{n:"Roma",info:"Centro de compilación del conocimiento agrícola.",wiki:"Tres importantes tratados agrícolas romanos sobreviven. El De Agri Cultura de Catón el Viejo (c. 160 a.C.) — la obra en prosa latina más antigua superviviente — es un manual práctico de gestión de fincas, incluyendo recetas de vino y pan. Las Res Rusticae de Varrón (37 a.C.) son más sistemáticas, cubriendo disposición de la granja, ganado e incluso aves de corral. El De Re Rustica de Columela (c. 65 d.C.) — 12 libros — es el más completo: tipos de suelo, rotación de cultivos, viticultura, arboricultura, ganadería y piscicultura. Juntos, documentan una ciencia agrícola sofisticada."},{n:"Gades",info:"Lugar de nacimiento de Columela — Cádiz actual.",wiki:"Lucio Junio Moderato Columela nació en Gades (Cádiz), España. Sirvió en el ejército en Siria antes de retirarse para cultivar en Italia. Su De Re Rustica es el manual agrícola más detallado de la antigüedad — incluyendo un libro sobre jardinería escrito en verso hexámetro."}],pathLabels:["De Gades a Roma: el conocimiento agrícola de Columela"]},
"sci14":{name:"Dioscórides y Farmacología",desc:"De Materia Medica: 600 plantas, más de 1.000 medicinas: referencia farmacológica estándar 1.500 años.",facts:["600 plantas y más de 1.000 medicinas catalogadas","Referencia estándar 1.500 años","Describió opio, corteza de sauce (precursor aspirina), aloe vera"],locs:[{n:"Roma",info:"Dioscórides sirvió como médico militar romano.",wiki:"Pedanio Dioscórides sirvió como médico con los ejércitos romanos, recolectando especímenes de plantas por todo el Mediterráneo. Su De Materia Medica (c. 70 d.C.) cataloga unas 600 plantas y más de 1.000 preparaciones medicinales. Fue el texto farmacológico más influyente del mundo durante 1.500 años — usado por médicos árabes, bizantinos y europeos hasta el siglo XVII. Describió los usos medicinales del opio, la corteza de sauce (precursor de la aspirina) y el aloe vera."},{n:"Anazarba",info:"Lugar de nacimiento de Dioscórides en Cilicia (Turquía actual).",wiki:"Anazarba (Anavarza actual, Turquía) fue el lugar de nacimiento de Dioscórides. Una ciudad de habla griega en la Cilicia romana, produjo uno de los científicos más influyentes de la antigüedad. Su enfoque empírico — probar remedios personalmente y registrar observaciones — anticipó la farmacología moderna."}],pathLabels:["De Cilicia al servicio militar: los viajes botánicos de Dioscórides"]},
"sci15":{name:"Cartografía Romana",desc:"Mapa mundial de Agripa, Forma Urbis Romae (plano de mármol de Roma), Tabula Peutingeriana.",facts:["Mapa mundial de Agripa: primer atlas romano completo","Forma Urbis: plano de mármol de cada edificio en Roma","Tabula Peutingeriana: rollo de 6,75 m de todas las calzadas romanas"],locs:[{n:"Roma",info:"Centro de los esfuerzos cartográficos romanos.",wiki:"Marco Vipsanio Agripa (mano derecha de Augusto) creó un monumental mapa del mundo expuesto en la Porticus Vipsania tras su muerte en 12 a.C. — midiendo el mundo conocido a partir de levantamientos de caminos. La Forma Urbis Romae, encargada por Septimio Severo alrededor del 203 d.C., era un enorme plano de mármol de Roma (18 x 13 metros) montado en un muro de templo — sobreviven 1.186 fragmentos mostrando cada habitación de cada edificio. La Tabula Peutingeriana — una copia medieval de un original romano — es un pergamino de 6,75 metros mostrando toda la red de caminos romanos desde Britania hasta India, con distancias, paradas de descanso y ciudades principales."}]},
"dlf1":{name:"La Casa Romana: Domus e Insulae",desc:"Los ricos vivían en domus centradas en atrio. Los pobres hacinados en insulae de 5-7 pisos propensas al fuego.",facts:["Insulae: 5-7 pisos","Augusto limitó la altura de edificios","Casa del Fauno: 40 habitaciones"],locs:[{n:"Pompeya",info:"Casa del Fauno — mayor domus de Pompeya.",wiki:"La rica domus romana se organizaba alrededor de un atrio (sala con techo abierto que recogía agua de lluvia) y peristilo (jardín columnado). La Casa del Fauno en Pompeya cubría una manzana entera con 40 habitaciones, dos atrios y el famoso Mosaico de Alejandro. Las habitaciones estaban ricamente pintadas con frescos."},{n:"Ostia",info:"Insulae (bloques de apartamentos) mejor conservadas.",wiki:"La mayoría de los romanos vivían en insulae — bloques de apartamentos de 5-7 pisos que albergaban cientos de inquilinos. Las plantas bajas tenían tiendas; los pisos superiores eran más baratos y peligrosos. Sin agua corriente por encima de la planta baja. Los incendios eran constantes — Juvenal bromeaba que para cuando te despertabas, tu vecino del tercer piso ya estaba en llamas. Augusto limitó la altura a 70 pies romanos (~20 m)."}],pathLabels:["Lujo de la domus vs realidad de las insulae"]},
"dlf2":{name:"Comida y Banquetes Romanos",desc:"Garum en todo, cenas de tres platos reclinados en divanes, vino mezclado con agua.",facts:["Garum (salsa de pescado fermentada) en todo","Vino siempre mezclado con agua","Más de 150 termopolios en Pompeya"],locs:[{n:"Roma",info:"La cena era la comida principal — se comía reclinado.",wiki:"Los romanos comían tres comidas: ientaculum (desayuno — pan y queso), prandium (almuerzo — sobras frías) y cena (cena — el evento principal). Los romanos ricos se reclinaban en divanes (triclinio) para cenar. Una cena formal tenía tres platos: gustatio (aperitivos), mensa prima (principal) y mensa secunda (postre). El vino siempre se mezclaba con agua — beberlo puro se consideraba bárbaro."},{n:"Pompeya",info:"Termopolios: mostradores de comida rápida antiguos.",wiki:"Se han encontrado más de 150 termopolios (mostradores de comida caliente) en Pompeya — el equivalente antiguo de la comida rápida. Servían guisos calientes, lentejas y vino a trabajadores que no tenían cocina. Excavaciones recientes encontraron un termopolio con comida aún en las ollas: pato, cabra, pescado y caracoles."}]},
"dlf3":{name:"La Toga y la Moda Romana",desc:"La toga = ciudadanía. 6 metros de lana drapeada. Púrpura tiria más valiosa que el oro.",facts:["6 metros de lana drapeada","12.000 caracoles = 1,5 g de tinte","Púrpura no autorizada = traición"],locs:[{n:"Roma",info:"Vestir la toga era derecho y deber del ciudadano.",wiki:"La toga era la prenda romana por excelencia — 6 metros de lana semicircular drapeada sin alfileres ni costuras. Era pesada, caliente e impracticable, que era el punto: solo un ciudadano de ocio necesitaba llevarla. La toga praetexta (con borde púrpura) la llevaban los magistrados y los niños libres. La toga candida (blanqueada con tiza) la llevaban los candidatos políticos — origen de \"candidato\"."},{n:"Tiro",info:"Fuente del tinte púrpura tirio — valía más que el oro.",wiki:"La púrpura tiria se extraía de caracoles de mar murex — 12.000 caracoles producían 1,5 g de tinte. Una libra de lana teñida de púrpura costaba más que una libra de oro. Solo los emperadores podían llevar la toga picta (púrpura sólida). Llevar púrpura no autorizada era traición."}],pathLabels:["Púrpura tiria: de Fenicia al emperador"]},
"dlf4":{name:"Mujeres en Roma",desc:"Ciudadanas pero no podían votar. Cornelia era la matrona ideal. Fulvia comandó ejércitos.",facts:["Ciudadanas pero no podían votar","Cornelia: 'Estas son mis joyas' (sus hijos)","Fulvia comandó ejércitos"],locs:[{n:"Roma",info:"El estatus legal mejoró a lo largo de los siglos.",wiki:"Las mujeres romanas eran ciudadanas pero no podían votar, ocupar cargos ni servir en el ejército. República temprana: las mujeres estaban bajo tutela masculina perpetua. A finales de la República, las lagunas permitían que mujeres ricas gestionaran propiedades, dirigieran negocios y ejercieran influencia política. Cornelia, madre de los Gracos, encarnaba la matrona ideal — llamaba a sus hijos \"mis joyas\". Fulvia (esposa de Antonio) reclutó tropas y comandó ejércitos. Livia gobernó junto a Augusto durante 51 años. Las libertas y esclavas tenían muchos menos derechos."}]},
"dlf5":{name:"Educación y Alfabetización Romanas",desc:"Tres niveles: ludus, grammaticus, rhetor. Tutores griegos. Alfabetización crucial para política y comercio.",facts:["Tres niveles: ludus, grammaticus, rhetor","Profesores a menudo esclavos griegos","~15-20% tasa de alfabetización"],locs:[{n:"Roma",info:"La educación era privada — no había escuelas estatales.",wiki:"La educación romana tenía tres niveles. El ludus (7-12 años): lectura, escritura, aritmética. El gramático (12-15): literatura, gramática, griego. El retor (15+): retórica, oratoria, derecho. Los profesores eran a menudo esclavos o libertos griegos. Las niñas podían asistir al ludus pero rara vez iban más allá. Los niños de la élite estudiaban filosofía en Atenas. Las tasas de alfabetización son debatidas — quizás 15-20% en general, mucho más altas en las ciudades."},{n:"Éfeso",info:"La Biblioteca de Celso albergaba 12.000 rollos.",wiki:"La Biblioteca de Celso en Éfeso, construida ~117 d.C., albergaba 12.000 rollos. Su elegante fachada (restaurada) es una de las ruinas romanas más fotografiadas. Las bibliotecas eran símbolos de estatus para las ciudades de todo el imperio."},{n:"Atenas",info:"Los romanos de élite estudiaban filosofía aquí.",wiki:"Atenas permaneció como la capital intelectual. Jóvenes romanos de élite — Cicerón, Horacio, Bruto — estudiaban en la Academia, el Liceo y el Pórtico. Marco Aurelio dotó cuatro cátedras de filosofía (platónica, aristotélica, estoica, epicúrea) en 176 d.C."}],pathLabels:["Las bibliotecas se extienden por el imperio","La juventud de élite estudia en Atenas"]},
"dlf6":{name:"Termas Romanas y Vida Social",desc:"Más de 900 baños en la Roma del siglo IV: centro social para ejercicio, negocios, cotilleo y relax.",facts:["Más de 900 baños en Roma del s. IV","Termas de Diocleciano: 3.000 bañistas","Godos cortaron los acueductos en 537"],locs:[{n:"Roma",info:"Termas de Diocleciano: mayores termas, 3.000 bañistas.",wiki:"En el siglo IV, Roma tenía más de 900 baños desde pequeños balnea de barrio hasta enormes termas imperiales. Las Termas de Diocleciano (completadas en 306 d.C.) acomodaban a 3.000 bañistas simultáneamente. Una visita típica seguía un circuito: desvestirse en el apodyterium, ejercitarse en la palestra, sudar en el laconicum (sauna), bañarse en el caldarium (caliente), tepidarium (tibio) y frigidarium (frío). La entrada era barata — a veces gratis. Las termas eran donde los romanos socializaban, hacían negocios y mostraban estatus. Funcionaron hasta que los godos cortaron los acueductos de Roma en 537."},{n:"Bath",info:"Aquae Sulis — aguas termales sagradas en Britania.",wiki:"Bath actual, Inglaterra. Aguas termales naturales dedicadas a la diosa Sulis Minerva. El complejo romano incluía un templo, suite de baños y manantial sagrado que producía 1,2 millones de litros de agua a 46°C diarios. La cabeza de bronce dorada de Minerva y miles de tablillas de maldición arrojadas al manantial sobreviven."}],pathLabels:["La cultura del baño llega a las fronteras"]},
"dlf7":{name:"Esclavitud en la Vida Diaria",desc:"Uno de cada tres en Italia era esclavo: de esclavos de minas que vivían meses a tutores griegos que dirigían hogares.",facts:["1 de cada 3 en Italia esclavizados","10.000/día en Delos","Libertos podían ser más ricos que senadores"],locs:[{n:"Roma",info:"2-3 millones de esclavos solo en Italia.",wiki:"La esclavitud era fundamental para la sociedad romana. Los hogares ricos tenían cientos de esclavos sirviendo como cocineros, limpiadores, tutores, secretarios, médicos y animadores. Los esclavos urbanos podían acumular un peculium (fondo personal) y comprar la libertad. Los esclavos liberados (liberti) podían hacerse ricos — algunos más ricos que senadores. Pero las condiciones variaban enormemente: los esclavos de las minas de Laurión o Carthago Nova rara vez sobrevivían más de unos meses."},{n:"Delos",info:"Mayor mercado de esclavos — 10.000 vendidos por día en su apogeo.",wiki:"La isla de Delos era el mayor mercado de esclavos del Mediterráneo. En su apogeo en los siglos II-I a.C., las fuentes antiguas afirman que 10.000 esclavos podían comprarse y venderse en un solo día. Los esclavos procedían de la guerra, la piratería, la deuda y la cría."},{n:"Laurión",info:"Minas de plata trabajadas por decenas de miles de esclavos.",wiki:"Las minas de plata de Laurión en Ática empleaban hasta 30.000 esclavos en condiciones horribles. Alturas de túnel de solo 1 metro. Condiciones similares existían en las minas españolas. La esperanza de vida en las minas se medía en meses."}],pathLabels:["Comercio de esclavos de Delos a Roma","Esclavos enviados a las minas"]},
"dlf8":{name:"Matrimonio y Familia Romanos",desc:"Patria potestas: poder absoluto del padre sobre vida y muerte. Confarreatio, dote, divorcio fácil.",facts:["Patria potestas: poder absoluto del padre","Augusto penalizó a los solteros","Divorcio fácil en la República tardía"],locs:[{n:"Roma",info:"La familia (familia) era la unidad básica de la sociedad romana.",wiki:"El paterfamilias romano tenía patria potestas — poder legal absoluto sobre sus hijos, incluyendo (en teoría) el derecho de vida y muerte. Las formas de matrimonio iban desde la elaborada confarreatio (ceremonia de compartir pan para patricios, presidida por el Pontífice Máximo) hasta el informal usus (convivencia durante un año). La dote (dos) pasaba de la familia de la novia al marido. A finales de la República, el divorcio era fácil y frecuente — cualquiera de las partes podía iniciarlo. La legislación moral de Augusto (Lex Julia, 18 a.C.) intentó fomentar el matrimonio y la procreación con penas para los solteros y recompensas para las familias numerosas."}]},
"dlf9":{name:"Gladiadores y la Arena",desc:"Murmillo, retiario, secutor: luchadores entrenados, no solo muerte. Muchos sobrevivieron largas carreras.",facts:["La mayoría de combates no eran a muerte","Tipos murmillo, retiario, secutor","Prohibidos 404 d.C. por Honorio"],locs:[{n:"Roma",info:"Coliseo: 50.000 espectadores para combate gladiatorio.",wiki:"El combate gladiatorio comenzó como ritos funerarios en 264 a.C. y creció hasta convertirse en una enorme industria del entretenimiento. Los gladiadores se entrenaban en tipos especializados: el murmillo (infantería pesada con casco de cresta de pez), retiario (red y tridente), secutor (perseguidor), tracio (espada curva). El entrenamiento tenía lugar en ludi (escuelas) bajo un lanista. Contrariamente a la creencia popular, la mayoría de las peleas no eran a muerte — los gladiadores entrenados eran inversiones costosas. Las lápidas muestran luchadores con carreras de más de 30 combates. Algunos se convirtieron en celebridades con seguidores. Los juegos fueron prohibidos por Honorio en 404 d.C."},{n:"Pompeya",info:"Anfiteatro: anfiteatro de piedra superviviente más antiguo (70 a.C.).",wiki:"El anfiteatro de Pompeya, construido ~70 a.C., es el anfiteatro de piedra superviviente más antiguo conocido. Los grafitis nombran a luchadores populares y sus récords. Los barracones cercanos albergaban gladiadores — se encontraron 63 esqueletos, incluyendo una mujer ricamente enjoyada."},{n:"Capua",info:"Mayor escuela de gladiadores — donde entrenó Espartaco.",wiki:"Capua era la sede de la escuela de gladiadores más famosa. Espartaco escapó del ludus de Lentulo Batiato aquí en 73 a.C. con 70 compañeros gladiadores, desencadenando la mayor revuelta de esclavos de la historia romana."}],pathLabels:["La cultura gladiatoria se extiende de Campania a Roma","Combate gladiatorio por todo el imperio"]},
"dlf11":{name:"Niños Romanos e Infancia",desc:"Amuleto bulla, día del nombre, 50% mortalidad infantil: la infancia era breve y peligrosa.",facts:["~50% mortalidad infantil antes de los 10 años","Amuleto bulla hasta la mayoría de edad","Niñas casadas a 12-14, niños a 14-16"],locs:[{n:"Roma",info:"La vida de los niños gobernada por ritual estricto y alta mortalidad.",wiki:"La infancia romana estaba moldeada por la alta mortalidad — aproximadamente el 50% de los niños morían antes de los 10 años. Un recién nacido se colocaba a los pies del padre; si lo levantaba (tollere), vivía. El abandono de bebés no deseados era legal. El dies lustricus (día del nombre, 8º día para niñas, 9º para niños) marcaba la aceptación social. Los niños llevaban la bulla — un amuleto de oro o cuero contra espíritus malignos. Los niños asumían la toga virilis a los 14-16 años, marcando la mayoría de edad. Las niñas típicamente se casaban a los 12-14. A pesar de la brevedad, la evidencia arqueológica muestra que los niños jugaban con muñecas, carros de juguete y animales de compañía."},{n:"Pompeya",info:"Juguetes infantiles y grafitis preservados aquí.",wiki:"Pompeya ha producido conmovedora evidencia de la infancia: una cuna infantil, campanas de bronce, fichas de mármol para juegos y grafitis de niños aprendiendo a escribir. Un garabato dice \"Cayo estuvo aquí\" — la versión infantil del impulso universal de dejar una marca. Los moldes de yeso incluyen niños atrapados en la erupción."}]},
"dlf12":{name:"Muerte y Prácticas Funerarias",desc:"Cremación dio paso a inhumación: procesiones fúnebres, máscaras de ancestros, catacumbas, tumbas en la Vía Apia.",facts:["Cremación (República) a inhumación (Imperio)","Máscaras de ancestros en procesiones fúnebres","600 km de catacumbas, 6 millones de enterramientos"],locs:[{n:"Roma/Vía Apia",info:"Bordeada de tumbas durante kilómetros fuera de las murallas.",wiki:"La ley romana prohibía el entierro dentro de las murallas de la ciudad, así que las tumbas bordeaban los caminos fuera — más famosamente la Vía Apia. Los romanos republicanos y del Imperio temprano practicaban la cremación; las cenizas se colocaban en urnas en columbarios (tumbas de nichos). Desde el siglo II d.C., la inhumación en sarcófagos se volvió dominante. Los funerales aristocráticos incluían plañideras profesionales, músicos y actores llevando máscaras de ancestros (imagines) — creando una procesión de toda la historia familiar. Las catacumbas cristianas bajo Roma contienen más de 6 millones de entierros en 600 km de túneles."},{n:"Roma/Catacumbas",info:"Catacumbas cristianas: 600 km de túneles, 6 millones de entierros.",wiki:"Las catacumbas de Roma son vastos cementerios subterráneos, mayormente cristianos, que datan de los siglos II-V d.C. Se han descubierto más de 40 catacumbas. La Catacumba de San Calixto sola albergó a 16 papas. Las pinturas murales representan escenas bíblicas y símbolos cristianos tempranos. Contrariamente a la creencia popular, las catacumbas no eran escondites durante las persecuciones — las autoridades las conocían."}]},
"dlf13":{name:"Juegos y Ocio Romanos",desc:"Dados, juegos de mesa, juegos de pelota, apuestas: baños como centros de entretenimiento.",facts:["135 días festivos públicos/año en el s. IV","Ludus latrunculorum: ajedrez romano","Juego ilegal pero universalmente practicado"],locs:[{n:"Roma",info:"El juego era técnicamente ilegal pero universal.",wiki:"Los romanos eran apasionados por los juegos y el ocio. Los dados (tesserae) y astrágalos (tali) estaban por todas partes — el juego era técnicamente ilegal pero universalmente practicado. Los juegos de mesa incluían ludus latrunculorum (estrategia, similar al ajedrez), tabula (como backgammon) y ludus duodecim scriptorum (juego de doce líneas). Los juegos de pelota (trigon — pase entre tres jugadores, harpastum — juego violento similar al rugby) se jugaban en palestras. Las termas servían como complejos de entretenimiento con jardines, bibliotecas, salas de conferencias y bares. En los días festivos públicos — que sumaban 135 días al año en el siglo IV — el Estado proporcionaba carreras de carros, juegos gladiatorios y teatro."},{n:"Pompeya",info:"Tableros de juego rayados en calles y mostradores de tabernas.",wiki:"Pompeya preserva tableros de juego rayados en pavimento, mostradores de tabernas y escalones del foro. Dados, fichas de juego y grafitis de tableros aparecen por toda la ciudad. Un grafito dice: \"Gané 855 sestercios sin hacer trampa\" — probablemente una mentira."}]},
"dlf14":{name:"Crimen y Castigo Romanos",desc:"Vigiles como policía antiincendios, crucifixión, exilio, damnatio ad bestias: sin prisiones; castigo inmediato.",facts:["Vigiles: brigada antiincendios de 7.000 y vigilancia nocturna","Sin prisiones a largo plazo — castigo inmediato","Crucifixión solo para esclavos y no ciudadanos"],locs:[{n:"Roma",info:"Los vigiles patrullaban las calles por la noche.",wiki:"Roma no tuvo fuerza policial hasta que Augusto creó los vigiles (7.000 libertos) en 6 d.C. — principalmente una brigada de bomberos que también manejaba el desorden nocturno. La seguridad diurna correspondía a las cohortes urbanas. La ley penal romana era clasista: los honestiores (clases altas) enfrentaban exilio o multas; los humiliores (clases bajas) enfrentaban ejecución, trabajo forzado en minas o condena a las fieras (damnatio ad bestias). La crucifixión estaba reservada para esclavos y no ciudadanos. Roma no tenía prisiones a largo plazo — el Tullianum (Prisión Mamertina) era una celda de retención para ejecución. El castigo era público, ejemplar e inmediato."}]},
"dlf15":{name:"Libertos y Movilidad Social",desc:"Manumisión, exceso de Trimalción, libertos imperiales dirigiendo la burocracia: movilidad social en sociedad esclavista.",facts:["Manumisión: esclavos podían comprar o ganar libertad","Libertos dirigían la burocracia imperial","Sus hijos podían entrar al Senado"],locs:[{n:"Roma",info:"Los libertos fueron cruciales para la vida económica y política romana.",wiki:"La esclavitud romana se caracterizaba únicamente por la manumisión — la liberación de esclavos era común, esperada y legalmente formalizada. Los esclavos liberados (liberti) se convertían en ciudadanos romanos (con algunas restricciones). Algunos acumularon riqueza extraordinaria: el ficticio Trimalción de Petronio simbolizaba el liberto nuevo rico. Libertos reales como Narciso y Palas — secretarios de Claudio — estaban entre las personas más ricas del imperio y efectivamente dirigían la burocracia imperial. Sus hijos no tenían restricciones y podían entrar en el Senado. El sistema romano creó una notable movilidad social dentro de una sociedad fundamentalmente jerárquica."},{n:"Pompeya",info:"Tumbas y negocios de libertos prominentes aquí.",wiki:"La evidencia de libertos en Pompeya es rica: la Tumba de los Augustales (sacerdotes libertos del culto imperial), la Casa de los Vettii (hermanos libertos ricos con frescos lujosos) y numerosas tiendas y panaderías dirigidas por liberti. Eumachia, sacerdotisa descendiente de libertos, construyó el mayor edificio del Foro."}]},
"dlf10":{name:"Viajes y el Cursus Publicus",desc:"Sistema postal imperial, mansiones cada 40 km, y el mapa de calzadas Tabula Peutingeriana.",facts:["Cursus publicus: 80 km/día por mensajero","Mansiones cada 40 km","Tabula Peutingeriana: mapa de calzadas romanas"],locs:[{n:"Roma",info:"Todos los caminos llevaban aquí — 90.000 km de calzadas.",wiki:"La red de caminos romanos totalizaba ~400.000 km, con ~90.000 km de calzadas pavimentadas. Augusto estableció el cursus publicus — un sistema postal y de transporte imperial con estaciones de relevo (mutationes) cada 15-25 km para cambio de caballos y mansiones (paradas de descanso con alojamiento) cada 40 km. Un mensajero podía cubrir 80 km/día; despachos urgentes hasta 250 km/día usando relevos. Los civiles viajaban a pie, en carro, litera o barco. El viaje por mar era más rápido pero estacional — Mare Clausum (mar cerrado) de noviembre a marzo."},{n:"Ostia",info:"Puerto de Roma — puerta al viaje marítimo.",wiki:"La mayor parte del viaje de larga distancia era por barco. Roma a Alejandría tomaba 10-14 días con vientos favorables. Ostia y Portus eran los principales puntos de embarque. La Tabula Peutingeriana — una copia medieval de un mapa de caminos romano — muestra toda la red con distancias y paradas de descanso, extendiéndose desde Britania hasta India."}],pathLabels:["Caminos y rutas marítimas conectan el imperio"]},
"exp16":{name:"Conquista de la Galia",desc:"Campaña de 8 años de César: 1 millón de muertos, 1 millón esclavizados, 800 ciudades tomadas. La Galia se convirtió en la provincia occidental más rica de Roma.",facts:["1 millón de galos muertos, 1 millón esclavizados","800 ciudades tomadas en 8 años","Vercingetórix estrangulado tras el triunfo de César"],locs:[{n:"Bibracte",info:"58 a.C.: César derrotó aquí a los helvecios.",wiki:"Primera gran batalla de César en la Galia (58 a.C.). Los helvecios — 368.000 personas migrando hacia el oeste — fueron interceptados y derrotados cerca del oppidum de Bibracte, capital de los eduos. César había entrado en la Galia con seis legiones, aparentemente para proteger a los aliados romanos. No se iría durante ocho años."},{n:"Alesia",info:"52 a.C.: asedio decisivo que terminó la resistencia gala.",wiki:"Vercingétorix unió a las tribus galas y derrotó a César en Gergovia, pero luego fue atrapado en Alesia con 80.000 guerreros. César construyó 18 km de muros de asedio hacia dentro Y 21 km hacia fuera contra el ejército de socorro de 250.000 hombres. Derrotó a ambos. Vercingétorix se rindió personalmente. Fue mantenido en una mazmorra romana seis años, paseado en el triunfo de César, luego estrangulado."},{n:"Gergovia",info:"52 a.C.: única derrota de César en la Galia.",wiki:"Vercingétorix derrotó a César en Gergovia — su única pérdida en la campaña gala. 700 romanos murieron en un asalto fallido a la fortaleza en la cima de la colina. La derrota impulsó a la mayor parte de la Galia a unirse a la revuelta."}],pathLabels:["Las campañas de César por la Galia","De la derrota en Gergovia a la victoria en Alesia"]},
"exp17":{name:"Conquista de África",desc:"De la destrucción de Cartago a la Guerra Africana de César: África Proconsular se convirtió en el granero de Roma.",facts:["Cartago ardió 17 días (146 a.C.)","César refundó Cartago (44 a.C.)","África producía un tercio del grano de Roma"],locs:[{n:"Cartago",info:"146 a.C.: destruida. Más tarde refundada por César.",wiki:"En el 146 a.C., Escipión Emiliano destruyó Cartago tras un asedio de tres años. La ciudad ardió durante 17 días. La población fue vendida como esclavos. El sitio fue simbólicamente arado con sal (aunque esto es probablemente leyenda). Un siglo después, Julio César la refundó como Colonia Julia Cartago (44 a.C.), y Augusto completó el proyecto. La ciudad renacida se convirtió en la cuarta más grande del Imperio Romano."},{n:"Tapsos",info:"46 a.C.: César aplastó la resistencia pompeyana en África.",wiki:"En Tapsos, César derrotó a las fuerzas combinadas de Metelo Escipión, Juba I de Numidia y los últimos irreductibles pompeyanos. La victoria dio a Roma control completo del norte de África. Catón se suicidó en Útica antes que someterse a César."},{n:"Útica",info:"Catón el Joven se suicidó aquí, 46 a.C.",wiki:"Tras la victoria de César en Tapsos, Catón — el defensor más principista de la República — leyó el Fedón de Platón sobre la inmortalidad del alma, luego se apuñaló. Cuando los médicos cosieron su herida, la abrió con sus propias manos. Su muerte lo convirtió en el símbolo definitivo de la virtud republicana."}],pathLabels:["Campaña africana de César","Última resistencia de Catón en Útica"]},
"exp18":{name:"Legado de Pérgamo y Asia Menor",desc:"Átalo III legó su reino a Roma: la provincia más rica de Oriente. Siguieron escándalos de recaudación de impuestos.",facts:["Átalo III legó su reino a Roma","80.000 itálicos masacrados en 88 a.C.","La provincia más rica del Oriente romano"],locs:[{n:"Pérgamo",info:"Capital del reino atálida, legada en el 133 a.C.",wiki:"El rey Átalo III de Pérgamo murió sin herederos legítimos en el 133 a.C. y legó todo su reino al pueblo romano. El legado incluía el oeste de Asia Menor — una de las regiones más ricas del mundo antiguo. Los intentos de Roma de reclamarlo provocaron la revuelta de Aristónico (132-129 a.C.), pero la provincia de Asia fue finalmente organizada y se convirtió en el territorio más rico del imperio."},{n:"Éfeso",info:"Se convirtió en capital de la provincia de Asia.",wiki:"Éfeso reemplazó a Pérgamo como capital provincial. Creció hasta 250.000 personas — la ciudad más grande de Asia Menor. El arrendamiento de impuestos romanos (publicani) exprimió la provincia sin piedad, ayudando a provocar la masacre de Mitrídates de 80.000 italianos en el 88 a.C. La riqueza de la provincia financió las guerras de la República tardía de Roma."}],pathLabels:["Pérgamo legada, Éfeso se convierte en capital"]},
"exp19":{name:"Conquista de Dacia",desc:"Dos campañas de Trajano: 165 toneladas de oro capturadas. Dacia se convirtió en la única provincia de habla latina más allá del Danubio.",facts:["165 toneladas de oro, 331 toneladas de plata capturadas","El rumano desciende del latín dacio","La Columna de Trajano representa toda la campaña"],locs:[{n:"Sarmizegetusa",info:"Capital dacia — cayó en el 106 d.C.",wiki:"Sarmizegetusa Regia era la capital montañesa del rey Decébalo. Trajano la capturó en la Primera Guerra Dacia (101-102), pero Decébalo rompió la paz. En la Segunda Guerra (105-106), Trajano regresó, capturó la capital de nuevo y encontró el tesoro real — 165 toneladas de oro y 331 de plata — oculto bajo un río desviado. Decébalo se suicidó. Dacia fue colonizada con colonos de todo el imperio y se convirtió en la única provincia más allá del Danubio donde el latín echó raíces — el rumano moderno desciende del latín dacio."},{n:"Puente de Drobeta",info:"Obra maestra de Apolodoro: el puente de arcos más largo durante 1.000 años.",wiki:"Para cruzar el Danubio, Trajano encargó a Apolodoro de Damasco construir un puente en Drobeta. Tenía 1.135 metros de largo con 20 pilares — el puente de arcos más largo del mundo durante más de un milenio. Adriano lo desmanteló después para impedir el cruce bárbaro."}],pathLabels:["Trajano cruza el Danubio para conquistar Dacia"]},
"exp20":{name:"Conquista de Arabia",desc:"Trajano anexionó el reino nabateo: Petra se convirtió en ciudad romana. Arabia Pétrea conectó el comercio del Mar Rojo con el imperio.",facts:["Anexionada pacíficamente en 106 d.C.","Petra: el Tesoro tallado en arenisca","Via Nova Traiana conectó el comercio del Mar Rojo"],locs:[{n:"Petra",info:"Capital nabatea — anexionada pacíficamente en el 106 d.C.",wiki:"El reino nabateo, centrado en la ciudad excavada en roca de Petra, fue anexionado por Trajano en el 106 d.C. — aparentemente de forma pacífica, ya que el último rey Rabel II había muerto. El famoso Tesoro (Al-Khazneh) de Petra, tallado en arenisca, ya tenía siglos. Los romanos construyeron una calle columnada, termas y teatro. La provincia de Arabia Pétrea conectó la ruta comercial del Mar Rojo con la red comercial romana más amplia."},{n:"Bosra",info:"Capital provincial de Arabia Pétrea.",wiki:"Bosra (Bostra) reemplazó a Petra como capital provincial. Trajano construyó una Via Nova Traiana — calzada romana desde Bosra hasta Aila (Áqaba) en el Mar Rojo, facilitando el comercio. El teatro romano del siglo II bien conservado de la ciudad tiene capacidad para 15.000. Bosra se convirtió más tarde en importante centro cristiano primitivo."}],pathLabels:["El reino nabateo se convierte en la Arabia romana","Arabia conectada a la red comercial romana"]},
"cam19":{name:"Batalla de Zama",desc:"Escipión derrotó a Aníbal en suelo africano: la caballería decidió la batalla. Fin de la Segunda Guerra Púnica.",facts:["Escipión usó las tácticas de Aníbal contra él","80 elefantes de guerra neutralizados","Cartago fue despojada de su imperio"],locs:[{n:"Zama",info:"202 a.C.: Escipión Africano derrotó a Aníbal.",wiki:"En Zama, Escipión volvió las propias tácticas de Aníbal contra él. La caballería numidia bajo Masinisa alejó a los jinetes de Aníbal, mientras la infantería romana absorbió la carga de 80 elefantes de guerra abriendo pasillos en su formación. Cuando la caballería regresó, golpeó la retaguardia de Aníbal — exactamente como Aníbal había hecho en Cannas. 20.000 cartagineses muertos, 20.000 capturados. Aníbal, invicto durante 15 años, huyó. Cartago se rindió."},{n:"Cartago",info:"Cartago aceptó términos de paz humillantes.",wiki:"El Tratado de Zama despojó a Cartago de su imperio, flota (reducida a 10 naves) e independencia militar. Cartago pagó 10.000 talentos de plata durante 50 años. Roma se convirtió en la potencia indiscutida del Mediterráneo occidental."}],pathLabels:["De Zama a la rendición de Cartago"]},
"cam20":{name:"Batalla del Lago Trasimeno",desc:"La mayor emboscada de Aníbal: 15.000 romanos muertos en horas. La emboscada más grande de la historia militar.",facts:["15.000 muertos en 3 horas","La emboscada más grande de la historia militar","Fabio nombrado dictador"],locs:[{n:"Lago Trasimeno",info:"217 a.C.: Aníbal emboscó al cónsul Flaminio.",wiki:"En una mañana neblinosa de junio del 217 a.C., Aníbal ocultó todo su ejército — 50.000 hombres — en colinas a lo largo de la orilla norte del lago Trasimeno. El cónsul Cayo Flaminio marchó sus 25.000 tropas por la estrecha carretera de la orilla sin explorar por delante. Aníbal tendió la trampa: los cartagineses bajaron por tres lados mientras el lago bloqueaba la retirada. 15.000 romanos murieron en tres horas — muchos ahogados. Flaminio murió. Sigue siendo la mayor emboscada de la historia militar registrada."},{n:"Roma",info:"Pánico en Roma — Fabio Máximo nombrado dictador.",wiki:"Las noticias de Trasimeno causaron pánico en Roma. El Senado nombró a Fabio Máximo dictador. Adoptó una estrategia de retraso y desgaste — 'el Cunctator' (el Retrasador) — siguiendo al ejército de Aníbal pero negándose a combatir. Fue profundamente impopular pero finalmente acertada."}],pathLabels:["Las noticias del desastre llegan a Roma"]},
"cam21":{name:"Guerras Samnitas",desc:"Tres guerras por el control del centro de Italia: la humillación de las Horcas Caudinas. Roma aprendió la guerra de montaña.",facts:["Horcas Caudinas: 'pasar bajo el yugo'","Decio Mus se consagró a la muerte en Sentino","Vía Apia construida para la logística de la guerra samnita"],locs:[{n:"Caudium",info:"321 a.C.: ejército romano humillado en las Horcas Caudinas.",wiki:"En el 321 a.C., un ejército romano fue atrapado en un estrecho paso montañoso (las Horcas Caudinas) por los samnitas. Incapaz de combatir o retirarse, todo el ejército fue forzado a 'pasar bajo el yugo' — humillación ritual donde los soldados caminaban bajo un armazón de lanzas. Fue la derrota más vergonzosa de Roma antes de Cannas. El incidente moldeó la doctrina militar romana: nunca más marcharían ciegamente a terreno confinado."},{n:"Sentinum",info:"295 a.C.: batalla decisiva de la Tercera Guerra Samnita.",wiki:"En Sentinum, Roma enfrentó una coalición de samnitas, galos, etruscos y umbrios — la mayor alianza jamás reunida contra ella. El cónsul Decio Mus se consagró ritualmente a la muerte (devotio), cargando contra el enemigo para inspirar a sus tropas. Roma ganó, rompiendo la coalición. Fue la mayor batalla en Italia hasta la Guerra Social."},{n:"Roma",info:"Tres guerras (343-290 a.C.) forjaron la identidad militar de Roma.",wiki:"Las tres guerras samnitas transformaron a Roma de potencia regional italiana en la fuerza dominante de la península. Roma aprendió guerra de montaña, construyó colonias estratégicas (Luceria, Venusia, Benevento) y extendió su red de calzadas. La Vía Apia se inició en el 312 a.C. para apoyar la logística militar durante la Segunda Guerra Samnita."}],pathLabels:["El ejército romano marcha a Caudium","Tres guerras por el centro de Italia"]},
"cam22":{name:"Guerras Romano-Sasánidas",desc:"400 años de conflicto con Persia: Valeriano capturado, Juliano muerto. El rival más peligroso y duradero de Roma.",facts:["Valeriano: único emperador capturado vivo","Juliano muerto retirándose de Ctesifonte (363)","Primera guerra química conocida en Dura-Europos"],locs:[{n:"Ctesifonte",info:"Capital sasánida — saqueada por Roma tres veces.",wiki:"Ctesifonte, la capital sasánida en el Tigris, fue capturada por Roma tres veces (165, 197, 283 d.C.) pero nunca retenida. La frontera romano-persa a lo largo del Éufrates fue la zona de conflicto de mayor duración del mundo antiguo. En el 363, el emperador Juliano invadió con 65.000 hombres, llegó a Ctesifonte, pero no logró tomarla y murió durante la retirada — el último emperador pagano muriendo en Mesopotamia."},{n:"Edesa",info:"260 d.C.: Emperador Valeriano capturado — peor humillación romana.",wiki:"En el 260 d.C., el emperador Valeriano fue capturado vivo por Sapor I en Edesa — el único emperador romano jamás hecho prisionero. Los relieves rupestres persas muestran a Valeriano arrodillado ante Sapor. Según fuentes hostiles, Valeriano fue usado como reposapiés humano y eventualmente desollado — su piel rellenada exhibida en un templo persa."},{n:"Dura Europos",info:"Fortaleza fronteriza destruida por los sasánidas c. 257 d.C.",wiki:"Dura Europos — guarnición fronteriza romana en el Éufrates — cayó ante los sasánidas hacia el 257 d.C. Los túneles de asedio y contratúneles sobreviven, incluyendo evidencia de la guerra química más antigua conocida: los sasánidas quemaron azufre y betún para gasear a los defensores romanos en un túnel."}],pathLabels:["Campañas romanas en Mesopotamia","La frontera del Éufrates"]},
"cam23":{name:"Asedio de Veyes",desc:"El primer gran asedio de Roma: 10 años como Troya. Camilo desvió un túnel de drenaje. Roma duplicó su territorio.",facts:["Asedio de 10 años, comparado con Troya","Los romanos entraron por túneles de drenaje","Roma duplicó su territorio de la noche a la mañana"],locs:[{n:"Veyes",info:"Ciudad etrusca a 16 km de Roma — cayó en el 396 a.C.",wiki:"Veyes era el rival etrusco más cercano de Roma, a solo 16 km al norte. El asedio duró 10 años (los antiguos lo compararon con Troya). El avance llegó cuando Camilo descubrió el sistema de túneles de drenaje etrusco — soldados romanos entraron por los túneles y emergieron dentro del Templo de Juno. La ciudad fue capturada, su población esclavizada y su territorio anexionado. Roma duplicó su tamaño de la noche a la mañana."},{n:"Roma",info:"La caída de Veyes hizo a Roma la potencia dominante en el Lacio.",wiki:"La conquista de Veyes en el 396 a.C. transformó a Roma de una ciudad entre muchas en la potencia dominante de Italia central. El territorio anexionado fue distribuido a ciudadanos romanos — se crearon cuatro nuevas tribus. Camilo fue aclamado como un segundo Rómulo. Seis años después, los galos saquearon Roma; Camilo regresó para expulsarlos."}],pathLabels:["Asedio de 10 años de Veyes"]},
"fig16":{name:"Domiciano",desc:"Administrador capaz odiado por el Senado: expandió la frontera, el primero en exigir 'Dominus et Deus'. Asesinado.",facts:["Exigió 'Dominus et Deus'","Damnatio memoriae por el Senado","Estabilizó y expandió la frontera"],locs:[{n:"Roma",info:"Emperador 81-96 d.C. Último de los Flavios.",wiki:"Tito Flavio Domiciano se convirtió en emperador en el 81 d.C. tras la muerte de su hermano Tito. Gobernante capaz pero autocrático, expandió el imperio en Britania y Alemania, reformó la moneda y administró justicia eficientemente. Pero exigía ser llamado 'Dominus et Deus' (Señor y Dios) — impactando a senadores acostumbrados a la ficción de primero entre iguales. Su Reinado del Terror en sus últimos años vio senadores ejecutados por cargos endebles. Fue asesinado en el 96 d.C. por oficiales del palacio. El Senado condenó su memoria (damnatio memoriae) — su nombre cincelado de monumentos."},{n:"Frontera del Danubio",info:"Domiciano combatió campañas en el Danubio.",wiki:"Domiciano campañeó contra los dacios y los catos germánicos, fortaleciendo la frontera Rin-Danubio con fortificaciones permanentes. Sus guerras dacias fueron inconclusas — acordó pagar subsidios a Decébalo a cambio de paz, lo que Trajano encontró humillante y revirtió después."}]},
"fig17":{name:"Cómodo",desc:"El hijo indigno de Marco Aurelio: luchó como gladiador, renombró Roma 'Colonia Commodiana'. Estrangulado en Nochevieja.",facts:["Luchó como gladiador en el Coliseo","Renombró Roma en su honor","Gibbon fechó la decadencia de Roma desde su reinado"],locs:[{n:"Roma",info:"Emperador 180-192 d.C. El principio del fin.",wiki:"Lucio Aurelio Cómodo era todo lo que su padre filósofo no era: vanidoso, cruel y cada vez más trastornado. Abandonó las campañas danubianas de Marco Aurelio, negoció una paz que cedió territorio romano y se dedicó a la arena — luchando como gladiador (como secutor y también disparando a animales), lo que horrorizó al Senado. Renombró Roma 'Colonia Lucia Annia Commodiana,' los meses con su nombre, y se identificó como Hércules encarnado. Una conspiración de su amante Marcia, el prefecto Leto y el luchador Narciso lo estrangularon el 31 de diciembre del 192 d.C. Edward Gibbon fechó la decadencia de Roma desde su acceso."}]},
"fig18":{name:"Septimio Severo",desc:"Primer emperador africano: fundó una dinastía. Murió en York durante una campaña en Britania. 'Sed armoniosos, enriqueced a los soldados.'",facts:["Primer emperador africano","'Sed armoniosos, enriqueced a los soldados'","Caracalla asesinó a Geta en menos de un año"],locs:[{n:"Leptis Magna",info:"Nacido aquí — prodigó proyectos de construcción en su ciudad natal.",wiki:"Lucio Septimio Severo nació en Leptis Magna, Libia — el primer emperador romano de África. Ganó el Año de los Cinco Emperadores (193 d.C.), derrotando a Níger y Albino. Expandió el imperio en Mesopotamia, reformó el ejército (subiendo la paga 50%) y prodigó su ciudad natal con un magnífico foro, basílica y arco triunfal que sobreviven hoy."},{n:"Roma",info:"Emperador 193-211 d.C. Fundó la dinastía Severa.",wiki:"Severo gobernó con eficiencia férrea. Expandió la Guardia Pretoriana a 15.000 (reemplazando soldados italianos por provinciales), creó tres nuevas legiones y purgó el Senado. Su Arco de Septimio Severo sigue dominando el Foro. Su dinastía duró hasta el 235 d.C."},{n:"Eboracum",info:"Murió aquí en el 211 d.C. campañeando contra los caledonios.",wiki:"Severo invadió Escocia en el 208 con una fuerza masiva, combatiendo una brutal guerra de guerrillas contra los caledonios. Murió en Eboracum (York) el 4 de febrero del 211 d.C. Su consejo de lecho de muerte a sus hijos Caracalla y Geta: 'Sed armoniosos, enriqueced a los soldados y despreciad a todos los demás hombres.' Ignoraron la primera instrucción — Caracalla asesinó a Geta en un año."}],pathLabels:["De Leptis Magna a emperador","Campaña final en Britania"]},
"fig19":{name:"Antonino Pío",desc:"El reinado más pacífico: 23 años sin salir de Italia. Construyó el Muro Antonino. Deificado por aclamación.",facts:["23 años sin salir de Italia","Última palabra: 'Ecuanimidad'","Reformó la ley para proteger a los esclavos"],locs:[{n:"Roma",info:"Emperador 138-161 d.C. El cenit pacífico.",wiki:"Tito Aurelio Fulvo Boionio Arrio Antonino fue adoptado por Adriano y se convirtió en emperador en el 138 d.C. Su reinado de 23 años fue el más pacífico de la historia romana — nunca dejó Italia, pero el imperio funcionó sin problemas. Ganó el cognomen 'Pío' por persuadir al Senado de deificar a Adriano (a quien odiaban). Expandió hacia el sur de Escocia (Muro Antonino), reformó el sistema legal para proteger esclavos y mejorar derechos de propiedad de mujeres, y murió en el 161 d.C. — supuestamente su última palabra fue 'Ecuanimidad.'"},{n:"Lanuvium",info:"Lugar de nacimiento de Antonino — actual Lanuvio.",wiki:"Nacido en Lanuvium en familia senatorial rica de Nemausus (Nimes) en la Galia. Sus orígenes provinciales muestran cuán completamente romanizadas estaban las provincias occidentales en el siglo II."}]},
"fig20":{name:"Teodosio I",desc:"Último emperador en gobernar ambas mitades: hizo del cristianismo la única religión estatal (380). Prohibió los Juegos Olímpicos. Dividió el imperio.",facts:["Edicto de Tesalónica: cristianismo = religión estatal","Prohibió los Juegos Olímpicos (393 d.C.)","Hizo penitencia pública ante el obispo Ambrosio"],locs:[{n:"Constantinopla",info:"Gobernó desde aquí. Último en gobernar un imperio unido.",wiki:"Teodosio I (el Grande) fue el último emperador en gobernar un Imperio Romano unido. Cristiano devoto, emitió el Edicto de Tesalónica (380 d.C.) haciendo del cristianismo niceno la única religión estatal. Prohibió sacrificios paganos, cerró templos y abolió los Juegos Olímpicos (abolición en 393 d.C., tras 1.168 años). Hizo penitencia ante Ambrosio de Milán por la masacre de Tesalónica — la primera vez que un emperador se sometió a la autoridad de un obispo."},{n:"Tesalónica",info:"380 d.C.: Edicto haciendo del cristianismo religión estatal. 390: masacre.",wiki:"Dos acontecimientos épicos en Tesalónica. En el 380, Teodosio emitió el Edicto de Tesalónica — el cristianismo se convirtió en la religión estatal oficial del Imperio Romano. En el 390, tras un motín que mató a un general gótico, Teodosio ordenó una masacre de represalia que mató a 7.000 civiles. El obispo Ambrosio de Milán le negó la comunión hasta que hizo penitencia pública — estableciendo el principio de que incluso los emperadores responden ante la autoridad moral."},{n:"Roma",info:"La muerte de Teodosio (395) dividió permanentemente el imperio.",wiki:"Cuando Teodosio murió el 17 de enero del 395 d.C., el imperio se dividió entre sus hijos jóvenes: Arcadio (Este) y Honorio (Oeste). Nunca se reunió."}],pathLabels:["Edicto de Tesalónica","El imperio se divide con la muerte de Teodosio"]},
"evt17":{name:"Secesión de la Plebe",desc:"Los plebeyos se retiraron al Monte Sacro, rechazando el servicio militar: obtuvieron la creación de los Tribunos. Primera huelga general de la historia.",facts:["Primera huelga general de la historia","Se crearon los Tribunos de la Plebe","Al menos 5 secesiones en 200 años"],locs:[{n:"Roma",info:"Patricios vs. plebeyos — comenzó el Conflicto de los Órdenes.",wiki:"En el 494 a.C., los ciudadanos comunes de Roma (plebeyos) — agobiados por deudas, negados derechos políticos y sujetos a la dura justicia patricia — se retiraron de la ciudad al Monte Sagrado (Mons Sacer), 3 millas al noreste de Roma. Se negaron a servir en el ejército o trabajar. Los patricios, incapaces de hacer la guerra o dirigir la economía sin ellos, fueron forzados a negociar. El resultado: la creación de los Tribunos de la Plebe — magistrados sacrosantos que podían vetar cualquier acción del estado. Fue la primera huelga general registrada del mundo y el comienzo del Conflicto de los Órdenes."},{n:"Monte Sagrado",info:"Mons Sacer — donde los plebeyos se retiraron.",wiki:"El Mons Sacer (Monte Sagrado), en la Vía Nomentana al noreste de Roma, fue donde los plebeyos acamparon durante su secesión. La tradición dice que Menenio Agripa los persuadió de regresar con su famosa fábula del vientre y las extremidades: todas las partes del cuerpo deben trabajar juntas. Hubo al menos cinco secesiones entre el 494 y el 287 a.C."}],pathLabels:["Los plebeyos se retiran al Monte Sagrado"]},
"evt18":{name:"Disturbios de Nika",desc:"La peor violencia urbana de Constantinopla: 30.000 muertos. Media ciudad ardió. El discurso de Teodora salvó el trono de Justiniano.",facts:["30.000 muertos en el Hipódromo","'El púrpura es el más noble sudario' — Teodora","Condujo a la reconstrucción de Santa Sofía"],locs:[{n:"Constantinopla/Hipódromo",info:"Enero del 532 d.C.: facciones de carreras unidas en revuelta.",wiki:"El 13 de enero del 532 d.C., las facciones de carreras de carros Azul y Verde — normalmente rivales amargas — se unieron contra el gobierno de Justiniano, coreando '¡Nika!' (¡Ganar!). Durante cinco días, los manifestantes quemaron Constantinopla: la Santa Sofía original, la Casa del Senado y gran parte del centro de la ciudad fueron destruidos. Los manifestantes coronaron a un emperador rival. Justiniano preparó la huida — pero la emperatriz Teodora se negó, declarando 'La púrpura es el sudario más noble.' El general Belisario atrapó a los manifestantes en el Hipódromo y masacró aproximadamente 30.000. Justiniano luego reconstruyó la ciudad, incluyendo la magnífica nueva Santa Sofía."}]},
"evt19":{name:"Proscripciones de los Triunviros",desc:"Octaviano, Antonio y Lépido publicaron listas de muerte: 300 senadores, 2.000 caballeros marcados. Cicerón asesinado.",facts:["300 senadores y 2.000 caballeros proscritos","La cabeza de Cicerón clavada en la Rostra","Fulvia perforó su lengua con una horquilla"],locs:[{n:"Roma",info:"43 a.C.: el reinado del terror del Segundo Triunvirato.",wiki:"El 27 de noviembre del 43 a.C., el Segundo Triunvirato (Octaviano, Antonio, Lépido) fue legalmente establecido con el poder de proscripción — el derecho a publicar listas de ciudadanos condenados a muerte sin juicio. Aproximadamente 300 senadores y 2.000 ecuestres fueron proscritos. Su propiedad fue confiscada para financiar la guerra contra los asesinos de César. Los hombres fueron cazados por las calles; las cabezas exhibidas en la Rostra."},{n:"Formia",info:"Cicerón fue asesinado aquí, 7 de diciembre del 43 a.C.",wiki:"Marco Tulio Cicerón — el mayor orador de Roma y la voz más elocuente de la República — fue asesinado por soldados de Antonio en su villa cerca de Formia el 7 de diciembre del 43 a.C. Había sido proscrito por insistencia personal de Antonio (Octaviano accedió, traicionando a su mentor). La cabeza y manos de Cicerón fueron clavadas en la Rostra del Foro — la tribuna donde había pronunciado sus mayores discursos. La esposa de Antonio Fulvia supuestamente atravesó su lengua con un alfiler."}],pathLabels:["Cicerón huye de Roma pero es capturado en Formia"]},
"evt20":{name:"El Rapto de las Sabinas",desc:"Leyenda fundacional: los colonos de Rómulo secuestraron a mujeres vecinas. Guerra, luego reconciliación. Las propias mujeres detuvieron la lucha.",facts:["Las mujeres sabinas detuvieron la batalla","Romanos y sabinos se fusionaron en un solo pueblo","Una de las escenas más representadas del arte occidental"],locs:[{n:"Roma",info:"Uno de los mitos fundacionales más famosos de Roma.",wiki:"Según la tradición romana, el nuevo asentamiento de Rómulo tenía muchos hombres pero pocas mujeres. Invitó a los sabinos vecinos a un festival, luego sus hombres raptaron a las mujeres solteras. Los sabinos regresaron con un ejército. Cuando la batalla estaba por comenzar, las mujeres sabinas — ahora esposas y madres — corrieron entre las líneas, suplicando a sus padres y esposos que pararan. Los dos pueblos se fusionaron, y el rey sabino Tito Tacio co-gobernó con Rómulo. La historia, representada por Giambologna, Poussin y David, se convirtió en uno de los temas más pintados del arte occidental."}]},
"evt21":{name:"Deposición de Rómulo Augústulo",desc:"Odoacro depuso al último emperador occidental: envió las insignias imperiales a Constantinopla. Fin tradicional del Imperio Romano de Occidente.",facts:["Rómulo Augústulo: nombre irónico para el último emperador","Perdonado: enviado a Campania con una pensión","El Imperio de Oriente continuó 977 años más"],locs:[{n:"Rávena",info:"4 de septiembre del 476 d.C.: el último emperador occidental depuesto.",wiki:"El 4 de septiembre del 476 d.C., el jefe germánico Odoacro depuso al emperador niño Rómulo Augústulo en Rávena. La ironía del nombre no pasó desapercibida a los contemporáneos: Rómulo (fundador de Roma) Augústulo (pequeño Augusto). Odoacro no lo mató — envió al niño a Campania con una pensión. Más significativamente, envió las insignias imperiales al emperador Zenón en Constantinopla, declarando que no había necesidad de un emperador occidental. El Imperio Romano de Occidente había terminado."},{n:"Constantinopla",info:"Zenón recibió las insignias imperiales — el Este continuó solo.",wiki:"El emperador Zenón en Constantinopla aceptó la situación, reconociendo técnicamente a Odoacro como su representante en Italia. El Imperio Romano de Oriente (Imperio Bizantino) continuaría otros 977 años, hasta que Constantinopla cayó ante los turcos otomanos en 1453."}],pathLabels:["Las insignias imperiales enviadas al Este — el Oeste ha terminado"]},
"eng16":{name:"Insulae Romanas (Bloques de Apartamentos)",desc:"Edificios de 5-7 pisos que albergaban a los pobres urbanos: trampas mortales propensas al fuego y derrumbe. 46.000 insulae vs. 1.800 domus en Roma.",facts:["46.000 insulae vs. 1.800 domus en Roma","Augusto limitó la altura a 21 metros","El fuego era un terror constante"],locs:[{n:"Roma",info:"46.000 bloques de apartamentos frente a 1.800 casas privadas.",wiki:"La gran mayoría de la población de más de un millón de Roma vivía en insulae — bloques de apartamentos de 5-7 pisos construidos con madera, ladrillo y hormigón. Un censo del siglo IV contó 46.602 insulae frente a solo 1.797 domus (casas privadas). Los pisos superiores eran los más baratos, calurosos y peligrosos. Augusto limitó la altura de los edificios a 70 pies (21 m) tras derrumbes; Trajano la redujo a 60 pies. El fuego era un terror constante — Roma no tenía bomberos, y los pisos superiores de madera ardían fácilmente."},{n:"Ostia",info:"Insulae mejor conservadas — aún en pie hasta 3-4 pisos.",wiki:"Las insulae de Ostia son las mejor conservadas del mundo romano — algunas aún se mantienen hasta 3-4 pisos. La Casa dei Dipinti y la Insula de las Bóvedas Pintadas muestran pequeños apartamentos con paredes al fresco, balcones y patios compartidos. Dan la mejor imagen de cómo vivían realmente los romanos ordinarios: apiñados, ruidosos, pero no sin dignidad."}]},
"eng17":{name:"Faros Romanos",desc:"La Torre de Hércules sigue en pie (UNESCO). El Faro de Dover guiaba el cruce del Canal. Los faros romanos servían a todo el imperio.",facts:["Torre de Hércules: 2.000 años de uso continuo","Único faro romano en funcionamiento","Faro de Dover: estructura romana más alta de Britania"],locs:[{n:"A Coruña/Torre de Hércules",info:"Único faro romano aún en funcionamiento — Patrimonio Mundial UNESCO.",wiki:"La Torre de Hércules en A Coruña, España es el único faro romano aún en operación. Construida a finales del siglo I d.C., mide 55 metros de altura y guiaba a las naves que se aproximaban al noroeste de la península ibérica. Renovada en el siglo XVIII, conserva su núcleo y cimientos romanos. Ha servido como faro durante casi 2.000 años — Patrimonio Mundial UNESCO desde 2009."},{n:"Dover",info:"El faro romano guiaba el cruce del Canal.",wiki:"El faro romano (pharos) en el Castillo de Dover es la estructura romana superviviente más alta de Britania — 19 metros del trabajo romano original aún permanecen. Guiaba a las naves que cruzaban el Canal de la Mancha desde Boulogne (Gesoriacum). Existía un faro gemelo en el lado francés. La pareja formaba un sistema de navegación para el crítico cruce del Canal."}],pathLabels:["Los faros romanos guiaban el Atlántico y el Canal"]},
"eng18":{name:"Grúas y Máquinas de Construcción Romanas",desc:"Polispasto, grúa de rueda, martinete: levantaban bloques de 6 toneladas. Vitruvio documentó la tecnología.",facts:["Grúas de rueda levantaban bloques de 6 toneladas","Vitruvio documentó los diseños de grúas","Piedras de Baalbek: 800 toneladas, método desconocido"],locs:[{n:"Roma",info:"Las grúas permitieron la arquitectura monumental de Roma.",wiki:"La tecnología de construcción romana era notablemente sofisticada. Vitruvio (De Architectura, Libro X) describió múltiples tipos de grúas: el trispastos (3 poleas, capacidad 150 kg), pentaspaston (5 poleas) y el enorme polyspaston. Las grúas de rueda de treadmill — accionadas por hombres caminando dentro de un gran tambor — podían levantar bloques de 6 toneladas con una tripulación de solo 4-5 hombres. Los romanos también desarrollaron martinetes para cimentación y sofisticados sistemas de andamios."},{n:"Baalbek",info:"Piedras del Trilithon: 800 toneladas cada una — ¿cómo las movieron?",wiki:"El Templo de Júpiter en Baalbek contiene el Trilithon — tres piedras que pesan aproximadamente 800 toneladas cada una, colocadas 7 metros sobre el suelo. Una cuarta piedra (la Piedra de la Mujer Embarazada, 1.000 toneladas) fue extraída pero nunca colocada. Cómo los romanos movieron estas piedras sigue debatiéndose — ninguna grúa romana conocida podía levantarlas. Puede que usaran planos inclinados, rodillos y miles de trabajadores."}]},
"eng19":{name:"Anfiteatros Romanos",desc:"Más de 230 anfiteatros en todo el imperio: El Djem, Arlés, Nimes, Pula. No solo el Coliseo.",facts:["Más de 230 anfiteatros construidos en el imperio","El Djem: tercero más grande, 35.000 asientos","Arlés: aún en uso tras 1.900 años"],locs:[{n:"El Djem",info:"Tercer anfiteatro más grande — capacidad 35.000. UNESCO.",wiki:"El Anfiteatro de El Djem (Thysdrus) en Túnez es el tercer anfiteatro romano más grande (tras el Coliseo y Capua), con capacidad para 35.000. Construido alrededor de 238 d.C., está notablemente bien conservado — la fachada completa de tres pisos sobrevive. Demuestra cuán profundamente penetró la cultura romana en el norte de África. Patrimonio Mundial UNESCO desde 1979."},{n:"Arlés",info:"Aún usado para corridas de toros — capacidad 20.000.",wiki:"El anfiteatro de Arlés (Arelate) en el sur de Francia tiene capacidad para 20.000 y aún se usa para eventos hoy. Construido alrededor de 90 d.C., sobrevivió la Edad Media al ser convertido en pueblo fortificado — más de 200 casas fueron construidas dentro. Las casas fueron despejadas en el siglo XIX, revelando la estructura romana subyacente."},{n:"Pula",info:"Anfiteatro mejor conservado del Adriático — capacidad 23.000.",wiki:"El anfiteatro de Pula en Croacia es la sexta arena romana superviviente más grande, con capacidad para 23.000. Construido bajo Augusto y ampliado bajo Vespasiano, conserva su muro exterior completo — cuatro pisos en el lado hacia el mar. Aún se usa para conciertos y festivales de cine."}],pathLabels:["Anfiteatros por todo el imperio","De la Galia al Adriático"]},
"eng20":{name:"Letrinas Públicas y Saneamiento Romano",desc:"Aseos comunales con 20-80 asientos: agua corriente por debajo. Esponja en un palo. Notablemente higiénico para la antigüedad.",facts:["144 letrinas públicas en la Roma del siglo IV","Tersorium: esponja en un palo para limpieza","Ir al aseo era una ocasión social"],locs:[{n:"Roma",info:"144 letrinas públicas en la Roma del siglo IV.",wiki:"Las letrinas públicas romanas (foricae) eran instalaciones comunales con asientos para 20-80 personas lado a lado en bancos de piedra o mármol con aberturas en forma de ojo de cerradura. El agua que fluía continuamente del sistema de acueductos corría bajo los asientos, llevando los desechos a las cloacas. Los usuarios se limpiaban con un tersorium — una esponja de mar en un palo, enjuagada en un canal de agua corriente a sus pies. Un censo del siglo IV contó 144 letrinas públicas en Roma."},{n:"Ostia",info:"Letrinas bien conservadas muestran el diseño comunal.",wiki:"Ostia tiene varias letrinas bien conservadas que muestran el diseño estándar romano: asientos de mármol dispuestos alrededor de tres paredes de una sala, con agua corriente debajo y suelos de mosaico decorativos. El uso comunal del retrete era totalmente normal — una ocasión social para conversación y negocios."},{n:"Éfeso",info:"Letrina calefaccionada con asientos de mármol.",wiki:"La letrina pública de Éfeso cuenta con asientos de mármol calefaccionados (los patrones ricos enviaban esclavos por adelantado para calentarlos), columnas decorativas y un patio central al aire libre. Tenía capacidad para unas 50 personas y estaba conectada al sofisticado sistema de agua y alcantarillado de la ciudad."}]},
"cul16":{name:"Catulo y la Poesía Amorosa",desc:"Poemas apasionados y personales a 'Lesbia': inventó la elegía amorosa latina. 'Vivamos y amemos.' Influyó en toda la poesía occidental.",facts:["'Odi et amo': el dístico latino más famoso","Murió con apenas 30 años","Influyó en toda la poesía amorosa occidental"],locs:[{n:"Verona",info:"Lugar de nacimiento de Catulo — procedía de familia acomodada.",wiki:"Cayo Valerio Catulo nació en Verona alrededor del 84 a.C. en una familia lo suficientemente rica para hospedar a Julio César. Se mudó a Roma de joven y se enamoró apasionadamente de una mujer a la que llamaba 'Lesbia' — probablemente Clodia Metelli, una notoria belleza aristocrática. Sus 116 poemas supervivientes revolucionaron la literatura latina: intensamente personales, emocionalmente crudos, técnicamente brillantes. 'Vivamus, mea Lesbia, atque amemus' (Vivamos y amemos, mi Lesbia) se convirtió en el poema de amor más famoso en latín."},{n:"Roma",info:"Donde Catulo amó, escribió y sufrió.",wiki:"Los poemas de Catulo trazan toda una relación amorosa: pasión extática, celos, traición y odio amargo. 'Odi et amo' (Odio y amo — ¿por qué lo hago? No lo sé, pero lo siento y estoy atormentado) puede ser el dístico más famoso de la literatura occidental. Murió alrededor del 54 a.C., apenas 30 años. Su influencia en Ovidio, Horacio, Petrarca y toda la poesía amorosa posterior es incalculable."}],pathLabels:["De Verona a Roma: la vida literaria de Catulo"]},
"cul17":{name:"Cartas de Plinio el Joven",desc:"247 cartas: testigo del Vesubio, correspondencia con Trajano, vida cotidiana de la élite. La mejor fuente de historia social imperial.",facts:["247 cartas: mejor fuente de la vida de la élite romana","Relato de testigo ocular del Vesubio","Erupción 'pliniana' nombrada por su tío"],locs:[{n:"Como",info:"Lugar de nacimiento de Plinio — actual Como.",wiki:"Cayo Plinio Cecilio Segundo (Plinio el Joven) nació en Comum (Como) en 61 d.C., sobrino e hijo adoptivo de Plinio el Viejo. Sus 247 cartas supervivientes, cuidadosamente seleccionadas para publicación, cubren todos los aspectos de la vida de la clase alta romana: cenas, casos legales, gestión de fincas, historias de fantasmas y el gobierno de Bitinia-Ponto."},{n:"Roma",info:"Plinio sirvió como senador, cónsul y abogado.",wiki:"Las cartas de Plinio incluyen su correspondencia con el emperador Trajano sobre el gobierno de Bitinia — incluyendo el famoso intercambio sobre cómo tratar a los cristianos (Trajano: no buscarlos, pero castigarlos si son denunciados y se niegan a retractarse). Su carta describiendo la erupción del Vesubio, la muerte de su tío y su propia huida de Miseno es el relato antiguo más detallado de un testigo presencial de un desastre natural."},{n:"Miseno",info:"Plinio de 17 años presenció el Vesubio desde aquí.",wiki:"En agosto del 79 d.C., Plinio de 17 años observó el Vesubio eruptar desde Miseno, a 30 km. Su tío Plinio el Viejo navegó hacia la erupción para investigar y rescatar amigos — y murió. Las dos cartas del Plinio más joven a Tácito describiendo el evento son tan importantes que los vulcanólogos llaman 'pliniana' a cierto tipo de erupción."}],pathLabels:["De Como a Roma","Testigo presencial en Miseno"]},
"cul18":{name:"Pintura Mural Romana (Cuatro Estilos)",desc:"Incrustación, Arquitectónico, Ornamental, Intrincado: Pompeya preserva la evolución completa. Influyó en el arte renacentista.",facts:["Los Cuatro Estilos Pompeyanos abarcan 200 años","'Grotesco' proviene de descubrimientos en la Domus Aurea","Villa de los Misterios: mayor fresco antiguo superviviente"],locs:[{n:"Pompeya",info:"Preserva los cuatro estilos — la colección más rica del mundo.",wiki:"La pintura mural romana se categoriza en cuatro Estilos Pompeyanos. Estilo I (Incrustación, 200-80 a.C.): yeso pintado imitando paneles de mármol. Estilo II (Arquitectónico, 80-20 a.C.): arquitectura ilusionista creando profundidad — el friso báquico de la Villa de los Misterios es la obra maestra. Estilo III (Ornamental, 20 a.C.-20 d.C.): delicados paneles ornamentales con escenas mitológicas centrales. Estilo IV (Intrincado, 20-79 d.C.): fantasía teatral combinando todos los estilos anteriores. Cuando los artistas del Renacimiento entraron en la enterrada Domus Aurea, descubrieron el Estilo IV y llamaron a los diseños 'grotescos' — revolucionando el arte decorativo europeo."},{n:"Roma",info:"La Villa de Livia y la Domus Aurea preservan ejemplos clave.",wiki:"Roma preserva importantes pinturas murales fuera de Pompeya. La Villa de Livia en Prima Porta tiene una famosa sala de jardín — una pintura ilusionista de árboles, pájaros y flores cubriendo las cuatro paredes, creando la impresión de estar en un jardín. Las decoraciones del Estilo IV de la Domus Aurea inspiraron los diseños de la logia vaticana de Rafael."}]},
"cul19":{name:"Apuleyo y El Asno de Oro",desc:"La única novela latina completa superviviente: Lucio transformado en burro. Picaresca, procaz, filosófica. Contiene Cupido y Psique.",facts:["Única novela latina completa superviviente","Contiene el cuento de Cupido y Psique","Juzgado por magia y absuelto"],locs:[{n:"Madauros",info:"Lugar de nacimiento de Apuleyo en el norte de África (actual M'Daourouch, Argelia).",wiki:"Lucio Apuleyo nació alrededor del 125 d.C. en Madauros, Numidia (actual Argelia). Educado en Cartago y Atenas, era un polígrafo que escribió sobre filosofía, retórica e historia natural. Fue famosamente juzgado por ganarse el afecto de su rica esposa mediante magia (Apología) — y absuelto."},{n:"Cartago",info:"Apuleyo estudió y enseñó aquí.",wiki:"Apuleyo estudió y luego enseñó en Cartago — la capital intelectual de la África romana. Las Metamorfosis (El Asno de Oro) es la única novela latina completa que sobrevive. Cuenta la historia de Lucio, accidentalmente transformado en asno, vagando por un mundo picaresco de bandidos, brujas y amantes antes de ser salvado por la diosa Isis. Incrustada en ella está el cuento de hadas de Cupido y Psique — una de las historias más recontadas de la cultura occidental."},{n:"Roma",info:"La influencia literaria de la novela llegó a Roma y más allá.",wiki:"El Asno de Oro influyó en el Decamerón de Boccaccio, el Don Quijote de Cervantes y el Sueño de una noche de verano de Shakespeare (la transformación de Bottom). El cuento de Cupido y Psique ha sido ilustrado por Canova, Rafael e incontables otros."}],pathLabels:["De Madauros a Cartago","La influencia literaria llega a Roma"]},
"cul20":{name:"Escultura y Retrato Romanos",desc:"Retratos veristas republicanos (con verrugas y todo), clasicismo idealizado augusteo, Marco Aurelio ecuestre. La identidad visual de Roma.",facts:["Verismo republicano: retratos con 'verrugas y todo'","Marco Aurelio ecuestre: sobrevivió como 'Constantino'","Inspiró a Donatello y Verrocchio"],locs:[{n:"Roma",info:"Centro de producción escultórica romana.",wiki:"La escultura romana evolucionó a través de fases distintas. El verismo republicano (siglos III-I a.C.) produjo retratos brutalmente honestos — cabezas arrugadas, cicatrizadas, calvas que enfatizaban los valores romanos de edad y experiencia. Augusto revolucionó el retrato con el clasicismo idealizado — su estatua de Prima Porta, modelada sobre originales griegos, muestra un emperador eternamente juvenil. Los retratos imperiales se convirtieron en propaganda. La estatua ecuestre de Marco Aurelio (Museos Capitolinos) sobrevivió porque fue confundida con Constantino. Inspiró el Gattamelata de Donatello y el Colleoni de Verrocchio."},{n:"Pompeya",info:"Preservó escultura de bronce y mármol en contextos domésticos.",wiki:"Pompeya preservó escultura en contexto — desde el elegante Fauno Danzante de la Casa del Fauno hasta hermas de jardín y bustos retrato. El Mosaico de Alejandro (técnicamente opus vermiculatum, no escultura) está entre las obras de arte más famosas de la antigüedad."}]},
"rel16":{name:"Misterios Báquicos y el Escándalo de las Bacanales",desc:"El Senado aplastó el culto báquico en 186 a.C.: 7.000 arrestados. Primera persecución religiosa de la historia romana.",facts:["7.000 arrestados, muchos ejecutados","Primera persecución religiosa de la historia romana","Los frescos de la Villa de los Misterios pueden mostrar la iniciación"],locs:[{n:"Roma",info:"186 a.C.: Senatus Consultum de Bacchanalibus.",wiki:"En 186 a.C., el Senado romano descubrió que las reuniones del culto mistérico báquico (Bacanales) se habían extendido por Italia — involucrando rituales nocturnos, danza extática, iniciación sexual y presuntos crímenes incluyendo asesinato, falsificación y envenenamiento. El Senado aprobó el Senatus Consultum de Bacchanalibus — una de las inscripciones más importantes supervivientes de Roma — restringiendo reuniones a máximo 5 personas y requiriendo permiso del Senado. Más de 7.000 personas fueron arrestadas; muchas ejecutadas. Fue la primera persecución religiosa a gran escala de Roma."},{n:"Pompeya/Villa de los Misterios",info:"Famosos frescos pueden representar iniciación báquica.",wiki:"La Villa de los Misterios en Pompeya contiene los frescos más famosos del mundo antiguo — 29 figuras de tamaño natural en una narrativa continua. Su interpretación se debate, pero la mayoría de estudiosos ven un rito de iniciación báquico: revelación de un falo, flagelación, danza y lectura de textos sagrados. A pesar de la represión del 186 a.C., el culto báquico nunca desapareció completamente."}]},
"rel17":{name:"Sol Invictus y el Culto Solar",desc:"Aureliano hizo de Sol Invictus la deidad estatal suprema: el 25 de diciembre era su festividad. Pudo influir en la fecha de la Navidad.",facts:["25 de diciembre: cumpleaños del Sol Invicto","Aureliano hizo de Sol Invictus la deidad suprema (274)","Constantino era devoto antes de convertirse"],locs:[{n:"Roma",info:"Templo de Sol Invictus construido en el Campo de Marte.",wiki:"El emperador Aureliano estableció el culto de Sol Invictus (Sol Invencible) como deidad suprema del estado romano en 274 d.C., construyendo un magnífico templo en el Campo de Marte. El 25 de diciembre — Dies Natalis Solis Invicti (Cumpleaños del Sol Invencible) — fue designado como el festival principal. Si la Navidad fue deliberadamente colocada en esta fecha para competir con o absorber el festival solar es una de las preguntas más debatidas en la historia religiosa. Constantino, antes de su conversión, era devoto de Sol Invictus — el sol aparece en su moneda."}]},
"rel18":{name:"Religión Funeraria Romana",desc:"Lares, Manes, Lemures: el culto a los ancestros moldeó la identidad romana. 'Dis Manibus' en cada lápida.",facts:["'D.M.' (Dis Manibus) en cada lápida","Parentalia: festival de 9 días de los muertos","Lemures: fantasmas inquietos apaciguados con habas negras"],locs:[{n:"Roma/Vía Apia",info:"Las tumbas bordeaban las calzadas fuera de cada ciudad romana.",wiki:"La religión romana estaba profundamente preocupada por los muertos. Los Manes (espíritus de los muertos) eran venerados en las tumbas familiares. La inscripción 'D.M.' (Dis Manibus — a los espíritus divinos) aparece en prácticamente cada lápida romana. Las Parentalias (13-21 de febrero) era un festival de los muertos cuando las familias visitaban tumbas con comida y vino. Las Lemurias (9, 11, 13 de mayo) era una observancia más temerosa — el paterfamilias caminaba descalzo a medianoche, escupiendo habas negras para apaciguar a los Lemures (fantasmas inquietos y malévolos). Las máscaras de ancestros (imagines) de los muertos se guardaban en el atrio y se llevaban en procesiones fúnebres."}]},
"rel19":{name:"Epicureísmo en Roma",desc:"Filosofía del jardín: el placer como bien supremo (definido como ausencia de dolor). El poema de Lucrecio. Rival del estoicismo.",facts:["Placer = ausencia de dolor (ataraxia)","1.800 rollos en Herculano, muchos epicúreos","Epicuro admitió mujeres y esclavos"],locs:[{n:"Roma",info:"El epicureísmo tuvo poderosos adherentes romanos.",wiki:"El epicureísmo entró en Roma en el siglo II a.C. y atrajo poderosos adherentes. Epicuro enseñaba que el placer (hedone) — correctamente entendido como ausencia de dolor y ansiedad (ataraxia) — era el bien supremo. Los dioses existen pero no intervienen; el alma es mortal; el universo está compuesto de átomos en el vacío. En Roma, el De Rerum Natura de Lucrecio fue su mayor expresión. El suegro de Julio César, Calpurnio Pisón, construyó una villa en Herculano repleta de textos epicúreos."},{n:"Atenas",info:"El Jardín de Epicuro — donde comenzó la filosofía.",wiki:"Epicuro (341-270 a.C.) fundó su escuela en un jardín fuera de Atenas — de ahí 'el Jardín.' Únicamente, admitía mujeres y esclavos. El epicureísmo rivalizó con el estoicismo como la filosofía romana dominante; Cicerón, aunque simpatizante estoico, escribió extensamente sobre ambos."},{n:"Herculano/Villa de los Papiros",info:"1.800 rollos de papiro carbonizados — muchos textos epicúreos.",wiki:"La Villa de los Papiros en Herculano — enterrada por el Vesubio en 79 d.C. — contenía una biblioteca de 1.800 rollos de papiro carbonizados, muchos con obras del filósofo epicúreo Filodemo. La tecnología moderna (escaneo de rayos X) está leyendo lentamente estos rollos, recuperando textos antiguos perdidos."}],pathLabels:["El epicureísmo llega a Roma","Biblioteca epicúrea en Herculano"]},
"rel20":{name:"Concilio de Constantinopla",desc:"Concilio de Teodosio I: Credo Niceno finalizado, arrianismo condenado. Constantinopla elevada al segundo rango tras Roma.",facts:["Credo Niceno finalizado en su forma actual","Arrianismo definitivamente condenado","Constantinopla elevada al segundo rango, sembrando el Cisma"],locs:[{n:"Constantinopla",info:"381 d.C.: Segundo Concilio Ecuménico.",wiki:"El Primer Concilio de Constantinopla (381 d.C.), convocado por el emperador Teodosio I, fue el segundo concilio ecuménico de la Iglesia cristiana. Expandió el Credo Niceno a su forma final (aún recitado hoy), condenó definitivamente el arrianismo (que negaba la plena divinidad de Cristo) y elevó al obispo de Constantinopla al segundo rango tras Roma — 'porque es la Nueva Roma.' Este último canon enfureció a Roma y plantó las semillas del eventual Gran Cisma (1054)."}]},
"plg16":{name:"Derrumbe del Anfiteatro de Fidenas",desc:"Anfiteatro de madera barato se derrumbó: 20.000-50.000 víctimas. El peor desastre estructural de la historia romana.",facts:["20.000-50.000 víctimas","Peor desastre estructural de la historia romana","Llevó a regulaciones de seguridad edilicia"],locs:[{n:"Fidenas",info:"27 d.C.: colapso catastrófico durante juegos gladiatorios.",wiki:"En 27 d.C., un anfiteatro de madera construido barato en Fidenas (a solo 8 km de Roma) colapsó durante juegos gladiatorios. Tácito informa 50.000 víctimas (muertos y heridos) — aunque los historiadores modernos estiman 20.000-30.000. Un liberto llamado Atilio lo había construido sobre cimientos inadecuados para lucrarse de juegos prohibidos en Roma. El desastre impulsó al Senado a aprobar regulaciones requiriendo inspecciones estructurales y riqueza mínima para patrocinadores de juegos. Tiberio envió cirujanos y abrió su palacio a los heridos."}]},
"plg17":{name:"Erupción del Vesubio (79 d.C.)",desc:"18 horas de erupción: oleadas piroclásticas, Plinio el Viejo muerto, más de 2.000 fallecidos. Ciudades enterradas durante 1.700 años.",facts:["18 horas de erupción","Plinio el Viejo murió: erupción 'pliniana' nombrada por él","Pompeya redescubierta en 1748"],locs:[{n:"Pompeya",info:"Enterrada bajo 4-6 metros de piedra pómez y ceniza.",wiki:"El 24 de agosto (u octubre 24) del 79 d.C., el Monte Vesubio eruptó catastróficamente. Pompeya — población ~11.000 — fue enterrada bajo 4-6 metros de piedra pómez y ceniza volcánica durante 18 horas. La mayoría de residentes evacuaron, pero aproximadamente 1.150 cuerpos han sido encontrados (quizás 2.000 murieron). La primera fase dejó caer piedra pómez; la fase letal fueron las oleadas piroclásticas — gas y roca sobrecalentados viajando a más de 100 km/h. La ciudad fue olvidada hasta su redescubrimiento en 1748, proporcionando una instantánea incomparable de la vida diaria romana."},{n:"Herculano",info:"Enterrada bajo 20 metros de lodo volcánico — mejor preservada que Pompeya.",wiki:"Herculano — una próspera ciudad costera de ~5.000 — fue enterrada bajo 20 metros de material volcánico, mayormente flujos piroclásticos que carbonizaron material orgánico pero también lo preservaron. Más de 300 esqueletos fueron encontrados apiñados en los cobertizos de botes, muertos instantáneamente por el calor. La profundidad del enterramiento preservó muebles de madera, comida y la famosa biblioteca de papiros de la Villa de los Papiros."},{n:"Estabias",info:"Plinio el Viejo murió aquí durante la erupción.",wiki:"Plinio el Viejo — almirante, naturalista y autor de la Historia Natural — navegó desde Miseno para rescatar amigos en Estabias. Murió en la playa, probablemente de un ataque al corazón o asfixia por gases volcánicos. El relato de su sobrino Plinio el Joven a Tácito es la descripción de testigo presencial más detallada de una erupción volcánica de la antigüedad."}],pathLabels:["Plinio el Viejo navega desde Miseno a Estabias"]},
"plg18":{name:"Peste de Atenas (Contexto Romano)",desc:"Aunque griega, moldeó profundamente la conciencia romana sobre las plagas: el relato de Tucídides se convirtió en modelo de toda la escritura romana sobre pestes.",facts:["Hasta 100.000 muertos en Atenas","Relato de Tucídides: modelo para toda la escritura romana sobre plagas","La identidad de la enfermedad aún se debate"],locs:[{n:"Atenas",info:"430-426 a.C.: hasta 100.000 muertos.",wiki:"La Peste de Atenas (430-426 a.C.) mató quizás una cuarta parte de la población ateniense, incluyendo a Pericles. Aunque un evento griego, fue fundacional para el mundo romano: la descripción clínica de Tucídides se convirtió en el modelo literario para toda narrativa romana de peste posterior — el De Rerum Natura de Lucrecio termina con una devastadora recreación poética. Escritores romanos incluyendo Livio, Diodoro Sículo y Procopio todos se basaron en la plantilla de Tucídides al describir epidemias posteriores. La identidad de la enfermedad sigue debatiéndose: tifus, viruela, ébola y sarampión han sido propuestos."}]},
"plg19":{name:"Subasta Pretoriana del Imperio",desc:"Tras asesinar a Pertinax, la Guardia Pretoriana subastó el imperio al mejor postor: Didio Juliano pagó 25.000 sestercios por hombre.",facts:["Imperio subastado por 25.000 sestercios por hombre","Didio Juliano duró solo 66 días","Septimio Severo marchó sobre Roma en respuesta"],locs:[{n:"Roma/Castra Praetoria",info:"28 de marzo del 193 d.C.: el imperio vendido en subasta.",wiki:"El 28 de marzo del 193 d.C., la Guardia Pretoriana asesinó al emperador Pertinax tras solo 87 días. Luego literalmente subastaron el imperio desde lo alto de las murallas del Castra Praetoria (campamento pretoriano). Dos postores compitieron: Sulpiciano y Didio Juliano. Juliano ganó ofreciendo 25.000 sestercios a cada guardia. Entró al palacio pero encontró el tesoro vacío. Las legiones fronterizas se rebelaron — Septimio Severo marchó sobre Roma desde Panonia. Juliano fue abandonado por todos y ejecutado tras 66 días. El episodio epitomizó la degradación política de Roma."}]},
"plg20":{name:"Deforestación y Degradación Ambiental",desc:"Roma arrasó bosques para barcos, combustible y construcción: los bosques del norte de África desaparecieron. Erosión del suelo. Catástrofe ambiental antigua.",facts:["Los bosques de Italia arrasados en la República tardía","Los bosques del norte de África se convirtieron en semidesierto","Sedimentación del puerto de Ostia por erosión de deforestación"],locs:[{n:"Roma",info:"Enorme demanda de madera y combustible.",wiki:"La enorme demanda del Imperio Romano de madera — construcción naval, construcción, combustible para termas e industria, y carbón para fundición — impulsó la deforestación por todo el Mediterráneo. Los bosques de Italia fueron en gran parte talados para finales de la República. Estrabón notó que Córcega alguna vez estuvo tan boscosa que 'las abejas no encontraban espacio para sus colmenas.' Plinio lamentó la desaparición de los bosques italianos. El impacto ambiental fue severo: erosión del suelo, sedimentación de puertos (Ostia se sedimentó), pérdida de tierra agrícola y cambios climáticos locales."},{n:"Norte de África",info:"Antaño boscoso — ahora en gran parte desierto.",wiki:"El norte de África — el granero de Roma — fue extensamente deforestado para agricultura y madera. Regiones que estaban boscosas en la antigüedad son ahora semiáridas. El análisis de núcleos de polen de Túnez y Argelia muestra una masiva tala forestal durante el período romano. La transformación ambiental contribuyó al declive de la productividad agrícola en la antigüedad tardía."}]},
"bio21":{name:"Germánico",desc:"Príncipe dorado: vengó Teutoburgo, amado por el pueblo. Murió misteriosamente en Antioquía. Su muerte convulsionó Roma.",facts:["Recuperó las águilas perdidas de Varo","Murió a los 33, posiblemente envenenado","Padre de Calígula, abuelo de Nerón"],locs:[{n:"Roma",info:"El hombre más popular de Roma — multitudes acudieron a su funeral.",wiki:"Nerón Claudio Germánico era todo lo que los romanos querían en un líder: guapo, valiente, generoso, brillante y modesto. Sobrino e hijo adoptivo de Tiberio, era la figura más amada del imperio. Cuando murió en Antioquía el 10 de octubre del 19 d.C. — posiblemente envenenado por el gobernador Pisón por órdenes de Tiberio — Roma estalló en duelo. Multitudes arrojaron piedras a los templos. Sus cenizas fueron llevadas por su esposa Agripina la Mayor en una procesión que atrajo dolientes por todo el imperio."},{n:"Teutoburgo",info:"Germánico recuperó las águilas perdidas y enterró a los muertos.",wiki:"En 15-16 d.C., Germánico lideró campañas masivas en Germania para vengar el desastre de Teutoburgo. Recuperó dos de las tres águilas perdidas, derrotó a Arminio dos veces, y encontró el campo de batalla de Teutoburgo — enterrando los huesos blanqueados de las legiones de Varo seis años después del desastre. Tiberio lo reclamó antes de que pudiera terminar — quizás celoso de su popularidad."},{n:"Antioquía",info:"Murió aquí el 10 de octubre del 19 d.C. — ¿envenenado?",wiki:"Germánico murió en Antioquía a los 33 años. Creía que Pisón lo había envenenado y lo maldijo desde su lecho de muerte. El juicio de Pisón en Roma fue la sensación de la época — Pisón se suicidó antes del veredicto. Los estudiosos modernos debaten si Tiberio ordenó el asesinato. Los hijos de Germánico incluyeron a Calígula y Agripina la Menor (madre de Nerón)."}],pathLabels:["Venga Teutoburgo","Muere misteriosamente en Antioquía"]},
"bio22":{name:"Agripa",desc:"Mano derecha de Augusto: ganó Accio, construyó el Panteón, se casó con Julia. El mayor general del Imperio temprano.",facts:["Ganó Accio para Augusto","Construyó el Panteón original","Murió a los 50: le siguió una crisis sucesoria"],locs:[{n:"Roma",info:"Construyó el Panteón original, Termas de Agripa y el Aqua Virgo.",wiki:"Marco Vipsanio Agripa fue el socio indispensable de Augusto — genio militar y maestro constructor. De orígenes humildes, ganó prácticamente cada batalla que Augusto necesitaba: Nauloco contra Sexto Pompeyo (36 a.C.), Accio contra Antonio (31 a.C.). En tiempos de paz, construyó el primer Panteón (27 a.C., luego reconstruido por Adriano), las Termas de Agripa y el acueducto Aqua Virgo. Se casó con la hija de Augusto Julia y claramente estaba destinado como sucesor. Su muerte en 12 a.C. a los 50 años dejó a Augusto luchando por un heredero."},{n:"Accio",info:"31 a.C.: las tácticas navales de Agripa ganaron la batalla decisiva.",wiki:"En Accio, Agripa comandó la flota de Octaviano contra Antonio y Cleopatra. Sus innovadoras tácticas navales — usando naves más pequeñas y rápidas contra las fortalezas flotantes de Antonio — resultaron decisivas. Cuando Cleopatra huyó con el escuadrón egipcio, Antonio la siguió, y la batalla se ganó. Agripa había entregado el Mediterráneo a Augusto."},{n:"Nimes",info:"La Maison Carrée pudo haber sido construida por Agripa.",wiki:"Agripa gobernó la Galia y construyó infraestructura por toda la provincia. El acueducto del Pont du Gard pudo haber sido encargado durante su gobierno. Su proyecto cartográfico — topografiar todo el sistema de caminos romanos — se exhibió tras su muerte en la Pórtica Vipsania."}],pathLabels:["Victoria en Accio asegura el imperio","Agripa construye infraestructura en la Galia"]},
"bio23":{name:"Catón el Joven",desc:"Último defensor de la República: filósofo estoico y político. Desafió a César. Su suicidio en Útica se convirtió en símbolo de la virtud republicana.",facts:["Se arrancó la herida antes que vivir bajo César","Dante lo colocó como guardián del Purgatorio","César: el único hombre que realmente lo amenazó"],locs:[{n:"Roma",info:"Pasó su carrera oponiéndose a César, Pompeyo y la corrupción.",wiki:"Marco Porcio Catón (Catón el Joven, bisnieto de Catón el Viejo) fue el defensor más principista — y más obstinado — de la República Romana. Devoto estoico, caminaba descalzo, vestía ropa basta y practicaba el ascetismo. Se opuso al Primer Triunvirato, obstruyó la legislación de César, y luchó incansablemente contra la corrupción. Su autoridad moral era inmensa incluso para quienes lo encontraban exasperante. César dijo que Catón era el único hombre que genuinamente amenazaba sus ambiciones."},{n:"Útica",info:"46 a.C.: Catón se suicidó antes que someterse a César.",wiki:"Tras la victoria de César en Tapso (46 a.C.), Catón quedó atrapado en Útica en el norte de África. En lugar de aceptar el perdón de César (que habría reconocido la autoridad de César para otorgarlo), leyó el Fedón de Platón sobre la inmortalidad del alma, luego se apuñaló en el abdomen. Cuando los médicos cosieron la herida, la abrió con sus propias manos. Su suicidio se convirtió en el acto definitorio de la virtud republicana — Dante lo colocó como guardián del Purgatorio."}],pathLabels:["Última resistencia de Catón en Útica"]},
"bio24":{name:"Virgilio",desc:"El mayor poeta de Roma: Bucólicas, Geórgicas, Eneida. 'Canto las armas y al hombre.' Quiso quemar la Eneida.",facts:["'Canto las armas y al hombre'","Quiso quemar la Eneida: Augusto lo impidió","Guía de Dante por el Infierno y el Purgatorio"],locs:[{n:"Mantua",info:"Lugar de nacimiento de Virgilio — 'Mantua me engendró.'",wiki:"Publio Virgilio Marón nació cerca de Mantua en 70 a.C. en una modesta familia rural. Sus Églogas (poemas pastorales, 42-39 a.C.) llamaron la atención de Mecenas, consejero cultural de Augusto. Las Geórgicas (sobre agricultura, 29 a.C.) se consideran la mejor poesía didáctica en cualquier idioma. Luego vino la Eneida (19 a.C.) — epopeya que vincula el destino de Roma con Troya a través del héroe Eneas. Virgilio murió antes de terminarla y supuestamente pidió que se quemara. Augusto anuló la petición."},{n:"Roma",info:"Figura central del programa cultural de Augusto.",wiki:"Virgilio fue la pieza central de la revolución cultural augusta — su Eneida proporcionó a Roma una epopeya nacional que rivalizaba con Homero. 'Arma virumque cano' (Canto las armas y el hombre) se convirtió en el inicio más famoso de la literatura latina. El poema justificó el gobierno de Augusto presentando la historia de Roma como destino divinamente ordenado. Virgilio se volvió cuasi-sagrado en la Edad Media — Dante lo eligió como guía por el Infierno y el Purgatorio."},{n:"Nápoles",info:"La tumba de Virgilio está aquí — lugar de peregrinación durante 2.000 años.",wiki:"La tumba de Virgilio a la entrada de la Gruta de Posilipo en Nápoles se convirtió en lugar de peregrinación. En la Edad Media, Virgilio era considerado mago y profeta — la Cuarta Égloga, que profetizaba una edad de oro y un niño divino, se leyó como predicción de Cristo. Petrarca, Boccaccio y Chaucer visitaron la tumba."}],pathLabels:["De Mantua a Roma: ascenso literario de Virgilio","Tumba de Virgilio en Nápoles"]},
"bio25":{name:"Ovidio",desc:"Metamorfosis, Arte de Amar: exiliado por Augusto por 'un poema y un error'. Murió en el exilio junto al Mar Negro.",facts:["'Carmen et error': el misterio de su exilio","Metamorfosis: una de las obras más influyentes jamás escritas","Nunca fue perdonado: murió en el exilio"],locs:[{n:"Sulmona",info:"Lugar de nacimiento de Ovidio — actual Sulmona, Abruzzo.",wiki:"Publio Ovidio Nasón nació en Sulmona en 43 a.C. en una antigua familia ecuestre. Fue entrenado para la ley pero eligió la poesía. Sus Amores (poemas de amor) y Ars Amatoria (Arte de amar — esencialmente manual de seducción) lo hicieron el poeta más ingenioso y popular de la Roma augusta. Las Metamorfosis — 250 mitos de transformación en 15 libros — es una de las obras más influyentes de la literatura occidental."},{n:"Roma",info:"La capital literaria — hasta el exilio.",wiki:"Ovidio fue el poeta más de moda de Roma hasta el 8 d.C., cuando Augusto lo desterró repentinamente a Tomis en el Mar Negro por 'carmen et error' — un poema y un error. El poema probablemente era el Ars Amatoria (ofensivo para la legislación moral de Augusto); el error sigue siendo el mayor misterio literario de la historia — quizás implicación en un escándalo que tocaba a Julia, nieta de Augusto. Ovidio nunca regresó."},{n:"Tomis",info:"Actual Constanza, Rumanía — lugar de exilio y muerte de Ovidio.",wiki:"Ovidio pasó sus últimos nueve años (8-17 d.C.) en Tomis (actual Constanza, Rumanía) — ciudad fronteriza en el Mar Negro que describió como helada, bárbara e insoportable. Su poesía del exilio (Tristes, Epístolas desde el Ponto) suplica el regreso con elocuencia desgarradora. Murió allí en 17 d.C., nunca perdonado. Su influencia en Dante, Chaucer, Shakespeare, Tiziano y Bernini es incalculable."}],pathLabels:["De Sulmona a Roma: fama literaria","Exiliado a Tomis en el Mar Negro"]},
"eco16":{name:"Industria de la Construcción Romana",desc:"El mayor empleador del mundo antiguo: collegia de constructores, fabricantes de ladrillos, cortadores de mármol. Los sellos de ladrillo rastrean la cadena de suministro.",facts:["Los sellos de ladrillo permiten datación exacta a los arqueólogos","Gremios de construcción organizados como sindicatos modernos","Escala no igualada hasta la Revolución Industrial"],locs:[{n:"Roma",info:"La construcción constante empleaba decenas de miles.",wiki:"La industria de la construcción romana era el mayor empleador organizado del mundo antiguo. Colegios especializados (gremios) de constructores (fabri), fabricantes de ladrillos, cortadores de mármol, colocadores de mosaicos y pintores operaban por todo el imperio. Los ladrillos romanos llevaban estampado el nombre del productor, fecha y año consular — proporcionando herramienta de datación invaluable para arqueólogos. El Monte Testaccio (colina de 53 millones de ánforas rotas) muestra la escala de la gestión organizada de residuos de construcción."},{n:"Ostia",info:"Los gremios de construcción tenían sedes aquí.",wiki:"El Piazzale delle Corporazioni de Ostia — pórtico con 61 oficinas — muestra mosaicos identificando gremios comerciales: constructores navales, cordeleros, medidores de grano y proveedores de construcción. La organización de la industria de la construcción romana no tuvo parangón en Europa hasta la Revolución Industrial."}]},
"eco17":{name:"Construcción Naval e Industria Marítima",desc:"Más de 1.200 pecios encontrados. Los cargueros de grano transportaban más de 1.000 toneladas. Los barcos de Nemi tenían plataformas giratorias y fontanería.",facts:["Más de 1.200 pecios romanos encontrados","Los barcos de grano transportaban más de 1.000 toneladas","Los barcos de Nemi destruidos por los alemanes en 1944"],locs:[{n:"Miseno",info:"Base de la flota mediterránea romana.",wiki:"La industria naval romana era enorme. Solo la flota de grano requería cientos de grandes cargueros (algunos llevando más de 1.000 toneladas — rivalizando con naves del siglo XVIII). La flota en Miseno era la mayor base naval del imperio, albergando naves de guerra incluyendo quinquerremes y trirremes. Se han encontrado más de 1.200 naufragios romanos por todo el Mediterráneo, proporcionando evidencia de rutas comerciales, cargas y técnicas de construcción."},{n:"Lago Nemi",info:"Palacios flotantes de Calígula — recuperados en los años 30.",wiki:"Dos enormes naves fueron recuperadas del Lago Nemi en los años 30 — construidas para el emperador Calígula como palacios flotantes. Medían 70 m y 73 m de largo, con termas calefaccionadas, suelos de mármol, plataformas giratorias y plomería de plomo. Representaban la cumbre de la tecnología naval romana. Trágicamente, ambas fueron destruidas por fuerzas alemanas en retirada en 1944."},{n:"Ostia",info:"Puerto comercial — cientos de naves fondeadas.",wiki:"Ostia y el complejo portuario claudio-trajánico en Portus manejaban la mayor parte del comercio marítimo de Roma. Naves de grano desde Alejandría, petroleros desde Hispania y naves de vino desde la Galia convergían aquí. El puerto podía acomodar más de 200 naves simultáneamente."}],pathLabels:["Centros navales y comerciales","Barcazas de placer de Calígula en el Lago Nemi"]},
"eco18":{name:"Mercados Urbanos y Tabernae",desc:"Mercado de Trajano (más de 150 tiendas), macellum, tabernae en cada calle: la economía de consumo de Roma.",facts:["Mercado de Trajano: más de 150 tiendas en 6 niveles","Pompeya: más de 150 termopolios","Comida romana real preservada en Pompeya"],locs:[{n:"Roma/Mercado de Trajano",info:"Primer centro comercial del mundo — más de 150 tiendas en 6 niveles.",wiki:"El Mercado de Trajano (Mercati di Traiano), construido por Apolodoro de Damasco alrededor del 110 d.C., a menudo se llama el primer centro comercial del mundo. Sus más de 150 tiendas y oficinas se elevaban en seis niveles, vendiendo de todo desde especias y seda hasta pescado y flores. Tabernae (tiendas) individuales bordeaban virtualmente cada calle romana — las excavaciones de Ostia revelan panaderías, bares, lavanderías y mostradores de comida rápida (thermopolia) con notable densidad."},{n:"Pompeya",info:"Tiendas, bares y thermopolia conservados.",wiki:"Pompeya tenía más de 150 thermopolia (mostradores de comida rápida con jarras empotradas para comida caliente), docenas de panaderías (con piedras de molino y hornos intactos), fullonicae, tintorerías y el macellum (mercado cubierto de alimentos) en el Foro. Un thermopolium conservó comida real: pato, cabra, pescado, caracoles y habas."}]},
"eco19":{name:"Esclavitud Romana como Sistema Económico",desc:"2-3 millones de esclavos solo en Italia: cuadrillas agrícolas, mineros, sirvientes domésticos. Motor económico de la República.",facts:["2-3 millones de esclavos solo en Italia","10.000 vendidos al día en Delos","Esclavos de minas sobrevivían meses, no años"],locs:[{n:"Delos",info:"Mayor mercado de esclavos — 10.000 vendidos por día en su apogeo.",wiki:"La economía esclavista era fundamental para Roma. En su apogeo, 2-3 millones de esclavos trabajaban solo en Italia — aproximadamente un tercio de la población. Delos era el mayor mercado de esclavos del Mediterráneo: Estrabón afirmó que 10.000 podían comprarse y venderse en un solo día. Fuentes de esclavos: cautivos de guerra, víctimas de piratas, bebés expuestos y cría. Los latifundios agrícolas usaban cuadrillas de esclavos encadenados. Los esclavos de minas en Laurión o minas de plata hispanas tenían expectativas de vida medidas en meses."},{n:"Roma",info:"Los esclavos realizaban toda función en la sociedad romana.",wiki:"En Roma, los esclavos servían como sirvientes domésticos, tutores, contadores, médicos, secretarios, artesanos, gladiadores, trabajadores sexuales y burócratas imperiales. La contribución económica era enorme: los esclavos construyeron la infraestructura, trabajaron las granjas, atendieron las minas y produjeron los bienes. Los libertos (liberti) a menudo se volvieron empresarios ricos — creando una paradoja de movilidad social dentro de un sistema esclavista."},{n:"Laurión",info:"Minas de plata trabajadas por esclavos en condiciones horribles.",wiki:"La minería era el peor destino para un esclavo romano. En Laurión (Grecia), Cartago Nova (Hispania) y otros sitios, los esclavos trabajaban en túneles de tan solo 1 metro de alto, respirando polvo tóxico, en oscuridad. La expectativa de vida se medía en meses. Diodoro Sículo describió condiciones en minas hispanas que hacen estremecer a lectores modernos."}],pathLabels:["Comercio de esclavos de Delos a Roma","Esclavos enviados a las minas"]},
"eco20":{name:"Calzadas Romanas como Infraestructura Económica",desc:"400.000 km de calzadas: redujeron costes de transporte, permitieron mercados, conectaron el imperio. 'Todos los caminos llevan a Roma.'",facts:["400.000 km de calzadas en total","80.000-90.000 km de vías pavimentadas","Milliarium Aureum: todas las distancias medidas desde Roma"],locs:[{n:"Roma/Vía Apia",info:"'Reina de los caminos' — comenzó 312 a.C. para apoyar las Guerras Samnitas.",wiki:"La red de caminos romanos totalizó aproximadamente 400.000 km, con 80.000-90.000 km de carreteras pavimentadas. Los caminos se construyeron principalmente con fines militares pero tuvieron efectos económicos transformadores: redujeron costos de transporte, permitieron mercados regulares, facilitaron la recaudación de impuestos y conectaron productores con consumidores por todo el imperio. La Vía Apia (iniciada 312 a.C. por el censor Apio Claudio el Ciego) fue el prototipo — camino pavimentado de 4,1 m de ancho de Roma a Capua, luego extendido a Brindisi."},{n:"Brindisi",info:"Terminal oriental de la Vía Apia — puerta a Grecia.",wiki:"Brundisium (Brindisi) era el terminal oriental de la Vía Apia y el principal punto de embarque de Roma para Grecia y el Este. El camino era tan importante que los hitos sobreviven a lo largo de toda su longitud. El Milliarium Aureum (Hito Dorado) en el Foro era el punto simbólico desde el cual se medían todas las distancias — 'Todos los caminos llevan a Roma.'"}],pathLabels:["Vía Apia: Roma a Brindisi"]},
"law16":{name:"Edicto del Pretor e Ius Honorarium",desc:"Edicto anual anunciando innovaciones legales: creó equidad junto al rígido derecho civil. Adriano lo codificó permanentemente.",facts:["El edicto anual creó un sistema legal flexible","El ius honorarium complementó las rígidas Doce Tablas","Adriano lo hizo permanente c. 130 d.C."],locs:[{n:"Roma/Foro",info:"Los pretores anunciaban sus edictos al inicio de cada año.",wiki:"El praetor urbanus (pretor urbano) era el principal magistrado judicial de Roma. Cada año, al tomar posesión, publicaba un edictum — anunciando los principios legales y remedios que aplicaría durante su mandato. Durante siglos, pretores sucesivos construyeron un cuerpo de derecho (ius honorarium) que complementaba y corregía las rígidas Doce Tablas. El edicto introdujo principios de equidad, buena fe y justicia que faltaban en el viejo derecho civil. Alrededor del 130 d.C., el jurista Salvio Juliano, por órdenes de Adriano, codificó el edicto en forma permanente e inmutable — el Edictum Perpetuum."}]},
"law17":{name:"Ius Gentium (Derecho de Gentes)",desc:"Derecho aplicable a todos los pueblos: precursor del derecho internacional. Basado en la razón natural, no en la costumbre romana.",facts:["Desarrollado desde 242 a.C. para casos de no ciudadanos","Basado en la razón natural, no en la costumbre romana","Fundamento del derecho internacional moderno"],locs:[{n:"Roma",info:"Desarrollado por el pretor peregrino desde 242 a.C.",wiki:"Desde 242 a.C., el praetor peregrinus (pretor extranjero) administraba justicia en casos que involucraban no ciudadanos. Dado que el derecho civil romano (ius civile) aplicaba solo a ciudadanos, el pretor extranjero desarrolló el ius gentium — 'derecho de gentes' — basado en principios considerados comunes a todos los pueblos: razón natural, buena fe y justicia. Este enfoque universal influyó en el desarrollo del derecho internacional. Hugo Grocio (siglo XVII), el 'padre del derecho internacional', se basó fuertemente en conceptos del ius gentium romano. La idea estoica de que todos los humanos comparten razón proporcionó la base filosófica."}]},
"law18":{name:"Relaciones Patrón-Cliente (Clientela)",desc:"Fundamento de la estructura social romana: salutatio matutina, reparto de sportula. Obligaciones políticas que unían a todas las clases.",facts:["Salutatio: los clientes visitaban al patrón cada amanecer","Sportula: 6,25 sestercios de limosna diaria","Marcial: '¿Qué poeta no ama la limosna?'"],locs:[{n:"Roma",info:"Cada mañana, los clientes acudían en masa a las casas de los patronos.",wiki:"La relación patrón-cliente (clientela) era el pegamento de la sociedad romana. Los patronos ricos (patroni) proporcionaban protección legal, apoyo financiero y avance político a sus clientes (clientes). A cambio, los clientes proporcionaban apoyo político, votos y asistencia diaria en la salutatio matutina — saludo ritual en la casa del patrón. Desde la República tardía, los patronos distribuían la sportula — originalmente cesta de comida, luego entrega en efectivo de 6,25 sestercios. Los poemas de Marcial están llenos de quejas amargas sobre las indignidades de la vida del cliente: despertar antes del amanecer, caminar bajo la lluvia, adular a un grosero por una limosna mezquina."}]},
"law19":{name:"Contratos y Derecho Comercial Romano",desc:"Stipulatio, emptio venditio, locatio conductio: el derecho contractual romano sustenta el derecho comercial moderno mundial.",facts:["Stipulatio: '¿Prometes? Prometo'","Bona fides (buena fe) sigue siendo principio legal","Digesto de Justiniano: 9.000 fragmentos jurídicos"],locs:[{n:"Roma",info:"Los juristas romanos crearon la base del derecho contractual moderno.",wiki:"El derecho contractual romano era notablemente sofisticado y forma la base de los sistemas de derecho civil modernos en todo el mundo. Tipos clave de contrato: stipulatio (contrato verbal formal — '¿Prometes? Prometo'), emptio venditio (venta), locatio conductio (arrendamiento), mandatum (mandato/agencia) y societas (sociedad). Juristas romanos como Gayo, Papiniano, Ulpiano y Paulo desarrollaron conceptos aún usados hoy: bona fides (buena fe), consensus (acuerdo mutuo), vitium (defecto) y dolus malus (fraude). El Digest de Justiniano recopiló 9.000 fragmentos de escritos jurídicos, preservando esta tradición legal para la posteridad."}]},
"law20":{name:"Imperium y Auctoritas",desc:"Imperium: poder ejecutivo de mando. Auctoritas: autoridad moral. El genio de Augusto fue reclamar solo auctoritas mientras ejercía imperium.",facts:["Imperium: poder legal de mando","Auctoritas: autoridad moral y prestigio","Augusto: maestro de la ficción"],locs:[{n:"Roma",info:"Los dos pilares de la autoridad política romana.",wiki:"El poder político romano descansaba en dos conceptos. Imperium era autoridad ejecutiva legal — el poder de comandar ejércitos, administrar justicia y ejecutar ciudadanos. Lo tenían cónsules, pretores y dictadores, simbolizado por los fasces (haz de varas y hacha) llevados por lictores. Auctoritas era autoridad moral informal — influencia derivada de prestigio, sabiduría y historial de servicio. El poder del Senado era mayormente auctoritas, no imperium. La genialidad política de Augusto fue afirmar en sus Res Gestae que superaba a todos en auctoritas mientras no ocupaba cargo que no tuvieran sus colegas — ficción magistral que disfrazaba autocracia como República."}]},
"mil16":{name:"Ingenieros de Asedio Romanos",desc:"Balistas, onagros, escorpiones: torres de asedio, arietes, minería. Apolodoro diseñó el equipamiento de Trajano.",facts:["Rampa de Masada: 100 metros de alto","Alesia: doble circunvalación (39 km en total)","Balistas con precisión de 300 metros"],locs:[{n:"Masada",info:"73 d.C.: Roma construyó una enorme rampa de asedio por el acantilado.",wiki:"La ingeniería de asedio romana no tuvo parangón en el mundo antiguo. La artillería incluía ballistae (lanzadores de proyectiles precisos a 300 m), onagri (lanzadores de piedras) y scorpiones (armas ligeras anti-persona). En Masada, Flavio Silva construyó una enorme rampa de tierra de 100 metros de alto por la cara del acantilado para alcanzar la fortaleza — hazaña de ingeniería visible hoy. En Alesia, César construyó 18 km de murallas mirando hacia adentro Y 21 km mirando hacia afuera. Apolodoro de Damasco diseñó equipo de asedio para las Guerras Dacias de Trajano."},{n:"Alesia",info:"52 a.C.: doble circunvalación de César — obra maestra de ingeniería militar.",wiki:"El asedio de Alesia por César presentó doble línea de fortificaciones: 18 km de contravalación frente a los galos sitiados dentro, y 21 km de circunvalación frente al ejército de socorro fuera. Las trampas incluían estacas afiladas (lilia), cepos con puntas de hierro (stimuli) y fosos ocultos. Era la ingeniería de asedio más sofisticada que el mundo antiguo había visto."},{n:"Roma",info:"La tecnología de asedio se desarrolló durante siglos.",wiki:"La guerra de asedio romana evolucionó de simple escalada a ingeniería compleja. Vitruvio (Libro X) describe arietes, torres de asedio y pantallas protectoras (testudo). La ventaja clave romana era paciencia y logística — podían sostener asedios durante años (Veii: 10 años, Numancia: 8 meses de circunvalación, Jerusalén: 5 meses)."}],pathLabels:["Ingeniería de asedio romana por todo el imperio"]},
"mil17":{name:"Estandartes Militares y Águilas Romanas",desc:"El aquila (águila) era sagrada para cada legión: su pérdida era imperdonable. Augusto recuperó los estandartes perdidos de Craso.",facts:["Mario hizo del águila el único estandarte (104 a.C.)","Perder un águila: la legión podía ser disuelta","Augusto recuperó las águilas de Craso (20 a.C.)"],locs:[{n:"Roma",info:"Los estandartes se guardaban en el santuario de la legión (sacellum).",wiki:"Cada legión romana llevaba un aquila (águila) — estandarte de águila de oro o plata que era el alma de la legión. Se guardaba en el sacellum (santuario) del campamento y custodiado por la primera cohorte. Perder un águila era la máxima desgracia — la legión podía ser disuelta. Mario hizo del águila el único estandarte legionario en 104 a.C. Cuando Craso perdió tres águilas en Carras (53 a.C.), atormentó a Roma durante décadas. Augusto las recuperó mediante diplomacia en 20 a.C. — evento celebrado en monedas y la estatua de Prima Porta."},{n:"Carras",info:"53 a.C.: las águilas de Craso capturadas por Partia.",wiki:"La pérdida de las águilas de Craso en Carras fue un trauma nacional. Los partos las desfilaron en triunfo. Augusto hizo de su recuperación prioridad diplomática — en 20 a.C., el rey parto las devolvió. Augusto construyó el Templo de Marte Vengador para albergarlas. Fue una de sus mayores victorias propagandísticas."}],pathLabels:["Águilas perdidas recuperadas de Partia"]},
"mil18":{name:"El Limes y el Sistema de Defensa Fronteriza",desc:"Más de 10.000 km de frontera: torres de vigilancia, estaciones de señales, caminos de patrulla, zonas de amortiguación. La piel del imperio.",facts:["Más de 10.000 km de defensas fronterizas","Limes Germánico: 900 torres de vigilancia, 60 fuertes","Muro de Adriano: 15.000 soldados de guarnición"],locs:[{n:"Saalburg",info:"Fuerte reconstruido en el Limes germánico.",wiki:"La frontera romana (limes) se extendía más de 10.000 km desde el Muro de Adriano en Britania hasta el Éufrates en Siria. No era un solo muro sino un sistema: torres de observación (cada 500 m en el Limes germánico), estaciones de señales usando fuego y humo, caminos de patrulla, fuertes (cada 10-15 km) y zonas de amortiguación. Solo el Limes germánico tenía 568 km de empalizada/muro, 900 torres de vigilancia y 60 fuertes."},{n:"Muro de Adriano",info:"Muro de 117 km con 80 milecastles y 160 torres.",wiki:"El Muro de Adriano era la frontera más elaborada del imperio: muro de piedra de 3 m de ancho y 4-5 m de alto, extendiéndose 117 km de costa a costa por Britania. Tenía un milecastle cada milla romana, dos torres entre cada milecastle, y un foso (vallum) al sur. 15.000 tropas guarnecían sus fuertes."},{n:"Dura-Europos",info:"Guarnición fronteriza oriental en el Éufrates.",wiki:"La frontera oriental a lo largo del Éufrates se defendía diferente — fuertes del desierto, tribus árabes aliadas y caballería móvil. Dura-Europos era una ciudad guarnición clave cuya destrucción por los sasánidas (c. 257 d.C.) preservó asombrosa evidencia arqueológica de la vida militar fronteriza, incluyendo escudos pintados, edificios religiosos y túneles de asedio."}],pathLabels:["Limes septentrional desde Alemania a Britania","10.000 km de frontera"]},
"mil19":{name:"Inteligencia y Espionaje Romanos",desc:"Speculatores (exploradores/espías), frumentarii (policía secreta), agentes in rebus. La inteligencia de César ganó la Galia.",facts:["Speculatores: exploradores, espías y asesinos","Frumentarii: policía secreta tan odiada que fue disuelta","César: maestro de la inteligencia militar"],locs:[{n:"Roma",info:"Redes de inteligencia operaban desde Roma por todo el imperio.",wiki:"Roma mantuvo sofisticadas operaciones de inteligencia a lo largo de su historia. Los speculatores servían como exploradores, espías y asesinos adjuntos a cada legión. Bajo el Imperio, los frumentarii (originalmente oficiales de suministro de grano) se convirtieron en policía secreta — recopilando inteligencia, entregando mensajes sensibles y realizando arrestos y asesinatos. Eran tan temidos y odiados que Diocleciano los disolvió, reemplazándolos con los agentes in rebus. César era maestro de la inteligencia: sus Comentarios de la Guerra de las Galias revelan uso sistemático de exploradores, interrogación de prisioneros y soborno de informantes locales."}]},
"mil20":{name:"Logística y Cadena de Suministro Romana",desc:"Alimentar a más de 300.000 soldados: grano, vino, aceite, equipamiento. Graneros horrea. Las tablillas de Vindolanda revelan los detalles.",facts:["Cada legión consumía 7.500 kg de grano diarios","Tablillas de Vindolanda: 'por favor envíen más cerveza'","Sistema de suministro no igualado hasta la era moderna"],locs:[{n:"Vindolanda",info:"Tablillas de madera revelan los detalles del suministro militar romano.",wiki:"Las tablillas de escritura de Vindolanda — encontradas en un fuerte cerca del Muro de Adriano — están entre los hallazgos romanos más importantes en Britania. Revelan la logística cotidiana de una guarnición fronteriza: peticiones de suministro ('por favor envía más cerveza'), informes de estado, listas de deberes, invitaciones a fiestas de cumpleaños y cartas a casa. Proporcionan visión incomparable de la cadena de suministro militar romana."},{n:"Roma",info:"Centro logístico central del ejército romano.",wiki:"Abastecer a más de 300.000 tropas en 10.000 km de frontera requería un sistema logístico sin parangón hasta la era moderna. Cada legión consumía aproximadamente 7.500 kg de grano diariamente. Los horrea (graneros) en bases principales podían almacenar el suministro de un año entero. El cursus publicus (correo imperial) y la red de caminos proporcionaban comunicación. El transporte marítimo movía suministros a granel — mucho más barato que por tierra. La annona militaris (impuesto de suministro militar) extraía grano, animales, cuero y reclutas de poblaciones provinciales."},{n:"Carnunto",info:"Importante base legionaria con extensa infraestructura de suministro.",wiki:"Carnunto en el Danubio era una de las mayores bases militares del imperio — albergando la Legio XIV Gemina y luego la Legio XV Apollinaris. Las excavaciones revelan enormes graneros, talleres produciendo armas y armadura, y un asentamiento civil de 50.000 apoyando la guarnición. El anfiteatro, complejo de termas y museo militar sobreviven."}],pathLabels:["Cadena de suministro desde la frontera a Roma","Logística a la frontera danubiana"]},
"cit16":{name:"Siracusa",desc:"La ciudad de Arquímedes: cayó ante Marcelo tras un asedio de 2 años. Cicerón encontró la tumba de Arquímedes cubierta de maleza. La mayor ciudad griega de Occidente.",facts:["Las máquinas de Arquímedes retrasaron el asedio 2 años","Marcelo lloró ante la destrucción de la ciudad","Cicerón encontró la tumba de Arquímedes cubierta de maleza"],locs:[{n:"Siracusa",info:"Mayor y más rica ciudad griega del Mediterráneo occidental.",wiki:"Siracusa en Sicilia era la mayor ciudad griega del Mediterráneo occidental — rivalizando con Atenas en poder y cultura. Durante la Segunda Guerra Púnica, se alió con Cartago. Roma la sitió durante dos años (214-212 a.C.) — retrasada por las ingeniosas máquinas de guerra de Arquímedes (catapultas, grúas de agarre, posiblemente espejos). Cuando cayó, Marcelo lloró ante la destrucción. Arquímedes fue asesinado por un soldado romano a pesar de las órdenes de perdonarlo (leyenda: \"No perturbes mis círculos\"). Cicerón, visitando 75 años después, encontró la tumba de Arquímedes cubierta de maleza. Bajo Roma, Siracusa siguió siendo importante — su trigo alimentaba la capital."}]},
"cit17":{name:"Baalbek (Heliópolis)",desc:"El mayor complejo de templos romanos jamás construido: columnas de 19 m, piedras del Trilithon de 800 toneladas cada una.",facts:["El mayor complejo de templos romanos jamás construido","Piedras del Trilithon: 800 toneladas cada una","El Templo de Baco es mayor que el Partenón"],locs:[{n:"Baalbek",info:"Patrimonio de la Humanidad por la UNESCO — los templos romanos más colosales.",wiki:"Baalbek (antigua Heliópolis — Ciudad del Sol) en el Líbano actual contiene el mayor complejo de templos romanos jamás construido. El Templo de Júpiter Heliopolitano tenía 54 columnas de 19 metros de altura cada una — solo 6 sobreviven, pero son las columnas romanas en pie más altas del mundo. El podio descansa sobre el Trilithon — tres piedras que pesan aproximadamente 800 toneladas cada una, entre los mayores bloques de construcción de la historia. Una cuarta piedra (la Piedra de la Mujer Embarazada, 1.000 toneladas) fue extraída pero nunca movida. El adyacente Templo de Baco (en realidad mejor conservado) es más grande que el Partenón. Patrimonio de la Humanidad por la UNESCO."}]},
"cit18":{name:"Petra",desc:"Capital nabatea anexionada por Trajano: el Tesoro tallado en arenisca. Ingeniería hidráulica en el desierto. UNESCO.",facts:["Tesoro tallado en arenisca viva","Ingeniería hidráulica sostenía 30.000 personas en un desierto","Redescubierta por Burckhardt en 1812"],locs:[{n:"Petra",info:"Patrimonio de la Humanidad por la UNESCO — una de las Nuevas Siete Maravillas.",wiki:"Petra — \"la ciudad rosa-roja, mitad de antigua como el tiempo\" — fue la capital del reino nabateo desde el siglo IV a.C. Los nabateos se enriquecieron controlando el comercio de incienso desde Arabia hasta el Mediterráneo. El Tesoro (Al-Khazneh), tallado directamente en arenisca rosa, es uno de los monumentos antiguos más reconocidos del mundo. La ingeniería hidráulica de la ciudad era notable: canales, presas y cisternas sustentaban una población de 30.000 en medio del desierto. Roma anexó el reino nabateo en 106 d.C. bajo Trajano. Petra siguió prosperando como ciudad romana, con una calle principal columnada, teatro y termas añadidos. Un terremoto en 363 d.C. y el cambio de rutas comerciales provocaron su declive. Estuvo \"perdida\" para el mundo occidental hasta que Burckhardt la redescubrió en 1812."}]},
"cit19":{name:"Pérgamo",desc:"Gran Altar de Zeus, biblioteca rival de Alejandría, pergamino inventado aquí. Centro de curación Asclepion. Joya del Asia romana.",facts:["Biblioteca: 200.000 rollos, segunda tras Alejandría","Pergamino (pergamena) inventado aquí","Galeno se formó en el Asclepion"],locs:[{n:"Pérgamo",info:"Bergama actual, Turquía — magníficas ruinas helenísticas y romanas.",wiki:"Pérgamo (Bergama actual, Turquía) era una de las mayores ciudades del mundo antiguo. Su biblioteca albergaba 200.000 rollos — solo superada por Alejandría. Cuando Egipto cortó las exportaciones de papiro, Pérgamo inventó el pergamino (pergamena) como material de escritura. El Gran Altar de Zeus (ahora en el Museo de Pérgamo de Berlín) presentaba un friso de 113 metros de la Gigantomaquia — una de las obras maestras de la escultura antigua. El Asclepeion (centro de curación) atraía a pacientes de todo el Mediterráneo; Galeno se formó aquí. Legada a Roma en 133 a.C., se convirtió en la capital de la provincia de Asia."}]},
"cit20":{name:"Aquileya",desc:"Puerta de los Alpes orientales: 4.ª ciudad más grande de Italia. Atila la arrasó. Los refugiados fundaron Venecia. Mosaicos impresionantes.",facts:["4.ª ciudad más grande de Italia","Mayor mosaico paleocristiano de suelo en Occidente","Los refugiados de Atila fundaron Venecia"],locs:[{n:"Aquilea",info:"Patrimonio de la Humanidad por la UNESCO — ciudad puerta del noreste romano.",wiki:"Aquilea fue fundada en 181 a.C. como colonia latina para defenderse de las incursiones celtas e ilirias. Se convirtió en la cuarta ciudad más grande de Italia (tras Roma, Milán y Capua) y la principal puerta hacia los Alpes orientales y la frontera del Danubio. Su comercio de ámbar, talleres de vidrio y puerto la hicieron enormemente próspera. La basílica del siglo IV contiene el mayor y más fino mosaico de suelo paleocristiano de Occidente — 760 m² que representa la historia de Jonás, el Buen Pastor y criaturas marinas. En 452 d.C., los hunos de Atila sitiaron y destruyeron Aquilea; los refugiados huyeron a las lagunas y — según la tradición — fundaron Venecia. Patrimonio de la Humanidad por la UNESCO."}]},
"sci16":{name:"Cirugía e Instrumentos Quirúrgicos Romanos",desc:"Operación de cataratas, trepanación, amputación: más de 200 tipos de instrumentos encontrados. Mejor que la cirugía medieval.",facts:["Más de 200 tipos de instrumentos identificados","Celso describió cirugía de cataratas y hernias","No superada hasta el siglo XVIII"],locs:[{n:"Pompeya",info:"Casa del Cirujano: más de 40 instrumentos encontrados.",wiki:"La práctica quirúrgica romana era notablemente sofisticada. Se han identificado más de 200 tipos de instrumentos quirúrgicos — escalpelos, fórceps, palancas óseas, espéculos, catéteres y herramientas de trepanación. La Casa del Cirujano en Pompeya produjo más de 40 instrumentos. Celso describe la reclinación de cataratas (empujar el cristalino nublado con una aguja), litotomía (extracción de cálculos vesicales), reparación de hernias y cirugía plástica para reversión de circuncisión. Galeno realizó cirugía cerebral y operaciones oculares."},{n:"Rímini",info:"Domus del Chirurgo: más de 150 instrumentos encontrados — el hallazgo más rico.",wiki:"La Domus del Chirurgo (Casa del Cirujano) en Rímini (Ariminum) produjo más de 150 instrumentos quirúrgicos — la mayor colección jamás encontrada en un solo yacimiento romano. Los instrumentos sugieren que el médico practicaba cirugía general, oftalmología, ortopedia y ginecología. La calidad de la artesanía rivaliza con equivalentes modernos."},{n:"Roma",info:"Cirujanos militares y civiles practicaban por toda la ciudad.",wiki:"Roma tenía tanto cirujanos militares (adscritos a las legiones) como practicantes civiles. Arcatago — el primer cirujano griego en Roma (219 a.C.) — fue inicialmente llamado \"el Sanador\" pero fue renombrado \"el Carnicero\" tras demasiadas amputaciones. En el Imperio, la cirugía era lo suficientemente sofisticada como para no ser superada hasta el siglo XVIII."}],pathLabels:["Conocimiento quirúrgico por toda Italia"]},
"sci17":{name:"Metalurgia Romana",desc:"Armas de acero, tuberías de plomo, estatuaria de bronce: los núcleos de hielo de Groenlandia muestran que la contaminación por plomo romana alcanzó su pico en el siglo I d.C.",facts:["Núcleos de hielo de Groenlandia muestran el pico de contaminación romana","Armas de acero producidas por carburación","La escoria de Río Tinto aún contamina los ríos hoy"],locs:[{n:"Roma",info:"La enorme demanda de metales impulsó la minería en todo el imperio.",wiki:"La metalurgia romana era la más avanzada del mundo antiguo. El hierro se fundía en hornos de pozo que alcanzaban 1.200°C — no suficiente para fundir completamente el hierro, pero suficiente para producir acero (hierro carburado) para armas y herramientas. La fundición de bronce producía grandes estatuas: la estatua ecuestre de Marco Aurelio es una obra maestra. El plomo se usaba extensivamente para tuberías, ataúdes y como edulcorante (acetato de plomo en el vino). Los núcleos de hielo de Groenlandia muestran que la contaminación atmosférica por plomo alcanzó su máximo durante el período romano — no superada hasta la Revolución Industrial."},{n:"Río Tinto",info:"Enorme complejo minero romano en España.",wiki:"Río Tinto en España era una de las mayores operaciones mineras del mundo romano. Se extraían cobre, oro y plata usando molinos de estampación accionados por agua y tornillos de Arquímedes para drenaje. Los montones de escoria de las operaciones romanas contienen millones de toneladas de residuos. La contaminación fue tan severa que escoria de 2.000 años aún contamina los ríos locales."}],pathLabels:["Los metales españoles fluyen hacia Roma"]},
"sci18":{name:"Sorano y la Medicina Femenina",desc:"Ginecología y obstetricia: describió anticoncepción, embarazo, parto. El texto antiguo más avanzado sobre salud femenina.",facts:["Texto antiguo más avanzado sobre salud femenina","Describió técnicas anticonceptivas y obstétricas","Referencia estándar hasta el periodo medieval"],locs:[{n:"Éfeso",info:"Lugar de nacimiento de Sorano — centro de aprendizaje médico.",wiki:"Sorano de Éfeso (fl. 98-138 d.C.) escribió el texto antiguo más completo sobre ginecología y obstetricia. Su Ginecología cubre menstruación, concepción, embarazo, partos difíciles, cuidado del recién nacido y enfermedades ginecológicas. Describió métodos anticonceptivos (pesarios, métodos de barrera, calendario), criterios para seleccionar una nodriza y técnicas para girar bebés de nalgas. Rechazó supersticiones comunes e insistió en medicina racional y empírica."},{n:"Roma",info:"Sorano practicó medicina en Roma.",wiki:"Sorano practicó en Roma bajo Trajano y Adriano. Perteneció a la escuela metódica de medicina (que se centraba en los estados de tensión y relajación del cuerpo). Su obra influyó en el resumen latino de Muscio, que permaneció como texto obstétrico estándar en la Europa medieval. Su descripción del cuidado infantil no fue mejorada durante siglos."}],pathLabels:["De Éfeso a Roma"]},
"sci19":{name:"Astronomía y Medición del Tiempo Romanas",desc:"Relojes de sol, clepsidras, Astronómica de Manilio: el gran reloj solar de Augusto en el Campo de Marte usaba un obelisco egipcio.",facts:["Reloj solar de Augusto: obelisco de 30 m como gnomon","Las 'horas' romanas variaban según la estación","El modelo geocéntrico de Ptolomeo duró 1.400 años"],locs:[{n:"Roma/Campo de Marte",info:"Solarium de Augusto: un obelisco como gnomon para un gigantesco reloj de sol.",wiki:"La medición del tiempo romana dependía de relojes de sol (horologia solaria) y clepsidras. Augusto erigió un enorme reloj de sol en el Campo de Marte usando un obelisco egipcio de 30 metros (de Heliópolis) como gnomon — su sombra marcaba las horas y estaciones a través de un pavimento de incrustaciones de bronce. Los romanos dividían el día en 12 horas independientemente de la estación, así que las \"horas\" variaban en longitud a lo largo del año. El Astronomica de Manilio (c. 10 d.C.) fue el primer poema latino sobre astrología y astronomía."},{n:"Alejandría",info:"Fuente del conocimiento astronómico que Roma adoptó.",wiki:"El conocimiento astronómico romano procedía principalmente de fuentes griegas y egipcias vía Alejandría. El Almagesto de Ptolomeo (c. 150 d.C.) — escrito en el Egipto romano — presentaba el modelo geocéntrico que dominó la astronomía durante 1.400 años. La astronomía práctica romana se centraba en el calendario (reforma juliana), el calendario agrícola, la navegación y la astrología — que era enormemente popular; los emperadores mantenían astrólogos de corte."}],pathLabels:["La astronomía alejandrina llega a Roma"]},
"sci20":{name:"Medicina Veterinaria Romana",desc:"Mulomedicina de Vegecio: el ejército dependía de caballos y mulas sanos. La gestión ganadera era una ciencia.",facts:["'Veterinario' viene del latín veterinae","Vegecio: texto veterinario antiguo más completo","El ejército romano empleaba médicos veterinarios especializados"],locs:[{n:"Roma",info:"El cuidado veterinario era esencial para el ejército y la agricultura.",wiki:"La medicina veterinaria romana (ars veterinaria — el término mismo viene del latín veterinae, \"bestias de carga\") era una ciencia práctica impulsada por necesidades militares y agrícolas. Vegecio Renato (siglos IV-V d.C.) escribió la Mulomedicina (también llamada Digesta Artis Mulomedicinae) — el texto veterinario antiguo más completo. Cubre enfermedades equinas, procedimientos quirúrgicos, tratamientos farmacológicos y gestión de establos. El tratado agrícola de Columela dedica extensas secciones a la salud del ganado. El ejército romano empleaba especialistas veterinarios (medici veterinarii) — una caballería sana dependía de caballos sanos."}]},
"dlf16":{name:"Patronazgo Romano y la Salutatio",desc:"Los clientes visitaban a los patronos cada amanecer para el saludo matutino: limosna en metálico de la sportula. Marcial se quejaba amargamente. Pegamento social de Roma.",facts:["Sportula: 6,25 sestercios de limosna diaria","Los clientes se ponían la toga y caminaban antes del amanecer","Marcial: cronista amargo de la vida del cliente"],locs:[{n:"Roma",info:"Cada mañana, los clientes abarrotaban las puertas de los patronos.",wiki:"La salutatio (saludo matutino) era uno de los rituales sociales más distintivos de Roma. Antes del amanecer, los clientes (clientes) se ponían sus togas y caminaban — a veces por toda la ciudad — hasta la casa de su patrón. Esperaban en el vestíbulo hasta ser admitidos para saludar formalmente al patrón: \"Ave, domine\" (Salve, señor). A cambio, recibían la sportula — originalmente una cesta de comida, luego una limosna en efectivo de 6,25 sestercios (aproximadamente los gastos básicos de un día). Los epigramas de Marcial están llenos de humor amargo sobre este sistema: la humillación de esperar en el frío, el patrón tacaño, la invitación a cenar incomible. Sin embargo, el sistema funcionaba: unía ricos y pobres, poderosos y débiles, en una red de obligación mutua que sustentó el orden social de Roma durante siglos."}]},
"dlf17":{name:"Mascotas y Animales Romanos",desc:"Perros, gatos, pájaros, mascotas exóticas: mosaicos 'Cave canem'. Los romanos amaban a sus animales tanto como cualquier sociedad moderna.",facts:["'Cave canem': el mosaico romano más famoso","Craso supuestamente lloró por su anguila mascota","El comercio de animales agotó la fauna de tres continentes"],locs:[{n:"Pompeya",info:"Mosaicos \"Cave canem\" y esqueletos de perros encontrados aquí.",wiki:"Los romanos tenían una gran variedad de mascotas. Los perros eran los más populares — el moloso (tipo mastín) para guardia, el laconio (tipo galgo) para caza y pequeños perros falderos (catelli) como compañía. El famoso mosaico \"Cave canem\" (Cuidado con el perro) en la Casa del Poeta Trágico de Pompeya muestra un perro negro encadenado. Los gatos eran valorados como cazadores de ratones. Los romanos ricos tenían mascotas exóticas: loros enseñados a hablar latín, monos vestidos con ropa, anguilas de compañía (Craso supuestamente lloró cuando murió la suya) e incluso ciervos domesticados. Plinio el Joven describió delfines salvajes que se hicieron amigos de nadadores."},{n:"Roma",info:"El comercio de animales exóticos abastecía tanto mascotas como arena.",wiki:"El comercio de animales de Roma era enorme — abasteciendo tanto el mercado de mascotas como la arena. El norte de África proporcionaba leones, leopardos y elefantes. India enviaba tigres y loros. España suministraba caballos. El comercio agotó la vida silvestre en tres continentes. En el siglo IV, Hipona (norte de África) no tenía hipopótamos, y los leones de Numidia estaban extinguidos."}]},
"dlf18":{name:"Carreras de Carros y las Facciones",desc:"Azules, Verdes, Rojos, Blancos: 250.000 en el Circo Máximo. Los aurigas eran superestrellas. Los disturbios de Nika empezaron por las facciones.",facts:["Diocleciano: el atleta mejor pagado de la historia","250.000 espectadores en el Circo Máximo","Las facciones evolucionaron en partidos políticos"],locs:[{n:"Roma/Circo Máximo",info:"250.000 espectadores — mayor recinto de entretenimiento de Roma.",wiki:"Las carreras de carros eran el entretenimiento más popular de Roma — superando con creces el combate gladiatorio. El Circo Máximo albergaba 250.000 espectadores (cinco veces el Coliseo). Cuatro facciones — Azules, Verdes, Rojos y Blancos — competían con seguidores fanáticos. Los aurigas exitosos se volvieron increíblemente ricos: Cayo Apuleyo Diocles (siglo II d.C.) ganó 35.863.120 sestercios en su carrera — el atleta mejor pagado de la historia ajustado por economía. Las carreras eran 7 vueltas alrededor de la spina (barrera central), a velocidad letal. Los choques (naufragia — naufragios) eran comunes y a menudo fatales."},{n:"Constantinopla/Hipódromo",info:"Las facciones se convirtieron en partidos políticos — los disturbios de Nika (532 d.C.).",wiki:"En Constantinopla, las facciones de carros evolucionaron en cuasi-partidos políticos. Azules y Verdes tenían sus propios barrios, líderes y agendas políticas. En 532 d.C., ambas facciones se unieron contra Justiniano en los disturbios de Nika — 30.000 murieron. Las carreras de carros continuaron en el Hipódromo hasta 1204."}],pathLabels:["La cultura de las carreras de Roma a Constantinopla"]},
"dlf19":{name:"Grafitis y Vida Callejera Romana",desc:"Más de 11.000 grafitis en Pompeya: eslóganes electorales, poemas de amor, insultos, anuncios. 'Me asombra, oh muro, que no te hayas derrumbado.'",facts:["Más de 11.000 grafitis en Pompeya","'Votad a Vatia: todos los borrachos lo apoyan'","El primer verso de Virgilio aparece 9 veces"],locs:[{n:"Pompeya",info:"Más de 11.000 grafitis — la voz de los romanos ordinarios.",wiki:"Pompeya preserva más de 11.000 grafitis y dipinti (inscripciones pintadas) — la mayor colección del mundo antiguo. Incluyen: eslóganes electorales (\"Vota por Vatia — todos los borrachos lo apoyan\"), declaraciones de amor (\"Suceso el tejedor ama a Iris, la tabernera\"), alardes sexuales, reflexiones filosóficas, citas literarias (la línea inicial de Virgilio aparece 9 veces), dibujos obscenos, arte de fans de gladiadores, práctica de aritmética, y el conmovedor \"Me pregunto, oh muro, que no te hayas derrumbado en ruinas, ya que debes soportar los tediosos garabatos de tantos escritores\". Son la voz auténtica de los romanos ordinarios — sin filtrar por la convención literaria."}]},
"dlf20":{name:"Fiestas Romanas y el Calendario",desc:"135 días festivos públicos en el siglo IV: Lupercalia, Parentalia, Saturnalia. Religión, entretenimiento y política se fusionaban.",facts:["135 días festivos públicos en el siglo IV","Lupercalia: tiras de piel de cabra para la fertilidad","'Pan y circo': la famosa queja de Juvenal"],locs:[{n:"Roma",info:"Los romanos tenían más días festivos que cualquier nación moderna.",wiki:"En el siglo IV d.C., el calendario romano contenía 135 días festivos públicos (dies festi) — más de uno de cada tres días. Los festivales principales incluían: Lupercalia (15 de febrero — jóvenes semidesnudos corrían por las calles golpeando a mujeres con tiras de piel de cabra para fertilidad), Parentalia (13-21 de febrero — nueve días honrando a los muertos), Floralia (28 de abril-3 de mayo — festival de primavera con representaciones teatrales y calles cubiertas de flores), Ludi Romani (septiembre — 15 días de juegos honrando a Júpiter) y Saturnalia (17-23 de diciembre — inversión de roles, intercambio de regalos, festines). Los días festivos públicos combinaban ritual religioso, entretenimiento (carreras de carros, juegos gladiatorios, teatro) y exhibición política (los magistrados patrocinaban juegos para ganar votos). La famosa queja de Juvenal: el pueblo romano solo se preocupaba por \"pan y circo\" (panem et circenses)."}]}
};